/// Default keychain service-name prefix for the session token (one per
/// tenant). The matching account-name is `session_token`. The Tauri
/// shell reads this entry at startup to know the bearer token to
/// present.
const SESSION_TOKEN_ACCOUNT: &str = "session_token";

fn keychain_service_for(tenant: &str) -> String {
    format!("aberp.nav.{tenant}")
}

/// Persisted artifacts (cert PEM + key PEM + fingerprint) for the
/// loopback HTTPS listener live in `~/.aberp/serve/<tenant>/`. ADR-0007
/// §Transport names "next to the keychain material" — for the
/// per-platform Keychain/Credential-Manager/secret-service backends
/// "next to" is the user-home convention. A future ADR can pick a
/// per-OS path if needed; for now the user-home posture works on all
/// three platforms.
fn serve_artifacts_dir(tenant: &str) -> Result<PathBuf> {
    let home = dirs_home_or_loud_fail()?;
    Ok(home
        .join(crate::build_profile::edition_data_dirname())
        .join("serve")
        .join(tenant))
}

/// S291 / PR-272 — env-var override for the loopback HTTPS port. The
/// dev-test.sh launcher pins ABERP to a fixed port so the storefront's
/// sister-service URL stays stable across restarts. Pure function so
/// `serve.rs::tests` can pin the precedence + parse-error behaviour
/// without touching the listener.
///
/// Precedence:
/// - `ABERP_HTTPS_PORT` parses as `u16` → use it
/// - `ABERP_HTTPS_PORT` unset OR unparseable → `args_port`
///
/// We do NOT loud-fail on a typo'd env value: the dev-test launcher
/// sets a known-good value and the operator pathway with `--port`
/// keeps working unchanged. A typo'd env in some unrelated shell
/// shouldn't deny boot.
pub(crate) fn resolve_listener_port(args_port: u16) -> u16 {
    match std::env::var("ABERP_HTTPS_PORT") {
        Ok(s) => match s.trim().parse::<u16>() {
            Ok(p) => p,
            Err(_) => {
                tracing::warn!(
                    raw = %s,
                    "ABERP_HTTPS_PORT set but not a valid u16 — falling back to --port / dynamic"
                );
                args_port
            }
        },
        Err(_) => args_port,
    }
}

/// We deliberately do NOT import the `dirs` crate (one more dep, one
/// more supply-chain surface). `std::env::var("HOME")` covers macOS
/// and Linux; `USERPROFILE` covers Windows. Loud-fail if neither is
/// set per CLAUDE.md rule 12.
fn dirs_home_or_loud_fail() -> Result<PathBuf> {
    if let Ok(h) = std::env::var("HOME") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    if let Ok(h) = std::env::var("USERPROFILE") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    Err(anyhow!(
        "neither HOME nor USERPROFILE is set — cannot locate ~/.aberp/serve/<tenant>/"
    ))
}

/// S165 / deliverable #5 — the hülye-biztos cross-stream guard. A
/// PRODUCTION build (compiled `--features production`) MUST run as
/// `tenant=prod`; a DEV build MUST NOT run as `tenant=prod`. Either
/// mismatch is a loud `exit(1)` with a remediation hint — never a
/// silent wrong-environment start (CLAUDE.md rule 12). The prod/test
/// choice is baked in at compile time, so the two streams can never
/// cross: a dev binary cannot touch real NAV even if launched as prod.
/// S434 — synthetic operator-login marker for a NAV-disabled tenant's
/// `Ready` boot state. There is no NAV technical-user login to read from
/// the keychain (the keychain is never touched in NAV-off mode), so this
/// constant stands in as the `Actor` login for the international
/// operator's mutations. Distinct, greppable, and obviously non-NAV.
pub const NAV_DISABLED_LOGIN: &str = "nav-disabled";

fn guard_tenant_matches_build(tenant: &str) {
    // ADR-0093 — the editions cross-stream guard. The sawed-off tree builds
    // only Defense (`--features production`) or Portable; the frozen prod
    // line — and its reserved `prod` tenant + `~/.aberp/prod/` database —
    // live in a *different* repo. So BOTH editions refuse the reserved
    // `prod` tenant slug. The old guard hard-locked a `--features
    // production` build onto `tenant == "prod"`, which pointed Defense
    // straight at prod's exact DB (`~/.aberp/prod/aberp.duckdb`) — the
    // ADR-0093 §Context violation. That lock is removed: Defense now runs
    // its own tenants under `~/.aberp-defense/<tenant>/`. The data ROOT is
    // edition-locked at compile time (`build_profile::EDITION`), so even
    // were this guard bypassed a binary still resolves only its own
    // `~/.aberp-<edition>/` root; this is the loud, early, operator-facing
    // half of that guarantee (CLAUDE.md rule 12).
    if tenant == "prod" {
        eprintln!(
            "❌ FATAL: '{tenant}' is the frozen prod line's reserved tenant — the {edition} \
             edition refuses it (ADR-0093). Refusing to start.",
            edition = crate::build_profile::edition_label(),
        );
        eprintln!(
            "   The editions never open prod's database (~/{prod}/prod/aberp.duckdb); they use \
             their own ~/{own}/<tenant>/ root.",
            prod = crate::build_profile::PROD_DATA_DIRNAME,
            own = crate::build_profile::edition_data_dirname(),
        );
        eprintln!(
            "   Launch run/run_defense.sh or run/run_portable.sh with ABERP_TENANT set to a \
             non-prod tenant."
        );
        std::process::exit(1);
    }
}

/// ADR-0093 — the edition DB-binding guard. Refuses to boot `serve` against
/// a database that resolves into a FOREIGN edition's root — prod's
/// `~/.aberp/` or the sibling edition's `~/.aberp-<other>/` — no matter how
/// the path arrived (`--db`, `ABERP_DB`, a hand-edited launcher, a switch
/// hint). The DB root is *derived* from the compile-time edition
/// ([`crate::build_profile::EDITION`]); this is the runtime backstop that
/// makes "a build physically cannot open another edition's DB" true even
/// under env/misconfig (FOUNDATION §5). Fires loud + `exit(1)` like
/// [`guard_tenant_matches_build`], before any port / keychain / DB access.
fn guard_db_matches_edition(db: &std::path::Path) {
    if let Err(e) = crate::tenant_registry::ensure_db_path_isolated(db) {
        eprintln!("❌ FATAL: {e}");
        eprintln!(
            "   Point --db / ABERP_DB at this edition's ~/{}/<tenant>/aberp.duckdb, or launch via \
             run/run_defense.sh / run/run_portable.sh.",
            crate::build_profile::edition_data_dirname()
        );
        std::process::exit(1);
    }
}

/// S2 / ADR-0093 — the edition STOREFRONT-REACH guard. The mirror of
/// [`guard_db_matches_edition`] for the customer storefront (`abenerp.com`):
/// refuses to boot a daemon set that polls the storefront for customer CAD /
/// pushes the catalogue when this build's edition is not allowed to reach it
/// ([`crate::build_profile::storefront_polling_allowed`] — Defense only). The
/// reach capability is *derived* from the compile-time
/// [`crate::build_profile::EDITION`]; this is the LOUD runtime backstop that
/// makes "a Portable build physically cannot poll abenerp.com" true even when
/// it is handed `[quote_intake]` config or `ABERP_QUOTE_INTAKE_*` env
/// (FOUNDATION §5). Fires loud + `exit(1)` like [`guard_db_matches_edition`],
/// before any storefront daemon spawns. Called only once storefront config
/// has actually resolved (operator asked for reach) — a Portable build with
/// no `[quote_intake]` config simply skips the spawn, no refusal needed.
fn guard_storefront_reach_matches_edition() {
    if let Err(e) = crate::build_profile::assert_storefront_reach_allowed(
        "quote-intake poll + catalogue-push + pricing-pipeline storefront daemons",
    ) {
        eprintln!("❌ FATAL: {e}");
        eprintln!(
            "   This {} build was handed [quote_intake] storefront config (seller.toml \
             or ABERP_QUOTE_INTAKE_* env), but storefront reach is compiled OUT of this \
             edition. Remove the [quote_intake] config / unset the env, or run a Defense \
             build (run/run_defense.sh).",
            crate::build_profile::edition_label()
        );
        std::process::exit(1);
    }
}

/// S165 / deliverable #3 — one-shot boot banner. PRODUCTION builds get a
/// loud red/yellow REAL-NAV warning; dev builds get a dim one-liner.
/// Bilingual (HU + EN) per the closed-vocab banner constraint. ANSI
/// colours are emitted only when stderr is a real terminal so the Tauri
/// stderr-pump's log ring does not show escape-code garbage.
fn print_boot_banner(tenant: &str) {
    use std::io::IsTerminal as _;
    let color = std::io::stderr().is_terminal();
    let endpoint = crate::build_profile::nav_endpoint().hostname();

    // ANSI helpers — no-ops when the sink is not a terminal.
    let red_bold = if color { "\x1b[1;31m" } else { "" };
    let yellow = if color { "\x1b[33m" } else { "" };
    let dim = if color { "\x1b[2m" } else { "" };
    let reset = if color { "\x1b[0m" } else { "" };

    if crate::build_profile::IS_PRODUCTION_BUILD {
        let rule = "═══════════════════════════════════════════════════════";
        eprintln!("{red_bold}{rule}{reset}");
        eprintln!("{red_bold}  ⚠️  PRODUCTION MODE — REAL NAV — REAL EMAILS{reset}");
        eprintln!("{yellow}      ÉLES ÜZEM — VALÓDI NAV — VALÓDI E-MAILEK{reset}");
        eprintln!("{red_bold}  tenant={tenant}  endpoint={endpoint}{reset}");
        eprintln!("{red_bold}{rule}{reset}");
    } else {
        eprintln!("{dim}[dev] ABERP — tenant={tenant}  endpoint={endpoint}{reset}");
        eprintln!("{dim}      [teszt] nincs valódi fiskális hatás / no real fiscal effect{reset}");
    }
}

/// S166 / prod-prep PR #2 — outcome of [`sanity_check_environment`].
///
/// `fatal` is `Some(bilingual message)` when a check failed in a way that
/// must refuse the boot; the caller prints it to stderr and `exit(1)`.
/// `warnings` are non-fatal advisories the caller logs via `tracing::warn!`.
pub(crate) struct SanityReport {
    pub fatal: Option<String>,
    pub warnings: Vec<String>,
}

/// S166 / prod-prep PR #2 — the SECOND refuse-to-start guard pass, after
/// [`guard_tenant_matches_build`]. That guard cross-checks the build vs
/// the tenant NAME; this one cross-checks the build vs the on-disk +
/// keychain ENVIRONMENT.
///
/// PRODUCTION builds enforce:
///   A. seller.toml identity — a PRESENT seller.toml whose `tax_number`
///      differs from the documented prod entity is FATAL. (A *missing*
///      seller.toml is NOT fatal here: the existing `NeedsSellerConfig`
///      boot state drives the seller-config wizard.)
///   B. NAV credentials — missing creds are FATAL only if the first-launch
///      ceremony was already completed (touchfile present) — that means
///      the keychain entries were deleted out from under a configured
///      install. Missing creds + no touchfile is the legitimate
///      first-launch path: not fatal, the wizard will populate them.
///   C. SMTP — a missing `[seller.smtp]` is a WARNING, not fatal: the
///      operator can still issue invoices, auto-email just won't fire.
///
/// Dev/test builds enforce NOTHING (any identity, creds may be absent,
/// SMTP silent) — the dev loop is unchanged.
///
/// All inputs are injected (not read inside) so the decision logic is
/// unit-testable without a keychain, a `HOME`, or a prod build.
pub(crate) fn sanity_check_environment(
    is_production: bool,
    expected_identity: Option<(&str, &str)>,
    seller_tax_number: Option<&str>,
    nav_creds_present: bool,
    first_launch_acknowledged: bool,
    smtp_configured: bool,
) -> SanityReport {
    let mut report = SanityReport {
        fatal: None,
        warnings: Vec::new(),
    };
    if !is_production {
        // Dev/test: no enforcement. The caller logs the (dev) group line.
        return report;
    }

    let tenant_name = expected_identity.map(|(t, _)| t).unwrap_or("prod");

    // A. seller.toml identity consistency.
    if let Some((_, expected_tax)) = expected_identity {
        match seller_tax_number {
            Some(tax) if tax == expected_tax => {
                tracing::info!(
                    tax_number = tax,
                    "sanity (A): seller.toml identity matches the documented prod entity"
                );
            }
            Some(other) => {
                let lines = [
                    format!("❌ FATAL: PRODUCTION build expects seller.toml tax_number {expected_tax} (Áben Consulting Kft.)"),
                    format!("            but found {other}. Refusing to start."),
                    "   This is hülye-biztos protection: a prod binary must only run against the documented prod identity.".to_string(),
                    format!("   Either: fix seller.toml at ~/{}/{tenant_name}/seller.toml, OR", crate::build_profile::edition_data_dirname()),
                    "   rebuild without --features production for dev use.".to_string(),
                    String::new(),
                    format!("❌ VÉGZETES: az ÉLES build a(z) {expected_tax} adószámot várja a seller.toml-ban (Áben Consulting Kft.),"),
                    format!("            de {other} szerepel. Az indítás megtagadva."),
                    "   Ez hülye-biztos védelem: éles bináris kizárólag a dokumentált éles identitással futhat.".to_string(),
                    format!("   Vagy: javítsd a seller.toml-t itt: ~/{}/{tenant_name}/seller.toml, VAGY", crate::build_profile::edition_data_dirname()),
                    "   fordítsd újra a --features production kapcsoló nélkül fejlesztői használatra.".to_string(),
                ];
                report.fatal = Some(lines.join("\n"));
            }
            None => {
                tracing::info!(
                    "sanity (A): seller.toml absent / identity-incomplete — deferring to the \
                     NeedsSellerConfig wizard (not fatal)"
                );
            }
        }
    }

    // B. NAV credentials present (or legitimately in first-launch).
    if nav_creds_present {
        tracing::info!("sanity (B): NAV credentials present in keychain");
    } else if first_launch_acknowledged {
        let lines = [
            "❌ FATAL: PRODUCTION build can't find NAV credentials in keychain.".to_string(),
            "   The first-launch ceremony was completed previously but the keychain entries are gone.".to_string(),
            format!("   Either: re-run the first-launch wizard (clear ~/{}/{tenant_name}/.first-launch-acknowledged), OR", crate::build_profile::edition_data_dirname()),
            "   restore the keychain entries.".to_string(),
            String::new(),
            "❌ VÉGZETES: az ÉLES build nem találja a NAV hitelesítő adatokat a kulcstartóban.".to_string(),
            "   A first-launch ceremónia korábban lezárult, de a kulcstartó-bejegyzések eltűntek.".to_string(),
            format!("   Vagy: futtasd újra a first-launch varázslót (töröld: ~/{}/{tenant_name}/.first-launch-acknowledged), VAGY", crate::build_profile::edition_data_dirname()),
            "   állítsd vissza a kulcstartó-bejegyzéseket.".to_string(),
        ];
        // Prefer the first fatal (A) if it already fired — the operator
        // fixes identity first, reboots, then sees this if still broken.
        if report.fatal.is_none() {
            report.fatal = Some(lines.join("\n"));
        }
    } else {
        tracing::info!(
            "sanity (B): NAV credentials absent and first-launch not yet acknowledged — the \
             first-launch wizard will populate them (not fatal)"
        );
    }

    // C. SMTP configured (warning only).
    if smtp_configured {
        tracing::info!("sanity (C): [seller.smtp] is configured");
    } else {
        report.warnings.push(
            "[seller.smtp] is not configured — invoices can still be issued, but auto-email \
             will not fire. Configure SMTP via Maintenance → Tenants to enable delivery. / \
             Az [seller.smtp] nincs beállítva — a számlák kiállíthatók, de az automatikus \
             e-mail nem indul el. Állítsd be az SMTP-t a Karbantartás → Bérlők menüben."
                .to_string(),
        );
    }

    report
}

/// S433 — consume the one-shot `~/.aberp/next_tenant` switch hint and, if
/// present + valid, build a `ServeArgs` with `--tenant` + `--db`
/// overridden to the switched-to tenant. Returns the (possibly cloned)
/// args plus `Some(from_slug)` when a switch was honored (so the boot can
/// record `TenantSwitched` in the new tenant's ledger).
///
/// The hint is ALWAYS consumed (deleted) on read — honor-once. An invalid
/// hint (unknown / Archived tenant, unresolvable db path) is logged loud
/// and ignored, falling back to the CLI `--tenant`: a corrupt hint can
/// never strand the operator on a tenant that won't boot.
fn resolve_effective_serve_args(args: &ServeArgs) -> (ServeArgs, Option<String>) {
    let hint = match crate::tenant_registry::consume_next_tenant_hint() {
        Ok(h) => h,
        Err(e) => {
            tracing::warn!(error = ?e, "could not read tenant switch hint; continuing with --tenant");
            None
        }
    };
    let Some(target) = hint else {
        return (args.clone(), None);
    };
    if target == args.tenant {
        return (args.clone(), None);
    }
    let bootable = matches!(
        crate::tenant_registry::read_registry(),
        Ok(reg) if reg.is_bootable(&target)
    );
    if !bootable {
        tracing::warn!(
            target = %target,
            "tenant switch hint names an unknown or archived tenant; ignored (keeping --tenant)"
        );
        return (args.clone(), None);
    }
    let db = match crate::tenant_registry::tenant_db_path(&target) {
        Ok(p) => p,
        Err(e) => {
            tracing::warn!(error = ?e, "cannot resolve switched-to tenant db path; keeping --tenant");
            return (args.clone(), None);
        }
    };
    tracing::warn!(
        from = %args.tenant,
        to = %target,
        db = %db.display(),
        "tenant switch hint honored: overriding --tenant + --db for this boot only"
    );
    let mut eff = args.clone();
    let from = std::mem::replace(&mut eff.tenant, target);
    eff.db = db;
    (eff, Some(from))
}

/// S433 — make sure the boot tenant has a row in `tenants.toml`. Existing
/// single-tenant deployments predate the registry, so the first boot of
/// this version self-heals by appending the running tenant (Active).
/// Idempotent; the display name defaults to the slug (renamable later is
/// out of scope).
fn ensure_boot_tenant_registered(slug: &str) -> Result<()> {
    let path = crate::tenant_registry::registry_path()?;
    let mut reg = crate::tenant_registry::TenantRegistry::read_from(&path)?;
    if reg.find(slug).is_some() {
        return Ok(());
    }
    reg.add(slug, slug, time::OffsetDateTime::now_utc())
        .map_err(|e| anyhow!("seed boot tenant into registry: {e}"))?;
    reg.write_to(&path)?;
    tracing::info!(tenant = %slug, "seeded boot tenant into tenants.toml registry");
    Ok(())
}

/// S433 — seed the bundled `demo` tenant on a fresh install: append it to
/// the registry (state `Demo`), provision its keychain session token +
/// fresh ledger DB, and fire `TenantDemoSeeded` in the demo tenant's own
/// ledger. Idempotent (a present `demo` slug short-circuits). Best-effort.
///
/// NOTE (S433 / NAV-off follow-up): this seeds demo as a switchable
/// registry citizen; it does NOT yet make the binary BOOT into demo by
/// default, nor seed sample partners/products/quotes. Both wait on the
/// "NAV submission off" toggle — without it the demo tenant boots into the
/// NeedsSetup wizard (no NAV creds), so booting-into-demo would just move
/// the wall. See the NAV-off readiness assessment in the session report.
fn bootstrap_demo_tenant(binary_hash: &BinaryHashHandle) -> Result<()> {
    use crate::tenant_registry;
    let path = tenant_registry::registry_path()?;
    let mut reg = tenant_registry::TenantRegistry::read_from(&path)?;
    if reg.find(tenant_registry::DEMO_SLUG).is_some() {
        return Ok(());
    }
    let now = time::OffsetDateTime::now_utc();
    // Provision the demo DB + keychain token + the TenantDemoSeeded row
    // BEFORE the registry write, so a registry row never points at a
    // half-provisioned tenant (mirrors create_tenant_request).
    let db = tenant_registry::tenant_db_path(tenant_registry::DEMO_SLUG)?;
    if let Some(parent) = db.parent() {
        std::fs::create_dir_all(parent)
            .with_context(|| format!("create demo tenant dir {}", parent.display()))?;
    }
    load_or_create_session_token(tenant_registry::DEMO_SLUG)
        .context("provision session token for demo tenant")?;
    let bh = binary_hash
        .wait()
        .map_err(|e| anyhow!("binary hash unavailable for demo seed audit: {e}"))?;
    let demo_tenant = TenantId::new(tenant_registry::DEMO_SLUG.to_string())
        .ok_or_else(|| anyhow!("demo slug is not a valid tenant id"))?;
    let payload = audit_payloads::TenantDemoSeededPayload {
        slug: tenant_registry::DEMO_SLUG.to_string(),
        display_name: tenant_registry::DEMO_DISPLAY_NAME.to_string(),
    };
    tenant_registry::emit_tenant_event(
        &db,
        demo_tenant,
        bh,
        "system-demo-seed",
        EventKind::TenantDemoSeeded,
        payload.to_bytes(),
    )
    .context("record TenantDemoSeeded in demo tenant ledger")?;
    reg.add_demo(now)
        .map_err(|e| anyhow!("seed demo tenant: {e}"))?;
    reg.write_to(&path)?;
    tracing::info!("seeded bundled demo tenant into tenants.toml registry");

    // S434 — populate the demo with a little sample data so an
    // international operator's first boot lands in a *used-looking*
    // system, not an empty one. Best-effort: a seed hiccup must never
    // block boot ([[hulye-biztos]]). The demo DB is migrated here (it is
    // a separate DB from whatever tenant booted), then seeded idempotently.
    if let Err(e) = seed_demo_sample_data(&db) {
        tracing::warn!(error = ?e, "could not seed demo sample partners/products (boot continues)");
    }
    Ok(())
}

/// S434 — idempotently seed the demo tenant's DB with a handful of
/// partners + products. Migrates the partner/product schemas first (the
/// demo DB is provisioned fresh and, unless the binary booted AS demo,
/// the main boot migration never touched it). No-op once any partner
/// exists, so re-running on an already-seeded demo costs nothing.
///
/// Sample partners use `PrivatePerson` VAT status: the demo is the
/// NAV-off international sandbox, so the HU §169 ADÓSZÁM requirement that
/// `Domestic` status carries does not apply (and `Other` is v1-deferred).
///
/// NOTE: the brief's "1 closed sample LocalOnly invoice" is deliberately
/// NOT seeded here — issuing a real invoice needs the full pipeline
/// (seller.toml identity + MNB rates provider + gap-free numbering + NAV
/// XML render), disproportionate to a boot-time seed. The operator (and
/// the customer-journey E2E gate) issues a LocalOnly invoice through the
/// real route, which is the authentic demonstration. See session report.
fn seed_demo_sample_data(db: &std::path::Path) -> Result<()> {
    use crate::nav_xml::CustomerVatStatus;
    use crate::partners::{self, PartnerInputs, PartnerKind};
    use crate::products::{self, ProductInputs, ProductUnit};
    use aberp_billing::Currency;

    let conn = Connection::open(db)
        .with_context(|| format!("open demo DuckDB at {} for sample-data seed", db.display()))?;
    partners::ensure_schema(&conn).context("ensure partners schema on demo DB")?;
    products::ensure_schema(&conn).context("ensure products schema on demo DB")?;

    // Idempotency: only seed an empty partner table.
    let existing = partners::list_partners(&conn, crate::tenant_registry::DEMO_SLUG, None)
        .context("list demo partners for idempotency check")?;
    if !existing.is_empty() {
        return Ok(());
    }

    let partner = |display: &str, legal: &str, kind: PartnerKind| PartnerInputs {
        display_name: display.to_string(),
        legal_name: legal.to_string(),
        kind,
        customer_vat_status: CustomerVatStatus::PrivatePerson,
        customer_type: Default::default(),
        tax_number: None,
        eu_vat_number: None,
        address_street: None,
        address_postal_code: None,
        address_city: None,
        address_country: Some("ZA".to_string()),
        bank_account: None,
        contact_email: None,
        contact_phone: None,
    };
    for p in [
        partner(
            "Sample Customer Ltd",
            "Sample Customer Ltd",
            PartnerKind::Customer,
        ),
        partner(
            "Acme Tooling Supplies",
            "Acme Tooling Supplies",
            PartnerKind::Supplier,
        ),
        partner(
            "Karoo Metals",
            "Karoo Metals (Pty) Ltd",
            PartnerKind::Supplier,
        ),
    ] {
        partners::create_partner(&conn, crate::tenant_registry::DEMO_SLUG, &p)
            .with_context(|| format!("seed demo partner {}", p.display_name))?;
    }

    let product = |name: &str, unit: &str, price: i64| ProductInputs {
        name: name.to_string(),
        unit: ProductUnit::Own(unit.to_string()),
        currency: Currency::Eur,
        unit_price_minor: price,
    };
    for pr in [
        product("CNC Machining — per hour", "hour", 9_000),
        product("Aluminium bracket", "pcs", 1_250),
    ] {
        products::create_product(&conn, crate::tenant_registry::DEMO_SLUG, &pr)
            .with_context(|| format!("seed demo product {}", pr.name))?;
    }
    tracing::info!("seeded demo sample data (3 partners + 2 products)");
    Ok(())
}

/// S433 — boot-time registry self-heal + fresh-install demo seed +
/// post-switch audit. Best-effort: a registry/audit hiccup must never
/// block boot ([[hulye-biztos]]).
fn record_tenant_boot(
    args: &ServeArgs,
    switched_from: Option<&str>,
    binary_hash: &BinaryHashHandle,
    tenant: &TenantId,
    fresh_install: bool,
    nav_enabled: bool,
) {
    if let Err(e) = ensure_boot_tenant_registered(&args.tenant) {
        tracing::warn!(
            error = ?e,
            "could not self-heal tenant registry at boot (Tenants screen may omit the running tenant)"
        );
    }
    if fresh_install {
        if let Err(e) = bootstrap_demo_tenant(binary_hash) {
            tracing::warn!(error = ?e, "could not seed bundled demo tenant on fresh install");
        }
    }
    // S434 — record that this tenant booted Ready WITHOUT the §169 seller
    // gate (NAV-off). One row per boot into the running tenant's own
    // ledger so operations can see which tenants run NAV-disabled.
    if !nav_enabled {
        match binary_hash.wait() {
            Ok(bh) => {
                let payload = audit_payloads::TenantSellerSetupOptionalPayload {
                    slug: args.tenant.clone(),
                };
                if let Err(e) = crate::tenant_registry::emit_tenant_event(
                    &args.db,
                    tenant.clone(),
                    bh,
                    NAV_DISABLED_LOGIN,
                    EventKind::TenantSellerSetupOptional,
                    payload.to_bytes(),
                ) {
                    tracing::warn!(error = ?e, "could not record TenantSellerSetupOptional audit");
                }
            }
            Err(e) => {
                tracing::warn!(error = ?e, "binary hash unavailable; skipping TenantSellerSetupOptional audit")
            }
        }
    }
    let Some(from) = switched_from else {
        return;
    };
    match binary_hash.wait() {
        Ok(bh) => {
            let payload = audit_payloads::TenantSwitchedPayload {
                from_slug: from.to_string(),
                to_slug: args.tenant.clone(),
            };
            if let Err(e) = crate::tenant_registry::emit_tenant_event(
                &args.db,
                tenant.clone(),
                bh,
                "tenant-switch",
                EventKind::TenantSwitched,
                payload.to_bytes(),
            ) {
                tracing::warn!(error = ?e, "could not record TenantSwitched audit in switched-to tenant ledger");
            }
        }
        Err(e) => {
            tracing::warn!(error = ?e, "binary hash unavailable; skipping TenantSwitched audit")
        }
    }
}

/// ADR-0095 §1 — actor login recorded on a `db.auto_recovered` audit entry.
/// Boot/CLI auto-recovery is a SYSTEM action, not an operator one.
const AUTO_RECOVER_LOGIN: &str = "system:auto-recover";

/// Outcome of a guarded ADR-0095 §1 recovery decision at boot.
enum BootRecovery {
    /// The DB was rebuilt + atomically installed; boot may continue.
    Recovered,
    /// A guard rail declined (no valid snapshot, or snapshot+mirror prove
    /// inconsistent). The caller keeps today's preserve-and-surface; the
    /// string is the boot-fatal reason.
    Refused(String),
}

/// Human suffix naming the retained `<db>.CORRUPT-<tag>` evidence copy, if any.
fn retained_suffix(retained: &Option<PathBuf>) -> String {
    match retained {
        Some(p) => format!(" (corrupt DB retained at {})", p.display()),
        None => String::new(),
    }
}

/// ADR-0098 R3 regression fix — pre-install hook body for
/// [`aberp_snapshot::recover_or_refuse_with_audit`]. BUILDS the
/// `db.auto_recovered` audit row (event kind + serialized payload + actor +
/// binary hash); the recovery engine appends it into the freshly-rebuilt
/// **STAGING** DB and tops the mirror up to it BEFORE the atomic swap +
/// verified-good marker. Because the row lands in the staging file (which the
/// snapshot layer folds + installs + markers), the installed DB already carries
/// the row and the marker covers the FINAL on-disk bytes — there is NO
/// post-install mutation, so nothing stales the marker and no re-checkpoint
/// window exists.
///
/// This only BUILDS the row (the app owns the payload schema); the DB open +
/// append + `sync_mirror` happen inside `aberp-snapshot`, so no new live-path
/// opener surfaces in the app tree (ADR-0093 D5 residual-opener freeze) and the
/// crate layering (aberp-snapshot below the app audit types) is respected.
/// Returns `None` (skip the row) if the binary hash is not ready — best-effort,
/// matching the historical "audit append never fails a durable recovery".
fn build_db_auto_recovered_row(
    binary_hash: &BinaryHashHandle,
    trigger: &str,
    meta: &aberp_snapshot::RecoveredMeta,
) -> Option<aberp_snapshot::StagedAuditRow> {
    // The running binary hash goes on the entry; if it is not ready yet we skip
    // the row (best-effort — same posture as the old emit path). The recovery
    // itself is already durable regardless.
    let bh = match binary_hash.wait() {
        Ok(bh) => bh,
        Err(e) => {
            tracing::warn!(error = ?e, "binary hash unavailable; skipping db.auto_recovered audit");
            return None;
        }
    };
    let payload = audit_payloads::DbAutoRecoveredPayload {
        trigger: trigger.to_string(),
        source_snapshot_seq: meta.source_snapshot_seq,
        snapshot_audit_count: meta.snapshot_audit_count,
        replayed_entries: meta.replayed_entries,
        recovered_max_seq: meta.recovered_max_seq,
        retained_corrupt_db: meta.retained_corrupt_db.clone(),
    };
    Some(aberp_snapshot::StagedAuditRow {
        binary_hash: bh,
        kind: EventKind::DbAutoRecovered,
        payload: payload.to_bytes(),
        actor: Actor::from_local_cli(Ulid::new().to_string(), AUTO_RECOVER_LOGIN),
    })
}

/// ADR-0095 §1 — attempt the guarded, reversible auto-recovery of the tenant
/// DB. Covers BOTH failure modes (a torn/unopenable live DB and an
/// ahead-of-DB mirror) with the one algorithm in
/// [`aberp_snapshot::recover_or_refuse`]: preserve evidence → rebuild from the
/// latest VALID snapshot → REPLAY the preserved mirror delta (never truncated)
/// → validate → atomic-install + marker. On success emits `db.auto_recovered`
/// and returns [`BootRecovery::Recovered`]; on a guard-rail refusal returns
/// [`BootRecovery::Refused`] (caller keeps the preserve-and-surface fallback).
/// Returns `Err` only for a hard MECHANICAL failure (a true boot-fatal).
fn attempt_db_auto_recovery(
    db_path: &Path,
    tenant: &TenantId,
    binary_hash: &BinaryHashHandle,
    trigger: &str,
) -> Result<BootRecovery> {
    let store_dir = crate::snapshot::resolve_store(tenant.as_str(), None)
        .context("resolve snapshot store for ADR-0095 auto-recovery")?;
    let mirror_path = aberp_audit_ledger::mirror_path_for(db_path);
    tracing::warn!(
        db = %db_path.display(),
        store = %store_dir.display(),
        trigger,
        "ADR-0095 §1 — attempting guarded snapshot+replay auto-recovery"
    );
    // ADR-0098 R3 fix — emit the db.auto_recovered audit row into the STAGING
    // DB (and mirror) BEFORE install, so the verified-good marker covers the
    // final DB and no post-install mutation stales it.
    let outcome = aberp_snapshot::recover_or_refuse_with_audit(
        db_path,
        &store_dir,
        &mirror_path,
        tenant.as_str(),
        |meta: &aberp_snapshot::RecoveredMeta| {
            build_db_auto_recovered_row(binary_hash, trigger, meta)
        },
    )
    .context("ADR-0095 recover_or_refuse")?;
    match outcome {
        aberp_snapshot::RecoveryOutcome::Recovered {
            source_snapshot_seq,
            snapshot_audit_count,
            replayed_entries,
            recovered_max_seq,
            retained_corrupt_db,
        } => {
            let retained = retained_corrupt_db
                .as_ref()
                .map(|p| p.display().to_string());
            tracing::warn!(
                source_snapshot_seq,
                snapshot_audit_count,
                replayed_entries,
                recovered_max_seq,
                retained_corrupt_db = ?retained,
                "ADR-0095 §1 — auto-recovery SUCCEEDED; live DB rebuilt with the \
                 db.auto_recovered row appended pre-install + verified-good marker \
                 covering the final DB (no post-install mutation)"
            );
            Ok(BootRecovery::Recovered)
        }
        aberp_snapshot::RecoveryOutcome::RefusedNoSnapshot {
            retained_corrupt_db,
        } => Ok(BootRecovery::Refused(format!(
            "no VALID snapshot in {} to rebuild from{}",
            store_dir.display(),
            retained_suffix(&retained_corrupt_db)
        ))),
        aberp_snapshot::RecoveryOutcome::RefusedUnsafe {
            reason,
            retained_corrupt_db,
        } => Ok(BootRecovery::Refused(format!(
            "{reason}{}",
            retained_suffix(&retained_corrupt_db)
        ))),
    }
}

/// ADR-0095 §1 — `aberp recover`. The single supported MANUAL crash-recovery
/// path (replaces the old hand-clear-the-sidecar surgery): runs the same
/// guarded [`aberp_snapshot::recover_or_refuse`] the boot path runs, prints the
/// outcome, and records `db.auto_recovered` on success. Returns `Err` on a
/// guard-rail refusal so a script can detect it (process exits non-zero).
pub fn run_recover(args: &crate::cli::RecoverArgs) -> Result<()> {
    // Validate the tenant id up-front (fail fast); the recovery engine re-derives
    // it from `&args.tenant` for the pre-install audit append.
    let _tenant = TenantId::new(args.tenant.clone())
        .ok_or_else(|| anyhow!("invalid tenant id {:?}", args.tenant))?;
    let store_dir = crate::snapshot::resolve_store(&args.tenant, args.store.as_deref())
        .context("resolve snapshot store for `aberp recover`")?;
    let mirror_path = aberp_audit_ledger::mirror_path_for(&args.db);
    let binary_hash = BinaryHashHandle::start_background();

    println!("aberp recover — ADR-0095 §1 guarded, reversible recovery");
    println!("  db:     {}", args.db.display());
    println!("  store:  {}", store_dir.display());
    println!("  mirror: {}", mirror_path.display());

    // ADR-0098 R3 fix — pre-install audit append (see `attempt_db_auto_recovery`).
    let outcome = aberp_snapshot::recover_or_refuse_with_audit(
        &args.db,
        &store_dir,
        &mirror_path,
        &args.tenant,
        |meta: &aberp_snapshot::RecoveredMeta| {
            build_db_auto_recovered_row(&binary_hash, "manual_cli", meta)
        },
    )
    .context("recover_or_refuse")?;
    match outcome {
        aberp_snapshot::RecoveryOutcome::Recovered {
            source_snapshot_seq,
            snapshot_audit_count,
            replayed_entries,
            recovered_max_seq,
            retained_corrupt_db,
        } => {
            let retained = retained_corrupt_db
                .as_ref()
                .map(|p| p.display().to_string());
            // ADR-0098 R3 fix — the db.auto_recovered row was appended into the
            // staging DB + mirror BEFORE install (see the hook above), so the
            // verified-good marker already covers the final DB; no post-install
            // mutation and no re-checkpoint needed here.
            println!("RECOVERED");
            println!(
                "  rebuilt from snapshot seq {source_snapshot_seq} (audit head {snapshot_audit_count})"
            );
            println!(
                "  replayed {replayed_entries} mirror entries; recovered head seq {recovered_max_seq}"
            );
            if let Some(p) = retained {
                println!("  corrupt DB retained at {p}");
            }
            Ok(())
        }
        aberp_snapshot::RecoveryOutcome::RefusedNoSnapshot {
            retained_corrupt_db,
        } => {
            if let Some(p) = &retained_corrupt_db {
                println!("  corrupt DB retained at {}", p.display());
            }
            Err(anyhow!(
                "REFUSED: no VALID snapshot in {} to rebuild from — nothing was changed; \
                 the corrupt DB and any ahead mirror are preserved for investigation",
                store_dir.display()
            ))
        }
        aberp_snapshot::RecoveryOutcome::RefusedUnsafe {
            reason,
            retained_corrupt_db,
        } => {
            if let Some(p) = &retained_corrupt_db {
                println!("  corrupt DB retained at {}", p.display());
            }
            Err(anyhow!(
                "REFUSED (unsafe): {reason} — nothing was changed; the corrupt DB and any \
                 ahead mirror are preserved for investigation"
            ))
        }
    }
}

pub fn run(args: &ServeArgs) -> Result<()> {
    // S433 — honor-once tenant switch. The Tenants admin screen writes a
    // one-shot `~/.aberp/next_tenant` hint and restarts the binary; this
    // boot consumes it (read + delete) and overrides BOTH `--tenant` and
    // `--db` to the switched-to tenant's canonical
    // `~/.aberp/<slug>/aberp.duckdb`. The override is one boot only —
    // the hint is deleted on read, so a bare `aberp serve --tenant X`
    // emergency relaunch sees no hint and runs as X (CLI path stays
    // additive). A hint pointing at an unknown/Archived tenant is
    // refused + logged loud (rule 12) rather than stranding the operator
    // on a tenant that can't boot — [[trust-code-not-operator]].
    let (effective, switched_from) = resolve_effective_serve_args(args);
    let args = &effective;

    // S433 — detect a fresh install (no tenants.toml + no per-tenant DB)
    // BEFORE any DB/registry write below turns it non-fresh. Drives the
    // bundled demo-tenant seed in `record_tenant_boot`. Backward-compat:
    // an install already in flight carries a tenant DB → not fresh → no
    // demo injection.
    let fresh_install = crate::tenant_registry::is_fresh_install_default().unwrap_or(false);

    // S434 — resolve the running tenant's NAV-synchron mode ONCE here, the
    // single switch every NAV chokepoint below reads ([[trust-code-not-operator]]):
    // the boot-state derivation (skip keychain + §169 gate → Ready), the
    // NAV daemon spawns (skip), and `submit_invoice` (store LOCAL ONLY).
    // A read/parse error falls back to NAV-on (preserves existing HU
    // behaviour). Demo + international tenants resolve `false`.
    let nav_enabled = match crate::tenant_registry::tenant_nav_enabled(&args.tenant) {
        Ok(v) => v,
        Err(e) => {
            tracing::warn!(
                error = ?e,
                tenant = %args.tenant,
                "could not resolve tenant nav_enabled from registry; defaulting NAV ON"
            );
            true
        }
    };

    // S165 / deliverable #5 — hülye-biztos cross-stream guard. Runs
    // FIRST, before the binary-hash thread, keychain, or DB are touched,
    // so a mismatched launch dies instantly with a remediation hint.
    // `args.tenant` is the authoritative tenant the server runs as (the
    // launchers set ABERP_TENANT, aberp-ui forwards it as `--tenant`).
    // The prod/test choice is COMPILE-TIME (`build_profile`), so a dev
    // binary physically cannot run as tenant=prod and vice versa.
    guard_tenant_matches_build(&args.tenant);

    // ADR-0093 — refuse to open a DB outside this edition's own root,
    // even if a launcher / env / misconfig handed us prod's or the
    // sibling edition's path via --db / ABERP_DB. Fires before the
    // port, keychain, or DB are touched (same early-refuse posture).
    guard_db_matches_edition(&args.db);

    // S165 / deliverable #3 — one-shot boot banner naming the NAV
    // environment this build talks to. Loud + colourised on a real
    // terminal so the operator can never confuse a PROD launch for a
    // dev one. Emitted to stderr (stdout carries the handshake line).
    print_boot_banner(&args.tenant);

    let _span = tracing::info_span!(
        "serve",
        tenant = %args.tenant,
        port = args.port,
        db = %args.db.display(),
    )
    .entered();

    // PR-46α.1 / session-62-fix — explicit step-entry log emits so a
    // hang at any boot step surfaces in the SPA's loading pane (via
    // recent_logs) with a name. Pre-fix, the only operator-visible
    // emit between subprocess spawn and the cert-ready log was the
    // background-thread binary-hash completion — which made a hung
    // foreground boot indistinguishable from a missing-handshake
    // emit. Step markers below name what step is in flight; the
    // LAST one logged before a stall is the suspect.
    tracing::info!("boot step: spawning background binary-hash compute");

    // PR-45a / session-61 — kick off the binary-hash compute FIRST,
    // before any other boot work. On a cold-cache debug build this
    // read+hash takes 5-10s; doing it on a background OS thread lets
    // the listener bind + handshake fire while the hash is still
    // crunching. Handlers block on `BinaryHashHandle::wait` if they
    // beat the background thread to the finish line (vanishingly
    // unlikely once the SPA finishes its initial /health probe).
    let binary_hash_handle = BinaryHashHandle::start_background();

    // 1. Resolve tenant id + load session token from the keychain.
    tracing::info!("boot step: resolving tenant id");
    let tenant = TenantId::new(args.tenant.clone()).ok_or_else(|| {
        anyhow!(
            "--tenant value '{}' is empty or has a null byte",
            args.tenant
        )
    })?;
    // PR-46α.1 / session-62-fix — explicit step-entry log so a
    // macOS keychain ACL prompt blocking `entry.get_password()` is
    // visible at the operator-facing layer. The keychain re-prompts
    // any time the binary signature changes (e.g. a rebuild); the
    // prompt window may be hidden behind the Tauri window and the
    // operator can't tell what they're waiting for.
    tracing::info!(
        "boot step: reading session token from OS keychain (may prompt for keychain access)"
    );
    let session_token = {
        let _s = tracing::info_span!("serve.session_token").entered();
        load_or_create_session_token(&args.tenant)?
    };

    // PR-44ζ / session-59 — load the NAV credentials at startup so the
    // `POST /invoices/issue` mutation route can derive a per-request
    // `Actor` without paying keychain latency on every issuance. The
    // only field we stash is `login()` (non-secret); the secret bytes
    // are dropped when this scope exits.
    //
    // PR-46α / session-62 — pre-PR-46α a missing keychain entry exited
    // the backend non-zero, which made the desktop window flash blank
    // (post-PR-45a: the Tauri shell rendered an unrecoverable Failed
    // pane). Now: a `KeychainItemMissing` variant transitions the
    // backend into the `NeedsSetup` boot state — the listener still
    // binds, the handshake still fires (with `state=needs-setup`
    // suffix), and the new `POST /api/setup-nav-credentials` route
    // lets the SPA's first-run wizard populate the four artifacts
    // without any terminal interaction. Every OTHER credential failure
    // (locked keychain, permission denied, etc.) still loud-fails per
    // CLAUDE.md rule 12 — those are operator-triage situations, not
    // first-run setup situations.
    // PR-46α.1 / session-62-fix — same prompt-warning posture as the
    // session_token step above. PR-57 / session-77: the four NAV
    // artifacts now live in ONE keychain item (`nav_credentials_blob`),
    // so the boot path is ONE `get_password` call → ONE potential ACL
    // prompt on a freshly-rebuilt binary (down from four pre-PR-57).
    // The first boot after applying PR-57 on an installation with the
    // four legacy entries still present additionally reads each of
    // those once to migrate; subsequent boots take the blob-only path.
    tracing::info!(
        "boot step: reading NAV credentials blob from OS keychain (may prompt for keychain access; \
         legacy 4-item migration on first launch after PR-57)"
    );
    // S434 — NAV-off tenants skip the entire keychain + §169 gate and boot
    // straight to Ready under a synthetic "nav-disabled" login marker. No
    // NAV credentials are loaded (none exist), the seller-identity gate is
    // optional (handled at seller-save time), and the SPA — seeing a Ready
    // handshake — mounts the dashboard, never the setup wizard.
    let initial_boot_state = if !nav_enabled {
        tracing::info!(
            tenant = %args.tenant,
            "boot step: NAV synchron OFF for this tenant — skipping keychain + §169 seller gate, \
             booting straight to Ready"
        );
        ServeBootState::Ready {
            operator_login: NAV_DISABLED_LOGIN.to_string(),
        }
    } else {
        let _s = tracing::info_span!("serve.nav_credentials").entered();
        match NavCredentials::load_from_keychain(&args.tenant) {
            Ok(creds) => {
                // PR-51 / session-71 — NAV creds present; the second
                // gate is the per-tenant seller.toml. A missing or
                // identity-incomplete file transitions to
                // NeedsSellerConfig so the SPA can fire its wizard
                // INSTEAD OF letting the operator hit the route
                // surface and get a typed `missing_seller_config` 400
                // hours later.
                derive_initial_boot_state_with_seller_check(creds.login().to_string(), &args.tenant)
            }
            Err(NavTransportError::KeychainItemMissing { item, .. }) => {
                tracing::warn!(
                    item = item,
                    "NAV credential missing from OS keychain — entering needs-setup boot state; \
                     SPA first-run wizard will populate via POST /api/setup-nav-credentials"
                );
                ServeBootState::NeedsSetup
            }
            Err(other) => {
                return Err(anyhow!(other)
                    .context("load NAV credentials from OS keychain for actor derivation"));
            }
        }
    };

    // Session-149 — read the SMTP password into the in-process cache
    // NOW, while we are still inside the boot keychain-read burst
    // (session token → NAV blob → SMTP password). Doing it here means
    // the OS sees one contiguous prompt burst on a freshly-rebuilt
    // binary, so the operator's Always-Allow consolidates and no SMTP
    // prompt surprises them later (e.g. opening Maintenance → Tenants).
    // Skips the read silently if `[seller.smtp]` is absent; never
    // hard-fails boot on a missing/locked SMTP item (see SecretsCache).
    tracing::info!(
        "boot step: reading SMTP password from OS keychain (may prompt for keychain access if \
         [seller.smtp] is configured)"
    );
    let secrets_cache = {
        let _s = tracing::info_span!("serve.smtp_password").entered();
        match setup_seller_info::seller_toml_path_for_tenant(&args.tenant) {
            Ok(path) => SecretsCache::init_at_boot(&args.tenant, &path),
            Err(e) => {
                tracing::warn!(
                    error = %format!("{e:#}"),
                    "could not resolve seller.toml path at boot — SMTP password cache left empty"
                );
                SecretsCache::empty()
            }
        }
    };

    // S166 / prod-prep PR #2 — the SECOND refuse-to-start guard pass.
    // `guard_tenant_matches_build` (above) cross-checked the build vs the
    // tenant NAME; this cross-checks the build vs the on-disk + keychain
    // ENVIRONMENT. Runs after the keychain-read burst so it reuses the
    // already-computed `initial_boot_state` (NeedsSetup ⟺ NAV creds
    // missing) — no second keychain read, no second ACL prompt. Prod
    // builds enforce; dev builds are a no-op (sanity_check_environment
    // returns an empty report).
    {
        let group = if build_profile::IS_PRODUCTION_BUILD {
            "boot step: sanity checks (prod)"
        } else {
            "boot step: sanity checks (dev)"
        };
        tracing::info!("{group}");
        let _s = tracing::info_span!("serve.sanity_checks").entered();
        let seller_path = setup_seller_info::seller_toml_path_for_tenant(&args.tenant).ok();
        let seller_tax_number = seller_path
            .as_ref()
            .and_then(|p| setup_seller_info::read_seller_identity(p).ok().flatten())
            .map(|id| id.tax_number);
        let smtp_configured = seller_path
            .as_ref()
            .map(|p| matches!(smtp_config_mod::read_smtp_config(p), Ok(Some(_))))
            .unwrap_or(false);
        let nav_creds_present = !matches!(initial_boot_state, ServeBootState::NeedsSetup);
        let first_launch_acknowledged = crate::first_launch::is_acknowledged(&args.tenant);

        let report = sanity_check_environment(
            build_profile::IS_PRODUCTION_BUILD,
            build_profile::expected_tenant_identity(),
            seller_tax_number.as_deref(),
            nav_creds_present,
            first_launch_acknowledged,
            smtp_configured,
        );
        for w in &report.warnings {
            tracing::warn!("sanity check warning: {w}");
        }
        if let Some(msg) = report.fatal {
            eprintln!("{msg}");
            std::process::exit(1);
        }

        // S171 / PR-171 — upgrade-snapshot check. If the operator ran
        // `tools/snapshot-prod.sh` before this upgrade, a
        // `.upgrade-snapshot.toml` sits alongside `seller.toml` carrying
        // the pre-upgrade `[seller.smtp]` + `[seller.numbering]`
        // sections; we compare against the current seller.toml and
        // refuse to start on drift. See `crate::upgrade_snapshot` for
        // the trust-code-not-operator rationale and the four-scenario
        // unit tests.
        if let Some(seller_path) = seller_path.as_ref() {
            let snapshot_path = seller_path.with_file_name(".upgrade-snapshot.toml");
            let _s = tracing::info_span!("serve.upgrade_snapshot_check").entered();
            match upgrade_snapshot::check_upgrade_snapshot(seller_path, &snapshot_path) {
                Ok(upgrade_snapshot::Outcome::Absent) => {
                    tracing::info!(
                        "upgrade-snapshot check: no .upgrade-snapshot.toml present — skipping"
                    );
                }
                Ok(upgrade_snapshot::Outcome::Matches) => {
                    use time::format_description::well_known::Rfc3339;
                    let ts = time::OffsetDateTime::now_utc()
                        .format(&Rfc3339)
                        .unwrap_or_else(|_| "verified".to_string());
                    // Sanitize the timestamp for use in a filename: keep
                    // ASCII alphanumerics + `-`, replace everything else
                    // (the `:` in RFC3339) with `-`.
                    let safe_ts: String = ts
                        .chars()
                        .map(|c| {
                            if c.is_ascii_alphanumeric() || c == '-' {
                                c
                            } else {
                                '-'
                            }
                        })
                        .collect();
                    if let Err(e) = upgrade_snapshot::mark_verified(&snapshot_path, &safe_ts) {
                        tracing::warn!(
                            error = %format!("{e:#}"),
                            "upgrade-snapshot matched but rename failed; \
                             boot continues — next boot will re-check (harmless)"
                        );
                    } else {
                        tracing::info!(
                            "upgrade-snapshot check: matched current seller.toml — boot proceeding"
                        );
                    }
                }
                Ok(upgrade_snapshot::Outcome::Mismatch { deltas }) => {
                    use time::format_description::well_known::Rfc3339;
                    let detected_at = time::OffsetDateTime::now_utc()
                        .format(&Rfc3339)
                        .unwrap_or_else(|_| "unknown".to_string());
                    // Best-effort audit append BEFORE the exit so the
                    // divergence is permanently hash-chained even if
                    // the operator later resolves it by mv-ing the
                    // snapshot file. A failure to append is logged but
                    // does NOT mask the refusal-to-boot.
                    if let Err(e) = record_upgrade_snapshot_mismatch_audit(
                        &args.db,
                        &args.tenant,
                        &binary_hash_handle,
                        &deltas,
                        &detected_at,
                    ) {
                        tracing::warn!(
                            error = %format!("{e:#}"),
                            "could not write UpgradeSnapshotMismatch audit entry; refusing boot anyway"
                        );
                    }
                    let msg = upgrade_snapshot::format_bilingual_error(&deltas, &snapshot_path);
                    eprintln!("{msg}");
                    std::process::exit(1);
                }
                Err(e) => {
                    // Parse failure on the snapshot file — surface and
                    // continue. The check is opt-in (operator must have
                    // run snapshot-prod.sh), so a malformed file is the
                    // operator's responsibility; loud-fail-on-parse
                    // would hold the binary hostage to a bad file.
                    tracing::warn!(
                        error = %format!("{e:#}"),
                        "upgrade-snapshot check errored — treating as Absent"
                    );
                }
            }
        }
    }

    // ADR-0098 R2 (finding B) — BEFORE any DuckDB open at boot, resume any
    // install-intent journal left by a `durable_checkpoint` that crashed mid
    // swap. This deterministically completes an interrupted rename, or deletes a
    // now-stale foreign WAL that a naive checkpoint-on-shutdown pragma would let
    // the next open double-replay, or — if it cannot be reconciled — preserves
    // evidence and refuses the boot. MUST precede provision_atomic + the first
    // billing-store open below (runs alongside R1's boot recovery guard).
    match aberp_snapshot::resume_pending_install(&args.db)
        .context("ADR-0098 R2 — resume interrupted durable-checkpoint install at boot")?
    {
        aberp_snapshot::ResumeAction::NoPendingInstall => {}
        resumed => tracing::warn!(
            db = %args.db.display(),
            ?resumed,
            "ADR-0098 R2 — resumed a crash-interrupted durable-checkpoint install before opening the DB"
        ),
    }

    // PR-73a / hotfix — run the idempotent billing schema migrations
    // at boot so an existing pre-PR-73 tenant DB picks up the five
    // `bank_account_*` columns on `invoice` before the first
    // `list_invoices` request runs `load_invoice_bank_snapshot_in_tx`.
    // Pre-PR-73a the migration only ran lazily inside the issue path's
    // `pre_tx_setup` (issue_invoice / issue_storno / issue_modification);
    // a read-only operator who opened the SPA without issuing first hit
    // a 500 from the bank-snapshot SELECT against the un-migrated
    // schema. `ADD COLUMN IF NOT EXISTS` is idempotent so re-running on
    // every boot costs nothing on already-migrated DBs.
    tracing::info!("boot step: ensuring billing schema (idempotent migrations)");
    {
        let _s = tracing::info_span!("serve.ensure_billing_schema").entered();
        if let Some(parent) = args.db.parent() {
            std::fs::create_dir_all(parent).with_context(|| {
                format!(
                    "create parent directory {} for tenant DuckDB",
                    parent.display()
                )
            })?;
        }
        // ADR-0095 §2 — atomic initial creation. When the tenant DB does not
        // yet exist, build it ASIDE at `<db>.creating-<tag>.duckdb` (run the
        // billing schema there), then atomically swap it onto the live path
        // and write a verified-good marker. A crash mid-creation leaves only a
        // disposable temp (cleaned next boot), NEVER a torn file at the live
        // path — the exact Defense first-launch failure (root cause #3). Inert
        // on the happy path: an existing DB skips this branch entirely.
        if !args.db.exists() {
            tracing::info!(
                db = %args.db.display(),
                "boot: tenant DB absent — provisioning atomically (ADR-0095 §2)"
            );
            aberp_snapshot::provision_atomic(&args.db, |creating| {
                let mut store = DuckDbBillingStore::open(creating)?;
                store.ensure_schema()?;
                Ok::<(), anyhow::Error>(())
            })
            .with_context(|| {
                format!(
                    "atomically provision initial tenant DuckDB at {}",
                    args.db.display()
                )
            })?;
        }
        // ADR-0095 §1 — boot safe-open + auto-recover. Open the live DB; if it
        // EXISTS but will not open, that is the torn-checkpoint signature
        // (`Failed to load metadata pointer`, root cause #1). Route it through
        // the guarded, reversible recovery instead of a fatal boot. On a
        // guard-rail refusal keep today's preserve-and-surface (now the last
        // resort, not the only outcome). The happy path — a clean open — is
        // byte-identical to before.
        let mut billing_store = match DuckDbBillingStore::open(&args.db) {
            Ok(store) => store,
            Err(open_err) if args.db.exists() => {
                tracing::error!(
                    db = %args.db.display(),
                    error = %open_err,
                    "billing DB exists but failed to open at boot — attempting ADR-0095 §1 auto-recovery"
                );
                let recovery =
                    attempt_db_auto_recovery(&args.db, &tenant, &binary_hash_handle, "torn_open")?;
                match recovery {
                    BootRecovery::Recovered => {
                        DuckDbBillingStore::open(&args.db).with_context(|| {
                            format!(
                                "re-open billing DuckDB at {} after ADR-0095 auto-recovery",
                                args.db.display()
                            )
                        })?
                    }
                    BootRecovery::Refused(reason) => {
                        return Err(anyhow::Error::new(open_err)).with_context(|| {
                            format!(
                                "billing DB at {} could not be opened and auto-recovery refused \
                                 ({reason}); the corrupt DB and any ahead mirror were preserved — \
                                 investigate, then run `aberp recover`",
                                args.db.display()
                            )
                        });
                    }
                }
            }
            Err(open_err) => {
                return Err(anyhow::Error::new(open_err)).with_context(|| {
                    format!(
                        "open billing DuckDB at {} for boot migration",
                        args.db.display()
                    )
                });
            }
        };
        billing_store
            .ensure_schema()
            .context("ensure billing schema at serve boot")?;
    }

    // PR-91 — pin the products table schema at boot for the same
    // read-only-cold-start reason as the partners + billing tables
    // (PR-73a). Idempotent CREATE TABLE IF NOT EXISTS so re-runs on
    // already-migrated DBs cost nothing.
    {
        let _s = tracing::info_span!("serve.ensure_products_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for products boot migration",
                args.db.display()
            )
        })?;
        products::ensure_schema(&conn).context("ensure products schema at serve boot")?;
    }

    // S231 / PR-227 / ADR-0061 — pin the inventory schema at boot
    // (extends products with stock_qty/min_stock/bin_location/
    // last_movement_at cache columns + creates the stock_movements
    // append-only ledger). Same idempotent ALTER ADD COLUMN IF NOT
    // EXISTS / CREATE TABLE IF NOT EXISTS posture as products /
    // ap_invoice / restored_invoice — re-runs on migrated DBs cost
    // nothing. MUST run AFTER the products migration above because
    // the ALTER targets that table.
    {
        let _s = tracing::info_span!("serve.ensure_inventory_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for inventory boot migration",
                args.db.display()
            )
        })?;
        aberp_inventory::ensure_schema(&conn).context("ensure inventory schema at serve boot")?;
    }

    // S266 / PR-255 — pin the quoting_materials schema at boot + seed a
    // small set of common grades on a brand-new (empty) table. Idempotent:
    // the CREATE is IF NOT EXISTS and the seed is a no-op once any row
    // exists (the operator may have edited or deleted seeds — we never
    // re-add). First tunable table of the auto-quoting strand (design §3).
    {
        let _s = tracing::info_span!("serve.ensure_quoting_materials_schema").entered();
        let mut conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for quoting_materials boot migration",
                args.db.display()
            )
        })?;
        crate::quoting_materials::seed_if_empty(&mut conn, tenant.as_str())
            .context("ensure + seed quoting_materials at serve boot")?;
        // S418 [[trust-code-not-operator]] — refuse to start if any
        // catalogue grade carries an invalid machining_difficulty (the
        // model multiplies machining minutes by it). Runs after the
        // seed/migration so it validates the post-migration catalogue.
        crate::quoting_materials::validate_catalogue_machining_difficulty(&conn, tenant.as_str())
            .context("validate quoting_materials machining_difficulty at serve boot")?;
    }

    // S267 / PR-256 — pin the four quoting tunables schemas at boot
    // (complexity rules, tolerance multipliers, parameters singleton,
    // stock adjustments). Idempotent CREATE IF NOT EXISTS + idempotent
    // seeds for the tolerance enum + the parameters singleton. MUST run
    // AFTER the materials migration above because `quoting_stock_adjustments`
    // app-layer-FK-checks against `quoting_materials.grade`.
    {
        let _s = tracing::info_span!("serve.ensure_quoting_tunables_schema").entered();
        let mut conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for quoting_tunables boot migration",
                args.db.display()
            )
        })?;
        crate::quoting_tunables::ensure_schema(&mut conn, tenant.as_str())
            .context("ensure quoting_tunables schemas + seeds at serve boot")?;
        // S4 / ADR-0094 Gap 2 — machine-rate catalogue: idempotent schema +
        // six-family seed (insert-if-absent). Co-located with the tunables
        // boot migration; the pricing pipeline snapshots this into the engine.
        crate::quoting_machine_rates::ensure_schema(&conn)
            .context("ensure quoting_machine_rates schema at serve boot")?;
        crate::quoting_machine_rates::seed_machine_rates_if_absent(&conn, tenant.as_str())
            .context("seed quoting_machine_rates families at serve boot")?;
        // S6 / ADR-0094 Gap 3 — gear-process catalogue: idempotent schema +
        // five-process seed (insert-if-absent). Co-located with the machine-
        // rate boot migration; the pricing pipeline snapshots this into the
        // engine's 11th `gear_process_rates` argument. Seeding is inert for
        // existing quotes (gear cost accrues only on a part that carries gear
        // ops, a brand-new defaulted-empty field).
        crate::quoting_gear_processes::ensure_schema(&conn)
            .context("ensure quoting_gear_processes schema at serve boot")?;
        crate::quoting_gear_processes::seed_gear_processes_if_absent(&conn, tenant.as_str())
            .context("seed quoting_gear_processes at serve boot")?;
        // T4 / ADR-0097 Part 2 — tolerance cost-rate catalogue: idempotent
        // schema + five-band ZERO-CONTRIBUTION seed (insert-if-absent). The
        // pricing pipeline snapshots this into the engine's
        // `CatalogueSnapshot.tolerance_cost_rates`. The seed moves no money
        // (every row contributes 0.0 EUR until the operator tunes it, R4);
        // existing quotes are untouched.
        crate::quoting_tolerance_cost_rates::ensure_schema(&conn)
            .context("ensure quoting_tolerance_cost_rates schema at serve boot")?;
        crate::quoting_tolerance_cost_rates::seed_tolerance_cost_rates_if_absent(
            &conn,
            tenant.as_str(),
        )
        .context("seed quoting_tolerance_cost_rates at serve boot")?;
    }

    // S232 / PR-228 / ADR-0062 — pin the work-orders schema at boot
    // (creates work_orders + boms + routings tables). Same idempotent
    // CREATE TABLE IF NOT EXISTS posture as the inventory migration
    // above. MUST run AFTER the products migration (BOM rows reference
    // products by id even though no FK is declared per [[no-sql-specific]]).
    {
        let _s = tracing::info_span!("serve.ensure_work_orders_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for work-orders boot migration",
                args.db.display()
            )
        })?;
        aberp_work_orders::ensure_schema(&conn)
            .context("ensure work-orders schema at serve boot")?;
    }

    // S233 / PR-229 / ADR-0063 — pin the QA-queue schema at boot
    // (creates qa_inspections table). Same idempotent posture as the
    // work-orders migration above. MUST run AFTER the work-orders
    // migration because the QA module references routing-op ids
    // (no FK is declared per [[no-sql-specific]]).
    {
        let _s = tracing::info_span!("serve.ensure_qa_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for qa boot migration",
                args.db.display()
            )
        })?;
        aberp_qa::ensure_schema(&conn).context("ensure qa schema at serve boot")?;
    }

    // S234 / PR-230 — pin the dispatches schema at boot, same posture
    // as the other Stage 3 Phase γ siblings (inventory / work-orders /
    // qa). The route layer also calls `ensure_schema` defensively so a
    // fresh DB + first route hit does not 500. No FK to `work_orders`
    // / `partners` / `invoice` per [[no-sql-specific]] — the
    // application-level eligibility gate in `aberp_dispatch::create_dispatch`
    // is the authoritative check.
    {
        let _s = tracing::info_span!("serve.ensure_dispatch_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for dispatch boot migration",
                args.db.display()
            )
        })?;
        aberp_dispatch::ensure_schema(&conn).context("ensure dispatch schema at serve boot")?;
    }

    // S236 / PR-230b — pin the `invoice_draft` schema at boot. Mirrors
    // the dispatch / WO / QA boot posture above. The route layer also
    // calls `ensure_schema` defensively so a fresh DB + first route hit
    // does not 500. The table backs the new `InvoiceState::Draft` SPA
    // surface; the BillingInvoiceSpawner writes here on
    // dispatches→Shipped.
    {
        let _s = tracing::info_span!("serve.ensure_invoice_draft_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for invoice_draft boot migration",
                args.db.display()
            )
        })?;
        invoice_draft::ensure_schema(&conn).context("ensure invoice_draft schema at serve boot")?;
    }

    // S177 / PR-177 — pin the ap_invoice (incoming AP-side mirror)
    // schema at boot, same posture as products + partners. The route
    // layer also calls `ensure_schema` defensively so a fresh DB +
    // first route hit does not 500.
    {
        let _s = tracing::info_span!("serve.ensure_ap_invoice_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for ap_invoice boot migration",
                args.db.display()
            )
        })?;
        incoming_invoices::ensure_schema(&conn)
            .context("ensure ap_invoice schema at serve boot")?;
    }

    // S180 / PR-180 — pin the `restored_invoice` schema at boot, same
    // posture as `ap_invoice`. The route layer also calls
    // `ensure_schema` defensively so a fresh DB + first wizard
    // invocation does not 500.
    {
        let _s = tracing::info_span!("serve.ensure_restored_invoice_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for restored_invoice boot migration",
                args.db.display()
            )
        })?;
        restore_outgoing::ensure_schema(&conn)
            .context("ensure restored_invoice schema at serve boot")?;
        // S261 / PR-250 — crashed-restore detection. The restore lock is
        // a DB row (survives a crash); if one is held at boot, a prior
        // `aberp serve` died mid-restore. Surface it LOUD per CLAUDE.md
        // rule 12 — the Issue + AP-sync routes will refuse to proceed
        // (restore_lock_block) and the SPA banner will prompt the
        // operator to abandon or re-run until the lock is cleared.
        match restore_outgoing::read_restore_lock(&conn, args.tenant.as_str()) {
            Ok(Some(lock)) => tracing::warn!(
                acquired_at = %lock.acquired_at,
                operator = %lock.operator,
                year = lock.year,
                "S261: a restore-from-NAV lock is HELD at boot — a prior process likely \
                 crashed mid-restore. Issue + AP-sync are blocked until the operator \
                 abandons the restore (Settings → Restore from NAV) or completes it via re-run."
            ),
            Ok(None) => {}
            Err(e) => tracing::error!(error = ?e, "S261: boot restore-lock probe failed"),
        }
    }

    // Session 152b — reconcile the audit-ledger mirror against the DB
    // at boot. The mirror (`<db>.audit.log`) is a derivable cache, not
    // a source of truth. If the operator nuked the DuckDB per the
    // dev-DB-disposable rule but left the mirror in place, the mirror
    // is now AHEAD of the fresh DB; pre-152b the first post-commit
    // `sync_mirror` 500'd ("mirror is ahead of DB"), skipping the NAV
    // XML write and cascading into a submit 500. Boot reconciliation
    // handles missing / behind / corrupt / hash-mismatch idempotently.
    // CHUNK-3 RECONCILE SAFETY (ADR-0093 / ADR-0082): a mirror that is
    // AHEAD of the DB is the fingerprint of a torn-write / lost DB commit
    // (the 2026-06-22 corruption class). The editions tree NO LONGER
    // silently truncates it (that destroyed recovery evidence) — it
    // preserves the ahead mirror to a side file and REFUSES boot so a
    // human investigates. Per-write `sync_mirror` still loud-fails on
    // mid-process divergence — that IS a runtime bug.
    tracing::info!("boot step: reconciling audit-ledger mirror with DB (idempotent recovery)");
    {
        let _s = tracing::info_span!("serve.recover_audit_mirror").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for audit-ledger mirror recovery",
                args.db.display()
            )
        })?;
        aberp_audit_ledger::ensure_schema(&conn)
            .context("ensure audit-ledger schema at serve boot")?;
        let mirror_path = aberp_audit_ledger::mirror_path_for(&args.db);
        match aberp_audit_ledger::ensure_consistent_with_db(&conn, &mirror_path) {
            Ok(action) => tracing::info!(?action, "audit-ledger mirror reconciled at boot"),
            Err(e @ aberp_audit_ledger::AppendError::MirrorAheadOfDb { .. }) => {
                // ADR-0095 §1 — an ahead mirror is the fingerprint of a
                // torn-write / lost DB commit (root cause #4). Instead of a
                // fatal stop, attempt the guarded, reversible auto-recovery:
                // rebuild from the latest VALID snapshot and REPLAY the
                // preserved ahead mirror (the chunk-3 P1 guard already copied
                // it to `<mirror>.ahead-*.bak`; recover_or_refuse READS it,
                // never truncates it). On a guard-rail refusal keep today's
                // preserve-and-surface (demoted from the ONLY outcome to the
                // last resort). Drop the open handle first so the atomic swap
                // can rename over the live path cleanly.
                tracing::error!(
                    error = %e,
                    "audit-ledger mirror is AHEAD of the DB — attempting ADR-0095 §1 auto-recovery"
                );
                drop(conn);
                let recovery = attempt_db_auto_recovery(
                    &args.db,
                    &tenant,
                    &binary_hash_handle,
                    "mirror_ahead",
                );
                match recovery {
                    Ok(BootRecovery::Recovered) => {
                        tracing::warn!(
                            "ADR-0095 §1 — auto-recovery reconciled the ahead mirror with the DB at boot"
                        );
                    }
                    Ok(BootRecovery::Refused(reason)) => {
                        tracing::error!(
                            reason = %reason,
                            "REFUSING to boot — ahead mirror could not be safely auto-recovered"
                        );
                        return Err(anyhow::Error::new(e)).context(
                            "audit-ledger mirror is AHEAD of the DB at boot (possible lost DB commit                      after a torn write). The ahead mirror was preserved to a side file;                      investigate before re-running. For an intentional dev DB-nuke, move the                      stale <db>.audit.log aside and re-run.",
                        );
                    }
                    Err(rec_err) => {
                        return Err(rec_err).context(
                            "ADR-0095 auto-recovery of an ahead mirror failed mechanically at boot",
                        );
                    }
                }
            }
            Err(e) => {
                return Err(anyhow::Error::new(e))
                    .context("reconcile audit-ledger mirror with DB at serve boot")
            }
        }
    }

    // S433 — self-heal the tenant registry with the running tenant and,
    // if this boot consumed a switch hint, record TenantSwitched in the
    // switched-to tenant's own ledger. Best-effort (never blocks boot).
    tracing::info!("boot step: reconciling tenant registry + recording any tenant switch");
    record_tenant_boot(
        args,
        switched_from.as_deref(),
        &binary_hash_handle,
        &tenant,
        fresh_install,
        nav_enabled,
    );

    // 2. Resolve / generate the loopback cert + key.
    tracing::info!("boot step: preparing serve-artifacts directory");
    let artifacts_dir = serve_artifacts_dir(&args.tenant)?;
    std::fs::create_dir_all(&artifacts_dir).with_context(|| {
        format!(
            "create serve artifacts directory at {}",
            artifacts_dir.display()
        )
    })?;
    let cert_path = artifacts_dir.join("loopback.crt.pem");
    let key_path = artifacts_dir.join("loopback.key.pem");
    let fingerprint_path = artifacts_dir.join("loopback.fingerprint.sha256");
    tracing::info!("boot step: ensuring loopback TLS cert + key (rcgen on first launch)");
    let (cert_pem, key_pem, fingerprint_hex) = {
        let _s = tracing::info_span!("serve.loopback_cert").entered();
        ensure_loopback_cert(&cert_path, &key_path, &fingerprint_path)?
    };
    tracing::info!(
        cert = %cert_path.display(),
        fingerprint = %fingerprint_hex,
        "loopback TLS certificate ready"
    );

    // 3. Build the rustls server config.
    tracing::info!("boot step: building rustls server config");
    let rustls_config = {
        let _s = tracing::info_span!("serve.rustls_config").entered();
        build_rustls_config(&cert_pem, &key_pem)?
    };

    // 4. Build the shared application state. `binary_hash` is the
    //    handle to the background compute kicked off at the top;
    //    handlers block on it if they need the hash before it
    //    resolves.
    //
    // PR-46α / session-62 — `boot_state` carries the (possibly
    // mutable) Ready / NeedsSetup discriminator. The setup route
    // takes the write lock when transitioning; every other handler
    // takes a read lock to either pull `operator_login` or reject
    // with 503 needs-setup.
    let state_token_at_print = initial_boot_state.state_token();
    // PR-209 / S213 — mint the shutdown token here so it's
    // available to BOTH `AppState` (cloned into every
    // dynamically-spawned NAV poll daemon) AND the
    // `ShutdownCoordinator` built inside the runtime block. Same
    // underlying token (CancellationToken is Arc<Inner> internally);
    // either side firing `cancel()` propagates to every clone.
    let shutdown_token_root = tokio_util::sync::CancellationToken::new();
    // S240 / PR-234 — empty registry created here so it can be cloned
    // into both `AppState` (for the dashboard handler) and the MES boot
    // path (which registers adapters into it after `start()` succeeds).
    let adapter_registry = Arc::new(std::sync::RwLock::new(AdapterRegistry::new()));
    // S257 / PR-246 — operator-managed adapter lifecycle. Shares the
    // registry above + parents per-adapter cancellation tokens off the
    // shutdown root so Settings → Adapters CRUD takes effect without a
    // restart.
    let adapter_manager = Arc::new(crate::mes_manager::AdapterManager::new(
        adapter_registry.clone(),
        shutdown_token_root.clone(),
    ));
    // ADR-0098 Session B (Gap 1a) — open the ONE shared DuckDB instance here,
    // after boot provisioning/recovery has left the live file known-good. All
    // daemons + (Session C) request handlers route through this; the binary
    // hash is NOT needed (the handle's mirror lockstep reads only tenant_id).
    let db_handle = open_tenant_handle(&args.db, tenant.clone())
        .context("open shared DuckDB handle + eager tenant schemas (ADR-0098 Gap 1a / C2)")?;
    let state = AppState {
        db_path: Arc::new(args.db.clone()),
        db: db_handle,
        tenant,
        nav_enabled,
        binary_hash: binary_hash_handle,
        session_token: Arc::new(session_token.clone()),
        boot_state: Arc::new(std::sync::RwLock::new(initial_boot_state)),
        secrets_cache,
        nav_poll_semaphore: Arc::new(tokio::sync::Semaphore::new(NAV_POLL_DAEMON_CONCURRENCY)),
        shutdown_token: shutdown_token_root.clone(),
        adapter_registry: adapter_registry.clone(),
        adapter_manager: adapter_manager.clone(),
        adapter_health_baseline: Arc::new(std::sync::Mutex::new(std::collections::HashMap::new())),
        restore_active: Arc::new(std::sync::atomic::AtomicBool::new(false)),
        catalogue_push: crate::catalogue_push::CataloguePushHandle::dormant(),
        email_relay_rate_limiter: Arc::new(crate::email_relay::RateLimiter::new()),
        pipeline_python_resolution: crate::quote_pricing_pipeline::PythonResolutionHandle::dormant(
        ),
        storefront_credential: crate::storefront_credential::StorefrontCredentialHandle::dormant(),
        email_outbox_daemon: crate::email_outbox_poll_daemon::EmailOutboxDaemonHandle::dormant(),
        quote_pdf_rerender_queue: crate::quote_pdf_rerender_queue::QuotePdfRerenderQueue::new(),
        // S344 / PR-38 — digital-identity provider. Mock-only today; the
        // INFO/WARN boot lines fire inside the helper.
        digital_id: build_digital_id_provider(),
    };

    // 5. Build the axum router. Clone the state first so the app-boot
    //    NAV poll daemon recovery (spawned inside the runtime below) has
    //    its own handle after `build_router` consumes `state`.
    let recovery_state = state.clone();
    let app = build_router(state);

    // 6. Build a tokio multi-thread runtime (the serve subcommand is
    //    long-running on a single operator workstation; a small
    //    worker pool is fine here).
    tracing::info!("boot step: building tokio multi-thread runtime");
    let runtime = {
        let _s = tracing::info_span!("serve.tokio_runtime").entered();
        tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .context("build tokio multi-thread runtime for axum")?
    };

    // 7. Bind the TCP listener synchronously so we can read the
    //    kernel-assigned port BEFORE printing the handshake. Pre-
    //    PR-45a we passed `127.0.0.1:0` straight to `bind_rustls`,
    //    which made the handshake unparseable: the operator-visible
    //    line read `https://127.0.0.1:0/`, and the desktop shell's
    //    handshake parser had no way to learn the resolved port.
    // S291 / PR-272 — `ABERP_HTTPS_PORT` env override. The dev-test.sh
    // launcher pins ABERP to a fixed port (e.g. 18443) so the storefront
    // sister-service has a stable `ABERP_INTERNAL_BASE_URL` across
    // restarts; the previous "operator runs `lsof` after every restart"
    // shape was a [[trust-code-not-operator]] gap. Env wins over the
    // clap default of 0; an explicit `--port` flag still wins over the
    // env (the launcher only sets env, never both). Invalid env value
    // logs at WARN and falls back to `args.port` rather than aborting —
    // a typo here shouldn't deny boot when the dynamic-port path still
    // works.
    let effective_port = resolve_listener_port(args.port);
    tracing::info!(
        port = effective_port,
        from_env = effective_port != args.port,
        "boot step: binding loopback TCP listener"
    );
    let bind_addr: SocketAddr =
        format!("127.0.0.1:{effective_port}")
            .parse()
            .with_context(|| {
                format!(
                    "parse loopback socket address 127.0.0.1:{effective_port} (port out of range?)"
                )
            })?;
    let listener = {
        let _s = tracing::info_span!("serve.tcp_bind").entered();
        TcpListener::bind(bind_addr).with_context(|| format!("bind TCP listener at {bind_addr}"))?
    };
    let resolved_addr = listener
        .local_addr()
        .context("read resolved local_addr from TCP listener")?;
    tracing::info!(
        bind = %resolved_addr,
        fingerprint = %fingerprint_hex,
        session_token_first8 = &session_token[..8.min(session_token.len())],
        "starting HTTPS loopback listener — present \
         `Authorization: Bearer <session_token>` to authenticated routes; \
         verify TLS cert against the SHA-256 fingerprint"
    );

    // PR-45a / session-61 — machine-parseable handshake line. The
    // Tauri shell's `handshake::parse` consumes the line as
    // whitespace-separated tokens (literal `READY`, a `SocketAddr`,
    // `sha256:<64-hex>`, and PR-46α-added optional `state=<token>`);
    // the addr token round-trips through `parse::<SocketAddr>()`
    // cleanly. The human-readable `aberp serve: …` line moved to the
    // tracing log above so an operator running the shell still sees
    // the resolved port in the forwarded stderr stream. A drift in
    // either side fails loudly at the SPA's handshake step rather
    // than silently mis-routing.
    //
    // PR-46α / session-62 — the trailing `state=<token>` token
    // exposes the boot lifecycle (Ready vs NeedsSetup) at the
    // handshake boundary so the Tauri shell can dispatch the SPA's
    // first-paint between the normal app and the first-run setup
    // wizard. Token values: `ready` | `needs-setup`. Missing token =
    // `ready` (backwards-compat with the PR-45a line shape for any
    // future-stable third-party reader; the parser tolerates absence).
    println!(
        "READY {} sha256:{} state={}",
        resolved_addr, fingerprint_hex, state_token_at_print
    );

    // S291 / PR-272 — write the runtime-discovery file (brief D). The
    // storefront's dev launcher reads this to learn the resolved port +
    // TLS fingerprint + keychain pointer without `lsof` or operator
    // memory. Best-effort: a write failure logs at WARN and continues —
    // the SPA handshake above is the load-bearing surface for the
    // desktop shell; the discovery file is a convenience for the
    // sister-service launcher.
    let started_at = {
        use time::format_description::well_known::Rfc3339;
        time::OffsetDateTime::now_utc()
            .format(&Rfc3339)
            .unwrap_or_else(|_| "1970-01-01T00:00:00Z".to_string())
    };
    let relay_keychain = format!(
        "{}.{}",
        crate::email_relay_credentials::service_name(&args.tenant),
        crate::email_relay_credentials::ITEM_EMAIL_RELAY_TOKEN,
    );
    let discovery = crate::runtime_discovery::RuntimeDiscovery {
        tenant: args.tenant.clone(),
        base_url: format!("https://{resolved_addr}"),
        tls_fingerprint: fingerprint_hex.clone(),
        started_at,
        relay_token_keychain_service: relay_keychain,
    };
    match crate::runtime_discovery::write(&discovery) {
        Ok(p) => tracing::info!(path = %p.display(), "wrote runtime-discovery file"),
        Err(e) => tracing::warn!(error = ?e, "runtime-discovery write failed (boot continues)"),
    }

    runtime.block_on(async move {
        // PR-209 / S213 — graceful-shutdown coordinator. Uses the
        // SAME token already minted at state-construction time
        // (`shutdown_token_root`) so post-issue NAV poll daemons
        // spawned via `state.shutdown_token.clone()` share the
        // cancellation signal with the boot-time daemons registered
        // here. The coordinator's `register` is the load-bearing
        // side — boot-time daemons whose JoinHandle is registered
        // get awaited during drain; post-issue daemons are not
        // registered (per-invoice ephemeral) but DO receive the
        // token, so they exit on cancellation even though the
        // coordinator doesn't track them by name.
        let mut coordinator = ShutdownCoordinator::from_token(shutdown_token_root.clone());

        // Session-161 — app-boot NAV poll daemon recovery. Scan the
        // audit ledger for invoices still in `Submitted` (NAV accepted,
        // no terminal ack yet) and re-spawn an indefinite poll daemon
        // for each. The audit trail is the truth; the daemon chases it.
        // Closing ABERP mid-poll and reopening tomorrow resumes the
        // chase. Best-effort: a scan failure logs and continues — the
        // operator can still poll manually. Runs BEFORE `serve()` so the
        // daemons are in flight as soon as the listener accepts.
        //
        // PR-209 / S213 — the boot-recovery FAN-OUT itself is wrapped
        // in ONE registered task (not per-invoice) so the coordinator
        // doesn't have to track 50 dynamic handles. The wrapper task
        // spawns one un-registered child per pending invoice; each
        // child's `run_nav_poll_daemon` receives the same shutdown
        // token, so cancellation still reaches every NAV poll loop.
        // The wrapper exits as soon as its fan-out completes (the
        // children outlive it — that's fine, the token reaches them
        // directly).
        //
        // S434 — both NAV daemons (this boot-recovery poll + the AP-sync
        // below) are gated on the tenant's NAV-synchron mode. A NAV-off
        // tenant has no NAV credentials, so spawning either would just log
        // recurring keychain errors forever ([[trust-code-not-operator]]:
        // skip at the spawn, not per-tick). No spawn = no error spam.
        if recovery_state.nav_enabled {
        let recovery_token = coordinator.token.clone();
        let recovery_for_task = recovery_state.clone();
        let recovery_handle = tokio::spawn(async move {
            match query_non_terminal_invoices(&recovery_for_task) {
                Ok(pending) => {
                    tracing::info!(
                        count = pending.len(),
                        "spawning NAV poll daemons for pending invoices"
                    );
                    for invoice_id in pending {
                        if recovery_token.is_cancelled() {
                            return;
                        }
                        let st = recovery_for_task.clone();
                        let child_token = recovery_token.clone();
                        tokio::spawn(async move {
                            match build_poll_daemon_inputs(&st, &invoice_id).await {
                                Ok(inputs) => {
                                    if let Err(e) = poll_ack::run_nav_poll_daemon(
                                        inputs,
                                        st.nav_poll_semaphore.clone(),
                                        child_token,
                                    )
                                    .await
                                    {
                                        tracing::warn!(
                                            invoice_id = %invoice_id,
                                            error = ?e,
                                            "boot-recovery NAV poll daemon failed"
                                        );
                                    }
                                }
                                Err(e) => tracing::warn!(
                                    invoice_id = %invoice_id,
                                    error = ?e,
                                    "boot-recovery could not build poll daemon inputs; skipping"
                                ),
                            }
                        });
                    }
                }
                Err(e) => tracing::warn!(
                    error = ?e,
                    "boot-recovery NAV poll daemon scan failed; continuing without recovery"
                ),
            }
        });
        coordinator.register("nav-poll-boot-recovery", recovery_handle);

        // S178 / PR-178 — AP-side auto-sync daemon. Mirrors the
        // outgoing-side NAV poll daemon's spawn-and-forget posture;
        // ticks 30s after boot then every 30 min. Builds its own
        // `CycleInputs` on every tick (so a mid-run NAV credential
        // rotation is picked up at the next cadence without a
        // restart). The closure clones state into the task so the
        // outer `recovery_state` move is safe.
        //
        // PR-209 / S213 — registered with the shutdown coordinator.
        // `ap_sync::run_daemon_forever` accepts the cancellation
        // token; a shutdown mid-cadence-sleep exits within ms instead
        // of waiting 30 minutes for the next tick.
        {
            let st = recovery_state.clone();
            let ap_sync_token = coordinator.token.clone();
            let ap_sync_handle = tokio::spawn(async move {
                let st = st;
                ap_sync::run_daemon_forever(move || {
                    let operator_login = match st.boot_state.read() {
                        Ok(guard) => match &*guard {
                            ServeBootState::Ready { operator_login } => operator_login.clone(),
                            other => {
                                return Err(anyhow!(
                                    "AP sync daemon waiting on boot_state ({}); skipping tick",
                                    other.state_token()
                                ));
                            }
                        },
                        Err(e) => return Err(anyhow!("boot_state RwLock poisoned: {e}")),
                    };
                    // Build a blocking-style call inside a closure
                    // that returns `Result<CycleInputs>` — the daemon
                    // helper awaits the daemon-internal work, but the
                    // input-building itself is synchronous (keychain
                    // read + seller.toml read + endpoint pick).
                    let binary_hash = st
                        .binary_hash
                        .wait()
                        .context("await background binary hash for AP sync daemon")?;
                    let credentials = NavCredentials::load_from_keychain(st.tenant.as_str())
                        .with_context(|| {
                            format!(
                                "load NAV credentials from OS keychain for tenant `{}` (AP sync daemon)",
                                st.tenant.as_str()
                            )
                        })?;
                    let supplier = supplier_from_seller_toml(st.tenant.as_str()).map_err(|e| {
                        anyhow!(
                            "load supplier identity for AP sync daemon (tenant `{}`): {:?}",
                            st.tenant.as_str(),
                            e
                        )
                    })?;
                    let parsed = nav_xml::parse_hungarian_tax_number(&supplier.tax_number)
                        .map_err(|e| {
                            anyhow!(
                                "parse supplier tax number `{}` for AP sync daemon: {:?}",
                                supplier.tax_number,
                                e
                            )
                        })?;
                    let endpoint = build_profile::nav_endpoint();
                    build_profile::assert_endpoint_allowed(endpoint)?;
                    let artifacts_dir = ap_artifacts_dir(st.tenant.as_str())?;
                    Ok(ap_sync::CycleInputs {
                        db: st.db.clone(),
                        tenant: st.tenant.clone(),
                        binary_hash,
                        operator_login,
                        ap_artifacts_dir: artifacts_dir,
                        tax_number_8: parsed.taxpayer_id,
                        endpoint,
                        credentials,
                    })
                }, ap_sync_token)
                .await;
            });
            coordinator.register("ap-sync", ap_sync_handle);
        }
        } else {
            tracing::info!(
                tenant = %recovery_state.tenant.as_str(),
                "NAV synchron OFF for this tenant — not spawning NAV poll-recovery or AP-sync daemons"
            );
        }

        // PR-216 / S218 — one-shot buyer-snapshot backfill for
        // `restored_invoice` rows the S180 wizard mirrored before
        // PR-216's S196-side write-back landed, OR rows whose S196
        // `queryInvoiceData` fetch failed mid-cycle (transport
        // glitch, NAV outage). Scans for rows with NULL customer_name
        // and re-fetches `queryInvoiceData OUTBOUND` to populate the
        // buyer label IN-ROW. Trust-code-not-operator: backfill runs
        // automatically on boot — Ervin's 14 already-imported prod
        // rows from 2026-06-01 light up without an operator action.
        //
        // Spawned on the tokio pool, cancel-aware. Per-row failures
        // are warn-and-continue; the row stays NULL and the next boot
        // will retry. Idempotent: a re-run after a successful pass
        // finds 0 rows and returns immediately. Registered with the
        // shutdown coordinator so a Tauri close mid-scan exits within
        // ms.
        {
            let st = recovery_state.clone();
            let backfill_token = coordinator.token.clone();
            let backfill_handle = tokio::spawn(async move {
                let inputs = {
                    let credentials =
                        match NavCredentials::load_from_keychain(st.tenant.as_str()) {
                            Ok(c) => c,
                            Err(e) => {
                                tracing::info!(
                                    error = ?e,
                                    "S218: buyer-backfill skipped — no NAV credentials in \
                                     keychain (first-boot tenant); next launch retries"
                                );
                                return;
                            }
                        };
                    let supplier = match supplier_from_seller_toml(st.tenant.as_str()) {
                        Ok(s) => s,
                        Err(e) => {
                            tracing::warn!(
                                error = ?e,
                                "S218: buyer-backfill skipped — could not load supplier \
                                 identity from seller.toml"
                            );
                            return;
                        }
                    };
                    let parsed = match nav_xml::parse_hungarian_tax_number(&supplier.tax_number) {
                        Ok(p) => p,
                        Err(e) => {
                            tracing::warn!(
                                error = ?e,
                                "S218: buyer-backfill skipped — could not parse supplier \
                                 tax number"
                            );
                            return;
                        }
                    };
                    let endpoint = build_profile::nav_endpoint();
                    if let Err(e) = build_profile::assert_endpoint_allowed(endpoint) {
                        tracing::warn!(
                            error = ?e,
                            "S218: buyer-backfill skipped — NAV endpoint not allowed"
                        );
                        return;
                    }
                    // PR-217 / S220 — resolve the binary hash so the
                    // cycle-completion audit entry can be appended.
                    // `wait()` blocks at most until the background
                    // hash-of-self task completes; on the boot path
                    // it has been running since `serve::run`'s start
                    // and is typically already resolved.
                    let binary_hash = match st.binary_hash.wait() {
                        Ok(h) => h,
                        Err(e) => {
                            tracing::warn!(
                                error = ?e,
                                "S218: buyer-backfill skipped — binary hash not available"
                            );
                            return;
                        }
                    };
                    restore_outgoing::BackfillInputs {
                        // ADR-0098 R7 — pass the shared Handle (not just the
                        // db_path) so the boot cycle-audit append routes through
                        // the one live instance's writer and cannot re-fork the
                        // ledger head (the 415/416 divergence).
                        db: st.db.clone(),
                        db_path: (*st.db_path).clone(),
                        tenant: st.tenant.clone(),
                        tax_number_8: parsed.taxpayer_id,
                        endpoint,
                        credentials,
                        binary_hash,
                    }
                };
                let _ = restore_outgoing::run_buyer_backfill_once(inputs, backfill_token).await;
            });
            coordinator.register("restore-buyer-backfill", backfill_handle);
        }

        // S210 / PR-204 — quote-intake daemon. Opt-in via either the
        // `ABERP_QUOTE_INTAKE_ENABLED=true` env var (S210, ops escape
        // hatch) OR the operator-typed `[quote_intake]` section in
        // seller.toml + a keychain token (S211, SPA-driven). Precedence
        // is env > toml+keychain > dormant. When the operator changes
        // the toml config via the SPA the daemon does NOT hot-reload
        // (S211 conservative-choice) — the change takes effect on the
        // next `aberp serve` boot.
        //
        // Refuse-to-start: `ENABLED=true` (env) OR `enabled=true`
        // (toml) with missing URL / TOKEN aborts the boot rather than
        // spawn a daemon that polls a wrong URL forever. Per
        // [[trust-code-not-operator]] and brief §8.
        {
            // S256 / PR-245 — stamp the boot wall-time so the
            // notifications route can tell catch-up arrivals (first
            // cycle after boot) from live arrivals (operator watching).
            mark_quote_intake_boot();
            let st = recovery_state.clone();
            let cfg_result: std::result::Result<QuoteIntakeConfig, QuoteIntakeError> =
                match QuoteIntakeConfig::from_env() {
                    Ok(c) => Ok(c),
                    Err(QuoteIntakeError::Disabled) => {
                        // Env-var path off; try toml + keychain.
                        let seller_path = setup_seller_info::seller_toml_path_for_tenant(
                            st.tenant.as_str(),
                        )
                        .context("resolve seller.toml path for quote-intake boot")?;
                        let toml_cfg = crate::quote_intake_config::read_quote_intake_config(
                            &seller_path,
                        )
                        .map_err(|e| anyhow!("read [quote_intake] from seller.toml: {e:#}"))?;
                        match toml_cfg {
                            None => Err(QuoteIntakeError::Disabled),
                            Some(c) if !c.enabled => Err(QuoteIntakeError::Disabled),
                            Some(c) => {
                                let base_url = c.base_url.clone().ok_or_else(|| {
                                    QuoteIntakeError::Config(
                                        "[quote_intake] enabled=true but base_url is missing"
                                            .to_string(),
                                    )
                                })?;
                                let token = crate::quote_intake_credentials::read_token(
                                    st.tenant.as_str(),
                                )
                                .map_err(|e| {
                                    QuoteIntakeError::Config(format!(
                                        "[quote_intake] enabled=true but keychain token \
                                         unreadable: {e}"
                                    ))
                                })?;
                                QuoteIntakeConfig::from_toml_and_keychain_parts(
                                    base_url,
                                    token,
                                    c.poll_interval_secs,
                                )
                            }
                        }
                    }
                    Err(other) => Err(other),
                };
            match cfg_result {
                Ok(mut cfg) => {
                    // S2 / ADR-0093 — storefront-reach edition gate. We are
                    // here ONLY because storefront config resolved to
                    // enabled (env or seller.toml `[quote_intake]`), i.e. the
                    // operator asked this build to reach abenerp.com. If this
                    // edition may not (Portable), refuse the boot LOUDLY now —
                    // BEFORE the credential is populated or any of the
                    // quote-intake / catalogue-push / pricing-pipeline
                    // storefront daemons spawn. Defense lifts the gate and
                    // falls straight through. Mirror of the DB-edition guard.
                    guard_storefront_reach_matches_edition();
                    // S291 / PR-272 — `ABERP_SISTER_SERVICE_BASE_URL`
                    // env override (brief C). The dev-test launcher
                    // sets this so a local-loopback session uses
                    // `http://localhost:5173` regardless of seller.toml
                    // / SPA-saved value. ONE-SHOT log at INFO so the
                    // operator-visible boot stream names what got
                    // overridden — silent override would re-introduce
                    // the [[trust-code-not-operator]] gap S289 closed.
                    // SPA edits post-boot still take effect via
                    // `state.storefront_credential.set` (matches the
                    // hot-reload posture already established).
                    if let Some(override_url) =
                        crate::storefront_credential::read_sister_service_base_url_override()
                    {
                        tracing::info!(
                            from = %cfg.base_url,
                            to = %override_url,
                            env = crate::storefront_credential::SISTER_SERVICE_BASE_URL_ENV,
                            "sister-service base URL overridden by env var"
                        );
                        cfg.base_url = override_url;
                    }
                    let operator_login = match st.boot_state.read() {
                        Ok(guard) => match &*guard {
                            ServeBootState::Ready { operator_login } => operator_login.clone(),
                            _ => "boot".to_string(),
                        },
                        Err(_) => "boot".to_string(),
                    };
                    let binary_hash = st
                        .binary_hash
                        .wait()
                        .context("await background binary hash for quote-intake daemon")?;
                    // S289 / PR-270 — populate the shared, hot-reloadable
                    // storefront credential ONCE here (boot resolve). The
                    // catalogue-push daemon reads it per cycle; the SPA
                    // PUT `/api/quote-intake/config` route updates it on
                    // save, so an operator URL/bearer change takes effect
                    // on the very next cycle without restart. SPOC
                    // ([[aberp-smtp-spoc]]): same handle covers both
                    // daemons' need for `{base_url}` + bearer (the
                    // quote-intake crate's daemon + the pricing-pipeline
                    // daemon stay restart-required per surgical scope —
                    // their observed behaviour was already correct;
                    // hot-reload only added to the daemon that drifted).
                    st.storefront_credential
                        .set(cfg.base_url.clone(), cfg.bearer_token.clone());
                    // Brief B — one-shot WARN if the operator is in
                    // dev-mode but the configured URL points at prod.
                    // The trap Ervin hit (PROD_v2.27.4 evening test):
                    // local dev box with `ABERP_DEV_MODE=1` AND a
                    // stale-but-prod URL → daemons hammered abenerp.com.
                    crate::storefront_credential::emit_dev_mode_prod_url_warning(&cfg.base_url);
                    // The pricing-pipeline daemon (S279) shares the same
                    // storefront credential at boot — capture clones now.
                    // It does NOT hot-reload in this PR (surgical scope).
                    let catalogue_base_url = cfg.base_url.clone();
                    let catalogue_bearer = cfg.bearer_token.clone();
                    // S279 / PR-265 — capture another snapshot for the
                    // pricing-pipeline daemon spawn below.
                    let pipeline_operator_login = operator_login.clone();
                    // S339 / PR-24 — resolve the optional storefront
                    // origin shared secret ONCE here (env override →
                    // keychain → None). When present the catalogue push
                    // attaches `X-CloudFront-Secret` so a direct/origin
                    // hit that CloudFront did not cover stops 403-ing.
                    // `None` is the common case and preserves pre-S339
                    // behaviour. One-shot INFO names the state so the
                    // boot stream is honest about whether the header is
                    // in play (no silent behaviour — [[trust-code-not-operator]]).
                    let origin_secret =
                        crate::storefront_origin_secret::resolve(st.tenant.as_str());
                    tracing::info!(
                        origin_secret_present = origin_secret.is_some(),
                        "catalogue-push origin-secret resolution (S339): \
                         present ⇒ X-CloudFront-Secret sent; absent ⇒ \
                         relying on CloudFront header injection"
                    );
                    let push_deps = crate::catalogue_push::CataloguePushDeps {
                        db_path: (*st.db_path).clone(),
                        db: st.db.clone(),
                        tenant: st.tenant.clone(),
                        binary_hash,
                        operator_login: operator_login.clone(),
                        origin_secret,
                    };
                    let push_handle = st.catalogue_push.clone();
                    let push_credential = st.storefront_credential.clone();
                    let deps = QuoteIntakeDeps {
                        db_path: (*st.db_path).clone(),
                        db: st.db.clone(),
                        tenant: st.tenant.clone(),
                        binary_hash,
                        operator_login,
                        default_currency: Currency::Huf,
                    };
                    match QuoteIntakeService::new(cfg, deps) {
                        Ok(service) => {
                            tracing::info!(
                                cadence_secs = service.poll_interval().as_secs(),
                                "spawning quote-intake daemon (S210 / PR-204)"
                            );
                            // PR-209 / S213 — registered with the
                            // shutdown coordinator; cancellation
                            // races the cadence sleep so a Tauri
                            // close exits within ms.
                            // S2 / ADR-0093 — defense-in-depth: this storefront daemon is only
                            // reachable in a Defense build (the boot guard / spawn gate above). The
                            // assert is the never-hit backstop that pins the invariant at the spawn.
                            debug_assert!(
                                crate::build_profile::storefront_polling_allowed(),
                                "quote-intake poll daemon spawned in a non-Defense edition — storefront reach is \
                                 compiled out (ADR-0093)"
                            );
                            let quote_intake_token = coordinator.token.clone();
                            let quote_intake_handle = tokio::spawn(async move {
                                service.run_daemon_forever(quote_intake_token).await;
                            });
                            coordinator.register("quote-intake", quote_intake_handle);
                        }
                        Err(e) => {
                            return Err(anyhow!(
                                "quote-intake daemon refused to start: {e:#}"
                            ));
                        }
                    }

                    // S266 / PR-255 — spawn the catalogue-push daemon onto
                    // the SAME storefront surface (design doc §4 / §14-C).
                    // Reuses the shared dormant handle in AppState so the
                    // CRUD routes' on-write trigger + the list route's
                    // status read both reach this daemon. S289 / PR-270
                    // hot-reload: the daemon takes a clone of the
                    // `storefront_credential` Arc and re-snapshots it at
                    // the top of every push cycle.
                    match crate::catalogue_push::CataloguePushService::new(
                        push_handle,
                        push_credential,
                        push_deps,
                    ) {
                        Ok(push_service) => {
                            tracing::info!(
                                cadence_secs = crate::catalogue_push::PUSH_CADENCE_SECS,
                                "spawning catalogue-push daemon (S266 / PR-255)"
                            );
                            // S2 / ADR-0093 — defense-in-depth: this storefront daemon is only
                            // reachable in a Defense build (the boot guard / spawn gate above). The
                            // assert is the never-hit backstop that pins the invariant at the spawn.
                            debug_assert!(
                                crate::build_profile::storefront_polling_allowed(),
                                "catalogue-push daemon spawned in a non-Defense edition — storefront reach is \
                                 compiled out (ADR-0093)"
                            );
                            let push_token = coordinator.token.clone();
                            let push_task_handle = tokio::spawn(async move {
                                push_service.run_daemon_forever(push_token).await;
                            });
                            coordinator.register("catalogue-push", push_task_handle);
                        }
                        Err(e) => {
                            return Err(anyhow!(
                                "catalogue-push daemon refused to start: {e:#}"
                            ));
                        }
                    }

                    // S279 / PR-265 (env-var opt-in) → S282 / PR-267
                    // (auto-discovery). Resolve the Python interpreter the
                    // daemon will exec via the [[trust-code-not-operator]]
                    // layered fallback: env-var override → canonical venv →
                    // alt-root venv → system-python-with-module. The audit
                    // row fires unconditionally so a forensic walker can
                    // answer "what venv did this install actually use?"
                    // The SPA `GET /api/quote-pipeline/status` route reads
                    // the dormant handle to differentiate the
                    // `PricingJobsList` empty-state copy (active / RED
                    // venv-missing / AMBER spawn-errored).
                    let aberp_root = std::env::current_dir()
                        .unwrap_or_else(|_| std::path::PathBuf::from("."));
                    let resolution =
                        crate::quote_pricing_pipeline::resolve_pipeline_python(&aberp_root);
                    // S286 / PR-268 — detect operator-disabled venv
                    // siblings (Ervin's `.venv.disabled-pending-hotfix`
                    // mitigation after PROD_v2.27.2). Feeds the SPA hint
                    // so a manually-disabled daemon shows distinct copy
                    // from a missing-install RED card.
                    let operator_disabled =
                        crate::quote_pricing_pipeline::detect_operator_disabled_venv(&aberp_root);
                    const PIPELINE_POLL_SECS: u64 = 60;
                    let mut status = crate::quote_pricing_pipeline::status_from_resolution(
                        &resolution,
                        Some(PIPELINE_POLL_SECS),
                        operator_disabled,
                    );
                    // Audit emit ONCE per daemon spawn — the durable
                    // `[[trust-code-not-operator]]` guarantee. Best-effort:
                    // an audit-emit failure logs but does NOT block daemon
                    // spawn (the resolved daemon is still safe to run; the
                    // missing audit row is operator-visible via the SPA
                    // status snapshot).
                    if let Err(e) = crate::quote_pricing_pipeline::emit_python_resolved_audit(
                        &st.db,
                        st.tenant.as_str(),
                        binary_hash,
                        &pipeline_operator_login,
                        &status,
                    ) {
                        tracing::warn!(
                            error = %e,
                            "quote.pipeline_python_resolved audit emit failed (non-fatal)"
                        );
                    }
                    match &resolution {
                        crate::quote_pricing_pipeline::PythonResolution::NotResolved {
                            canonical_path,
                        } => {
                            tracing::info!(
                                expected_venv = %canonical_path.display(),
                                "quote-pricing-pipeline daemon dormant — \
                                 Python venv not detected. Run ./run/upgrade_prod.sh \
                                 to provision."
                            );
                            // status.daemon_spawned stays false; SPA shows RED.
                            st.pipeline_python_resolution.record(status);
                        }
                        resolved => {
                            let python_bin = resolved
                                .resolved_path()
                                .expect("resolved arm always has a path")
                                .to_path_buf();
                            let artifact_dir = std::env::var(
                                "ABERP_QUOTE_PIPELINE_ARTIFACT_DIR",
                            )
                            .map(std::path::PathBuf::from)
                            .unwrap_or_else(|_| {
                                std::path::PathBuf::from("./quote-artifacts")
                            });
                            let pipeline_cfg =
                                crate::quote_pricing_pipeline::PricingPipelineConfig {
                                    base_url: catalogue_base_url,
                                    bearer_token: catalogue_bearer,
                                    poll_interval: std::time::Duration::from_secs(
                                        PIPELINE_POLL_SECS,
                                    ),
                                    artifact_dir,
                                    python_bin,
                                    default_tolerance:
                                        aberp_quote_engine::ToleranceRange::Standard,
                                };
                            let pipeline_deps =
                                crate::quote_pricing_pipeline::PricingPipelineDeps {
                                    db_path: (*st.db_path).clone(),
                                    db: st.db.clone(),
                                    tenant: st.tenant.clone(),
                                    binary_hash,
                                    operator_login: pipeline_operator_login.clone(),
                                };
                            // S430 / ADR-0083 — load (or mint on first
                            // boot) the tenant's AES-256-GCM CAD-blob key
                            // from the OS keychain. A freshly-minted key
                            // emits CadBlobKeyProvisioned. Keychain read +
                            // the one-shot audit write go through
                            // spawn_blocking. A provisioning error folds
                            // into the same graceful Err arm as a
                            // service-construction error (AMBER, boot
                            // survives) — we never fall back to writing
                            // CAD blobs in the clear.
                            let cad_blob_ctx_result = {
                                let cad_tenant = st.tenant.as_str().to_string();
                                let cad_db = st.db.clone();
                                let cad_login = pipeline_operator_login.clone();
                                tokio::task::spawn_blocking(
                                    move || -> Result<crate::cad_blob::CadBlobCtx> {
                                        let (key, prov) =
                                            crate::cad_blob::load_or_provision_key(&cad_tenant)?;
                                        if prov == crate::cad_blob::KeyProvision::Minted {
                                            // ADR-0098: route through the shared Handle, never a
                                            // separate boot opener. A raw Connection::open here is a
                                            // SECOND un-pragma'd DuckDB instance whose fold-on-close
                                            // double-applies the Handle's pending-WAL tail (the
                                            // audit_ledger has no UNIQUE on `seq` since S341), forking
                                            // a DB-only, mirror-absent audit row. write() folds on the
                                            // one instance and its WriteGuard drop runs sync_mirror.
                                            let mut guard = cad_db.write().context(
                                                "shared writer: cad-blob-key provision audit (ADR-0098)",
                                            )?;
                                            aberp_audit_ledger::ensure_schema(&guard)
                                                .context("ensure audit schema for cad-blob key")?;
                                            crate::cad_blob::emit_key_provisioned(
                                                &mut guard,
                                                &cad_tenant,
                                                binary_hash,
                                                &cad_login,
                                            )?;
                                        }
                                        Ok(crate::cad_blob::CadBlobCtx::new(key))
                                    },
                                )
                                .await
                                .context("cad-blob-key provision join")
                                .and_then(|r| r)
                            };
                            match cad_blob_ctx_result.and_then(|cad_blob_ctx| {
                                crate::quote_pricing_pipeline::PricingPipelineService::new(
                                    pipeline_cfg,
                                    pipeline_deps,
                                    cad_blob_ctx,
                                )
                            }) {
                                Ok(service) => {
                                    // S288 / PR-269 — boot-time migration:
                                    // detect + drop the orphan
                                    // `quote_pricing_jobs_tenant_state_idx`
                                    // secondary index that caused the
                                    // PROD_v2.27.2/3 DuckDB FATAL. Returns
                                    // `true` when migrating an existing
                                    // prod DB; `false` on fresh installs
                                    // or post-migration boots. The audit
                                    // row fires only on `true`, giving a
                                    // forensic walker one-shot evidence
                                    // that this install was migrated.
                                    let migrate_db = st.db.clone();
                                    let migrate_res = tokio::task::spawn_blocking(
                                        move || -> Result<bool> {
                                            // ADR-0098: shared-Handle write(), not a separate boot
                                            // opener. The migration DDL runs on the ONE instance so no
                                            // second un-pragma'd instance folds the Handle's pending
                                            // WAL (which would fork a DB-only, mirror-absent audit row
                                            // — no UNIQUE on audit_ledger.seq since S341).
                                            let guard = migrate_db.write().context(
                                                "shared writer: S288 index migration (ADR-0098)",
                                            )?;
                                            crate::quote_pricing_jobs::migrate_secondary_index_with_report(
                                                &guard,
                                            )
                                        },
                                    )
                                    .await;
                                    match migrate_res {
                                        Ok(Ok(true)) => {
                                            tracing::info!(
                                                "quote_pricing_jobs orphan secondary index \
                                                 detected + dropped (S288/PR-269 migration)"
                                            );
                                            if let Err(e) =
                                                crate::quote_pricing_pipeline::emit_index_migrated_audit(
                                                    &st.db,
                                                    st.tenant.as_str(),
                                                    binary_hash,
                                                    &pipeline_operator_login,
                                                )
                                            {
                                                tracing::warn!(
                                                    error = %e,
                                                    "quote.pricing_jobs_index_migrated audit \
                                                     emit failed (non-fatal)"
                                                );
                                            }
                                        }
                                        Ok(Ok(false)) => tracing::debug!(
                                            "quote_pricing_jobs orphan index absent — \
                                             migration no-op (S288/PR-269)"
                                        ),
                                        Ok(Err(e)) => tracing::warn!(
                                            error = %e,
                                            "quote_pricing_jobs index migration failed (non-fatal)"
                                        ),
                                        Err(e) => tracing::warn!(
                                            error = %e,
                                            "index-migration spawn_blocking join failed"
                                        ),
                                    }
                                    // S286 / PR-268 hotfix — log the
                                    // existing-row population at boot so
                                    // the operator can see what's in
                                    // `quote_pricing_jobs` before any
                                    // poll-cycle runs. Per the post-
                                    // mortem of PROD_v2.27.2: a pre-
                                    // existing row was racing the daemon
                                    // into a DuckDB FATAL.
                                    let count_db = st.db.clone();
                                    let count_tenant = st.tenant.as_str().to_string();
                                    let count_res =
                                        tokio::task::spawn_blocking(move || -> Result<u64> {
                                            // ADR-0098: shared-Handle read() (a coherent try_clone of
                                            // the one instance), not a separate boot opener whose
                                            // fold-on-close would double-apply the Handle's pending
                                            // WAL tail and fork a DB-only, mirror-absent audit row.
                                            let conn = count_db.read().context(
                                                "shared read: quote_pricing_jobs boot count (ADR-0098)",
                                            )?;
                                            crate::quote_pricing_jobs::count_jobs(
                                                &conn,
                                                &count_tenant,
                                            )
                                        })
                                        .await;
                                    match count_res {
                                        Ok(Ok(n)) => tracing::info!(
                                            existing_row_count = n,
                                            "quote_pricing_jobs boot snapshot (S286/PR-268)"
                                        ),
                                        Ok(Err(e)) => tracing::warn!(
                                            error = %e,
                                            "quote_pricing_jobs boot row-count failed (non-fatal)"
                                        ),
                                        Err(e) => tracing::warn!(
                                            error = %e,
                                            "boot row-count spawn_blocking join failed"
                                        ),
                                    }
                                    tracing::info!(
                                        resolution_kind = %status.resolution_kind,
                                        resolved_path =
                                            status.resolved_path.as_deref().unwrap_or("?"),
                                        "spawning quote-pricing-pipeline daemon \
                                         (S279 / PR-265, resolver S282 / PR-267, \
                                          supervisor S286 / PR-268)"
                                    );
                                    // S2 / ADR-0093 — defense-in-depth: this storefront daemon is only
                                    // reachable in a Defense build (the boot guard / spawn gate above). The
                                    // assert is the never-hit backstop that pins the invariant at the spawn.
                                    debug_assert!(
                                        crate::build_profile::storefront_polling_allowed(),
                                        "pricing-pipeline daemon spawned in a non-Defense edition — storefront reach is \
                                         compiled out (ADR-0093)"
                                    );
                                    let pipeline_token = coordinator.token.clone();
                                    let pipeline_handle = tokio::spawn(async move {
                                        // S286 / PR-268 — wrapped in panic-
                                        // recovery supervisor so a Rust-side
                                        // panic doesn't take down the host
                                        // process. C++-level libc++abi
                                        // terminations from DuckDB still
                                        // can't be caught — those are
                                        // defended by the SELECT-first
                                        // pattern in quote_pricing_jobs.
                                        service.run_daemon_supervised(pipeline_token).await;
                                    });
                                    coordinator.register(
                                        "quote-pricing-pipeline",
                                        pipeline_handle,
                                    );
                                    status.daemon_spawned = true;
                                    st.pipeline_python_resolution.record(status);
                                }
                                Err(e) => {
                                    // Resolved-but-spawn-errored → AMBER in SPA.
                                    // Don't kill boot — the rest of ABERP is fine.
                                    tracing::warn!(
                                        error = %e,
                                        "quote-pricing-pipeline daemon construction failed \
                                         after successful resolution"
                                    );
                                    st.pipeline_python_resolution.record(status);
                                }
                            }
                        }
                    }
                }
                Err(QuoteIntakeError::Disabled) => {
                    tracing::info!(
                        "quote-intake daemon disabled (no env vars and \
                         [quote_intake].enabled != true); skipping spawn"
                    );
                }
                Err(e) => {
                    // S2 / ADR-0093 — a non-Disabled error means storefront
                    // config WAS present (env flag / [quote_intake] set) but
                    // malformed. On a non-Defense build refuse with the clear
                    // edition message (exit 1) rather than a downstream
                    // "URL/token missing" symptom; on Defense this is a no-op
                    // and the original config error is returned as before.
                    guard_storefront_reach_matches_edition();
                    return Err(anyhow!("quote-intake config error: {e:#}"));
                }
            }
        }

        // S257 / PR-246 — Stage 3 manufacturing-adapter boot. The source
        // of truth is now the `[[mes.adapters]]` seller.toml slot, NOT
        // env vars (per [[trust-code-not-operator]]: operators manage
        // adapters from Settings → Adapters, never by editing env +
        // restart). Boot does two steps:
        //   1. migrate any env-defined adapter into the TOML, ONE-SHOT +
        //      idempotent (upsert by adapter_id) — an operator with
        //      `ABERP_ZEBRA_ENABLED=true` sees that printer appear in the
        //      Adapters page on first post-S257 boot with no action;
        //   2. start every persisted adapter via the AdapterManager,
        //      registering each spawned task with the shutdown
        //      coordinator. One bad adapter is logged + skipped, not
        //      boot-fatal (it stays in TOML for an operator fix).
        //
        // DoS bounds stay compiled-in per [[trust-code-not-operator]].
        {
            let operator_login = match recovery_state.boot_state.read() {
                Ok(guard) => match &*guard {
                    ServeBootState::Ready { operator_login } => operator_login.clone(),
                    _ => "boot".to_string(),
                },
                Err(_) => "boot".to_string(),
            };
            let binary_hash = recovery_state
                .binary_hash
                .wait()
                .context("await background binary hash for MES adapter boot")?;
            let mes_deps = crate::mes_boot::MesBootDeps {
                db_path: (*recovery_state.db_path).clone(),
                tenant: recovery_state.tenant.clone(),
                binary_hash,
                operator_login,
                session_id: Ulid::new().to_string(),
            };
            let seller_toml_path = setup_seller_info::seller_toml_path_for_tenant(
                recovery_state.tenant.as_str(),
            )
            .context("resolve seller.toml path for MES adapter boot")?;
            match crate::mes_boot::migrate_env_adapters_to_toml(&seller_toml_path) {
                Ok(0) => {}
                Ok(n) => tracing::info!(
                    migrated = n,
                    "migrated {n} env-defined MES adapter(s) into [[mes.adapters]] (S257)"
                ),
                Err(e) => return Err(anyhow!("MES env→TOML adapter migration failed: {e:#}")),
            }
            match recovery_state
                .adapter_manager
                .boot_from_toml(&mes_deps, &seller_toml_path)
                .await
            {
                Ok(handles) => {
                    for (label, handle) in handles {
                        coordinator.register(label, handle);
                    }
                }
                Err(e) => {
                    return Err(anyhow!("MES adapter boot failed: {e:#}"));
                }
            }
        }

        // S281 / PR-266 — spawn the email-relay drain daemon. Active by
        // default (the queue table is process-local and a row can
        // arrive any time the relay token is configured). The drain
        // shutdown-cooperates via the coordinator's cancellation
        // token per [[graceful-shutdown-s213]].
        //
        // ADR-0098 S0 (the interim-stopgap bridge) — this drain is the
        // one *unconditional* ~2s separate-instance DuckDB opener that the
        // stopgap otherwise cannot quiet (it opens the live DB every
        // `DRAIN_TICK_SECS` to claim a row; ADR-0098 D8 / the "Interim
        // stopgap" section). `ABERP_EMAIL_RELAY_DRAIN_DISABLED` (mirroring
        // the email-outbox / pdf-rerender kill switches) lets an operator
        // silence it for a degraded-but-stable manual-invoicing session.
        // Unset => today's behavior, byte-for-byte. Risk-reduction, not
        // tear-proof — the full fix is Session B's single shared
        // `aberp_db::Handle`.
        if crate::email_relay_daemon::is_disabled() {
            tracing::info!(
                env = crate::email_relay_daemon::POLL_DISABLE_ENV,
                "email-relay drain daemon NOT spawned — disabled by env \
                 (ADR-0098 S0 bridge); queued outbound email will not be sent \
                 until the flag is unset and serve is restarted"
            );
        } else {
            let operator_login = match recovery_state.boot_state.read() {
                Ok(guard) => match &*guard {
                    ServeBootState::Ready { operator_login } => operator_login.clone(),
                    ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
                    _ => "boot".to_string(),
                },
                Err(_) => "boot".to_string(),
            };
            let binary_hash = recovery_state
                .binary_hash
                .wait()
                .context("await background binary hash for email-relay drain daemon")?;
            let seller_toml_path = setup_seller_info::seller_toml_path_for_tenant(
                recovery_state.tenant.as_str(),
            )
            .context("resolve seller.toml path for email-relay drain")?;
            let relay_deps = crate::email_relay_daemon::EmailRelayDaemonDeps {
                db_path: (*recovery_state.db_path).clone(),
                db: recovery_state.db.clone(),
                tenant: recovery_state.tenant.clone(),
                binary_hash,
                operator_login,
                seller_toml_path,
                secrets_cache: recovery_state.secrets_cache.clone(),
            };
            let relay_token = coordinator.token.clone();
            let relay_handle = tokio::spawn(async move {
                crate::email_relay_daemon::run_drain_loop(relay_deps, relay_token).await;
            });
            coordinator.register("email-relay-drain", relay_handle);
            tracing::info!(
                tick_secs = crate::email_relay_daemon::DRAIN_TICK_SECS,
                retry_cap = crate::email_relay_daemon::MAX_ATTEMPTS_PER_ROW,
                "spawned email-relay drain daemon (S281 / PR-266)"
            );
        }

        // S431 — AVL re-screening reminder. One-shot at boot: fire
        // `supplier.avl_screening_overdue` once per non-revoked vendor whose
        // `approved_until_utc` has lapsed. Non-fatal — a reminder scan must
        // never block boot ([[hulye-biztos]]); errors are logged, not `?`-ed.
        {
            let operator_login = match recovery_state.boot_state.read() {
                Ok(guard) => match &*guard {
                    ServeBootState::Ready { operator_login } => operator_login.clone(),
                    ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
                    _ => "boot".to_string(),
                },
                Err(_) => "boot".to_string(),
            };
            match recovery_state.binary_hash.wait() {
                Ok(binary_hash) => {
                    let db_path = (*recovery_state.db_path).clone();
                    let tenant = recovery_state.tenant.clone();
                    let scan = tokio::task::spawn_blocking(move || {
                        crate::avl_vendors::fire_overdue_screening_reminders(
                            &db_path,
                            tenant,
                            binary_hash,
                            &operator_login,
                            time::OffsetDateTime::now_utc(),
                        )
                    })
                    .await;
                    match scan {
                        Ok(Ok(n)) if n > 0 => tracing::warn!(
                            overdue = n,
                            "S431: {n} AVL vendor(s) overdue for re-screening — \
                             supplier.avl_screening_overdue fired"
                        ),
                        Ok(Ok(_)) => {
                            tracing::info!("S431: no AVL vendors overdue for re-screening")
                        }
                        Ok(Err(e)) => tracing::error!(
                            error = ?e,
                            "S431: AVL re-screening reminder scan failed (non-fatal)"
                        ),
                        Err(join_err) => tracing::error!(
                            error = %join_err,
                            "S431: AVL re-screening reminder scan panicked (non-fatal)"
                        ),
                    }
                }
                Err(e) => tracing::error!(
                    error = %e,
                    "S431: binary hash unavailable for AVL re-screening scan (non-fatal)"
                ),
            }
        }

        // S439 (ADR-0090) — NCR escalation. One-shot at boot: auto-escalate
        // every `Critical` NCR not closed within the 24h window
        // ([[trust-code-not-operator]]). Non-fatal — a quality scan must never
        // block boot ([[hulye-biztos]]); errors are logged, not `?`-ed.
        {
            let operator_login = match recovery_state.boot_state.read() {
                Ok(guard) => match &*guard {
                    ServeBootState::Ready { operator_login } => operator_login.clone(),
                    ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
                    _ => "boot".to_string(),
                },
                Err(_) => "boot".to_string(),
            };
            match recovery_state.binary_hash.wait() {
                Ok(binary_hash) => {
                    let db_path = (*recovery_state.db_path).clone();
                    let tenant = recovery_state.tenant.clone();
                    let scan = tokio::task::spawn_blocking(move || {
                        crate::quality::escalate_overdue_ncrs(
                            &db_path,
                            tenant,
                            binary_hash,
                            &operator_login,
                            time::OffsetDateTime::now_utc(),
                        )
                    })
                    .await;
                    match scan {
                        Ok(Ok(n)) if n > 0 => tracing::warn!(
                            escalated = n,
                            "S439: {n} Critical NCR(s) auto-escalated — ncr.escalated fired"
                        ),
                        Ok(Ok(_)) => tracing::info!("S439: no NCRs overdue for escalation"),
                        Ok(Err(e)) => tracing::error!(
                            error = ?e,
                            "S439: NCR escalation scan failed (non-fatal)"
                        ),
                        Err(join_err) => tracing::error!(
                            error = %join_err,
                            "S439: NCR escalation scan panicked (non-fatal)"
                        ),
                    }
                }
                Err(e) => tracing::error!(
                    error = %e,
                    "S439: binary hash unavailable for NCR escalation scan (non-fatal)"
                ),
            }
        }

        // S307 / PR-276 — spawn the email-outbox poll daemon (ADR-0009).
        // Polls the storefront's `/api/internal/email-queue` outbound and
        // delivers via the same SMTP creds the S281 drain uses. The kill
        // switch `ABERP_EMAIL_OUTBOX_POLL_DISABLED=1` suppresses the
        // spawn for local-dev (when the operator is hitting the
        // deprecated push endpoint directly) or for emergency rollback.
        // The storefront-credential handle is the shared S289 SPOC; the
        // daemon snapshots it per cycle, so an operator URL change in
        // SPA → Settings → Quote Intake takes effect without a restart.
        if !crate::build_profile::storefront_polling_allowed() {
            // S2 / ADR-0093 — the email-outbox daemon polls + writes back to
            // the storefront's `/api/internal/email-queue`. Storefront reach
            // is Defense-only; a Portable build must not spawn it (the local
            // SMTP drain stays available). Never spawned ⇒ never reaches
            // abenerp.com, regardless of the storefront credential.
            tracing::info!(
                edition = crate::build_profile::edition_label(),
                "email-outbox poll daemon NOT spawned — storefront reach is a Defense-only \
                 capability, compiled out of this edition (ADR-0093)"
            );
        } else if crate::email_outbox_poll_daemon::is_disabled() {
            tracing::info!(
                env = crate::email_outbox_poll_daemon::POLL_DISABLE_ENV,
                "email-outbox poll daemon disabled by env (S307 / PR-276)"
            );
        } else {
            let operator_login = match recovery_state.boot_state.read() {
                Ok(guard) => match &*guard {
                    ServeBootState::Ready { operator_login } => operator_login.clone(),
                    ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
                    _ => "boot".to_string(),
                },
                Err(_) => "boot".to_string(),
            };
            let binary_hash = recovery_state
                .binary_hash
                .wait()
                .context("await background binary hash for email-outbox poll daemon")?;
            let seller_toml_path = setup_seller_info::seller_toml_path_for_tenant(
                recovery_state.tenant.as_str(),
            )
            .context("resolve seller.toml path for email-outbox poll")?;
            let poll_interval = crate::email_outbox_poll_daemon::resolve_poll_interval();
            let outbox_sender =
                std::sync::Arc::new(crate::email_outbox_poll_daemon::LettreSender {
                    seller_toml_path,
                    secrets_cache: recovery_state.secrets_cache.clone(),
                });
            let outbox_deps = crate::email_outbox_poll_daemon::EmailOutboxPollDaemonDeps {
                db_path: (*recovery_state.db_path).clone(),
                db: recovery_state.db.clone(),
                tenant: recovery_state.tenant.clone(),
                binary_hash,
                operator_login,
                storefront_credential: recovery_state.storefront_credential.clone(),
                status: recovery_state.email_outbox_daemon.clone(),
                poll_interval,
                sender: outbox_sender,
            };
            // S2 / ADR-0093 — defense-in-depth: this storefront daemon is only
            // reachable in a Defense build (the boot guard / spawn gate above). The
            // assert is the never-hit backstop that pins the invariant at the spawn.
            debug_assert!(
                crate::build_profile::storefront_polling_allowed(),
                "email-outbox poll daemon spawned in a non-Defense edition — storefront reach is \
                 compiled out (ADR-0093)"
            );
            let outbox_token = coordinator.token.clone();
            let outbox_handle = tokio::spawn(async move {
                crate::email_outbox_poll_daemon::run_supervised(outbox_deps, outbox_token).await;
            });
            coordinator.register("email-outbox-poll", outbox_handle);
            tracing::info!(
                poll_interval_secs = poll_interval.as_secs(),
                "spawned email-outbox poll daemon (S307 / PR-276)"
            );
        }

        // S325 / PR-25 — spawn the customer-PDF re-render daemon (EVE
        // addendum-2). Drains the in-memory `quote_pdf_rerender_queue`
        // (fed read-side by `handle_list_quote_intake` on a FALSE→TRUE
        // stock_alert flip) and re-POSTs `priced.pdf` with the stock-alert
        // banner to the storefront `/priced` (relaxed S323-side to accept
        // a same-hash, stock_alert:true re-post). Shares the S289
        // storefront-credential SPOC, so an operator URL change takes
        // effect on the next cycle. Kill switch:
        // `ABERP_PDF_RERENDER_DISABLED=1`.
        if !crate::build_profile::storefront_polling_allowed() {
            // S2 / ADR-0093 — the pdf-rerender daemon re-POSTs priced PDFs to
            // the storefront `/api/quotes/{id}/priced`. Storefront reach is
            // Defense-only; a Portable build must not spawn it. Never spawned
            // ⇒ never reaches abenerp.com.
            tracing::info!(
                edition = crate::build_profile::edition_label(),
                "pdf-rerender daemon NOT spawned — storefront reach is a Defense-only \
                 capability, compiled out of this edition (ADR-0093)"
            );
        } else if crate::quote_pdf_rerender_daemon::is_disabled() {
            tracing::info!(
                env = crate::quote_pdf_rerender_daemon::POLL_DISABLE_ENV,
                "pdf-rerender daemon disabled by env (S325 / PR-25)"
            );
        } else {
            let rr_operator_login = match recovery_state.boot_state.read() {
                Ok(guard) => match &*guard {
                    ServeBootState::Ready { operator_login } => operator_login.clone(),
                    ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
                    _ => "boot".to_string(),
                },
                Err(_) => "boot".to_string(),
            };
            let rr_binary_hash = recovery_state
                .binary_hash
                .wait()
                .context("await background binary hash for pdf-rerender daemon")?;
            let rr_poll_interval = crate::quote_pdf_rerender_daemon::resolve_poll_interval();
            // S329 / 🔴4 — the in-memory queue starts empty every boot; a
            // crash mid-drain loses the batch. Replay every
            // `QuotePdfRerenderEnqueued` audit row that never reached a
            // terminal back into the queue before the daemon spawns.
            // Best-effort: a recovery error is logged, not fatal — the
            // daemon still serves new transitions.
            match crate::quote_pdf_rerender_daemon::recover_unfinished_rerenders(
                &recovery_state.db,
                &recovery_state.tenant,
                &recovery_state.quote_pdf_rerender_queue,
            ) {
                Ok(n) if n > 0 => tracing::info!(
                    recovered = n,
                    "pdf-rerender boot recovery re-enqueued unfinished re-render intents (S329)"
                ),
                Ok(_) => {}
                Err(e) => tracing::error!(
                    error = %e,
                    "pdf-rerender boot recovery failed; new transitions still served (S329)"
                ),
            }
            let rr_deps = crate::quote_pdf_rerender_daemon::QuotePdfRerenderDaemonDeps {
                db_path: (*recovery_state.db_path).clone(),
                db: recovery_state.db.clone(),
                tenant: recovery_state.tenant.clone(),
                binary_hash: rr_binary_hash,
                operator_login: rr_operator_login,
                storefront_credential: recovery_state.storefront_credential.clone(),
                queue: recovery_state.quote_pdf_rerender_queue.clone(),
                poll_interval: rr_poll_interval,
            };
            // S2 / ADR-0093 — defense-in-depth: this storefront daemon is only
            // reachable in a Defense build (the boot guard / spawn gate above). The
            // assert is the never-hit backstop that pins the invariant at the spawn.
            debug_assert!(
                crate::build_profile::storefront_polling_allowed(),
                "pdf-rerender daemon spawned in a non-Defense edition — storefront reach is \
                 compiled out (ADR-0093)"
            );
            let rr_token = coordinator.token.clone();
            let rr_handle = tokio::spawn(async move {
                crate::quote_pdf_rerender_daemon::run_supervised(rr_deps, rr_token).await;
            });
            coordinator.register("pdf-rerender", rr_handle);
            tracing::info!(
                poll_interval_secs = rr_poll_interval.as_secs(),
                "spawned pdf-rerender daemon (S325 / PR-25)"
            );
        }

        // S426 / ADR-0082 — periodic, validated, logical DB-snapshot daemon
        // (`EXPORT DATABASE` every 4h → validate → retention). Every error
        // here is logged-and-skipped, NEVER fatal: a snapshot subsystem
        // problem must not block prod startup. Kill switch:
        // `ABERP_SNAPSHOT_DISABLE=1`.
        if crate::snapshot::is_disabled() {
            tracing::info!(
                env = crate::snapshot::POLL_DISABLE_ENV,
                "snapshot daemon disabled by env (S426 / ADR-0082)"
            );
        } else {
            match recovery_state.binary_hash.wait() {
                Ok(snap_binary_hash) => {
                    match crate::snapshot::resolve_store(recovery_state.tenant.as_str(), None) {
                        Ok(snap_store_dir) => {
                            let snap_deps = crate::snapshot::SnapshotDaemonDeps {
                                db_path: (*recovery_state.db_path).clone(),
                                tenant: recovery_state.tenant.clone(),
                                binary_hash: snap_binary_hash,
                                store_dir: snap_store_dir,
                                interval: crate::snapshot::interval_from_env(),
                                policy: crate::snapshot::policy_from_env(),
                            };
                            let snap_interval_secs = snap_deps.interval.as_secs();
                            let snap_token = coordinator.token.clone();
                            let snap_handle = tokio::spawn(async move {
                                crate::snapshot::run_supervised(snap_deps, snap_token).await;
                            });
                            coordinator.register("snapshot", snap_handle);
                            tracing::info!(
                                interval_secs = snap_interval_secs,
                                "spawned snapshot daemon (S426 / ADR-0082)"
                            );
                        }
                        Err(e) => tracing::error!(
                            error = %e,
                            "snapshot store dir unresolved; snapshot daemon NOT spawned (boot continues)"
                        ),
                    }
                }
                Err(e) => tracing::error!(
                    error = %e,
                    "binary hash unavailable; snapshot daemon NOT spawned (boot continues)"
                ),
            }
        }

        // ADR-0095 §3 — post-meaningful-write durable checkpoint (debounced).
        // Install the process-global coordinator for THIS tenant DB and spawn
        // its debounce loop on the graceful-shutdown token, so a durable
        // checkpoint follows a burst of regulated writes (invoice issue /
        // storno / modification) within ~1 min — bounding the exposure window
        // after an important commit without ever stalling the request path.
        // No-op when disabled by env; the periodic daemon checkpoint (§3) and
        // the clean-shutdown checkpoint remain regardless.
        match crate::live_checkpoint::install(
            (*recovery_state.db_path).clone(),
            recovery_state.tenant.as_str().to_string(),
        ) {
            Some(pw) => {
                let pw_token = coordinator.token.clone();
                let pw_handle = tokio::spawn(async move {
                    pw.run(pw_token).await;
                });
                coordinator.register("post_write_checkpoint", pw_handle);
                tracing::info!("spawned post-write durable-checkpoint debouncer (ADR-0095 §3)");
            }
            None => tracing::info!(
                "post-write durable-checkpoint debouncer NOT spawned (disabled by env)"
            ),
        }

        // S441 / ADR-0087 + ADR-0088 — DÁP/QES timestamp-anchored audit
        // chain. Gated on the tenant's `dap_enabled` flag (default false →
        // existing unsigned chain, no behaviour change). On opt-in: open the
        // service session BEFORE serving, run crash recovery, spawn the
        // heartbeat actor. Keychain + TSA only touched on this opt-in path.
        match crate::tenant_registry::tenant_dap_config(recovery_state.tenant.as_str()) {
            Ok((true, heartbeat_secs)) => {
                if let Err(e) =
                    spawn_dap_audit_chain(&recovery_state, &mut coordinator, heartbeat_secs)
                {
                    tracing::error!(
                        error = %e,
                        "DÁP audit chain boot FAILED; serving continues on the unsigned chain (S441)"
                    );
                }
            }
            Ok((false, _)) => {}
            Err(e) => tracing::warn!(
                error = %e,
                "could not read dap_enabled; assuming OFF (unsigned chain) — S441"
            ),
        }

        let config = RustlsConfig::from_der(rustls_config.0, rustls_config.1)
            .await
            .context("build axum-server RustlsConfig")?;

        // PR-209 / S213 — graceful-shutdown wiring. axum-server's
        // `Handle::graceful_shutdown(None)` stops accepting new
        // connections and lets in-flight requests drain; we then
        // call the coordinator's `shutdown(timeout)` to fan
        // cancellation out to every registered daemon, write ONE
        // `DaemonShutdownCompleted` audit row, log the result, and
        // force-exit. The process MUST exit after this — any
        // un-registered tokio task would otherwise hold it alive
        // forever, which is exactly the bug PR-209 closes.
        let axum_handle = axum_server::Handle::new();
        let signal_axum_handle = axum_handle.clone();
        let signal_token = coordinator.token.clone();

        // Listen for ctrl_c (terminal launch) OR SIGTERM (Tauri
        // close handler routes window-close → child SIGTERM via the
        // `Child::kill` upgrade landed in `apps/aberp-ui/src/
        // backend.rs`). The first signal to arrive wins the race;
        // the resulting trigger string flows into the audit payload.
        let signal_listener: tokio::task::JoinHandle<&'static str> = tokio::spawn(async move {
            #[cfg(unix)]
            {
                use tokio::signal::unix::{signal, SignalKind};
                let mut sigterm = match signal(SignalKind::terminate()) {
                    Ok(s) => s,
                    Err(e) => {
                        tracing::warn!(error = %e, "could not install SIGTERM handler; \
                             relying on ctrl_c only");
                        // Fall back to ctrl_c-only: install a
                        // never-firing future for the SIGTERM arm.
                        let trigger = tokio::signal::ctrl_c()
                            .await
                            .map(|_| "ctrl-c")
                            .unwrap_or("ctrl-c-error");
                        signal_token.cancel();
                        signal_axum_handle.graceful_shutdown(Some(Duration::from_secs(2)));
                        return trigger;
                    }
                };
                let mut sighup = signal(SignalKind::hangup()).ok();
                let trigger = tokio::select! {
                    res = tokio::signal::ctrl_c() => {
                        if let Err(e) = res {
                            tracing::warn!(error = %e, "ctrl_c listener errored");
                        }
                        "ctrl-c"
                    }
                    _ = sigterm.recv() => "sigterm",
                    _ = async {
                        match sighup.as_mut() {
                            Some(s) => { s.recv().await; }
                            None => std::future::pending::<()>().await,
                        }
                    } => "hangup",
                };
                tracing::info!(trigger, "shutdown signal received; draining daemons");
                signal_token.cancel();
                signal_axum_handle.graceful_shutdown(Some(Duration::from_secs(2)));
                trigger
            }
            #[cfg(not(unix))]
            {
                let _ = tokio::signal::ctrl_c().await;
                tracing::info!(trigger = "ctrl-c", "shutdown signal received; draining daemons");
                signal_token.cancel();
                signal_axum_handle.graceful_shutdown(Some(Duration::from_secs(2)));
                "ctrl-c"
            }
        });

        let serve_result = axum_server::from_tcp_rustls(listener, config)
            .handle(axum_handle)
            .serve(app.into_make_service())
            .await
            .context("axum_server::from_tcp_rustls(...).serve(...)");

        // Reach the trigger label. If the signal listener has fired
        // (the common path — serve only returns AFTER graceful_shutdown
        // is called), join completes immediately. If serve returned for
        // another reason (axum error), the listener is still pending;
        // we abort it and treat the trigger as "axum-error" so the
        // audit row carries the truthful cause.
        let trigger: String = if signal_listener.is_finished() {
            signal_listener.await.map(|s| s.to_string()).unwrap_or_else(|e| {
                tracing::warn!(error = ?e, "signal listener task failed");
                "signal-task-error".to_string()
            })
        } else {
            signal_listener.abort();
            "axum-error".to_string()
        };

        // Drive the coordinator's drain pass. Returns within
        // `shutdown_timeout_from_env()` (default 5s) regardless of
        // daemon cooperation.
        let timeout = shutdown::shutdown_timeout_from_env();
        let shutdown_result = coordinator.shutdown(timeout).await;
        log_shutdown_result(&shutdown_result);
        write_shutdown_audit_entry(&recovery_state, &trigger, &shutdown_result);

        // ADR-0082 follow-up (chunk 3) — leave the live DB crash-safe on a
        // CLEAN shutdown: fold the WAL into a fresh, verified-good file via
        // an atomic swap so the next boot needs no in-place WAL replay (the
        // path that historically tripped duckdb#23046). Best-effort; logged
        // loud and never blocks process exit. Editions-tree only.
        crate::snapshot::checkpoint_on_clean_shutdown(
            recovery_state.db_path.as_path(),
            recovery_state.tenant.as_str(),
        );

        // S291 / PR-272 — best-effort delete of the runtime-discovery
        // file (brief D). A leaked file from a crash is harmless
        // (next boot overwrites it), but the storefront's dev launcher
        // reads this as "is ABERP running?"; a stale-but-present file
        // would lie. Logged at DEBUG (the operator's local-loopback
        // test path needs no signal here on the success path).
        match crate::runtime_discovery::delete(recovery_state.tenant.as_str()) {
            Ok(true) => tracing::debug!("runtime-discovery file deleted"),
            Ok(false) => {}
            Err(e) => tracing::warn!(error = ?e, "runtime-discovery delete failed"),
        }

        // The serve_result was captured BEFORE the drain so a hard
        // axum error still bubbles up via the runtime. We return
        // Ok(()) on the success path so the binary exits 0 cleanly.
        serve_result
    })?;

    Ok(())
}

/// PR-209 / S213 — log the coordinator's drain outcome. Pretty-formats
/// the timeout list so a `RUST_LOG=info` operator sees exactly which
/// daemon hung (or that nothing did) without having to re-parse JSON.
fn log_shutdown_result(result: &ShutdownResult) {
    if result.timeout_kills.is_empty() {
        tracing::info!(
            clean_exits = result.clean_exits,
            elapsed_ms = result.elapsed_ms,
            "graceful shutdown drained all daemons within timeout"
        );
    } else {
        tracing::warn!(
            clean_exits = result.clean_exits,
            timeout_kills = ?result.timeout_kills,
            elapsed_ms = result.elapsed_ms,
            "graceful shutdown drain timed out; named daemons will be \
             force-killed by process exit"
        );
    }
}

/// PR-209 / S213 — write the per-shutdown audit row. Best-effort: a
/// failure here logs loud but does NOT block the process exit — the
/// alternative would be a stuck process the operator can't kill, which
/// is the original bug. The audit chain is anchored at the next boot
/// via the existing boot-recovery scan.
fn write_shutdown_audit_entry(state: &AppState, trigger: &str, result: &ShutdownResult) {
    let binary_hash = match state.binary_hash.wait() {
        Ok(h) => h,
        Err(e) => {
            tracing::error!(
                error = ?e,
                "could not resolve binary hash for shutdown audit entry; skipping"
            );
            return;
        }
    };
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            _ => "shutdown".to_string(),
        },
        Err(_) => "shutdown".to_string(),
    };

    let payload = audit_payloads::DaemonShutdownCompletedPayload {
        idempotency_key: aberp_billing::IdempotencyKey::new().to_canonical_string(),
        trigger: trigger.to_string(),
        registered_daemons: {
            // Re-derive from the result: clean + timeout names sum
            // to the full registration. We don't have the clean
            // daemon names individually (the coordinator's API only
            // reports the timeout side by name to keep allocations
            // off the shutdown hot path), so we list the timeout
            // names + a placeholder count for the clean side. A
            // future PR can extend the API if a postmortem ever
            // needs per-clean-daemon names.
            let mut v = Vec::new();
            v.push(format!("clean_exits={}", result.clean_exits));
            for name in &result.timeout_kills {
                v.push((*name).to_string());
            }
            v
        },
        clean_exits: result.clean_exits as u64,
        timeout_kills: result
            .timeout_kills
            .iter()
            .map(|s| (*s).to_string())
            .collect(),
        elapsed_ms: result.elapsed_ms,
    };

    let tenant = state.tenant.clone();
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);
    let bytes = payload.to_bytes();

    let write_outcome = (|| -> Result<()> {
        let mut conn = state
            .db
            .write()
            .context("shared writer: shutdown audit entry (ADR-0098 Gap 1a Session C)")?;
        aberp_audit_ledger::ensure_schema(&conn)
            .context("ensure audit-ledger schema for shutdown audit entry")?;
        let tx = conn
            .transaction()
            .context("begin DuckDB transaction for shutdown audit entry")?;
        let ledger_meta = aberp_audit_ledger::LedgerMeta::new(tenant.clone(), binary_hash);
        aberp_audit_ledger::append_in_tx(
            &tx,
            &ledger_meta,
            EventKind::DaemonShutdownCompleted,
            bytes,
            actor,
            None,
        )
        .context("audit_ledger::append_in_tx DaemonShutdownCompleted")?;
        tx.commit()
            .context("commit DuckDB transaction for shutdown audit entry")?;
        // ADR-0098 Session C: the shared Handle's post-commit hook runs the
        // lockstep sync_mirror when the write guard (conn) drops, so the
        // explicit Ledger::open + sync_mirror here (a SECOND live opener of the
        // tenant DB) is removed — the mirror is kept current by the hook.
        Ok(())
    })();

    if let Err(e) = write_outcome {
        tracing::error!(error = ?e, "shutdown audit entry write failed; continuing exit");
    }
}

// ── Cert / key / fingerprint persistence ─────────────────────────────

/// If the persisted artifacts already exist, read them. Otherwise
/// generate a fresh self-signed cert via `rcgen`, persist all three
/// artifacts (cert PEM, key PEM, hex fingerprint), and return them.
///
/// Returns the *PEM bytes* of cert and key (string-ish) and the hex
/// fingerprint string.
fn ensure_loopback_cert(
    cert_path: &Path,
    key_path: &Path,
    fingerprint_path: &Path,
) -> Result<(String, String, String)> {
    if cert_path.exists() && key_path.exists() {
        let cert_pem = std::fs::read_to_string(cert_path)
            .with_context(|| format!("read persisted cert PEM from {}", cert_path.display()))?;
        let key_pem = std::fs::read_to_string(key_path)
            .with_context(|| format!("read persisted key PEM from {}", key_path.display()))?;
        let fingerprint = compute_cert_fingerprint(&cert_pem)?;
        // Re-persist the fingerprint file even if it already exists —
        // a missing fingerprint file would otherwise be a confusing
        // first-startup-after-corrupted-state failure mode.
        std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
            format!(
                "write loopback fingerprint to {}",
                fingerprint_path.display()
            )
        })?;
        return Ok((cert_pem, key_pem, fingerprint));
    }

    // Generate fresh.
    let mut params = rcgen::CertificateParams::new(vec!["localhost".to_string()])
        .context("rcgen CertificateParams::new")?;
    let mut dn = DistinguishedName::new();
    dn.push(rcgen::DnType::CommonName, "ABERP loopback");
    params.distinguished_name = dn;
    params.key_usages = vec![
        KeyUsagePurpose::DigitalSignature,
        KeyUsagePurpose::KeyEncipherment,
    ];
    let key_pair = KeyPair::generate().context("rcgen KeyPair::generate")?;
    let cert = params
        .self_signed(&key_pair)
        .context("rcgen CertificateParams::self_signed")?;

    let cert_pem = cert.pem();
    let key_pem = key_pair.serialize_pem();
    let fingerprint = compute_cert_fingerprint(&cert_pem)?;

    std::fs::write(cert_path, &cert_pem)
        .with_context(|| format!("write loopback cert PEM to {}", cert_path.display()))?;
    std::fs::write(key_path, &key_pem)
        .with_context(|| format!("write loopback key PEM to {}", key_path.display()))?;
    std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
        format!(
            "write loopback fingerprint to {}",
            fingerprint_path.display()
        )
    })?;

    // Tighten the key file's permissions on POSIX. On Windows the call
    // is a no-op; we silently skip it.
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let mut perms = std::fs::metadata(key_path)
            .with_context(|| format!("stat {}", key_path.display()))?
            .permissions();
        perms.set_mode(0o600);
        std::fs::set_permissions(key_path, perms)
            .with_context(|| format!("chmod 0600 {}", key_path.display()))?;
    }

    Ok((cert_pem, key_pem, fingerprint))
}

/// SHA-256 fingerprint of the **DER body** of the first cert in a PEM
/// bundle, hex-encoded. Matches the format `openssl x509 -fingerprint
/// -sha256 -noout -in cert.pem` produces (lower-case, no colons).
fn compute_cert_fingerprint(cert_pem: &str) -> Result<String> {
    let mut bytes = cert_pem.as_bytes();
    let cert_der = rustls_pemfile::certs(&mut bytes)
        .next()
        .ok_or_else(|| anyhow!("no certificate found in PEM bundle"))?
        .context("parse certificate PEM")?;
    let mut hasher = Sha256::new();
    hasher.update(&cert_der);
    Ok(hex::encode(hasher.finalize()))
}

/// Parse the PEM bytes into the `Vec<u8>` DER pair `axum_server`'s
/// `RustlsConfig::from_der` wants.
fn build_rustls_config(cert_pem: &str, key_pem: &str) -> Result<(Vec<Vec<u8>>, Vec<u8>)> {
    let mut cert_bytes = cert_pem.as_bytes();
    let certs: Vec<Vec<u8>> = rustls_pemfile::certs(&mut cert_bytes)
        .map(|c| c.map(|der| der.to_vec()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse loopback cert PEM")?;
    if certs.is_empty() {
        return Err(anyhow!("loopback cert PEM contained no certificates"));
    }
    let mut key_bytes = key_pem.as_bytes();
    let key = rustls_pemfile::private_key(&mut key_bytes)
        .context("parse loopback key PEM")?
        .ok_or_else(|| anyhow!("loopback key PEM contained no private key"))?;
    Ok((certs, key.secret_der().to_vec()))
}

// ── Session token in the OS keychain ─────────────────────────────────

/// Look up the session token in the OS keychain for this tenant; if
/// absent, generate a fresh 256-bit random token (hex-encoded) and
/// persist it.
fn load_or_create_session_token(tenant: &str) -> Result<String> {
    let service = keychain_service_for(tenant);
    let entry = keyring::Entry::new(&service, SESSION_TOKEN_ACCOUNT)
        .context("build keyring::Entry for session token")?;
    match entry.get_password() {
        Ok(existing) if !existing.is_empty() => Ok(existing),
        Ok(_) | Err(keyring::Error::NoEntry) => {
            let fresh = generate_session_token();
            entry
                .set_password(&fresh)
                .context("write fresh session token to OS keychain")?;
            tracing::info!(
                tenant = tenant,
                "minted fresh session token in OS keychain (account `session_token`)"
            );
            Ok(fresh)
        }
        Err(e) => Err(anyhow!("keychain access for session token failed: {e}")),
    }
}

/// 32 random bytes from the OS RNG, hex-encoded. We do not pull in
/// `rand` for this — `std::time::SystemTime::now()` is the cheap
/// source for one-shot key material on a single workstation, mixed
/// with a per-process ULID. A proper rotation flow with a real RNG
/// can land when the operator-action surface needs it; for the first
/// MVP token a 256-bit value derived from system entropy is
/// sufficient.
///
/// Per CLAUDE.md rule 12, we name the trade-off loud: this is NOT a
/// cryptographic key. It is a single-workstation bearer secret that
/// gates one local HTTPS endpoint behind the OS-keychain trust
/// boundary the rest of ABERP already lives behind. A future
/// PR-9-1.5 (or session 12) can swap this for a `rand`-sourced
/// equivalent.
fn generate_session_token() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now_nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0u128);
    let ulid_bytes = ulid::Ulid::new().to_bytes();
    let pid = std::process::id();
    let mut hasher = Sha256::new();
    hasher.update(now_nanos.to_le_bytes());
    hasher.update(ulid_bytes);
    hasher.update(pid.to_le_bytes());
    hex::encode(hasher.finalize())
}

// ── Axum router + handlers ───────────────────────────────────────────

/// PR-46α / session-62 — boot lifecycle discriminator on the
/// [`AppState`]. `NeedsSetup` means the keychain is empty for this
/// tenant; the listener still binds + the handshake still fires so the
/// Tauri shell + SPA can render a first-run setup wizard against the
/// loopback. `Ready` carries the operator-login string the audit-
/// ledger actor derivation needs (mirrors the pre-PR-46α
/// `Arc<String>` shape).
///
/// Single-tenant scope per the brief: the boot-state is one bit of
/// in-process state shared between the setup route (which writes when
/// transitioning) and every other route (which reads to either pull
/// the login OR reject with 503). Multi-tenant CRUD lifts this to a
/// per-tenant registry in a later PR-46β.
///
/// PR-51 / session-71 — third variant `NeedsSellerConfig` for the
/// SPA's seller-config wizard. Detected at boot when the NAV
/// credentials load but `~/.aberp/<tenant>/seller.toml` is absent or
/// missing required identity fields. The state token
/// `needs-seller-config` rides the handshake suffix so the Tauri
/// shell's first-paint dispatch picks the right wizard without an
/// extra round-trip. `operator_login` is carried on the variant
/// because NAV creds are already loaded — only the seller-config gate
/// remains; the same login feeds the audit actor once the wizard
/// flips the state to Ready.
#[derive(Debug, Clone)]
pub enum ServeBootState {
    /// Keychain has no NAV credentials for this tenant. The only
    /// route that responds to mutations is
    /// `POST /api/setup-nav-credentials`; every other gated route
    /// returns 503 with a typed body the SPA renders inline.
    NeedsSetup,
    /// PR-51 / session-71 — keychain populated, but
    /// `~/.aberp/<tenant>/seller.toml` is missing or its identity
    /// block (legal_name + tax_number + address) is incomplete. The
    /// SPA's `SellerConfigWizard` fires; `POST /api/setup-seller-info`
    /// is the only mutation route that responds (bypasses Bearer-auth
    /// for the same A170 chicken-and-egg reason as the NAV-creds
    /// wizard). Every other gated route returns 503.
    NeedsSellerConfig { operator_login: String },
    /// Keychain is populated; the per-request audit-actor login was
    /// extracted at startup (or at setup-route-transition time) and
    /// is cached here for the Actor derivation site.
    Ready { operator_login: String },
}

impl ServeBootState {
    /// String token emitted on the handshake `state=<token>` suffix
    /// (PR-46α). The Tauri shell's `handshake::parse` reads it to
    /// route the SPA's first paint between the normal app and the
    /// setup wizard.
    ///
    /// PR-51 / session-71 — added the `needs-seller-config` token for
    /// the new boot-state variant. Mirror in
    /// `apps/aberp-ui/src/handshake.rs::parse_state_value`.
    pub fn state_token(&self) -> &'static str {
        match self {
            ServeBootState::NeedsSetup => "needs-setup",
            ServeBootState::NeedsSellerConfig { .. } => "needs-seller-config",
            ServeBootState::Ready { .. } => "ready",
        }
    }

    /// `true` iff the backend is past the needs-setup gate. Used by
    /// the route precondition helper.
    pub fn is_ready(&self) -> bool {
        matches!(self, ServeBootState::Ready { .. })
    }

    /// PR-51 / session-71 — `true` iff a setup-flow route (NAV creds
    /// OR seller info) should bypass the Bearer-auth gate. The
    /// chicken-and-egg posture from A170 (the SPA wizard runs BEFORE
    /// the operator has acquired a session token) extends to the
    /// seller-config wizard too. Used by both setup-route handlers.
    pub fn allows_setup_bypass(&self) -> bool {
        !matches!(self, ServeBootState::Ready { .. })
    }
}

/// PR-51 / session-71 — pick the boot state to enter when NAV creds
/// load cleanly. Reads `~/.aberp/<tenant>/seller.toml` and:
///
///   - missing file OR identity-incomplete → `NeedsSellerConfig`
///   - identity present → `Ready`
///
/// Reads outside the `RwLock` so a slow filesystem doesn't delay the
/// listener bind; called once at boot. Errors reading the file fall
/// through to `NeedsSellerConfig` with a tracing warning — that
/// surfaces the bad file to the operator AND lets the wizard
/// overwrite it (better than refusing to boot).
fn derive_initial_boot_state_with_seller_check(
    operator_login: String,
    tenant: &str,
) -> ServeBootState {
    match setup_seller_info::seller_toml_path_for_tenant(tenant) {
        Ok(path) => match setup_seller_info::read_seller_identity(&path) {
            Ok(Some(_id)) => {
                tracing::info!(
                    seller_toml = %path.display(),
                    "seller.toml identity block present; entering Ready boot state"
                );
                ServeBootState::Ready { operator_login }
            }
            Ok(None) => {
                tracing::warn!(
                    seller_toml = %path.display(),
                    "seller.toml missing or identity-incomplete; entering needs-seller-config boot state; \
                     SPA SellerConfigWizard will populate via POST /api/setup-seller-info"
                );
                ServeBootState::NeedsSellerConfig { operator_login }
            }
            Err(e) => {
                tracing::warn!(
                    seller_toml = %path.display(),
                    error = %format!("{e:#}"),
                    "seller.toml read failed; entering needs-seller-config boot state so the wizard can overwrite"
                );
                ServeBootState::NeedsSellerConfig { operator_login }
            }
        },
        Err(e) => {
            tracing::warn!(
                error = %format!("{e:#}"),
                "HOME env var missing; entering needs-seller-config boot state so the wizard can surface the error"
            );
            ServeBootState::NeedsSellerConfig { operator_login }
        }
    }
}

/// Per-request shared state passed to every authenticated handler.
///
/// Public surface as of PR-44ε.UI / session-58 so the
/// `apps/aberp/tests/serve_pdf_route.rs` integration test can
/// exercise [`get_invoice_pdf`] directly without spinning the axum
/// listener (the listener still owns the lifecycle in `run`). Fields
/// stay narrow — the cert + fingerprint + tokio runtime stay private
/// to `run` per ADR-0007 §Transport (the SPA never sees them, and
/// neither does the read-path test surface).
///
/// PR-44ζ / session-59 added `operator_login` so the new
/// `POST /invoices/issue` mutation route can derive an `Actor` per
/// request without re-loading NAV credentials from the keychain
/// (which already happened once at `run` startup). The full
/// [`NavCredentials`] is NOT stored on the state — only the
/// non-secret `login()` value, which is the only field the audit-
/// ledger actor needs. Keeps secrets out of the route surface.
///
/// PR-46α / session-62 — `operator_login` moved inside the
/// [`ServeBootState`] enum (`Arc<RwLock<ServeBootState>>`). On a
/// fresh install with empty keychain the backend now starts in
/// `NeedsSetup`; the new `POST /api/setup-nav-credentials` route
/// flips it to `Ready` after writing the four keychain entries.
/// Every existing route checks the state via [`require_ready`] and
/// either pulls `operator_login` OR returns 503 needs-setup.
/// ADR-0098 C2 fix-forward — eagerly ensure EVERY tenant table exists.
///
/// Under `read_returns_readonly=true` the read()-side connections are
/// read-only, and the tolerant `ensure_schema` (correctly) no-ops its DDL on
/// them. So any table that used to be created lazily on first *read* access
/// would now be missing. This creates them all up front on a read-write
/// connection (boot + test fixtures), making the "schema exists by boot time"
/// invariant true. Idempotent (`CREATE TABLE IF NOT EXISTS`).
pub fn ensure_all_tenant_schemas(conn: &mut Connection, tenant: &str) -> anyhow::Result<()> {
    aberp_audit_ledger::ensure_schema(conn).map_err(|e| anyhow!("audit-ledger schema: {e}"))?;
    crate::products::ensure_schema(conn)?;
    crate::partners::ensure_schema(conn)?;
    crate::avl_vendors::ensure_schema(conn)?;
    crate::margin_profiles::ensure_schema(conn)?;
    crate::material_inventory::ensure_schema(conn)?;
    crate::part_marking::ensure_schema(conn)?;
    crate::purchasing::ensure_schema(conn)?;
    crate::quality::ensure_schema(conn)?;
    crate::quote_calibration::ensure_schema(conn)?;
    crate::quote_pricing_jobs::ensure_schema(conn)?;
    crate::quoting_gear_processes::ensure_schema(conn)?;
    crate::quoting_machine_rates::ensure_schema(conn)?;
    crate::quoting_machines::ensure_schema(conn)?;
    crate::quoting_materials::ensure_schema(conn)?;
    crate::quoting_tolerance_cost_rates::ensure_schema(conn)?;
    crate::quoting_tunables::ensure_schema(conn, tenant)?;
    crate::email_relay_queue::ensure_schema(conn)?;
    crate::incoming_invoices::ensure_schema(conn)?;
    crate::invoice_draft::ensure_schema(conn)?;
    crate::restore_from_nav_outgoing::ensure_schema(conn)?;
    aberp_inventory::ensure_schema(conn)?;
    aberp_qa::ensure_schema(conn)?;
    aberp_dispatch::ensure_schema(conn)?;
    aberp_work_orders::ensure_schema(conn)?;
    aberp_quote_intake::log_table::ensure_schema(conn)
        .map_err(|e| anyhow!("quote-intake log schema: {e}"))?;
    Ok(())
}

/// Open the process-wide shared DuckDB [`aberp_db::Handle`] and eagerly ensure
/// all tenant schemas exist (so read()-side access finds every table). Used at
/// boot and by test fixtures (which bypass the boot schema-ensure path).
pub fn open_tenant_handle(
    db_path: &std::path::Path,
    tenant: TenantId,
) -> anyhow::Result<aberp_db::HandleArc> {
    // ADR-0093/0098 CHECK-10f — serve.rs must not open a new connection directly;
    // eager-ensure the tenant schemas through the ONE shared Handle's writer.
    let handle = aberp_db::Handle::open_default(db_path, tenant.clone())
        .context("open shared DuckDB handle (ADR-0098 Gap 1a)")?;
    {
        let mut guard = handle
            .write()
            .context("write guard for eager schema-ensure (ADR-0098 C2)")?;
        ensure_all_tenant_schemas(&mut guard, tenant.as_str())?;
    }
    Ok(handle)
}

#[derive(Clone)]
pub struct AppState {
    pub db_path: Arc<PathBuf>,
    /// ADR-0098 Session B (Gap 1a) — the ONE shared DuckDB handle the whole
    /// serve process routes runtime DB access through. Created at boot after
    /// `provision_atomic`/`recover_or_refuse`; cloned into every daemon
    /// `Deps`. Nothing else opens the live tenant DB at runtime.
    pub db: aberp_db::HandleArc,
    pub tenant: TenantId,
    /// S434 — the running tenant's NAV-synchron mode, resolved once at
    /// boot from `tenants.toml` (`tenant_registry::tenant_nav_enabled`).
    /// `false` (international / demo) means: no NAV daemons were spawned,
    /// `submit_invoice` stores invoices LOCAL ONLY, and the §169 seller
    /// gate was skipped at boot. The [[trust-code-not-operator]] switch
    /// every NAV chokepoint reads.
    pub nav_enabled: bool,
    /// PR-45a / session-61 — handle to the background-computed binary
    /// hash. Reading a debug `aberp` binary off cold disk + hashing it
    /// took ~7.5s in `aberp serve`'s synchronous boot path, which
    /// blew the desktop shell's 10s `HANDSHAKE_TIMEOUT`. The compute
    /// now runs on a dedicated OS thread spawned at `run` entry; HTTP
    /// handlers call `binary_hash.wait()` (essentially zero-latency
    /// after a few seconds of uptime). See [`BinaryHashHandle`] for
    /// the failure-mode posture.
    pub binary_hash: BinaryHashHandle,
    pub session_token: Arc<String>,
    /// PR-46α / session-62 — boot lifecycle gate. `Ready` carries
    /// the operator-login string; `NeedsSetup` means the keychain is
    /// empty and only the setup route responds to mutations.
    pub boot_state: Arc<std::sync::RwLock<ServeBootState>>,
    /// Session-149 — in-process secrets cache populated during the boot
    /// keychain-read burst. The SMTP password is read ONCE at boot and
    /// served from here for every post-boot consumer (Settings GET/PUT,
    /// email send, test connection), so the OS keychain is never read
    /// lazily mid-session. See [`SecretsCache`].
    pub secrets_cache: SecretsCache,
    /// Session-161 — concurrency cap for the indefinite NAV poll
    /// daemons. Each [`poll_ack::run_nav_poll_daemon`] holds one permit
    /// for its whole lifetime, so this bounds the number of invoices
    /// being actively watched (post-issue spawns + app-boot recovery
    /// spawns combined). At [`NAV_POLL_DAEMON_CONCURRENCY`] permits the
    /// steady-state poll rate is ≤ that many polls/min — well inside
    /// NAV's published limits. Excess spawns block on `acquire()` until
    /// a daemon terminates and frees its slot.
    pub nav_poll_semaphore: Arc<tokio::sync::Semaphore>,
    /// PR-209 / S213 — the graceful-shutdown coordinator's token,
    /// cloned into every dynamically-spawned NAV poll daemon (post-
    /// issue auto-poll + chain post-issue tail). Boot-time daemons
    /// (boot-recovery / AP sync / quote-intake) receive the token
    /// directly from the coordinator in `run`; the post-issue path
    /// has no other handle on the coordinator, so the token rides on
    /// `AppState` to reach those spawn sites.
    pub shutdown_token: tokio_util::sync::CancellationToken,
    /// S240 / PR-234 — shared handle to the MES adapter registry.
    /// Created empty at boot, populated by `mes_boot::boot_mes_adapters`
    /// after each adapter's `start()` succeeds. The Workshop dashboard
    /// handler takes a read lock to call `health_snapshot()`, replacing
    /// the prior `snapshot_mes_adapter_config()` env-var read with a
    /// live registry probe per [[trust-code-not-operator]].
    pub adapter_registry: Arc<std::sync::RwLock<AdapterRegistry>>,
    /// S257 / PR-246 — operator-managed adapter lifecycle. Owns the
    /// per-adapter cancellation tokens + the mutation serialiser; shares
    /// `adapter_registry` above. Backs the Settings → Adapters CRUD
    /// routes; persists to the `[[mes.adapters]]` seller.toml slot.
    pub adapter_manager: Arc<crate::mes_manager::AdapterManager>,
    /// S258 / PR-247 — per-adapter last-observed health status, keyed by
    /// adapter name, the diff baseline for `AdapterHealthTransitioned`
    /// emission. Seeds silently on first sight after process boot
    /// (boot-grace: a restart never re-emits an already-degraded
    /// adapter), so each ledger entry records a genuine in-session
    /// transition. The dashboard poll (`compute_workshop_dashboard`) is
    /// the detection site — health is pull-only, so there is no separate
    /// health-watcher daemon. The `Mutex` serialises concurrent polls so
    /// two SPA sessions can't double-emit the same transition.
    pub adapter_health_baseline:
        Arc<std::sync::Mutex<std::collections::HashMap<String, &'static str>>>,
    /// S264 / PR-253 (F1) — set TRUE only while a NAV-as-DR restore is
    /// actively executing in THIS process; cleared (RAII guard) the
    /// instant `restore_outgoing::run` returns. The restore lock is a
    /// crash-surviving DB row, but the row alone cannot distinguish a
    /// LIVE restore from one a crashed process left behind. The abandon
    /// route consults this flag to refuse clearing a lock that a running
    /// restore is actively using (per [[trust-code-not-operator]] —
    /// "only abandon a crashed restore" is the operator-trust pattern the
    /// lock was built to eliminate). A crash resets the process, so the
    /// flag is `false` on the next boot → a genuinely-stale lock is
    /// abandonable, a live one is not. Single-backend-process deployment:
    /// there is exactly one `aberp serve` per tenant, so an in-memory
    /// flag is a precise liveness signal (no cross-process restore).
    pub restore_active: Arc<std::sync::atomic::AtomicBool>,
    /// S266 / PR-255 — shared handle for the storefront catalogue-push
    /// daemon. Created dormant at boot; the daemon (spawned only when the
    /// storefront is configured) marks it running. The Material Catalogue
    /// CRUD routes call `.trigger()` after a successful write for an
    /// immediate push; the list route reads `.snapshot()` for the
    /// "last push" + paused (re-paste-bearer) banner.
    pub catalogue_push: Arc<crate::catalogue_push::CataloguePushHandle>,
    /// S281 / PR-266 — token-bucket rate limiter for the
    /// `POST /api/internal/send-email` storefront-relay surface. One
    /// bucket per submitter (identified by their bearer-token-resolved
    /// id, e.g. `"storefront"`). 30 req/min cap matching ADR-0007 §2.
    /// Lives in `AppState` so the rate-limit state survives across
    /// requests but resets on every `aberp serve` restart (an operator
    /// restart is itself rare enough that bucket drift is a non-issue).
    pub email_relay_rate_limiter: Arc<crate::email_relay::RateLimiter>,
    /// S282 / PR-267 — shared status surface for the pricing-pipeline
    /// daemon's Python-venv resolution. Created dormant at boot. The
    /// boot block runs `resolve_pipeline_python` ONCE, records the
    /// outcome here, and only spawns the daemon when resolved. The SPA
    /// `GET /api/quote-pipeline/status` route reads `.snapshot()` to
    /// drive the `PricingJobsList` empty-state copy (active vs RED-
    /// venv-missing vs AMBER-spawn-errored).
    pub pipeline_python_resolution: Arc<crate::quote_pricing_pipeline::PythonResolutionHandle>,
    /// S289 / PR-270 — shared, hot-reloadable storefront credential
    /// ([`quote_intake`] base_url + keychain bearer). The boot block
    /// populates it ONCE from env-vars-or-seller.toml-and-keychain; the
    /// PUT `/api/quote-intake/config` route updates it on save; the
    /// catalogue-push daemon snapshots it at the top of every push so
    /// an operator URL change in SPA → Maintenance → Quote Intake takes
    /// effect on the very next cycle (no restart). See
    /// [`crate::storefront_credential`] for the design rationale and
    /// the SPOC-vs-split argument.
    pub storefront_credential: Arc<crate::storefront_credential::StorefrontCredentialHandle>,
    /// S307 / PR-276 — shared status surface for the email-outbox poll
    /// daemon (ADR-0009). Created dormant at boot; the daemon writes
    /// `record_spawned` on its first scheduled tick. The
    /// `GET /api/quote-pipeline/email-outbox/status` route reads
    /// `.snapshot()` to hydrate the SPA panel. Lives in `AppState` so
    /// the same handle survives the supervisor's re-spawn loop (S286
    /// pattern) — restarts after a panic do not reset the operator-
    /// facing counters.
    pub email_outbox_daemon: Arc<crate::email_outbox_poll_daemon::EmailOutboxDaemonHandle>,
    /// S325 / PR-25 — shared, restart-tolerant in-memory queue of
    /// quote-ids whose customer-facing `priced.pdf` needs re-rendering
    /// with the EVE addendum-2 stock-alert banner. The read-side
    /// `handle_list_quote_intake` seam enqueues on a confirmed FALSE→TRUE
    /// `stock_alert` flip; the `quote_pdf_rerender_daemon` drains it every
    /// cycle and re-POSTs to the storefront `/priced`. In-memory (no DB
    /// table): loss-on-restart is tolerated because the read-side
    /// recompute re-detects undrained transitions on the next operator
    /// view. See [`crate::quote_pdf_rerender_queue`].
    pub quote_pdf_rerender_queue: Arc<crate::quote_pdf_rerender_queue::QuotePdfRerenderQueue>,
    /// S344 / PR-38 — process-wide digital-identity provider (the swap-point
    /// for the defense-aerospace pivot, `[[defense-aerospace-pivot]]`).
    /// Constructed once at boot by [`build_digital_id_provider`]; today the
    /// only backend is the deterministic, NON-PRODUCTION mock. Held as a
    /// trait object so a real backend (HU eID, US DoD CAC, …) swaps in
    /// without touching every consumer. Future audit-emit sites (S346) will
    /// consult this for the operator identity that authorised each event.
    pub digital_id: Arc<dyn aberp_digital_id::DigitalIdProvider>,
}

/// S344 / PR-38 — construct the process-wide [`DigitalIdProvider`] at boot.
/// Extended S363 / PR-50 with a second (still NON-PRODUCTION) backend.
///
/// The `ABERP_DIGITAL_ID_PROVIDER` env var selects the backend; it is the
/// swap point real backends (HU eID, Qatar MFA, …) register at per
/// `[[defense-aerospace-pivot]]`. Implemented arms today:
///
/// - `mock` (default, and the fallback for any unknown value) — the S344
///   deterministic [`aberp_digital_id::MockProvider`].
/// - `us-dod-cac` — the S363 deterministic [`aberp_digital_id::UsDodCacProvider`]
///   STUB (ADR-0080), added to prove the trait abstracts across a different
///   signing / session / verification shape. NOT real crypto.
///
/// Both backends are explicitly non-production and WARN on construction, so
/// neither can ship silently. An unknown value logs a WARN and falls back to
/// `mock`, so a half-configured deployment is loud, never silently unsigned.
///
/// Emits one INFO line naming the resolved provider + operator.
fn build_digital_id_provider() -> Arc<dyn aberp_digital_id::DigitalIdProvider> {
    let requested =
        std::env::var("ABERP_DIGITAL_ID_PROVIDER").unwrap_or_else(|_| "mock".to_string());
    let provider: Arc<dyn aberp_digital_id::DigitalIdProvider> = match requested.as_str() {
        "mock" => Arc::new(aberp_digital_id::MockProvider::new()),
        "us-dod-cac" => Arc::new(aberp_digital_id::UsDodCacProvider::new()),
        unknown => {
            tracing::warn!(
                requested = %unknown,
                "ABERP_DIGITAL_ID_PROVIDER requested an unknown backend; \
                 implemented backends are `mock` and `us-dod-cac`. Falling \
                 back to the mock provider."
            );
            Arc::new(aberp_digital_id::MockProvider::new())
        }
    };
    match provider.current_operator() {
        Ok(op) => tracing::info!(
            provider = provider.name(),
            operator_id = %op.id,
            "DigitalIdProvider configured: provider={}, operator={} ({})",
            provider.name(),
            op.display_name,
            op.id,
        ),
        Err(e) => tracing::warn!(
            error = %e,
            "DigitalIdProvider configured but current_operator() failed at boot"
        ),
    }
    provider
}

/// Session-161 — max number of NAV poll daemons polling concurrently.
/// At the 1-minute phase-2 cadence this caps total NAV poll traffic at
/// ≤ 50 requests/min even with every slot saturated.
pub const NAV_POLL_DAEMON_CONCURRENCY: usize = 50;

/// Assemble the axum `Router` over an [`AppState`]. `pub` so integration
/// tests can serve the real route table in-process (e.g. the S435
/// Portable-line `/health` smoke serves this over plain HTTP against a
/// demo, NAV-off `AppState` — exercising the exact handler the binary
/// serves without the OS-keychain dependency a full subprocess boot
/// carries).
pub fn build_router(state: AppState) -> Router {
    Router::new()
        .route("/health", get(handle_health))
        // S166 / prod-prep PR #2 — the operator's one-time consent to
        // real fiscal operation. A `/health` subroute (read by the SPA's
        // first-launch modal) that, unusually, writes to the audit
        // ledger: the human acknowledgment is a legal-grade event.
        .route(
            "/health/acknowledge-first-prod-launch",
            post(handle_acknowledge_first_prod_launch),
        )
        .route("/invoices", get(handle_list_invoices))
        .route("/invoices/issue", post(handle_issue_invoice))
        .route("/invoices/:id", get(handle_get_invoice))
        .route("/invoices/:id/pdf", get(handle_get_invoice_pdf))
        .route("/invoices/:id/submit", post(handle_submit_invoice))
        .route("/invoices/:id/poll-ack", post(handle_poll_ack))
        .route("/api/invoices/:id/storno", post(handle_storno_invoice))
        .route(
            "/api/invoices/:id/modification",
            post(handle_modification_invoice),
        )
        .route(
            "/api/invoices/:id/issuance-input",
            get(handle_get_issuance_input),
        )
        // PR-70 / ADR-0039 — operational "quick mark as paid" route.
        // Records a payment receipt against a Finalized invoice
        // WITHOUT changing the NAV regulatory state ladder
        // (paid-vs-unpaid is operational metadata, queried separately).
        .route(
            "/api/invoices/:id/mark-paid",
            post(handle_mark_invoice_paid),
        )
        // PR-217 / S220 — operator-paced manual partner link on a
        // restored ExtNav row. Per [[aberp-extnav-partner-nav-gap]] NAV
        // does not expose buyer info for invoices submitted via other
        // software, so [`restore_outgoing::run_buyer_backfill_once`] is
        // structurally unable to populate `customer_name` for those
        // rows. The SPA exposes a partner-picker for these so the
        // operator can annotate from their own records.
        .route(
            "/api/restored-invoices/:id/partner",
            post(handle_set_restored_partner),
        )
        .route("/audit/:invoice_id", get(handle_get_audit))
        // S424 / session-424 — cross-domain audit-events screen. The
        // general, filterable view of the WHOLE ledger (any domain,
        // paginated), generalising `/audit/:invoice_id` (one invoice's
        // chain). List rows omit payloads (NAV XML blobs are MBs — the
        // design report §3.3); the full single entry is fetched lazily
        // on row-expand via `/api/audit-events/:seq`.
        .route("/api/audit-events", get(handle_audit_events))
        .route("/api/audit-events/:seq", get(handle_audit_event_detail))
        // S429 — read-only closed-loop calibration page.
        .route("/api/calibration", get(handle_get_calibration))
        // S426 / ADR-0082 — operator Snapshots tab. List managed snapshots,
        // trigger one now, and run a guarded restore.
        .route("/api/snapshots", get(handle_list_snapshots))
        .route("/api/snapshots/now", post(handle_snapshot_now))
        .route("/api/snapshots/restore", post(handle_snapshot_restore))
        // PR-46α / session-62 — first-run setup route. Accepts the
        // four NAV credential artifacts and writes them to the OS
        // keychain. In `NeedsSetup` mode it bypasses bearer-auth (the
        // SPA wizard has no other way to populate the keychain on a
        // fresh machine — A170); once the boot state transitions to
        // `Ready` the route requires the standard Bearer-auth header
        // like every other mutation.
        .route(
            "/api/setup-nav-credentials",
            post(handle_setup_nav_credentials),
        )
        // PR-51 / session-71 — second-run-setup route. Accepts the
        // operator-typed seller identity (legal name + tax number +
        // address) + bank info and writes it to
        // `~/.aberp/<tenant>/seller.toml` atomically. In
        // `NeedsSetup` OR `NeedsSellerConfig` mode the route
        // bypasses Bearer-auth (the SPA wizard chain has no session-
        // token bearer yet — same A170 chicken-and-egg posture as
        // the NAV-creds wizard); once the boot state transitions to
        // `Ready` the route requires the standard Bearer-auth
        // header (so an operator can re-run the wizard from the
        // settings screen without losing auth).
        .route("/api/setup-seller-info", post(handle_setup_seller_info))
        // PR-53 / session-73 — read-side counterparts of the two setup
        // routes, plus the single-slot rotate route. All three are
        // Ready-only + bearer-required (rotation happens after the
        // wizard chain — A170 only applies to first-run-setup).
        .route("/api/seller-info", get(handle_get_seller_info))
        .route(
            "/api/nav-credentials-status",
            get(handle_get_nav_credentials_status),
        )
        .route(
            "/api/rotate-nav-credential",
            post(handle_rotate_nav_credential),
        )
        // PR-48α / session-68 — partner CRUD. Five routes (list +
        // create on the collection; get + update + delete on the
        // resource), all require_ready + bearer auth — partners is a
        // Ready-state feature, not a first-run-setup surface.
        .route(
            "/api/partners",
            get(handle_list_partners).post(handle_create_partner),
        )
        .route(
            "/api/partners/:id",
            get(handle_get_partner)
                .put(handle_update_partner)
                .delete(handle_delete_partner),
        )
        // S427 — quoting_machines master data. List + create on the
        // collection; get + update + archive (soft, no hard delete) on
        // the resource. Ready-only + bearer-gated; emits mes.machine_*.
        .route(
            "/api/machines",
            get(handle_list_machines).post(handle_create_machine),
        )
        .route(
            "/api/machines/:id",
            get(handle_get_machine)
                .put(handle_update_machine)
                .delete(handle_archive_machine),
        )
        // S428 — customer-type margin profiles CRUD. Ready-only +
        // bearer-gated; emits quote.margin_profile_*.
        .route(
            "/api/margin-profiles",
            get(handle_list_margin_profiles).post(handle_create_margin_profile),
        )
        .route(
            "/api/margin-profiles/:id",
            get(handle_get_margin_profile)
                .put(handle_update_margin_profile)
                .delete(handle_archive_margin_profile),
        )
        // S431 — Approved Vendor List (AVL). List + create on the
        // collection; get + edit (categories/until/notes) on the resource;
        // status-change + screen as resource sub-actions; po-check is the
        // refuse-at-point-of-use gate. Ready-only + bearer-gated; emits the
        // `supplier.*` AVL family. `avl-po-check` is a distinct top-level
        // path (no `:id` capture collision).
        .route(
            "/api/avl-vendors",
            get(handle_list_avl_vendors).post(handle_create_avl_vendor),
        )
        .route(
            "/api/avl-vendors/:id",
            get(handle_get_avl_vendor).put(handle_update_avl_vendor),
        )
        .route(
            "/api/avl-vendors/:id/status",
            post(handle_avl_vendor_status),
        )
        .route(
            "/api/avl-vendors/:id/screen",
            post(handle_avl_vendor_screen),
        )
        .route("/api/avl-po-check", post(handle_avl_po_check))
        // S433 — multi-tenant CRUD + switcher. List + create on the
        // collection; switch / archive / restore as resource sub-actions.
        // Ready-only + bearer-gated; emits the `tenant.*` family. Switch
        // writes the `next_tenant` hint and relies on the Tauri shell's
        // restart-on-ack to consume it (switch-via-restart, never live
        // in-process swap — [[trust-code-not-operator]]).
        .route(
            "/api/tenants",
            get(handle_list_tenants).post(handle_create_tenant),
        )
        .route("/api/tenants/:slug/switch", post(handle_switch_tenant))
        .route("/api/tenants/:slug/archive", post(handle_archive_tenant))
        .route("/api/tenants/:slug/restore", post(handle_restore_tenant))
        // S434 — flip a tenant's NAV-synchron toggle + the operator's
        // hide-demo preference.
        .route(
            "/api/tenants/:slug/toggle-nav",
            post(handle_toggle_tenant_nav),
        )
        .route("/api/tenants/hide-demo", post(handle_set_hide_demo))
        // S441 — DÁP "Sign in" stub. Runs MockDapTransport server-side and
        // returns a synthetic identity; the real operator-login overlay
        // (OidcDapTransport) lands when szeusz.gov.hu RP creds arrive.
        .route("/api/dap/mock-login", post(handle_dap_mock_login))
        // S257 / PR-246 — Settings → Adapters CRUD. List + create on the
        // collection; update (hot restart) + delete on the resource.
        // Ready-only + bearer-gated; the `:id` is the server-minted
        // adapter_id (the registry key), not operator-typed.
        .route(
            "/api/adapters",
            get(handle_list_adapters).post(handle_create_adapter),
        )
        .route(
            "/api/adapters/:id",
            put(handle_update_adapter).delete(handle_delete_adapter),
        )
        // S266 / PR-255 — Settings → Material Catalogue CRUD (the auto-
        // quoting strand's first tunable table). List + create on the
        // collection; update + delete on the resource. `:grade` is the
        // operator-typed PRIMARY KEY (URL-encoded by the Tauri command).
        // The list response also carries the catalogue-push status for
        // the "last push" / re-paste-bearer banner. Ready-only + bearer.
        .route(
            "/api/quoting-materials",
            get(handle_list_quoting_materials).post(handle_create_quoting_material),
        )
        .route(
            "/api/quoting-materials/:grade",
            put(handle_update_quoting_material).delete(handle_delete_quoting_material),
        )
        // S289 / PR-270 (brief D) — operator-clicked "Test catalogue push"
        // button on Settings → Material Catalogue. Runs ONE push attempt
        // using the current storefront credential snapshot and returns
        // the typed outcome inline. Mirror of `/api/quote-intake/test`
        // (which probes the read-only `/api/quotes` endpoint); this one
        // probes the write-side `/api/catalogue/materials` endpoint so
        // the operator can confirm auth + payload BEFORE waiting on the
        // 15-min cadence + audit row.
        .route(
            "/api/quoting-materials/test-push",
            post(handle_test_catalogue_push),
        )
        // S267 / PR-256 — auto-quoting tunables CRUD (engine internals,
        // NOT pushed to storefront). Four tables:
        //   - quoting-complexity-rules: feature × size_bucket rules
        //   - quoting-tolerance-multipliers: per-band multiplier (update-only)
        //   - quoting-parameters: global knobs singleton (GET + PUT, no id)
        //   - quoting-stock-adjustments: material × stock_status ±% tweak
        .route(
            "/api/quoting-complexity-rules",
            get(handle_list_complexity_rules).post(handle_create_complexity_rule),
        )
        .route(
            "/api/quoting-complexity-rules/:id",
            put(handle_update_complexity_rule).delete(handle_delete_complexity_rule),
        )
        .route(
            "/api/quoting-tolerance-multipliers",
            get(handle_list_tolerance_multipliers),
        )
        .route(
            "/api/quoting-tolerance-multipliers/:range",
            put(handle_update_tolerance_multiplier),
        )
        .route(
            "/api/quoting-parameters",
            get(handle_get_parameters).put(handle_update_parameters),
        )
        .route(
            "/api/quoting-stock-adjustments",
            get(handle_list_stock_adjustments).post(handle_create_stock_adjustment),
        )
        .route(
            "/api/quoting-stock-adjustments/:id",
            put(handle_update_stock_adjustment).delete(handle_delete_stock_adjustment),
        )
        // S4 / ADR-0094 Gap 2 — machine-family rate catalogue.
        .route(
            "/api/quoting-machine-rates",
            get(handle_list_machine_rates).post(handle_create_machine_rate),
        )
        .route(
            "/api/quoting-machine-rates/:id",
            put(handle_update_machine_rate).delete(handle_delete_machine_rate),
        )
        // S6 / ADR-0094 Gap 3 — per-process gear-generation coefficient catalogue.
        .route(
            "/api/quoting-gear-processes",
            get(handle_list_gear_processes).post(handle_create_gear_process),
        )
        .route(
            "/api/quoting-gear-processes/:id",
            put(handle_update_gear_process).delete(handle_delete_gear_process),
        )
        // T5 / ADR-0097 Part 2 — operator tolerance cost-rate catalogue.
        // Mirrors the machine-rate routes (auth, tenant, audit) and wires the
        // T4 `quoting_tolerance_cost_rates` handlers to HTTP.
        .route(
            "/api/quoting-tolerance-cost-rates",
            get(handle_list_tolerance_cost_rates).post(handle_create_tolerance_cost_rate),
        )
        .route(
            "/api/quoting-tolerance-cost-rates/:id",
            put(handle_update_tolerance_cost_rate).delete(handle_delete_tolerance_cost_rate),
        )
        // S273 / PR-262 / ADR-0069 — material-side inventory balances
        // (on_hand / reserved / committed / consumed). Read-only in v1;
        // writes happen via the DEAL saga (committed) and the future
        // workshop-completion hook (consumed). Operator-facing GET only.
        .route(
            "/api/inventory-balances",
            get(handle_list_inventory_balances),
        )
        // S432 (ADR-0085) — heat-lot assignment + material traceability view.
        .route(
            "/api/inventory-balances/:grade/heat-lot",
            post(handle_assign_heat_lot),
        )
        .route(
            "/api/material-traceability",
            get(handle_material_traceability),
        )
        // S438 (ADR-0089) — Part UID Lookup (forward: part_uid → chain;
        // reverse: customer_id → all part UIDs shipped). Fires
        // part.traceability_viewed. Lives under the Material Traceability tab.
        .route("/api/part-traceability", get(handle_part_traceability))
        // S439 (ADR-0090) — Quality module: NCR + CAPA workflow. NCR list /
        // create / detail / state-transition; CAPA create / approve / review /
        // close; dashboard alert counts. Fires the ncr.* / capa.* family.
        .route("/api/ncrs", get(handle_list_ncrs).post(handle_create_ncr))
        .route("/api/ncrs/:id", get(handle_get_ncr))
        .route("/api/ncrs/:id/transition", post(handle_transition_ncr))
        .route("/api/ncrs/:id/capas", post(handle_create_capa))
        .route("/api/capas/:id/approve", post(handle_approve_capa))
        .route("/api/capas/:id/review", post(handle_review_capa))
        .route("/api/capas/:id/close", post(handle_close_capa))
        .route("/api/quality-alert", get(handle_quality_alert))
        // S443 (ADR-0092) — QC dimensional inspection. Inspection-plan
        // master data (CRUD + archive) + record-inspection (verdict in
        // code → auto-NCR on out-of-tolerance) + per-WO/part lists + the
        // stale-calibration dashboard feed. Fires the qc.* family.
        .route(
            "/api/inspection-plans",
            get(handle_list_inspection_plans).post(handle_create_inspection_plan),
        )
        .route(
            "/api/inspection-plans/:id",
            axum::routing::put(handle_update_inspection_plan),
        )
        .route(
            "/api/inspection-plans/:id/archive",
            post(handle_archive_inspection_plan),
        )
        .route(
            "/api/qc-inspections",
            get(handle_list_qc_inspections).post(handle_record_qc_inspection),
        )
        .route(
            "/api/qc-stale-calibration",
            get(handle_qc_stale_calibration),
        )
        .route(
            "/api/tenants/:slug/qc-calibration-window",
            post(handle_set_qc_calibration_window),
        )
        // S440 (ADR-0068) — purchase orders. List + create (AVL-gated) +
        // detail + transition (issue/cancel/close) + receive. Fires the po.*
        // family; receiving auto-creates NCRs (S439) on failed inspection.
        .route(
            "/api/purchase-orders",
            get(handle_list_pos).post(handle_create_po),
        )
        .route("/api/purchase-orders/:id", get(handle_get_po))
        .route(
            "/api/purchase-orders/:id/transition",
            post(handle_transition_po),
        )
        .route("/api/purchase-orders/:id/receive", post(handle_receive_po))
        // PR-172 — buyer-facing notes typeahead source. GET-only,
        // ready+bearer-gated. `?scope=line|invoice|storno` is required.
        // Returns the most-recent-first deduplicated list of operator-
        // typed notes for the requested scope. Empty array on a fresh
        // tenant (no audit history yet).
        .route("/api/notes-history", get(handle_get_notes_history))
        // PR-91 — products master-data CRUD. Five routes (list + create
        // on the collection; get + update + delete on the resource), all
        // require_ready + bearer auth — products is a Ready-state
        // feature, not a first-run-setup surface. Mirrors the partners
        // route shape.
        .route(
            "/api/products",
            get(handle_list_products).post(handle_create_product),
        )
        .route(
            "/api/products/:id",
            get(handle_get_product)
                .put(handle_update_product)
                .delete(handle_delete_product),
        )
        // S231 / PR-227 / ADR-0061 — Stage 3 Phase γ Inventory v1.
        // GET lists the per-product `stock_movements` ledger
        // (descending by at_iso8601, paginated). POST appends one
        // operator-typed manual adjustment movement (reason +
        // qty_delta + optional notes). Both require_ready + bearer
        // auth; POST DoS-bounded by an explicit Json size cap +
        // closed-vocab reason validation per [[trust-code-not-operator]].
        // The dashboard's low-stock click-through reads
        // `GET /api/products/low-stock` (separate route below).
        .route(
            "/api/products/:id/stock-movements",
            get(handle_list_stock_movements).post(handle_create_stock_movement),
        )
        .route(
            "/api/products/low-stock",
            get(handle_list_low_stock_products),
        )
        // S232 / PR-228 / ADR-0062 — Stage 3 Phase γ Work Orders v1.
        // GET lists tenant WOs (optional `?state=` filter +
        // pagination); POST creates a new WO with product_id +
        // qty_target + routing-op rows. The detail GET expands the
        // routing operations + active BOM snapshot. The transitions
        // POST is the SAME handler future adapter events call per
        // ADR-0062 §3 — actor captured into the audit entry only.
        // BOM author GET / POST under `/api/products/:id/bom`.
        // All require_ready + bearer auth. DoS bounds per
        // [[trust-code-not-operator]]: axum's default Json size cap +
        // explicit per-WO routing-op cap (200) + per-BOM line cap
        // (200) inside the repository.
        .route(
            "/api/work-orders",
            get(handle_list_work_orders).post(handle_create_work_order),
        )
        .route("/api/work-orders/:id", get(handle_get_work_order_detail))
        .route(
            "/api/work-orders/:id/transitions",
            post(handle_transition_work_order),
        )
        // S438 (ADR-0089) — per-unit part-UID marking for a Completed
        // defense/aerospace WO. Mints `dp-`-prefixed UIDs, records serials +
        // DataMatrix payloads, fires part.serial_assigned + part.uid_marked.
        .route("/api/work-orders/:id/mark-parts", post(handle_mark_parts))
        // S233 / PR-229 Part A — per-routing-op Complete button (the
        // Active op only; cascade advances the next op + auto-creates
        // a Pending QA inspection).
        .route(
            "/api/work-orders/:id/routing-ops/:op_id/transitions",
            post(handle_transition_routing_op),
        )
        .route(
            "/api/products/:id/bom",
            get(handle_get_product_bom).post(handle_put_product_bom),
        )
        // S233 / PR-229 / ADR-0063 — Stage 3 Phase γ QA queue v1.
        // GET lists tenant QA inspections (optional `?state=` filter +
        // pagination — defaults to all states); detail GET; decisions
        // POST is the SAME handler future adapter events call per
        // ADR-0063 §3.
        .route("/api/qa-inspections", get(handle_list_qa_inspections))
        .route("/api/qa-inspections/:id", get(handle_get_qa_inspection))
        .route(
            "/api/qa-inspections/:id/decisions",
            post(handle_decide_qa_inspection),
        )
        // S234 / PR-230 / ADR-0064 — Stage 3 Phase γ Dispatch board v1.
        // GET lists tenant dispatches (optional `?state=` filter +
        // pagination — defaults to all states); detail GET; eligible-WO
        // read for the SPA's "Ready to dispatch" panel; create POST
        // refuses ineligible WO + duplicate-for-WO loud per ADR-0064 §2;
        // mark-shipped POST is the atomic transition (stock movement +
        // injected invoice spawn + audit) per ADR-0064 §4 + §5; cancel
        // POST is valid only from Drafted.
        .route(
            "/api/dispatches",
            get(handle_list_dispatches).post(handle_create_dispatch),
        )
        .route(
            "/api/dispatches/eligible-work-orders",
            get(handle_list_eligible_work_orders),
        )
        .route("/api/dispatches/:id", get(handle_get_dispatch))
        .route(
            "/api/dispatches/:id/ship",
            post(handle_mark_dispatch_shipped),
        )
        .route("/api/dispatches/:id/cancel", post(handle_cancel_dispatch))
        // S236 / PR-230b — pre-allocation invoice-draft routes. The
        // BillingInvoiceSpawner creates rows here on dispatches→Shipped;
        // these routes let the SPA list, inspect, and delete drafts.
        // Promotion to a Ready invoice rides the existing IssueInvoice
        // form path (the SPA pre-fills the form from a GET to
        // /api/invoice-drafts/:id, then DELETEs the draft after the
        // invoice creation succeeds; cross-pipeline atomic promote is
        // deferred to a future PR per the PR-230b scope-reduction).
        .route("/api/invoice-drafts", get(handle_list_invoice_drafts))
        .route(
            "/api/invoice-drafts/:id",
            get(handle_get_invoice_draft).delete(handle_delete_invoice_draft),
        )
        // S177 / PR-177 — AP module v1 BACKEND. Incoming-invoice list +
        // detail + manual ingestion + three closed-vocab status
        // transitions. All require_ready + bearer auth. The NAV
        // auto-sync daemon (queryInvoiceDigest INBOUND fanout) is a
        // SEPARATE PR — these routes are the foundation S178's UI
        // consumes and the same entry points the future daemon will
        // call. See `incoming_invoices.rs` module docs.
        .route("/api/incoming-invoices", get(handle_list_incoming_invoices))
        .route(
            "/api/incoming-invoices/ingest",
            post(handle_ingest_incoming_invoice),
        )
        .route(
            "/api/incoming-invoices/:id",
            get(handle_get_incoming_invoice),
        )
        .route(
            "/api/incoming-invoices/:id/mark-paid",
            post(handle_mark_incoming_paid),
        )
        .route(
            "/api/incoming-invoices/:id/mark-outstanding",
            post(handle_mark_incoming_outstanding),
        )
        .route(
            "/api/incoming-invoices/:id/mark-irrelevant",
            post(handle_mark_incoming_irrelevant),
        )
        // S178 / PR-178 — operator-clicked manual AP sync trigger.
        // Synchronous (blocks the response until the cycle returns
        // counts). Same daemon code path as the cadence tick;
        // emits one `IncomingInvoiceSyncCycleCompleted` audit
        // entry with `trigger="manual"`.
        .route(
            "/api/incoming-invoices/sync-now",
            post(handle_sync_incoming_now),
        )
        // S197 / PR-197 — XML download for an AP-side row whose S197
        // `queryInvoiceData` follow-on fetch has populated
        // `nav_xml_path`. Returns the on-disk InvoiceData XML bytes
        // verbatim with `Content-Type: application/xml` + a
        // `Content-Disposition: attachment` filename built from
        // supplier + invoice number. 404 when the row is missing OR
        // when `nav_xml_path` is still NULL (the digest-only fallback;
        // operator sees a disabled button in the SPA, so this route
        // 404 is defence-in-depth against direct curl calls).
        .route(
            "/api/incoming-invoices/:id/xml",
            get(handle_get_incoming_invoice_xml),
        )
        // S180 / PR-180 — NAV-as-DR restore wizard. POST { year }
        // walks NAV's `queryInvoiceDigest OUTBOUND` view for that
        // year and mirrors each new digest into the local
        // `restored_invoice` table. Operator-triggered; require_ready
        // + bearer auth; synchronous (12 months × pagination, may
        // take several seconds on a populated tenant). GET lists
        // every restored row for the tenant — used by the wizard
        // to render the "already-restored" panel.
        .route(
            "/api/restore-from-nav-outgoing",
            post(handle_restore_from_nav_outgoing),
        )
        // S261 / PR-250 — read-only Preview (dry-run) step. POST { year }
        // returns would-import counts + gap warnings + checksum without
        // writing. No confirm token, no lock (it does not mutate).
        .route(
            "/api/restore-from-nav-preview",
            post(handle_restore_from_nav_preview),
        )
        // S261 / PR-250 — restore-in-progress lock surface. GET reports
        // the held lock (drives the "Restore in progress" banner + the
        // boot-crash-recovery surface); POST /abandon (RESTORE token)
        // clears a crashed lock so operations can resume.
        .route("/api/restore-lock", get(handle_restore_lock_status))
        .route(
            "/api/restore-lock/abandon",
            post(handle_restore_lock_abandon),
        )
        .route("/api/restored-invoices", get(handle_list_restored_invoices))
        // S225 / PR-221 — financial-statistics dashboard endpoint.
        // Read-only aggregation over invoice + restored_invoice +
        // ap_invoice (digest-only sources combined with audit-ledger-
        // derived state). Query params: `period` (default current
        // month), `date_basis` (default `teljesites`). No audit-ledger
        // writes — reports are pure views per the no-silent-write
        // posture (CLAUDE.md rule 12).
        .route("/api/reports/financial", get(handle_financial_report))
        // S235 / PR-231 — Workshop / Műhely operator dashboard. ONE
        // endpoint that returns every count tile in one bundle: WO by
        // state, low-stock count, QA by state, dispatch by state +
        // eligible + shipped-today, today's invoice headline,
        // recent-activity tail, MES adapter env snapshot. The SPA
        // wall-TV polls this every 10s; one DuckDB tx beats six round-
        // trips. No writes — pure aggregation; same no-silent-write
        // posture as the financial-statistics route.
        .route("/api/workshop/dashboard", get(handle_workshop_dashboard))
        // PR-72 / session-94 — multi-bank-account CRUD (PR-B of the
        // multi-bank initiative; ADR-0040 §addendum). Five routes
        // (list + create on the collection; update + delete + flip-
        // default on the resource), all require_ready + bearer auth —
        // bank-accounts is a Ready-state feature; first-run setup goes
        // through SellerConfigWizard. The set-default flip is its own
        // route to keep the mental model crisp (mutating the default
        // is a separate intent from editing the entry's fields).
        .route(
            "/api/seller/banks",
            get(handle_list_seller_banks).post(handle_create_seller_bank),
        )
        .route(
            "/api/seller/banks/:id",
            axum::routing::put(handle_update_seller_bank).delete(handle_delete_seller_bank),
        )
        .route(
            "/api/seller/banks/:id/set-default",
            post(handle_set_default_seller_bank),
        )
        // PR-89 — operator-configurable invoice-number template
        // (`[seller.numbering]` section of seller.toml). GET returns
        // the persisted template (or the default INV-default/00001
        // shape when absent); PUT replaces it atomically, preserving
        // every other section of seller.toml (identity + banks).
        .route(
            "/api/seller/numbering",
            get(handle_get_seller_numbering).put(handle_put_seller_numbering),
        )
        // PR-92 / ADR-0047 — SMTP email delivery surfaces. GET returns
        // the `[seller.smtp]` config (non-secrets only) + a `password_set`
        // probe of the keychain. PUT writes the config (merge-not-replace
        // on seller.toml + optional password rotation to keychain).
        // POST /api/invoices/:id/email is the operator-clicked manual
        // send button on InvoiceDetail. All three require_ready + bearer
        // auth.
        .route(
            "/api/smtp-config",
            get(handle_get_smtp_config).put(handle_put_smtp_config),
        )
        // PR-98 — operator-clicked "Test connection" button on the
        // TenantSettings SMTP subsection. Runs the TLS handshake +
        // AUTH + NOOP using the operator-typed config + (entered
        // password OR existing keychain entry); reports the typed
        // outcome WITHOUT sending mail and WITHOUT persisting
        // anything.
        .route("/api/seller/smtp/test", post(handle_test_smtp_connection))
        .route(
            "/api/invoices/:id/email",
            post(handle_email_invoice_to_buyer),
        )
        // S211 / PR-210 — quote-intake daemon config + queue surface.
        // GET returns the persisted `[quote_intake]` config + a
        // `has_token` keychain probe + the latest poll summary; PUT
        // writes the toml section (merge-not-replace) + optional
        // token rotation to the keychain; POST /test runs a
        // read-only `GET /api/quotes?status=approved` against the
        // configured URL with the stored token (no persistence,
        // remote-read-only); GET /quotes returns staged
        // `quote_intake_log` rows for the operator queue.
        .route(
            "/api/quote-intake/config",
            get(handle_get_quote_intake_config).put(handle_put_quote_intake_config),
        )
        .route(
            "/api/quote-intake/test",
            post(handle_test_quote_intake_connection),
        )
        .route("/api/quote-intake/quotes", get(handle_list_quote_intake))
        // S279 / PR-265 — pricing-pipeline operator surface. Read-only list of
        // `quote_pricing_jobs` (Fetched/Extracting/Pricing/Rendering/PostingBack/
        // Posted/Failed) + a per-row retry button that re-enqueues a Failed
        // row at Fetched. The daemon does the work; the SPA shows progress.
        .route(
            "/api/quote-pricing-jobs",
            get(handle_list_quote_pricing_jobs),
        )
        // S349 / PR-40 (U1) — row-click detail panel. Full single-row
        // artifacts (breakdown + FeatureGraph + CAD filename + PDF
        // presence) keyed on the storefront quote id.
        //
        // S350 / PR-39 (U5) — PATCH on the same path is the operator
        // material-grade override: body `{ material_grade }`, validated
        // against the catalogue, resets the row to Fetched + audits.
        //
        // S391/F — DELETE on the same path removes a permanently-Failed
        // row (e.g. the S379 phantom-retry rows operators can't otherwise
        // clear). Conservative: only `Failed` rows are deletable; emits
        // `quote.pricing_failure_deleted` in the same tx as the removal.
        .route(
            "/api/quote-pricing-jobs/:quote_id",
            get(handle_get_quote_pricing_job_detail)
                .patch(handle_patch_quote_pricing_job_material)
                .delete(handle_delete_quote_pricing_job),
        )
        // S349 / PR-40 (U1) — paginated per-row audit trail feeding the
        // detail panel's status timeline + last-writeback-outcome +
        // raw-events sections.
        .route(
            "/api/quote-pricing-jobs/:quote_id/audit",
            get(handle_get_quote_pricing_job_audit),
        )
        // S352 / PR-41 — operator-facing PDF view/download. Streams the
        // rendered `priced.pdf` bytes for the row inline (the SPA opens
        // or downloads via a Bearer-authenticated fetch → blob). The
        // server filesystem path is never leaked; the URL is keyed on
        // the quote id only. 404 when the row is foreign-tenant, not yet
        // rendered, or its on-disk artifact has gone missing.
        .route(
            "/api/quote-pricing-jobs/:quote_id/pdf",
            get(handle_get_quote_pricing_job_pdf),
        )
        .route(
            "/api/quote-pricing-jobs/:quote_id/retry",
            post(handle_retry_quote_pricing_job),
        )
        // S427 — operator override of the engine-computed lead-time.
        // POST a `{ "override_days": N | null }` body; null clears the
        // override (reverts to computed). Emits quote.lead_time_overridden.
        .route(
            "/api/quote-pricing-jobs/:quote_id/lead-time-override",
            post(handle_override_quote_lead_time),
        )
        // S428 — assign/clear the buyer partner (drives the margin profile)
        // and re-price; emits quote.using_global_margin / margin_below_floor.
        .route(
            "/api/quote-pricing-jobs/:quote_id/buyer-partner",
            post(handle_set_quote_buyer_partner),
        )
        // S428 — operator margin override (markup %) + re-price. A
        // below-floor override needs `confirm_below_floor: true`; emits
        // quote.margin_overridden (+ margin_floor_overridden on confirm).
        .route(
            "/api/quote-pricing-jobs/:quote_id/margin-override",
            post(handle_override_quote_margin),
        )
        // S2 / ADR-0094 Gap 1 — set/clear the operator stock-form override
        // (kind + dims) and re-price in place. Inert when kind is null.
        .route(
            "/api/quote-pricing-jobs/:quote_id/stock-form",
            post(handle_set_quote_stock_form),
        )
        // S6 / ADR-0094 Gap 3 — set/clear the operator's per-quote gear ops
        // (a vector of kind/module/teeth/face-width/AGMA/process) and re-price
        // in place. Inert when the array is empty.
        .route(
            "/api/quote-pricing-jobs/:quote_id/gear-ops",
            post(handle_set_quote_gear_ops),
        )
        // T5 / ADR-0097 Part 2 — set/clear the operator's per-job tolerance
        // (overall spec + per-critical-feature callouts) + in-place re-price.
        .route(
            "/api/quote-pricing-jobs/:quote_id/tolerance",
            post(handle_set_quote_tolerance),
        )
        // S416 — the operator accept-on-behalf route (S354 / PR-42 / U16)
        // was REMOVED: it was redundant (the customer accepts via the
        // Accept button in their quote e-mail) and a footgun (an operator
        // click pre-bypassed the customer). The `quote.operator_accepted`
        // EventKind variant is RETAINED in the audit vocabulary for
        // back-compat with any historical ledger entries.
        // S282 / PR-267 — pricing-pipeline daemon status. Reads the
        // dormant handle that was filled in at boot by the layered
        // Python-venv resolver. Drives the `PricingJobsList` empty-
        // state copy: GREEN "polling every Ns" vs RED "venv missing"
        // vs AMBER "venv resolved but daemon errored at spawn".
        .route(
            "/api/quote-pipeline/status",
            get(handle_quote_pipeline_status),
        )
        // S307 / PR-276 — email-outbox poll daemon status (ADR-0009).
        // Drives the new SPA panel above the email-relay queue inspector
        // (`EmailRelayQueueList.svelte`): last poll, last seen cursor,
        // in-flight count, lifetime counters, panic count. The handler
        // is a thin read of the in-memory `EmailOutboxDaemonHandle`
        // snapshot — no DB walk.
        .route(
            "/api/quote-pipeline/email-outbox/status",
            get(handle_email_outbox_status),
        )
        // S256 / PR-245 — one polled endpoint feeding the sidebar badge
        // (un-picked count, DB truth) + the arrival toast (live arrivals
        // past the catch-up boundary) + the 401 re-paste-bearer prompt.
        .route(
            "/api/quote-intake/notifications",
            get(handle_quote_intake_notifications),
        )
        // S256 / PR-245 — dead-letter recovery for malformed (error-state)
        // rows: re-parse the stored payload, or dismiss as irrelevant.
        .route(
            "/api/quote-intake/:quote_id/retry-parse",
            post(handle_quote_intake_retry_parse),
        )
        .route(
            "/api/quote-intake/:quote_id/mark-irrelevant",
            post(handle_quote_intake_mark_irrelevant),
        )
        // S255 / PR-244 — operator-clicked pickup. POST mints a Draft
        // referencing the quote; the SPA navigates to the Invoices tab
        // where the new row surfaces under the [[aberp-invoice-draft-state]]
        // chip.
        .route(
            "/api/quotes/:quote_id/pickup-as-draft",
            post(handle_pickup_quote_as_draft),
        )
        // S272 / PR-261 — DEAL saga (ADR-0067). POST mints SO/WO
        // placeholder ids + 3 audit entries in a single DB tx.
        // EVE addendum 2 enforces typed REFRESH ack when `stock_alert`
        // is TRUE; addendum 3 enforces the BIG/RED single-use DEAL
        // token (first 8 chars of quote_id). Replay → 409
        // `deal_already_issued`.
        .route("/api/quote-intake/:quote_id/deal", post(handle_deal_saga))
        // S403 — operator REFUSE-with-reason. The DEAL step's negative
        // counterpart: when stock / capacity can't satisfy an accepted
        // auto-quote, the operator refuses with a reason. POST flips the
        // intake row to `refused`, audits `quote.operator_refused`,
        // queues the bilingual customer e-mail (same tx), and best-effort
        // writes back the storefront `rejected` status. NO draft invoice.
        .route(
            "/api/quote-intake/:quote_id/refuse",
            post(handle_refuse_quote),
        )
        // S281 / PR-266 — storefront email-relay (ADR-0007). The
        // storefront POSTs `/api/internal/send-email` with the
        // dedicated email-relay bearer; ABERP validates + persists +
        // returns 200 with audit_id. List + per-row read for the SPA
        // operator inspector.
        .route("/api/internal/send-email", post(handle_relay_send_email))
        .route("/api/email-relay/queue", get(handle_list_email_relay_queue))
        .route(
            "/api/email-relay/queue/:id",
            get(handle_get_email_relay_row),
        )
        .with_state(state)
}

/// PR-46α / session-62 — typed response body emitted when the backend
/// is in `NeedsSetup` and a gated route is called. The SPA reads the
/// `state` field to dispatch to the first-run wizard; the human-
/// readable `message` is rendered inline so an operator inspecting
/// the route via `curl` sees a recognisable string.
fn needs_setup_response() -> Response {
    (
        StatusCode::SERVICE_UNAVAILABLE,
        Json(serde_json::json!({
            "state": "needs-setup",
            "message": "Set up NAV credentials before using this endpoint.",
        })),
    )
        .into_response()
}

/// PR-51 / session-71 — sibling of [`needs_setup_response`] for the
/// post-NAV-creds, pre-seller-config gate. SPA reads `state` to
/// dispatch to `SellerConfigWizard` instead of `SetupWizard`.
fn needs_seller_config_response() -> Response {
    (
        StatusCode::SERVICE_UNAVAILABLE,
        Json(serde_json::json!({
            "state": "needs-seller-config",
            "message": "Save seller identity (legal name, tax number, address) before using this endpoint.",
        })),
    )
        .into_response()
}

// ── S433 — multi-tenant CRUD + switcher ──────────────────────────────

/// One tenant as the SPA sees it: registry row + the `running` flag
/// (true for the tenant this binary booted with).
#[derive(Debug, Serialize)]
struct TenantView {
    slug: String,
    display_name: String,
    /// `"active"` | `"archived"` | `"demo"`.
    state: String,
    created_at: String,
    running: bool,
    /// S434 — the per-tenant NAV-synchron flag. The SPA renders the toggle
    /// + the "LOCAL ONLY" badge from this.
    nav_enabled: bool,
    /// S441 — the per-tenant DÁP/QES audit-chain flag. The SPA shows the
    /// "Sign in with DÁP" button on the tenant row only when this is true.
    dap_enabled: bool,
    /// S443 (ADR-0092) — per-tenant QC probe calibration-stale window
    /// (seconds; default 86400 = 24h). The SPA renders/edits it on the row.
    qc_calibration_stale_window_seconds: u64,
}

#[derive(Debug, Serialize)]
struct TenantListResponse {
    tenants: Vec<TenantView>,
    /// Slug of the currently-running tenant (the switch/archive guards
    /// key off this; the SPA renders the running indicator from it).
    running_slug: String,
    /// S434 — operator preference: hide the bundled demo from the default
    /// view once a real tenant exists.
    hide_demo: bool,
    /// S434 — does a real (Active, non-demo) tenant exist? Gates whether
    /// the SPA offers/honours the "hide demo" filter.
    has_real_tenant: bool,
}

#[derive(Debug, Deserialize)]
struct CreateTenantRequest {
    slug: String,
    display_name: String,
}

/// Route-layer error → HTTP status mapping for the tenant endpoints.
enum TenantRouteError {
    /// Maps a registry invariant error to its HTTP status.
    Registry(crate::tenant_registry::TenantRegistryError),
    /// Operator asked to switch to the tenant already running.
    AlreadyRunning(String),
    Internal(anyhow::Error),
}

impl From<anyhow::Error> for TenantRouteError {
    fn from(e: anyhow::Error) -> Self {
        TenantRouteError::Internal(e)
    }
}

impl From<crate::tenant_registry::TenantRegistryError> for TenantRouteError {
    fn from(e: crate::tenant_registry::TenantRegistryError) -> Self {
        TenantRouteError::Registry(e)
    }
}

fn build_tenant_list(
    reg: &crate::tenant_registry::TenantRegistry,
    running_slug: &str,
) -> TenantListResponse {
    let tenants = reg
        .tenants
        .iter()
        .map(|t| TenantView {
            slug: t.slug.clone(),
            display_name: t.display_name.clone(),
            state: t.state.as_token().to_string(),
            created_at: t.created_at.clone(),
            running: t.slug == running_slug,
            nav_enabled: t.nav_enabled,
            dap_enabled: t.dap_enabled,
            qc_calibration_stale_window_seconds: t.qc_calibration_stale_window_seconds,
        })
        .collect();
    TenantListResponse {
        tenants,
        running_slug: running_slug.to_string(),
        hide_demo: reg.hide_demo,
        has_real_tenant: reg.has_real_tenant(),
    }
}

// POST /api/dap/mock-login — S441 structural stub. Runs the deterministic
// MockDapTransport server-side (initiate + complete) and returns the
// synthetic DÁP identity. The real operator-login overlay (OidcDapTransport,
// `todo!`) lands when szeusz.gov.hu RP creds arrive (ADR-0086).
async fn handle_dap_mock_login(headers: HeaderMap, State(state): State<AppState>) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    use aberp_digital_id::{CallbackResponse, DapLoginContext, DapTransport, MockDapTransport};
    let transport = MockDapTransport::with_test_operator();
    let ctx = DapLoginContext {
        tenant: state.tenant.as_str().to_string(),
        dap_env: "mock".to_string(),
        callback_port: 0,
    };
    let challenge = match transport.initiate_login(&ctx) {
        Ok(c) => c,
        Err(e) => return internal_error("dap_mock_login:initiate", anyhow!("{e}")),
    };
    let identity = match transport.complete_login(&CallbackResponse {
        flow_id: challenge.flow_id,
        raw_presentation: b"synthetic".to_vec(),
    }) {
        Ok(id) => id,
        Err(e) => return internal_error("dap_mock_login:complete", anyhow!("{e}")),
    };
    Json(serde_json::json!({
        "subject": identity.subject,
        "display_name": identity.display_name,
        "attested_at_utc": identity.attested_at_utc,
        "mock": true,
    }))
    .into_response()
}

