/// Map a [`TenantRouteError`] to its HTTP response. The registry
/// invariants ([[trust-code-not-operator]]) decide the status: bad input
/// → 400, missing → 404, conflicting state (taken slug, archive-running,
/// archive-only-active, already-running) → 409.
fn tenant_error(label: &'static str, e: TenantRouteError) -> Response {
    use crate::tenant_registry::TenantRegistryError as RErr;
    let (status, msg) = match e {
        TenantRouteError::Registry(re) => match re {
            RErr::InvalidSlug(_) | RErr::InvalidDisplayName => {
                (StatusCode::BAD_REQUEST, re.to_string())
            }
            RErr::NotFound(_) => (StatusCode::NOT_FOUND, re.to_string()),
            RErr::SlugTaken(_)
            | RErr::CannotArchiveRunning(_)
            | RErr::CannotArchiveOnlyActive(_)
            | RErr::CannotArchiveDemo(_) => (StatusCode::CONFLICT, re.to_string()),
        },
        TenantRouteError::AlreadyRunning(slug) => (
            StatusCode::CONFLICT,
            format!("tenant {slug:?} is already running"),
        ),
        TenantRouteError::Internal(err) => return internal_error(label, err),
    };
    (status, Json(error_body(msg))).into_response()
}

/// PR-46α / session-62 — precondition gate for every Ready-only
/// route. Returns `Ok(operator_login)` if the backend is `Ready`;
/// returns `Err(response)` with the typed 503 needs-setup body
/// otherwise. The poison-arm guards against a panic in the setup
/// route's write transaction leaving the RwLock unusable — that's
/// treated as a 500 (the operator-visible message points at
/// internal-state corruption, which is the truth at that point).
///
/// PR-51 / session-71 — `NeedsSellerConfig` now exists as a third
/// state; the gate emits a distinct 503 body (`needs-seller-config`)
/// so the SPA can route the operator to the right wizard.
fn require_ready(state: &AppState) -> std::result::Result<String, Response> {
    let guard = state.boot_state.read().map_err(|e| {
        tracing::error!(error = %e, "boot_state RwLock poisoned");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(error_body("boot_state lock poisoned".to_string())),
        )
            .into_response()
    })?;
    match &*guard {
        ServeBootState::Ready { operator_login } => Ok(operator_login.clone()),
        ServeBootState::NeedsSetup => Err(needs_setup_response()),
        ServeBootState::NeedsSellerConfig { .. } => Err(needs_seller_config_response()),
    }
}

/// PR-46α / session-62 — request body for
/// `POST /api/setup-nav-credentials`. Field names are the
/// operator-readable form rather than the on-disk `ITEM_*` keychain
/// names; the SPA composer mirrors this shape.
#[derive(Debug, Deserialize)]
pub struct SetupNavCredentialsRequest {
    pub technical_user_login: String,
    pub technical_user_password: String,
    pub xml_sign_key: String,
    pub xml_change_key: String,
}

/// PR-46α / session-62 — response body for the setup route. Surfaces
/// the post-write boot state so the SPA can flip its wizard view-mode
/// to the normal app without a second probe roundtrip.
///
/// PR-51 / session-71 — `state` widened from a single `"ready"`
/// literal to either `"ready"` or `"needs-seller-config"`. The
/// chained-wizard posture (NAV creds first → seller config next when
/// the file is missing) means the post-success state is no longer
/// always Ready. The SPA's Tauri-shell wrapper reads this field and
/// flips its boot-state mirror to the matching variant.
#[derive(Debug, Serialize)]
struct SetupNavCredentialsResponse {
    state: &'static str,
}

/// PR-46α / session-62 — `POST /api/setup-nav-credentials` handler.
///
/// 1. Bearer-auth check ONLY if already `Ready` (chicken-and-egg
///    bypass in `NeedsSetup`; A170).
/// 2. Validate-then-write via [`setup_nav_credentials::setup_credentials_from_inputs`]
///    (the shared core both the CLI subcommand and this route go
///    through — A167).
/// 3. Re-load NAV credentials from the now-populated keychain to
///    extract the audit-actor login.
/// 4. Take the boot_state write lock and flip
///    `NeedsSetup → Ready { operator_login }`.
/// 5. Return 200 with `{ "state": "ready" }`. From the SPA's
///    perspective, this is the operator's exit from the wizard.
///
/// Failure modes:
///   - `400 Bad Request` — validation failure (empty field).
///   - `401 Unauthorized` — bearer missing in `Ready` mode.
///   - `500 Internal Server Error` — keychain write failed OR the
///     re-load couldn't find the entries we just wrote (which would
///     indicate the OS keychain backend silently dropped a write —
///     CLAUDE.md rule 12 surfaces it as a 500 rather than a partial-
///     success lie).
async fn handle_setup_nav_credentials(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<SetupNavCredentialsRequest>,
) -> Response {
    // Bearer check only in Ready mode. In NeedsSetup mode the operator
    // has no way to acquire a bearer (the SPA's session-token loader
    // path runs after the backend handshake, but the setup wizard
    // fires BEFORE the normal app mounts — A170).
    let is_ready_pre_call = state
        .boot_state
        .read()
        .map(|g| g.is_ready())
        .unwrap_or(false);
    if is_ready_pre_call {
        if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
            return resp;
        }
    }

    let inputs = NavCredentialInputs {
        technical_user_login: request.technical_user_login,
        technical_user_password: request.technical_user_password,
        xml_sign_key: request.xml_sign_key,
        xml_change_key: request.xml_change_key,
    };

    match setup_nav_credentials_request(&state, &inputs) {
        Ok(next_state_token) => Json(SetupNavCredentialsResponse {
            state: next_state_token,
        })
        .into_response(),
        Err(SetupRouteHelperError::Validation(msg)) => {
            (StatusCode::BAD_REQUEST, Json(error_body(msg))).into_response()
        }
        Err(SetupRouteHelperError::Other(e)) => internal_error("setup_nav_credentials_request", e),
    }
}

/// PR-46α / session-62 — typed error from
/// [`setup_nav_credentials_request`]. The route handler maps
/// `Validation` → 400 and `Other` → 500 via the existing
/// [`internal_error`] helper.
#[derive(Debug)]
pub enum SetupRouteHelperError {
    Validation(String),
    Other(anyhow::Error),
}

impl From<anyhow::Error> for SetupRouteHelperError {
    fn from(e: anyhow::Error) -> Self {
        SetupRouteHelperError::Other(e)
    }
}

/// PR-46α / session-62 — library helper that backs the
/// `POST /api/setup-nav-credentials` handler. Extracted as `pub` so
/// the integration test can hit it for end-to-end pin tests without
/// spinning the HTTPS listener (same posture as `get_invoice_pdf` per
/// A158 and `issue_invoice_request` per A159 / A162 / A163).
///
/// On success: writes the four keychain entries via the shared core,
/// re-loads to extract the operator login, and flips the boot state
/// to Ready (or `NeedsSellerConfig` if the seller.toml is still
/// missing — PR-51 / session-71 chained-wizard posture). On
/// validation failure: returns `SetupRouteHelperError::Validation`
/// (→ 400). On any other error: returns
/// `SetupRouteHelperError::Other` (→ 500).
///
/// Returns the `state_token` of the post-transition boot state
/// (`"ready"` or `"needs-seller-config"`) so the HTTP route layer can
/// echo it on the 200 response body — the SPA's Tauri-shell wrapper
/// reads it to flip its mirror to the right variant without a second
/// probe.
pub fn setup_nav_credentials_request(
    state: &AppState,
    inputs: &NavCredentialInputs,
) -> std::result::Result<&'static str, SetupRouteHelperError> {
    match setup_nav_credentials::setup_credentials_from_inputs(state.tenant.as_str(), inputs) {
        Ok(()) => {}
        Err(SetupCredentialsError::Validation(msg)) => {
            return Err(SetupRouteHelperError::Validation(msg));
        }
        Err(SetupCredentialsError::Backend(e)) => {
            return Err(SetupRouteHelperError::Other(e));
        }
    }

    // Re-load to confirm the writes landed AND to extract the actor
    // login. A re-load failure here would indicate the OS keychain
    // silently dropped one of the four writes — loud per rule 12.
    let operator_login = NavCredentials::load_from_keychain(state.tenant.as_str())
        .map_err(|e| {
            SetupRouteHelperError::Other(anyhow!(e).context(
                "setup route wrote keychain entries but re-load failed; \
                 keychain backend may have silently dropped a write",
            ))
        })?
        .login()
        .to_string();

    // Flip the boot state. The write-lock acquisition can only fail
    // on a poisoned RwLock — same surface as `require_ready`'s poison
    // arm.
    //
    // PR-51 / session-71 — the post-NAV-creds transition is no longer
    // unconditionally Ready. If the per-tenant seller.toml is still
    // missing the wizard chain continues with the seller-config step;
    // the SPA's next `getBootStatus` poll picks up
    // `needs-seller-config` and dispatches `SellerConfigWizard`.
    let next_state =
        derive_initial_boot_state_with_seller_check(operator_login, state.tenant.as_str());
    let next_token = next_state.state_token();
    let mut guard = state.boot_state.write().map_err(|e| {
        SetupRouteHelperError::Other(anyhow!(
            "boot_state RwLock poisoned during setup transition: {e}"
        ))
    })?;
    *guard = next_state;

    tracing::info!(
        tenant = %state.tenant.as_str(),
        next_state = next_token,
        "NAV credentials populated via setup route; boot state transitioned"
    );

    Ok(next_token)
}

// ── PR-51 / session-71 — POST /api/setup-seller-info ─────────────────

/// PR-51 / session-71 — request body for
/// `POST /api/setup-seller-info`. Mirror of the SPA composer
/// `seller-config.ts::composeSellerConfigBody`. Snake_case wire
/// names; address + bank are flat sub-objects so the SPA's form
/// state maps 1:1 to the wire shape with no per-field renaming.
#[derive(Debug, Deserialize)]
pub struct SetupSellerInfoRequest {
    pub legal_name: String,
    pub tax_number: String,
    #[serde(default)]
    pub eu_vat_number: Option<String>,
    pub address: SetupSellerInfoAddress,
    #[serde(default)]
    pub bank: Option<SetupSellerInfoBank>,
}

#[derive(Debug, Deserialize)]
pub struct SetupSellerInfoAddress {
    pub country_code: String,
    pub postal_code: String,
    pub city: String,
    pub street: String,
}

#[derive(Debug, Deserialize, Default)]
pub struct SetupSellerInfoBank {
    #[serde(default)]
    pub account_number: Option<String>,
    #[serde(default)]
    pub iban: Option<String>,
    #[serde(default)]
    pub name: Option<String>,
    #[serde(default)]
    pub swift_bic: Option<String>,
}

/// PR-51 / session-71 — response body for the seller-info setup
/// route. `state` is always `"ready"` (a successful write means the
/// last gate has passed); the explicit field keeps the SPA's wrapper
/// posture identical to the NAV-creds route's response (one field
/// the Tauri shell reads to flip its mirror).
#[derive(Debug, Serialize)]
struct SetupSellerInfoResponse {
    state: &'static str,
}

/// PR-51 / session-71 — typed 400 body for field-level validation
/// failures. Mirrors the shape the SPA's `seller-config.ts` parser
/// reads: a top-level `error` discriminant + a `fields` array of
/// `{field, message}` records the wizard renders inline next to the
/// offending input.
#[derive(Serialize)]
struct SetupSellerInfoErrorBody {
    error: &'static str,
    fields: Vec<SetupSellerInfoFieldError>,
}

#[derive(Serialize)]
struct SetupSellerInfoFieldError {
    field: &'static str,
    message: String,
}

const ERR_SELLER_INFO_VALIDATION: &str = "validation_failed";

/// PR-51 / session-71 — `POST /api/setup-seller-info` handler. Same
/// shape as `handle_setup_nav_credentials`:
///
///   1. Bearer-auth check ONLY when already `Ready` (A170 bypass
///      while a wizard chain is in flight).
///   2. Validate-then-write via
///      [`setup_seller_info::setup_seller_info_from_inputs`] (the
///      shared core).
///   3. Take the boot_state write lock and flip to `Ready` (this is
///      the last gate; success means the operator is done).
///   4. Return 200 with `{ "state": "ready" }`.
///
/// Failure modes:
///   - `400 Bad Request` — one or more fields failed validation; the
///     typed body carries the per-field errors.
///   - `401 Unauthorized` — bearer missing in `Ready` mode.
///   - `500 Internal Server Error` — atomic write failed (parent
///     mkdir, tempfile open / write / fsync / rename, chmod).
async fn handle_setup_seller_info(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<SetupSellerInfoRequest>,
) -> Response {
    let bypass_bearer = state
        .boot_state
        .read()
        .map(|g| g.allows_setup_bypass())
        .unwrap_or(false);
    if !bypass_bearer {
        if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
            return resp;
        }
    }

    let bank = request.bank.unwrap_or_default();
    let inputs = SellerInfoInputs {
        legal_name: request.legal_name,
        tax_number: request.tax_number,
        eu_vat_number: request.eu_vat_number,
        address_country_code: request.address.country_code,
        address_postal_code: request.address.postal_code,
        address_city: request.address.city,
        address_street: request.address.street,
        bank_account_number: bank.account_number,
        iban: bank.iban,
        bank_name: bank.name,
        swift_bic: bank.swift_bic,
    };

    match setup_seller_info_request(&state, &inputs, None) {
        Ok(()) => Json(SetupSellerInfoResponse { state: "ready" }).into_response(),
        Err(SetupSellerRouteError::Validation(fields)) => {
            let body = SetupSellerInfoErrorBody {
                error: ERR_SELLER_INFO_VALIDATION,
                fields: fields
                    .into_iter()
                    .map(|f| SetupSellerInfoFieldError {
                        field: f.field,
                        message: f.message,
                    })
                    .collect(),
            };
            (StatusCode::BAD_REQUEST, Json(body)).into_response()
        }
        Err(SetupSellerRouteError::Other(e)) => internal_error("setup_seller_info_request", e),
    }
}

/// PR-51 / session-71 — typed error from
/// [`setup_seller_info_request`]. Two arms so the route handler can
/// map `Validation` → 400 with the field-level body and `Other` →
/// 500 with the opaque internal-error body.
#[derive(Debug)]
pub enum SetupSellerRouteError {
    Validation(Vec<SellerFieldError>),
    Other(anyhow::Error),
}

/// PR-51 / session-71 — library helper that backs the
/// `POST /api/setup-seller-info` handler. Extracted as `pub` so the
/// integration test in `tests/serve_setup_seller_info_route.rs` can
/// hit it without spinning the HTTPS listener (same posture as
/// [`setup_nav_credentials_request`] per A167).
///
/// On success: writes the file and flips the boot state to Ready.
/// On validation: returns `SetupSellerRouteError::Validation` (→ 400).
/// On any other error: returns `SetupSellerRouteError::Other` (→ 500).
///
/// `path_override`: production callers (the route handler) pass
/// `None` so the helper derives `~/.aberp/<tenant>/seller.toml` from
/// HOME; the integration test passes `Some(path)` to a per-test
/// tempfile so it doesn't mutate the dev box's actual seller.toml or
/// race with cargo's parallel test runner via HOME mutation. Mirrors
/// the `get_invoice_pdf(seller_toml_override)` precedent from
/// session-58.
pub fn setup_seller_info_request(
    state: &AppState,
    inputs: &SellerInfoInputs,
    path_override: Option<&std::path::Path>,
) -> std::result::Result<(), SetupSellerRouteError> {
    // S434 — region-aware tax validation: NAV-on enforces the HU §169
    // ADÓSZÁM shape; NAV-off accepts an optional opaque tax number.
    let result = match path_override {
        Some(p) => setup_seller_info::setup_seller_info_to_path(p, inputs, state.nav_enabled),
        None => setup_seller_info::setup_seller_info_from_inputs(
            state.tenant.as_str(),
            inputs,
            state.nav_enabled,
        ),
    };
    match result {
        Ok(_echo) => {}
        Err(SetupSellerInfoError::Validation(fields)) => {
            return Err(SetupSellerRouteError::Validation(fields));
        }
        Err(SetupSellerInfoError::Backend(e)) => {
            return Err(SetupSellerRouteError::Other(e));
        }
    }

    // Flip to Ready. The operator_login was carried on the
    // NeedsSellerConfig variant (it was extracted at boot when NAV
    // creds loaded); pull it out so the post-transition Ready state
    // carries the same value. The Ready-already case (operator re-
    // running the wizard from a future settings screen) re-uses the
    // current operator_login.
    let mut guard = state.boot_state.write().map_err(|e| {
        SetupSellerRouteError::Other(anyhow!(
            "boot_state RwLock poisoned during seller-info setup transition: {e}"
        ))
    })?;
    let operator_login = match &*guard {
        ServeBootState::Ready { operator_login } => operator_login.clone(),
        ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
        ServeBootState::NeedsSetup => {
            // Should be unreachable in practice — the route runs
            // AFTER NAV creds are present. If it fires here, that
            // means the wizard chain was driven out of order; loud-
            // fail per CLAUDE.md rule 12.
            return Err(SetupSellerRouteError::Other(anyhow!(
                "setup_seller_info_request called in NeedsSetup state — \
                 /api/setup-nav-credentials must run first"
            )));
        }
    };
    *guard = ServeBootState::Ready {
        operator_login: operator_login.clone(),
    };
    drop(guard);

    tracing::info!(
        tenant = %state.tenant.as_str(),
        "seller-info populated via setup route; boot state transitioned to Ready"
    );

    // S434 — record the region/NAV mode the tax validator ran under. One
    // row per successful seller-info save into the running tenant's
    // ledger. Best-effort: an audit hiccup must not undo a committed save.
    if let Ok(bh) = state.binary_hash.wait() {
        let payload = audit_payloads::TenantSellerRegionConfiguredPayload {
            country_code: inputs.address_country_code.trim().to_string(),
            nav_enabled: state.nav_enabled,
            operator_login: operator_login.clone(),
        };
        if let Err(e) = crate::tenant_registry::emit_tenant_event(
            &state.db_path,
            state.tenant.clone(),
            bh,
            &operator_login,
            EventKind::TenantSellerRegionConfigured,
            payload.to_bytes(),
        ) {
            tracing::warn!(error = ?e, "could not record TenantSellerRegionConfigured audit");
        }
    }

    Ok(())
}

// ── PR-53 / session-73 — GET /api/seller-info ────────────────────────

/// PR-53 / session-73 — read-only counterpart of the
/// `POST /api/setup-seller-info` write route. Used by the SPA's
/// Tenant Settings page (PR-53) to render the current saved values
/// before the operator decides to edit any of them.
///
/// Wire shape mirrors `SetupSellerInfoRequest` (camelCase via serde
/// rename to match the SPA composer is NOT used — the SPA owns the
/// case mapping on the read side too, matching the
/// `SetupSellerInfoRequest` direction).
#[derive(Debug, Serialize)]
pub struct SellerInfoResponse {
    pub legal_name: String,
    pub tax_number: String,
    pub eu_vat_number: Option<String>,
    pub address: SellerInfoAddress,
    pub bank: SellerInfoBank,
}

#[derive(Debug, Serialize)]
pub struct SellerInfoAddress {
    pub country_code: String,
    pub postal_code: String,
    pub city: String,
    pub street: String,
}

#[derive(Debug, Serialize, Default)]
pub struct SellerInfoBank {
    pub account_number: Option<String>,
    pub iban: Option<String>,
    pub name: Option<String>,
    pub swift_bic: Option<String>,
}

/// PR-53 / session-73 — `GET /api/seller-info` handler. Returns the
/// per-tenant seller.toml contents as JSON. The route requires the
/// backend to be in `Ready` (bearer auth + ready-gate); the wizard
/// path covers the not-yet-saved case via the boot-state
/// `needs-seller-config` dispatch.
///
/// Failure modes:
///   - `401` if bearer missing.
///   - `503` if backend is in `NeedsSetup` / `NeedsSellerConfig`.
///   - `404` if the file is unexpectedly missing (the boot gate
///     should have caught this — the route surfaces a loud-fail
///     message rather than synthesising defaults).
///   - `500` on filesystem read errors.
async fn handle_get_seller_info(headers: HeaderMap, State(state): State<AppState>) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match seller_info_request(&state) {
        Ok(Some(body)) => Json(body).into_response(),
        Ok(None) => {
            let path = match setup_seller_info::seller_toml_path_for_tenant(state.tenant.as_str()) {
                Ok(p) => p,
                Err(e) => return internal_error("seller_toml_path_for_tenant", e),
            };
            (
                StatusCode::NOT_FOUND,
                Json(error_body(format!(
                    "seller.toml at {} is missing or identity-incomplete; \
                     re-run the seller-config wizard",
                    path.display()
                ))),
            )
                .into_response()
        }
        Err(e) => internal_error("seller_info_request", e),
    }
}

/// PR-53 / session-73 — library helper backing
/// [`handle_get_seller_info`]. Extracted as `pub` so the integration
/// test in `tests/serve_settings_routes.rs` can hit it without
/// spinning the HTTPS listener (A158 posture).
///
/// Returns `Ok(None)` when the per-tenant seller.toml is absent OR
/// identity-incomplete; `Ok(Some(body))` when the file parses
/// cleanly; `Err` on filesystem read errors (the route maps these
/// to 500).
pub fn seller_info_request(state: &AppState) -> Result<Option<SellerInfoResponse>> {
    let path = setup_seller_info::seller_toml_path_for_tenant(state.tenant.as_str())
        .context("resolve seller.toml path for /api/seller-info")?;
    seller_info_request_from_path(&path)
}

/// PR-53 / session-73 — path-explicit sibling of
/// [`seller_info_request`] for the integration tests (HOME-mutation-
/// free per the session-58 path-override pattern).
pub fn seller_info_request_from_path(path: &std::path::Path) -> Result<Option<SellerInfoResponse>> {
    let identity = match setup_seller_info::read_seller_identity(path)? {
        Some(id) => id,
        None => return Ok(None),
    };
    let bank = setup_seller_info::read_seller_bank(path)?;
    Ok(Some(SellerInfoResponse {
        legal_name: identity.legal_name,
        tax_number: identity.tax_number,
        eu_vat_number: identity.eu_vat_number,
        address: SellerInfoAddress {
            country_code: identity.address_country_code,
            postal_code: identity.address_postal_code,
            city: identity.address_city,
            street: identity.address_street,
        },
        bank: SellerInfoBank {
            account_number: bank.account_number,
            iban: bank.iban,
            name: bank.name,
            swift_bic: bank.swift_bic,
        },
    }))
}

// ── PR-53 / session-73 — GET /api/nav-credentials-status ─────────────

/// PR-53 / session-73 — per-item presence flags for the four NAV
/// credential artifacts. The login VALUE is returned verbatim (it's
/// not a secret — it's the operator-visible identifier the audit
/// ledger stamps); the other three values are NEVER returned (they
/// are secrets in the keychain; only presence-bool surfaces).
#[derive(Debug, Serialize)]
pub struct NavCredentialsStatusResponse {
    pub login: bool,
    pub password: bool,
    pub sign_key: bool,
    pub change_key: bool,
    /// `Some(_)` iff the login is present; the SPA renders this as a
    /// plain-text row next to the three masked secret rows.
    pub login_value: Option<String>,
}

/// PR-53 / session-73 — `GET /api/nav-credentials-status` handler.
/// Lets the SPA's NAV Credentials settings page render the four
/// presence rows + the operator-visible login value without
/// surfacing the three secret values.
async fn handle_get_nav_credentials_status(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match nav_credentials_status_request(&state) {
        Ok(body) => Json(body).into_response(),
        Err(e) => internal_error("nav_credentials_status_request", e),
    }
}

/// PR-53 / session-73 — library helper backing
/// [`handle_get_nav_credentials_status`]. Reads the consolidated
/// `nav_credentials_blob` keychain entry (PR-57) and returns presence
/// flags + the operator-visible login value. `pub` for
/// integration-test access (A158).
///
/// # PR-57 / session-77 — blob-first read
///
/// Pre-PR-57 this helper made four `get_password` calls (one per
/// artifact). Post-PR-57 it goes through `NavCredentials::load_from
/// _keychain`, which itself reads the consolidated blob (ONE
/// `get_password` call) and transparently migrates any legacy entries
/// found on first call. The behavior on the wire is unchanged: all
/// four presence bools mirror whether the blob is populated, and
/// `login_value` carries the login string when present.
pub fn nav_credentials_status_request(state: &AppState) -> Result<NavCredentialsStatusResponse> {
    let tenant = state.tenant.as_str();
    match NavCredentials::load_from_keychain(tenant) {
        Ok(creds) => Ok(NavCredentialsStatusResponse {
            login: true,
            password: true,
            sign_key: true,
            change_key: true,
            login_value: Some(creds.login().to_string()),
        }),
        Err(aberp_nav_transport::NavTransportError::KeychainItemMissing { .. }) => {
            // Blob absent AND no legacy entries to migrate — NeedsSetup.
            Ok(NavCredentialsStatusResponse {
                login: false,
                password: false,
                sign_key: false,
                change_key: false,
                login_value: None,
            })
        }
        Err(other) => Err(anyhow!(other).context("read NAV credentials blob from OS keychain")),
    }
}

/// PR-53 / session-73 — keychain item-name slugs used in the rotate
/// route's wire body + this module's probe / write helpers. The
/// authoritative keychain-entry strings live on
/// `aberp_nav_transport::credentials::keychain::ITEM_*`; these
/// short slugs are the SPA-facing identifiers (matched verbatim in
/// the rotate route's request body's `item` discriminator).
const ITEM_LOGIN_NAME: &str = "login";
const ITEM_PASSWORD_NAME: &str = "password";
const ITEM_SIGN_KEY_NAME: &str = "sign_key";
const ITEM_CHANGE_KEY_NAME: &str = "change_key";

// ── PR-53 / session-73 — POST /api/rotate-nav-credential ─────────────

/// PR-53 / session-73 — request body for the single-slot rotate route.
/// The SPA's NAV Credentials settings page POSTs one of these per
/// "Rotate" button click so the operator can update an individual
/// secret without re-entering the other three (which they probably
/// don't remember; the wizard's all-four-required posture is
/// first-run scope, not rotation scope).
#[derive(Debug, Deserialize)]
pub struct RotateNavCredentialRequest {
    pub item: String,
    pub new_value: String,
}

#[derive(Debug, Serialize)]
struct RotateNavCredentialResponse {
    ok: bool,
    item: String,
}

/// PR-53 / session-73 — typed error from
/// [`rotate_nav_credential_request`] so the handler can map
/// validation arms to 400 and backend arms to 500.
#[derive(Debug)]
pub enum RotateNavCredentialError {
    Validation(String),
    Backend(anyhow::Error),
}

impl std::fmt::Display for RotateNavCredentialError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            RotateNavCredentialError::Validation(m) => write!(f, "{m}"),
            RotateNavCredentialError::Backend(e) => write!(f, "{e:#}"),
        }
    }
}

impl std::error::Error for RotateNavCredentialError {}

/// PR-53 / session-73 — handler. Ready-gated + bearer-required (this
/// is NOT a first-run route; rotation only happens after the wizard
/// chain). Validates the `item` slug + non-empty new_value, then
/// writes the single keychain entry. The login slot rewrite also
/// rebuilds the in-process `operator_login` so subsequent audit-actor
/// derivations pick up the new value without a restart.
async fn handle_rotate_nav_credential(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<RotateNavCredentialRequest>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match rotate_nav_credential_request(&state, &request.item, &request.new_value) {
        Ok(slug) => Json(RotateNavCredentialResponse {
            ok: true,
            item: slug.to_string(),
        })
        .into_response(),
        Err(RotateNavCredentialError::Validation(msg)) => {
            (StatusCode::BAD_REQUEST, Json(error_body(msg))).into_response()
        }
        Err(RotateNavCredentialError::Backend(e)) => {
            internal_error("rotate_nav_credential_request", e)
        }
    }
}

/// PR-53 / session-73 — library helper backing
/// [`handle_rotate_nav_credential`]. Validates the slug + non-empty
/// new_value, writes the keychain entry, and (for the login slot)
/// refreshes the in-process `operator_login` so subsequent
/// audit-actor derivations pick up the new value. Returns the
/// resolved slug string on success.
///
/// `pub` for integration-test access (A158).
///
/// # PR-57 / session-77 — blob round-trip
///
/// Pre-PR-57 this wrote a single per-field keychain entry. Post-PR-57
/// rotation is a read-blob → mutate-one-field → write-blob round-
/// trip, so the four artifacts continue to live in a single keychain
/// item. The wire shape (request body's `item` enum + response's
/// `item` echo) is unchanged.
pub fn rotate_nav_credential_request(
    state: &AppState,
    item_slug: &str,
    new_value: &str,
) -> std::result::Result<&'static str, RotateNavCredentialError> {
    let canonical_slug = canonical_credential_slug(item_slug).ok_or_else(|| {
        RotateNavCredentialError::Validation(format!(
            "unknown credential item `{item_slug}` — accepted values: \
             `login`, `password`, `sign_key`, `change_key`"
        ))
    })?;
    if new_value.is_empty() {
        return Err(RotateNavCredentialError::Validation(format!(
            "new_value for item `{item_slug}` is empty"
        )));
    }

    let tenant = state.tenant.as_str();

    // Read current blob → mutate target field → write blob.
    let current = NavCredentials::load_from_keychain(tenant).map_err(|e| {
        RotateNavCredentialError::Backend(anyhow!(e).context(
            "read NAV credentials blob before rotation; \
             cannot rotate a single field without the other three",
        ))
    })?;
    let (login, password, sign_key, change_key) = match canonical_slug {
        ITEM_LOGIN_NAME => (
            new_value,
            std::str::from_utf8(current.password_bytes()).map_err(utf8_err("password"))?,
            std::str::from_utf8(current.sign_key_bytes()).map_err(utf8_err("sign_key"))?,
            std::str::from_utf8(current.change_key_bytes()).map_err(utf8_err("change_key"))?,
        ),
        ITEM_PASSWORD_NAME => (
            current.login(),
            new_value,
            std::str::from_utf8(current.sign_key_bytes()).map_err(utf8_err("sign_key"))?,
            std::str::from_utf8(current.change_key_bytes()).map_err(utf8_err("change_key"))?,
        ),
        ITEM_SIGN_KEY_NAME => (
            current.login(),
            std::str::from_utf8(current.password_bytes()).map_err(utf8_err("password"))?,
            new_value,
            std::str::from_utf8(current.change_key_bytes()).map_err(utf8_err("change_key"))?,
        ),
        ITEM_CHANGE_KEY_NAME => (
            current.login(),
            std::str::from_utf8(current.password_bytes()).map_err(utf8_err("password"))?,
            std::str::from_utf8(current.sign_key_bytes()).map_err(utf8_err("sign_key"))?,
            new_value,
        ),
        _ => unreachable!("canonical_credential_slug already validated"),
    };

    aberp_nav_transport::credentials::keychain::write_blob(
        tenant, login, password, sign_key, change_key,
    )
    .map_err(|e| {
        RotateNavCredentialError::Backend(
            anyhow!(e).context("write NAV credentials blob to OS keychain during rotation"),
        )
    })?;

    // If the rotated slot is the login, refresh the cached operator_login
    // on the boot_state so subsequent issuance / submit routes derive
    // the audit actor from the new value.
    if canonical_slug == ITEM_LOGIN_NAME {
        let mut guard = state.boot_state.write().map_err(|e| {
            RotateNavCredentialError::Backend(anyhow!(
                "boot_state RwLock poisoned during login rotation: {e}"
            ))
        })?;
        let next = match &*guard {
            ServeBootState::Ready { .. } => ServeBootState::Ready {
                operator_login: new_value.to_string(),
            },
            other => other.clone(),
        };
        *guard = next;
    }

    tracing::info!(
        tenant = %tenant,
        item = canonical_slug,
        "NAV credential item rotated via /api/rotate-nav-credential (blob round-trip)"
    );

    Ok(canonical_slug)
}

/// PR-57 / session-77 — closure factory for the `from_utf8` map_err
/// arms in [`rotate_nav_credential_request`]. The blob's four fields
/// come out of `Zeroizing<String>` (UTF-8 by construction — the
/// keychain stored what we serialized as JSON UTF-8), so this arm
/// fires only on a corrupted keychain backend that returned non-UTF-8
/// bytes for one of the three retained fields. Loud per CLAUDE.md
/// rule 12.
fn utf8_err(field: &'static str) -> impl Fn(std::str::Utf8Error) -> RotateNavCredentialError {
    move |e| {
        RotateNavCredentialError::Backend(anyhow!(
            "NAV credentials blob field `{field}` is not valid UTF-8 \
             (keychain backend corruption?): {e}"
        ))
    }
}

/// PR-57 / session-77 — validate an SPA-facing slug and return the
/// canonical static-str form. Replaces the pre-PR-57
/// `resolve_credential_item` helper, which mapped to the legacy
/// per-artifact item-name constants — under the blob model the rotate
/// route only needs the slug itself, not the on-disk item name.
fn canonical_credential_slug(slug: &str) -> Option<&'static str> {
    match slug {
        ITEM_LOGIN_NAME => Some(ITEM_LOGIN_NAME),
        ITEM_PASSWORD_NAME => Some(ITEM_PASSWORD_NAME),
        ITEM_SIGN_KEY_NAME => Some(ITEM_SIGN_KEY_NAME),
        ITEM_CHANGE_KEY_NAME => Some(ITEM_CHANGE_KEY_NAME),
        _ => None,
    }
}

#[derive(Serialize)]
struct HealthResponse {
    ok: bool,
    binary_hash: String,
    nav_xsd_version: &'static str,
    /// S165 — whether this backend binary was compiled with
    /// `--features production`. The SPA reads this to drop the `TEST-`
    /// prefix from the Tenant-Settings invoice-number live preview on a
    /// production build (so the preview matches what actually emits).
    is_production_build: bool,
    /// S166 — `true` when this is a production build whose one-time
    /// first-launch ceremony has NOT yet been acknowledged (the
    /// `~/.aberp/<tenant>/.first-launch-acknowledged` touchfile is
    /// absent). The SPA blocks its main routes behind the
    /// `FirstProdLaunchModal` while this is true. Always `false` on
    /// dev/test builds.
    first_prod_launch_required: bool,
}

async fn handle_health(State(state): State<AppState>) -> Response {
    // PR-45a / session-61 — `binary_hash` is now a background-computed
    // handle (see `BinaryHashHandle`). `wait()` essentially never
    // blocks once the SPA has finished its first probe; the only
    // failure mode is the background compute itself erroring out
    // (e.g. macOS sandbox denied `current_exe`), which is the same
    // catastrophic surface pre-PR-45a hit at startup. Surface it as
    // 503 here rather than a Json with an "ok":true claim that
    // would be a lie.
    match state.binary_hash.wait() {
        Ok(hash) => Json(HealthResponse {
            ok: true,
            binary_hash: hex::encode(hash.as_bytes()),
            nav_xsd_version: aberp_nav_xsd_validator::NAV_XSD_VERSION,
            is_production_build: crate::build_profile::IS_PRODUCTION_BUILD,
            first_prod_launch_required: crate::first_launch::first_prod_launch_required(
                state.tenant.as_str(),
            ),
        })
        .into_response(),
        Err(e) => (
            StatusCode::SERVICE_UNAVAILABLE,
            Json(error_body(format!("binary hash unavailable: {e:#}"))),
        )
            .into_response(),
    }
}

/// S166 / prod-prep PR #2 — response shape for the first-prod-launch
/// acknowledgement route. Carries the RFC3339 instant stamped into the
/// touchfile + audit entry.
#[derive(Serialize)]
struct AcknowledgeFirstProdLaunchResponse {
    acknowledged_at: String,
}

/// `POST /health/acknowledge-first-prod-launch` — the operator's one-time
/// consent to real fiscal operation (S166). Writes the
/// `~/.aberp/<tenant>/.first-launch-acknowledged` touchfile AND a
/// permanent, hash-chained `FirstProdLaunchAcknowledged` audit entry.
///
/// Idempotent: re-acknowledging rewrites the touchfile stamp and appends
/// a fresh audit entry (a re-consent is itself worth recording). Requires
/// a valid bearer + Ready boot state, like every other mutation route —
/// the SPA only surfaces the modal once the backend is Ready, so the
/// operator login the audit entry records is always resolvable.
async fn handle_acknowledge_first_prod_launch(
    headers: HeaderMap,
    State(state): State<AppState>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(l) => l,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match acknowledge_first_prod_launch(&state, &operator_login) {
        Ok(acknowledged_at) => {
            Json(AcknowledgeFirstProdLaunchResponse { acknowledged_at }).into_response()
        }
        Err(e) => internal_error("acknowledge_first_prod_launch", e),
    }
}

/// Library core of [`handle_acknowledge_first_prod_launch`]: stamp the
/// touchfile, then append the audit entry. Returns the RFC3339 stamp.
fn acknowledge_first_prod_launch(state: &AppState, operator_login: &str) -> Result<String> {
    use time::format_description::well_known::Rfc3339;

    let tenant = state.tenant.as_str();
    let acknowledged_at = time::OffsetDateTime::now_utc()
        .format(&Rfc3339)
        .context("format first-launch acknowledgement timestamp")?;

    // 1. Touchfile — the gate the `/health` route reads. Written FIRST so
    //    that if the audit append later fails, the gate is still
    //    satisfied and the operator is not trapped behind the modal; the
    //    append failure loud-fails the request (surfacing the problem)
    //    without re-prompting forever.
    crate::first_launch::write_acknowledgement(tenant, &acknowledged_at)
        .context("write first-launch acknowledgement touchfile")?;

    // 2. Audit ledger — permanent, hash-chained record of the human
    //    consent. The unusual move (a `/health` subroute writing audit)
    //    is deliberate: this is a legal-grade event.
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute for first-launch acknowledgement")?;
    record_first_prod_launch_audit(
        &state.db_path,
        state.tenant.clone(),
        binary_hash,
        operator_login,
        &acknowledged_at,
    )?;

    tracing::info!(
        tenant = tenant,
        at = %acknowledged_at,
        "boot_step: first prod launch acknowledged"
    );
    Ok(acknowledged_at)
}

/// Append a single `FirstProdLaunchAcknowledged` entry to the on-disk
/// audit ledger. Split from [`acknowledge_first_prod_launch`] so the
/// ledger-write half is unit-testable against a scratch DuckDB without
/// constructing an [`AppState`] or mutating `HOME` (the touchfile-write
/// half is pinned separately in `crate::first_launch`).
fn record_first_prod_launch_audit(
    db_path: &std::path::Path,
    tenant: TenantId,
    binary_hash: aberp_audit_ledger::BinaryHash,
    operator_login: &str,
    acknowledged_at: &str,
) -> Result<()> {
    let tenant_str = tenant.as_str().to_string();
    let mut ledger = Ledger::open(db_path, tenant, binary_hash)
        .context("open audit ledger to record first-launch acknowledgement")?;
    let actor = Actor::from_local_cli(Ulid::new().to_string(), operator_login);
    let payload =
        audit_payloads::FirstProdLaunchAcknowledgedPayload::new(acknowledged_at, tenant_str);
    ledger
        .append(
            EventKind::FirstProdLaunchAcknowledged,
            payload.to_bytes(),
            actor,
            None,
        )
        .context("append FirstProdLaunchAcknowledged audit entry")?;
    Ok(())
}

/// S171 / PR-171 — append a single `UpgradeSnapshotMismatch` entry to
/// the on-disk audit ledger from the boot path. Called BEFORE the boot
/// refuses with exit(1) so the divergence is permanently hash-chained
/// even if the operator resolves it by `mv`-ing the snapshot file.
///
/// `tenant_str` comes from `ServeArgs.tenant`; `binary_hash_handle` is
/// the boot-thread handle (we block on `wait` — we're about to exit
/// anyway). The synthetic actor's `user_id` (`"system:upgrade-snapshot-check"`)
/// names the boot-time origin so an auditor can distinguish this from
/// operator-driven entries.
fn record_upgrade_snapshot_mismatch_audit(
    db_path: &std::path::Path,
    tenant_str: &str,
    binary_hash_handle: &BinaryHashHandle,
    deltas: &[upgrade_snapshot::Delta],
    detected_at: &str,
) -> Result<()> {
    let tenant = TenantId::new(tenant_str.to_string())
        .ok_or_else(|| anyhow!("tenant id empty for upgrade-snapshot audit"))?;
    let binary_hash = binary_hash_handle
        .wait()
        .context("await binary hash for upgrade-snapshot audit")?;
    let mut ledger = Ledger::open(db_path, tenant, binary_hash)
        .context("open audit ledger to record upgrade-snapshot mismatch")?;
    let actor = Actor::from_local_cli(Ulid::new().to_string(), "system:upgrade-snapshot-check");
    let payload = audit_payloads::UpgradeSnapshotMismatchPayload::new(
        tenant_str.to_string(),
        detected_at.to_string(),
        deltas
            .iter()
            .map(|d| audit_payloads::UpgradeSnapshotDelta {
                field: d.field.clone(),
                expected: d.expected.clone(),
                actual: d.actual.clone(),
            })
            .collect(),
    );
    ledger
        .append(
            EventKind::UpgradeSnapshotMismatch,
            payload.to_bytes(),
            actor,
            None,
        )
        .context("append UpgradeSnapshotMismatch audit entry")?;
    Ok(())
}

/// PR-28 / ADR-0036 §9 — typed wire shape for the eleven UI labels
/// emitted by `InvoiceTrace::derive_state`. Replaces the pre-PR-28
/// `&'static str` ladder per the §9 named-deferred trigger.
///
/// `Serialize` produces JSON strings matching the variant names
/// exactly (no `#[serde(rename_all = ...)]` — variants are already
/// PascalCase, matching the SPA's `InvoiceState` string union in
/// `apps/aberp-ui/ui/src/lib/api.ts`). Variant-name drift between
/// this enum and the SPA mirror surfaces at three layers per
/// CLAUDE.md rule 12: the Rust-side `invoice_state_wire_shape_pins_
/// pascalcase_strings` test pins each variant's JSON form loud; the
/// SPA's `Record<InvoiceState, LabelMeta>` table fails `npm run
/// check` on a missing key; the module-load runtime check in
/// `labels.ts` throws on a `LIFECYCLE_ORDER` divergence.
///
/// Variants kept in lifecycle order matching ADR-0036 §3's priority-
/// ladder inversion for readability; the discriminant order has no
/// wire impact (serde emits the variant identifier).
///
/// `Debug` + `PartialEq` + `Eq` + `Clone` + `Copy` keep the test
/// assertions ergonomic (the parameterised label-table test compares
/// against literal variants via `assert_eq!`).
#[derive(Serialize, Debug, PartialEq, Eq, Clone, Copy)]
enum InvoiceState {
    /// S236 / PR-230b — pre-allocation Draft state for `invoice_draft`
    /// rows. Has no `sequence_number` (the gap-free allocator hasn't
    /// run yet); can be freely edited / deleted without breaking
    /// ADR-0009 §169. Set ONLY on rows synthesised from
    /// `invoice_draft` in `list_invoices`; the audit-derived
    /// `derive_state` ladder NEVER returns this variant because drafts
    /// live in their own table and have no `InvoiceDraftCreated`
    /// audit entry pointing at an `inv_<ULID>` id. On operator Issue
    /// click the draft becomes a regular `invoice` row in `Ready`
    /// state via the existing `issue_invoice` allocator.
    Draft,
    Unknown,
    Ready,
    Pending,
    PendingNavExists,
    Submitted,
    Recovered,
    Finalized,
    Rejected,
    Storno,
    Amended,
    Abandoned,
    /// S434 — issued under a NAV-disabled tenant: the invoice has a PDF +
    /// audit trail but was never submitted to NAV (no NAV to submit to).
    /// Terminal from ABERP's side; derived from an
    /// `InvoiceLocalOnlyEmitted` ledger entry. The SPA renders a
    /// "LOCAL ONLY (no NAV)" badge.
    LocalOnly,
}

/// PR-213 / S215 — closed-vocab discriminator on the unified
/// invoices-list wire shape. `Own` rows are canonical ABERP-issued
/// invoices read out of the `invoice` table (with their full
/// audit-ledger-derived trace); `ExtNav` rows are the NAV-mirror
/// rows read out of the `restored_invoice` table (S180 / NAV-as-DR)
/// — invoices NAV knows were issued under our `supplierTaxNumber`
/// but that we did NOT issue through ABERP. The SPA reads this
/// field to (a) render the Kind column, (b) hide every write-back
/// affordance (Submit / Storno / Pay) on `ExtNav` rows since they
/// belong to whoever issued them and we can only observe.
///
/// Per ADR-0058 the union is a READ-TIME concat — neither table
/// carries a `row_kind` column; the discriminator lives in this
/// wire shape and in the SPA's render component only.
#[derive(Serialize, Debug, PartialEq, Eq, Clone, Copy)]
enum RowKind {
    /// Canonical ABERP-issued invoice from the `invoice` table.
    Own,
    /// NAV-mirror row from the `restored_invoice` table.
    ExtNav,
}

#[derive(Serialize)]
struct InvoiceListItem {
    invoice_id: String,
    sequence_number: u64,
    fiscal_year: i32,
    state: InvoiceState,
    total_gross: Option<i64>,
    /// PR-31 / session-35 — chain-link affordance for list rows
    /// (session-30-named Option M). `true` iff this invoice is the
    /// base of at least one `InvoiceStornoIssued` or
    /// `InvoiceModificationIssued` chain entry; mirrors
    /// `InvoiceTrace::is_storno_base || is_amended_base`. The SPA
    /// renders a small `↘` badge next to the state chip when this
    /// flag is true so an inspector can see at a glance which rows
    /// have a chain history without opening the detail modal. The
    /// flag is redundant-by-construction with `state ∈ {Storno,
    /// Amended}` for invoices that have only ever been the base of
    /// one chain kind; it carries additional signal when an invoice
    /// is the base of BOTH an amendment AND a storno (which the
    /// `derive_state` ladder collapses to `Storno` per ADR-0036 §3,
    /// hiding the prior amendment history at the state chip). Pinned
    /// by `list_invoices_emits_has_chain_children`.
    has_chain_children: bool,
    /// ADR-0049 §Screen render (session 156) — `true` iff this row IS a
    /// storno (the chain CHILD). Mirrors `InvoiceTrace::is_storno_self`.
    /// The billing row stores the storno's `total_gross` POSITIVE
    /// (negation lives only in the NAV-XML / PDF path), so the SPA reads
    /// this flag to render the list total negated (`-127 000 Ft`),
    /// matching the buyer-facing PDF. Not a DB column — derived from the
    /// ledger's `InvoiceStornoIssued` chain-link at read time.
    is_storno: bool,
    /// PR-44ε / session-53 — currency on the list-row wire shape per
    /// ADR-0037 §1.a + §3. Mirrors the `invoice.currency` DuckDB
    /// column PR-44γ added (NULL is treated as HUF at read time per
    /// the migration backfill posture). The SPA reads this field so
    /// the per-row total formatter can pick the EUR-vs-HUF symbol +
    /// minor-unit interpretation (`Money::Eur` stores EUR cents in
    /// the underlying `i64` per the issuance-path posture; the
    /// formatter divides by 100 when `currency == Eur`). Wire form
    /// is the existing `Currency` enum's `rename_all = "UPPERCASE"`
    /// serde shape — `"HUF"` or `"EUR"` — pinned by
    /// `invoice_list_item_emits_currency`.
    currency: Currency,
    /// PR-65 / session-86 — buyer label for the SPA's list-row
    /// "Partner" column (Tier-1 UX lift). Best-effort read of the
    /// PR-47α / A174 side-stored `<ULID>.input.json`'s
    /// `customer.name` field; `None` when the side-store is missing
    /// (CLI-issued invoices, pre-PR-47α SPA-issued invoices, or any
    /// I/O failure) so the SPA can render an em-dash placeholder
    /// rather than fabricate a label.
    ///
    /// A185 — single-name surface, not the brief's display/legal
    /// dual. Rationale: the side-store snapshot only carries one
    /// name field (`CustomerJson.name`), and per
    /// `partners::buyerFieldsFromPartner` the typeahead writes
    /// `partner.legal_name` into that slot at issuance time. The
    /// dual-name shape the brief opened with would require either a
    /// schema migration (add `partner_id` FK + JOIN at query time)
    /// OR a wire-shape extension to `CustomerJson` — both larger
    /// blast radius than the read-side snapshot consumption this
    /// field implements. The single `buyer_name` surface IS the
    /// regulatory legal name for partner-selected buyers and IS
    /// whatever the operator typed for one-off entries. Pinned by
    /// `invoice_list_item_emits_buyer_name` +
    /// `read_buyer_name_from_side_store_round_trip`.
    buyer_name: Option<String>,
    /// PR-70 / ADR-0039 §2 — operational payment-receipt summary
    /// for the SPA's "Paid" chip + quick-action gating. `Some` iff
    /// at least one `InvoicePaymentRecorded` audit entry exists for
    /// this invoice; `None` for unpaid invoices (the SPA renders no
    /// chip + shows the "💰 Pay" quick action on the row). The wire
    /// shape mirrors [`PaymentRecordSummary`] so a single TS
    /// interface drives both list-row and detail-modal rendering.
    /// Paid-vs-unpaid is operational metadata, NOT a regulatory
    /// state — the `state` field above continues to render the NAV
    /// ladder verbatim; the badge sits next to it.
    payment: Option<PaymentRecordSummary>,
    /// PR-73 / ADR-0040 §addendum — denormalized bank-account snapshot
    /// surfaced on the list row. `Some(_)` for SPA-issued invoices
    /// post-PR-73; `None` for pre-PR-73 invoices AND CLI-issued
    /// invoices (which never wrote the snapshot quintet). The SPA
    /// list view does NOT render the bank account on a list row
    /// (the "Pay to" surface lives on the detail modal), but the
    /// field rides on the same shape as the detail response so a
    /// single TS interface drives both surfaces.
    bank_account: Option<BankAccountSnapshotResponse>,
    /// PR-213 / S215 — discriminator for the virtual union. `Own`
    /// for `invoice`-table rows; `ExtNav` for `restored_invoice`-
    /// table rows. See [`RowKind`] for the read-time-only invariant
    /// per ADR-0058.
    row_kind: RowKind,
    /// PR-213 / S215 — `Some(_)` IFF `row_kind == ExtNav`; carries
    /// the raw NAV-emitted `<invoiceNumber>` from
    /// `restored_invoice.source_nav_invoice_number`. The SPA
    /// surfaces this on the ExtNav row as the operator-readable
    /// identity (since the digest does NOT carry a buyer name and
    /// the `sequence_number` slot is meaningless for non-ABERP
    /// invoices). `None` for `Own` rows — those carry their own
    /// composed `YYYY-NNNNNN` identifier via the existing
    /// `fiscal_year` + `sequence_number` pair.
    source_nav_invoice_number: Option<String>,
    /// S242 / PR-236 — canonical ISO-8601 `YYYY-MM-DD` issue date
    /// (Hungarian `Kelt` / "Issued"). Sourced per row kind:
    ///   - `Own` non-draft → `ready_invoice.issue_date` formatted as
    ///     `YYYY-MM-DD` (mirrors the detail-modal field; both come
    ///     from the same DB column).
    ///   - `ExtNav` → `restored_invoice.issue_date` (NOT NULL — the
    ///     NAV `queryInvoiceDigest` always carries `<invoiceIssueDate>`,
    ///     and `process_digest_loud_fails_on_missing_issue_date`
    ///     rejects rows without one).
    ///   - `Own` draft → `None` (drafts have no issue date by
    ///     construction; the SPA renders an empty cell, NOT an em-dash
    ///     placeholder).
    ///
    /// The SPA's "Issued" / "Kelt" column on the Outgoing tab reads
    /// this field strictly; a fallback / `--` shim is intentionally
    /// avoided per CLAUDE.md rule 12 (fail loud, not silent — a `null`
    /// on a non-draft Own row would surface as the empty cell and
    /// indicate a real backend wiring gap).
    issue_date: Option<String>,
    /// S262 / PR-251 — canonical ISO-8601 `YYYY-MM-DD` payment deadline
    /// (Hungarian `Fizetési határidő`), the AR-aging anchor. The S227
    /// hygiene click-through deliberately kept the AR "past deadline" row
    /// static because this field was absent from the list wire shape;
    /// PR-251 adds it so the Finance dashboard's receivables-aging bucket
    /// rows can deep-link into the outgoing list filtered to a bucket.
    /// Resolved value (the billing read path falls NULL → issue_date per
    /// PR-84), so `Own` non-draft rows always carry a date; `None` only
    /// for `Draft` (pre-issuance) and `ExtNav` (digest mirror has no
    /// deadline). Pinned by `invoice_list_item_emits_payment_deadline`.
    payment_deadline: Option<String>,
}

/// PR-73 / ADR-0040 §addendum — wire-shape mirror of the typed
/// `BankAccountSnapshot` from the billing crate. Mirrors the shape
/// of `SellerBankResponse` (PR-72) minus the `is_default` flag —
/// per-invoice snapshots are immutable post-issuance and have no
/// default-flag semantics.
#[derive(Debug, Serialize, Clone)]
struct BankAccountSnapshotResponse {
    id: String,
    currency: String,
    account_number: String,
    bank_name: String,
    swift_bic: String,
}

impl BankAccountSnapshotResponse {
    fn from_typed(snapshot: aberp_billing::BankAccountSnapshot) -> Self {
        Self {
            id: snapshot.id,
            currency: snapshot.currency,
            account_number: snapshot.account_number,
            bank_name: snapshot.bank_name,
            swift_bic: snapshot.swift_bic,
        }
    }
}

#[derive(Serialize)]
struct InvoiceDetailResponse {
    invoice_id: String,
    sequence_number: u64,
    fiscal_year: i32,
    state: InvoiceState,
    total_gross: Option<i64>,
    /// ADR-0049 §Screen render (session 156) — `true` iff this invoice IS
    /// a storno (the chain CHILD). Mirrors `InvoiceListItem.is_storno`;
    /// the SPA detail modal reads it to render the total negated, matching
    /// the buyer-facing PDF. Not a DB column — derived from the ledger.
    is_storno: bool,
    audit_entries: Vec<AuditEntryView>,
    /// PR-32 / session-36 — chain-children list (Option T). For an
    /// invoice that is the BASE of at least one chain entry, this
    /// vector enumerates every storno / modification invoice issued
    /// against it, in ledger-walk (i.e., issuance) order. Empty for
    /// invoices with no chain children. The list-row badge from
    /// PR-31 (`has_chain_children: bool`) tells the inspector
    /// "this row has children"; this field tells the inspector
    /// "WHICH children." The SPA renders the list in a section
    /// between the meta-grid and the audit-trail table, each entry
    /// clickable via the same `onNavigate` callback as the
    /// audit-row chain-link affordance (PR-26). Pinned by
    /// `invoice_detail_emits_chain_children`.
    chain_children: Vec<ChainChildView>,
    /// PR-33 / session-37 — typed wire emit of the latest NAV ack
    /// for this invoice (Option Q). `Some(AckStatus)` when at least
    /// one `InvoiceAckStatus` audit entry has been written for the
    /// invoice; `None` for invoices with no ack yet (Draft / Pending
    /// / etc) and for the rare case where a persisted string fails
    /// to parse as one of the four NAV v3.0 values. The SPA's
    /// `InvoiceDetail.svelte` renders the value as a meta-grid row
    /// alongside Series #, Fiscal year, State, and Total (gross); a
    /// `null` wire form renders as `—`. Mirrors the
    /// `InvoiceTrace.last_ack_status` accumulator (which stays
    /// `Option<String>` to preserve the persisted form for
    /// `derive_state`'s string-keyed match per ADR-0036 §3 and the
    /// `audit_query.rs` `prior_last_ack_status` command-side
    /// posture). Pinned by `invoice_detail_emits_last_ack_status` +
    /// `ack_status_wire_shape_pins_uppercase_strings`.
    last_ack_status: Option<AckStatus>,
    /// PR-44ε / session-53 — currency on the detail wire shape per
    /// ADR-0037 §1.a + §3. Same wire form as the list-row
    /// `InvoiceListItem.currency` field above (`"HUF"` / `"EUR"`).
    /// Pinned by `invoice_detail_emits_currency_and_rate_metadata`.
    currency: Currency,
    /// PR-44ε / session-53 — MNB exchange rate per ADR-0037 §1.a +
    /// §1.c (rate value) / C11 (precision). Decimal-as-string at
    /// exactly 6 decimal places (`"405.230000"` not `"405.23"`),
    /// mirroring the audit-ledger payload form
    /// `InvoiceDraftCreatedPayload.exchange_rate` PR-44γ added. `Some`
    /// iff `currency != Currency::Huf`; the SPA renders it as a
    /// meta-grid row only on the non-HUF branch. Pinned by
    /// `invoice_detail_emits_currency_and_rate_metadata`.
    exchange_rate: Option<String>,
    /// PR-44ε / session-53 — MNB source identifier per ADR-0037 §1.a
    /// (printed-invoice field) + §2.a (literal `"MNB"`). `Some` iff
    /// `currency != Currency::Huf`. Pinned by
    /// `invoice_detail_emits_currency_and_rate_metadata`.
    exchange_rate_source: Option<String>,
    /// PR-44ε / session-53 — MNB rate publication date per ADR-0037
    /// §1.a + §2.b (walk-back rule). ISO-8601 `YYYY-MM-DD`. `Some`
    /// iff `currency != Currency::Huf`. Pinned by
    /// `invoice_detail_emits_currency_and_rate_metadata`.
    exchange_rate_date: Option<String>,
    /// PR-44ε / session-53 — HUF-equivalent gross total per ADR-0037
    /// §1.a + §1.c / C5 / C11. Whole forints (HUF has no sub-unit
    /// per ADR-0009 §1 / `Huf(pub i64)`). `Some` iff `currency !=
    /// Currency::Huf`. Pinned by
    /// `invoice_detail_emits_currency_and_rate_metadata`.
    huf_equivalent_total: Option<i64>,
    /// PR-70 / ADR-0039 §2 — operational payment summary mirror of
    /// [`InvoiceListItem::payment`]. Same wire shape on both list
    /// and detail surfaces so one TS interface drives the SPA's
    /// chip rendering. `Some` iff at least one
    /// `InvoicePaymentRecorded` audit entry exists for this invoice.
    payment: Option<PaymentRecordSummary>,
    /// PR-73 / ADR-0040 §addendum — denormalized bank-account snapshot
    /// surfaced on the detail wire shape so the `InvoiceDetail.svelte`
    /// "Pay to" sub-section renders the bank account the invoice was
    /// issued with. `Some(_)` for SPA-issued invoices post-PR-73;
    /// `None` for pre-PR-73 invoices and CLI-issued rows. Operator-
    /// facing surface only; the renderer falls back to "(no bank
    /// account on file)" on `null`.
    bank_account: Option<BankAccountSnapshotResponse>,
    /// PR-82 — buyer-facing per-invoice global note ("Megjegyzés").
    /// `Some(text)` when the operator typed a note at issuance; `null`
    /// otherwise. Surfaced on the detail-modal "Megjegyzés" section so
    /// the operator can preview what the buyer will see on the printed
    /// PDF. NEVER on the NAV XML wire — recipient-facing only.
    invoice_note: Option<String>,
    /// PR-82 — buyer-facing per-line notes, one entry per annotated
    /// line. Empty array when no line has a note. Each entry carries
    /// the ordinal + the line's description (so the operator sees
    /// "Line 1 (Widget A): leave at the back door") and the note
    /// text. Pre-PR-82 invoices return an empty array regardless of
    /// `lines` shape.
    line_notes: Vec<LineNoteView>,
    /// PR-99 Item 5 — the three operator-meaningful invoice dates,
    /// canonical YYYY-MM-DD. Always Some on post-PR-84 invoices (the
    /// billing crate populates the columns at issuance time);
    /// pre-PR-84 rows fall back to the issue date for all three so
    /// the SPA never has to render an em-dash. The detail-modal
    /// meta-grid renders all three with bilingual labels (Számla
    /// kelte / Issue date — Fizetési határidő / Payment deadline —
    /// Teljesítési dátum / Delivery date).
    issue_date: Option<String>,
    payment_deadline: Option<String>,
    delivery_date: Option<String>,
}

/// PR-82 — one per-line note row on the detail wire shape. Surfaces
/// only lines that carry a non-empty `note`; unannotated lines are
/// omitted so the SPA's renderer can iterate the array directly.
#[derive(Serialize, Debug, PartialEq, Eq, Clone)]
struct LineNoteView {
    /// Zero-based ordinal matching the `invoice_line.ordinal` column.
    /// The SPA renders this as `Line {ordinal + 1}` to match the
    /// printed-PDF row numbering.
    ordinal: u32,
    /// The line's description, copied verbatim from
    /// `invoice_line.description` so the operator sees note context
    /// without the SPA having to issue a separate lines fetch.
    description: String,
    /// The per-line note text. Non-empty (empty / whitespace-only
    /// notes are filtered out at the wire boundary).
    note: String,
}

/// PR-32 / session-36 — chain-children list entry. One per storno /
/// modification invoice issued against a base.
#[derive(Serialize)]
struct ChainChildView {
    /// Which chain operation issued this child. Mirrors the two
    /// chain-link `EventKind` variants
    /// (`InvoiceStornoIssued` / `InvoiceModificationIssued`) under
    /// the same PascalCase wire shape as `InvoiceState` for SPA-
    /// side consumption (typed enum on the TS side per PR-28
    /// precedent).
    kind: ChainChildKind,
    /// The chain child's own invoice id (the `storno_invoice_id` /
    /// `modification_invoice_id` field from the chain-link payload
    /// per ADR-0023 / ADR-0024).
    invoice_id: String,
    /// PR-41 / session-45 — the per-base chain index allocated at
    /// issuance time (`InvoiceStornoIssuedPayload.modification_index`
    /// / `InvoiceModificationIssuedPayload.modification_index`).
    /// Shared name space across both kinds: the next storno or
    /// modification against the same base receives
    /// `max(modification_index) + 1` per
    /// `next_modification_index_in_tx` in `issue_storno.rs` /
    /// `issue_modification.rs`. Operator-meaningful as the per-row
    /// answer to "which entry in this base's chain?"; surfaced on
    /// the detail-modal chain-children list per Option W. Pinned by
    /// `invoice_detail_emits_chain_children`.
    modification_index: u32,
    /// S369 / S370 — the chain CHILD's own derived lifecycle state,
    /// computed from the child invoice's audit lineage (a fresh
    /// `InvoiceTrace` walked over the same ledger entries). Before
    /// S369 the chain-children list rendered ONLY the kind chip, so a
    /// REJECTED / ABORTED storno (the exact failure NAV returns for
    /// `INVOICE_LINE_ALREADY_EXISTS`) was invisible on the base's
    /// detail view — the operator saw "Storno → inv_X" with no signal
    /// the cancellation had failed at NAV. The SPA renders this as a
    /// state chip alongside the kind chip. Pinned by
    /// `invoice_detail_chain_children_carry_child_state`.
    state: InvoiceState,
    /// S369 / S370 — the chain child's latest NAV ack
    /// (`InvoiceAckStatus`), same typed wire form as the detail-level
    /// `last_ack_status`. `Some(Aborted)` is the value that surfaces a
    /// NAV-rejected storno on the base's chain-children row; `None`
    /// when the child has no ack yet. Pinned by
    /// `invoice_detail_chain_children_carry_child_state`.
    last_ack_status: Option<AckStatus>,
}

/// PR-32 / session-36 — typed kind discriminator for chain-children
/// rows. Mirrors the terminal `InvoiceState` labels rather than the
/// `EventKind` names so the SPA can render the same label set the
/// state chip uses (`labels.ts`).
#[derive(Serialize, Debug, PartialEq, Eq, Clone, Copy)]
enum ChainChildKind {
    Storno,
    Amended,
}

/// PR-33 / session-37 — typed wire mirror for the four NAV v3.0
/// `processingResult` values (Option Q). The audit-ledger stores the
/// NAV ack as a free `String` on `InvoiceAckStatusPayload.ack_status`
/// (per `apps/aberp/src/audit_payloads.rs`); the wire shape now
/// surfaces the latest-per-invoice value as a typed enum on
/// `InvoiceDetailResponse.last_ack_status` so the SPA reads "the
/// invoice's most-recent NAV ack" without parsing the audit-entries
/// payload soup. Continues the typed-enum precedent set by PR-28
/// (`InvoiceState`) and PR-32 (`ChainChildKind`).
///
/// `#[serde(rename_all = "UPPERCASE")]` matches the NAV wire literals
/// verbatim — see `ProcessingStatus` in
/// `crates/nav-transport/src/operations/query_transaction_status.rs`
/// for the same four strings on the inbound parse path. The four
/// values per ADR-0009 §2: two intermediate (`RECEIVED`,
/// `PROCESSING`) and two terminal (`SAVED`, `ABORTED`). The
/// deprecated `DONE` value is NOT represented — it does not appear
/// in NAV v3.0 and the inbound `from_nav_str` parse already rejects
/// it.
///
/// `Debug` + `PartialEq` + `Eq` + `Clone` + `Copy` keep test
/// assertions ergonomic (the per-variant wire-pin test compares
/// against literal variants via `assert_eq!`), mirroring `InvoiceState`'s
/// derive set.
#[derive(Serialize, Debug, PartialEq, Eq, Clone, Copy)]
#[serde(rename_all = "UPPERCASE")]
enum AckStatus {
    Received,
    Processing,
    Saved,
    Aborted,
}

/// PR-33 / session-37 — parse a persisted `InvoiceAckStatusPayload.ack_status`
/// string to the typed wire enum.
///
/// The stored values SHOULD always be one of the four NAV v3.0
/// strings — `query_transaction_status::ProcessingStatus::from_nav_str`
/// rejects every other value on the inbound parse path, so a stored
/// non-NAV string would indicate DB tampering OR a schema drift.
/// Returns `None` for unrecognised input rather than failing the
/// whole read endpoint; the audit-entries drill-down (PR-27) still
/// surfaces the raw string verbatim via the typed payload JSON, so
/// no information is lost at the operator surface.
///
/// Strict per-variant match (not a `serde_json::from_str` round-trip)
/// keeps the conversion local and avoids an allocation on the hot
/// path of `get_invoice_detail`.
fn parse_ack_status(s: &str) -> Option<AckStatus> {
    match s {
        "RECEIVED" => Some(AckStatus::Received),
        "PROCESSING" => Some(AckStatus::Processing),
        "SAVED" => Some(AckStatus::Saved),
        "ABORTED" => Some(AckStatus::Aborted),
        _ => None,
    }
}

#[derive(Serialize)]
struct AuditEntryView {
    seq: u64,
    kind: String,
    actor: String,
    /// PR-27 / session-31 lifted the "short view" posture: the wire
    /// shape now carries the full typed payload via the `payload`
    /// field below. The `/audit/:invoice_id` endpoint and the
    /// `/invoices/:id` endpoint return the same per-entry shape.
    occurred_at: String,
    /// PR-26 / session-30 — chain-link affordance for the detail
    /// modal. `Some(base_id)` for `InvoiceStornoIssued` /
    /// `InvoiceModificationIssued` entries (the typed payload's
    /// `base_invoice_id` field per ADR-0023 / ADR-0024); `None` for
    /// every other kind. Serialised as `null` for non-chain rows
    /// (matches `total_gross: Option<i64>`'s wire posture above so
    /// the SPA consumes a uniform `string | null`). The SPA's
    /// `InvoiceDetail.svelte` renders the field as a clickable
    /// navigation to the base invoice when present. Pinned by
    /// `audit_view_of_emits_chain_base_invoice_id`.
    chain_base_invoice_id: Option<String>,
    /// PR-27 / session-31 — full typed payload as raw JSON for the
    /// per-row drill-down in `InvoiceDetail.svelte`. The
    /// `audit_payloads::*` types serialise via `serde_json::to_vec`
    /// per F9 (closed in PR-6.1), so `entry.payload` bytes are
    /// always valid JSON; a malformed payload — which would
    /// indicate direct DB tampering — falls back to
    /// `Value::Null` so the SPA's pretty-printer renders `null`
    /// rather than crashing the view. The exposure matches the
    /// `aberp dump-audit-bundle` posture per the PR-27 lean: no
    /// redaction default (F43 bundle-redaction posture stays
    /// named-deferred; the SPA exposure is parity, not regression).
    /// Pinned by `audit_view_of_emits_typed_payload`.
    payload: serde_json::Value,
}

async fn handle_list_invoices(headers: HeaderMap, State(state): State<AppState>) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let result = tokio::task::spawn_blocking(move || list_invoices(&state_for_task)).await;
    match result {
        Ok(Ok(items)) => Json(items).into_response(),
        Ok(Err(e)) => internal_error("list_invoices", e),
        Err(join_err) => internal_error(
            "list_invoices:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

async fn handle_get_invoice(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let invoice_id_for_task = invoice_id.clone();
    let result = tokio::task::spawn_blocking(move || {
        get_invoice_detail(&state_for_task, &invoice_id_for_task)
    })
    .await;
    match result {
        Ok(Ok(Some(detail))) => Json(detail).into_response(),
        Ok(Ok(None)) => (
            StatusCode::NOT_FOUND,
            Json(error_body(format!("no invoice found with id {invoice_id}"))),
        )
            .into_response(),
        Ok(Err(e)) => internal_error("get_invoice_detail", e),
        Err(join_err) => internal_error(
            "get_invoice_detail:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

async fn handle_get_audit(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let invoice_id_for_task = invoice_id.clone();
    let result = tokio::task::spawn_blocking(move || {
        get_audit_for_invoice(&state_for_task, &invoice_id_for_task)
    })
    .await;
    match result {
        Ok(Ok(entries)) if entries.is_empty() => (
            StatusCode::NOT_FOUND,
            Json(error_body(format!(
                "no audit ledger entries for invoice id {invoice_id}"
            ))),
        )
            .into_response(),
        Ok(Ok(entries)) => Json(entries).into_response(),
        Ok(Err(e)) => internal_error("get_audit_for_invoice", e),
        Err(join_err) => internal_error(
            "get_audit_for_invoice:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

/// PR-44ε.UI / session-58 — printed-invoice PDF download route.
///
/// Wraps the `print_invoice::render_to_bytes` orchestrator behind a
/// loopback HTTPS endpoint so the SPA's "Download PDF" button on the
/// invoice-detail modal closes the operator-facing render path
/// end-to-end (no terminal drop). Same on-disk posture as the CLI
/// subcommand (A155): audit-ledger + on-disk NAV XML + per-tenant
/// `seller.toml` are read byte-verbatim; nothing is re-rendered or
/// re-fetched.
///
/// Returns:
///   - 200 + `Content-Type: application/pdf` + `Content-Disposition`
///     attachment + PDF bytes on the happy path.
///   - 404 if no `InvoiceDraftCreated` audit entry matches `id` —
///     mirrors the existing `/invoices/:id` 404 posture.
///   - 500 for every other propagated error (`get_invoice_detail`
///     pattern).
///
/// Seller-info path is resolved by `print_invoice` to
/// `~/.aberp/<tenant>/seller.toml`; no SPA-side override is wired
/// (the CLI's `--seller-toml` exists for fixture overrides; an
/// operator who needs an alternative path can land it via the CLI).
async fn handle_get_invoice_pdf(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let invoice_id_for_task = invoice_id.clone();
    let result = tokio::task::spawn_blocking(move || {
        get_invoice_pdf(&state_for_task, &invoice_id_for_task, None)
    })
    .await;
    match result {
        Ok(Ok(Some(rendered))) => {
            let filename = pdf_filename_for_invoice(&rendered.invoice_number);
            let disposition = format!("attachment; filename=\"{filename}\"");
            (
                [
                    (
                        axum::http::header::CONTENT_TYPE,
                        "application/pdf".to_string(),
                    ),
                    (axum::http::header::CONTENT_DISPOSITION, disposition),
                ],
                rendered.pdf_bytes,
            )
                .into_response()
        }
        Ok(Ok(None)) => (
            StatusCode::NOT_FOUND,
            Json(error_body(format!(
                "no InvoiceDraftCreated audit entry for invoice id {invoice_id}"
            ))),
        )
            .into_response(),
        Ok(Err(e)) => internal_error("get_invoice_pdf", e),
        Err(join_err) => internal_error(
            "get_invoice_pdf:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

/// PR-44ε.UI / session-58 — render the printed-invoice PDF for one
/// invoice id. Returns `None` when no draft entry is found (so the
/// route emits 404 rather than 500); every other failure mode is a
/// loud-fail per CLAUDE.md rule 12.
///
/// `seller_toml_override`: production callers (the route handler)
/// pass `None` so `print_invoice` resolves the default
/// `~/.aberp/<tenant>/seller.toml` path; the integration test in
/// `apps/aberp/tests/serve_pdf_route.rs` passes `Some(path)` to a
/// per-test fixture file so the test doesn't have to rebind the
/// process-wide HOME (which races under cargo's parallel test
/// runner per the Rust 2024 `unsafe set_var` discipline).
///
/// `pub` so the integration test can exercise the route's read path
/// without spinning up an HTTPS listener (same posture as
/// `list_invoices` / `get_invoice_detail` would have if they were
/// directly tested).
pub fn get_invoice_pdf(
    state: &AppState,
    invoice_id: &str,
    seller_toml_override: Option<&Path>,
) -> Result<Option<print_invoice::RenderedInvoice>> {
    match print_invoice::render_to_bytes(
        invoice_id,
        &state.db_path,
        state.tenant.as_str(),
        seller_toml_override,
    ) {
        Ok(rendered) => Ok(Some(rendered)),
        Err(e) => {
            // The "no draft entry" failure is the operator's most likely
            // mistake (wrong id pasted, wrong tenant DB) — discriminate
            // it from every other propagated error so the route emits
            // 404 rather than 500 per the existing `/invoices/:id`
            // shape. The error string is the one
            // `print_invoice::find_invoice_draft` mints.
            let msg = format!("{e:#}");
            if msg.contains("no InvoiceDraftCreated audit entry found for invoice id") {
                Ok(None)
            } else {
                Err(e)
            }
        }
    }
}

/// PR-44ε.UI / session-58 — `Content-Disposition` filename for the
/// PDF download. Mirrors the SPA's `filenameForInvoice` so the
/// browser-saved file matches the operator-facing
/// `invoice_<invoice_number>.pdf` shape regardless of whether the
/// browser honours the Content-Disposition or falls back to the SPA-
/// side download blob naming. Pinned by `pdf_filename_uses_invoice_number`.
fn pdf_filename_for_invoice(invoice_number: &str) -> String {
    format!("invoice_{invoice_number}.pdf")
}

// ── PR-44ζ / session-59 — POST /invoices/issue route ────────────────

/// Request body for `POST /invoices/issue`. Mirrors the CLI's
/// [`InvoiceInputJson`] (parties + lines, flattened in) with the
/// PR-44ζ-added wire fields the CLI's `--currency` / `--series` flags
/// carry. The Tauri SPA's `composeIssueInvoiceBody` (`issue-invoice.ts`)
/// emits exactly this shape; mirror invariant per A156 precedent.
///
/// `series` is optional with a `"INV-default"` fallback so the SPA
/// form does NOT have to expose a series-picker on the first cut —
/// the CLI's default behaviour is preserved.
/// PR-53 / session-73 — supplier removed from the wire shape. The
/// SPA's IssueInvoice form no longer surfaces seller-info inputs;
/// `issue_invoice_request` reads the per-tenant seller.toml server-
/// side and synthesises the `SupplierJson` for `issue_from_parsed`.
/// The setup-wizard chain (PR-46α + PR-51) guarantees the file is
/// present and identity-complete before the backend reaches `Ready`,
/// so a None branch in the synthesiser maps to the typed
/// `missing_seller_config` 400.
#[derive(Debug, Deserialize)]
pub struct IssueInvoiceRequest {
    pub customer: issue_invoice::CustomerJson,
    pub lines: Vec<issue_invoice::LineJson>,
    pub currency: Currency,
    #[serde(default)]
    pub series: Option<String>,
    /// PR-73 / ADR-0040 §addendum — operator-selected bank account
    /// id (the `bnk_<26-char>` deterministic value from
    /// `aberp::seller_banks`). `None` (or absent on the wire) → the
    /// resolver falls back to `default_bank_for(invoice.currency)`;
    /// `Some(id)` → looked up by id with a currency-match check. See
    /// `resolve_bank_snapshot` below for the typed loud-fail surface.
    #[serde(default, rename = "bankAccountId")]
    pub bank_account_id: Option<String>,
    /// PR-82 — buyer-facing per-invoice global note ("Megjegyzés").
    /// Optional; the SPA's IssueInvoice form surfaces a textarea that
    /// emits `null` when blank. Persisted on `invoice.invoice_note`
    /// and stamped on the `InvoiceDraftCreated` audit payload via
    /// `with_notes`. NEVER reaches the NAV InvoiceData XML —
    /// recipient-facing only. See
    /// `adr/0042-invoice-notes-never-in-nav-xml.md`. Per-line notes
    /// ride on `LineJson.note` inside each `lines[i]`.
    #[serde(default, rename = "invoiceNote")]
    pub invoice_note: Option<String>,
    /// PR-84 — operator-supplied payment deadline (Fizetési határidő)
    /// in canonical YYYY-MM-DD form. The SPA's IssueInvoice form
    /// surfaces a bidirectional offset/absolute pair (the offset days
    /// + the resolved absolute date update each other live); the wire
    /// form is the resolved absolute date. Optional on the wire so
    /// pre-PR-84 callers (integration tests pinned at the prior shape)
    /// still type-check; the issuance pipeline defaults to the system
    /// issue date when absent.
    #[serde(default, rename = "paymentDeadline")]
    pub payment_deadline: Option<String>,
    /// PR-84 — operator-supplied delivery / fulfillment date
    /// (Teljesítési dátum) in canonical YYYY-MM-DD form. REGULATORY:
    /// this is what the NAV emit writes as `<invoiceDeliveryDate>`,
    /// which drives the VAT-period assignment for the invoice.
    /// Optional on the wire for the same pre-PR-84 back-compat reason;
    /// the issuance pipeline defaults to the system issue date when
    /// absent.
    #[serde(default, rename = "deliveryDate")]
    pub delivery_date: Option<String>,
    /// PR-84 — audit discriminant the SPA's IssueInvoice form stamps
    /// when the operator picks a delivery date OUTSIDE the comfort
    /// zone [invoice_date, payment_deadline] and confirms via the
    /// inline "Are you sure?" affordance. Closed vocab:
    /// `"BeforeInvoiceDate"`, `"AfterPaymentDeadline"`, or `null`
    /// (in-range default path). Persisted verbatim on the
    /// `InvoiceDraftCreated` audit payload via `with_invoice_dates`
    /// so the tamper-evident regulatory trail records every confirmed
    /// out-of-range override.
    #[serde(default, rename = "deliveryDateOverride")]
    pub delivery_date_override: Option<String>,
    /// PR-92 / ADR-0047 — operator's per-invoice opt-out of the
    /// default-on auto-send-to-buyer. The SPA's IssueInvoice form
    /// renders a checkbox defaulted to `true`; the operator can flip
    /// it OFF before submitting to suppress the auto-send. Optional on
    /// the wire so pre-PR-92 callers (CLI / integration tests) still
    /// type-check; absent → defaults to `true` server-side at the
    /// `emailBuyerOnIssue.unwrap_or(true)` seam in
    /// `handle_issue_invoice`. The wire token is camelCase to match
    /// every other SPA-typed field in this struct.
    #[serde(default, rename = "emailBuyerOnIssue")]
    pub email_buyer_on_issue: Option<bool>,
    /// PR-99 Item 4 Part B — operator's per-invoice opt-out of the
    /// default-on auto-submit-to-NAV-on-issue. Mirrors
    /// `email_buyer_on_issue` exactly: optional on the wire so pre-
    /// PR-99 callers still type-check, absent → defaults to `true`
    /// server-side at the `submit_to_nav_on_issue.unwrap_or(true)`
    /// seam in `handle_issue_invoice`. When `true` the issuance
    /// handler fires the same `submit_invoice_request` +
    /// `poll_ack_request` path the manual button hits — no body
    /// bypass; identical audit-ledger footprint (one
    /// `InvoiceSubmissionAttempt` row, one `InvoiceSubmissionResponse`
    /// row, one or more `InvoiceAckStatus` rows from the poll).
    /// Failures are tolerated (the invoice remains in `Ready` /
    /// `Submitted`) so a transient NAV outage doesn't undo the
    /// issuance commit.
    #[serde(default, rename = "submitToNavOnIssue")]
    pub submit_to_nav_on_issue: Option<bool>,
    /// S160 — operator-selected payment method (Fizetési mód). The SPA's
    /// IssueInvoice form renders a dropdown defaulted to `TRANSFER`
    /// (Átutalás). Wire form is the bare NAV token string (`"TRANSFER"`,
    /// `"CASH"`, …) per `PaymentMethod`'s SCREAMING_SNAKE serde. Optional
    /// on the wire (`#[serde(default)]` → `Transfer`) so pre-S160 callers
    /// / integration tests still type-check; threaded into
    /// `InvoiceInputJson.payment_method` and emitted as `<paymentMethod>`
    /// (ADR-0050).
    #[serde(default, rename = "paymentMethod")]
    pub payment_method: aberp_billing::PaymentMethod,
    /// PR-203 / S203 — operator-typed per-invoice email recipient
    /// override ("Email-címzett(ek)"). Comma-separated address list
    /// (canonical `", "` separator); `None`/absent → the send-path
    /// resolver falls back to the partner master record's
    /// `contact_email` (today's behaviour, pre-PR-203). Validated at
    /// `validate_issue_request` via `partners::parse_and_validate_emails`
    /// so a malformed shape surfaces as 400 BEFORE the issuance
    /// commits; defence in depth at the SMTP send-time guard
    /// (`validate_no_crlf` + per-token shape on the `Mailbox` build).
    ///
    /// Persisted on `invoice.email_recipient_override` (NOT on the
    /// partner record) — editing it here is a one-off per-invoice
    /// override that NEVER writes back to the partner master.
    #[serde(default, rename = "emailRecipientOverride")]
    pub email_recipient_override: Option<String>,
}

/// Response body for `POST /invoices/issue`. The SPA reads
/// `invoice_id` to navigate the detail modal open; `invoice_number` +
/// `state` are surfaced for the success-flash render. Private to this
/// module — the response shape never leaves the axum handler, so
/// keeping the type at the JSON-emit boundary avoids leaking the
/// internal `InvoiceState` enum into the public surface.
#[derive(Debug, Serialize)]
struct IssueInvoiceResponse {
    invoice_id: String,
    invoice_number: String,
    state: InvoiceState,
    /// PR-92 — outcome of the default-on post-issue auto-send.
    /// `Some(_)` when the operator left the toggle on AND the
    /// auto-send was attempted (success or failure both populate);
    /// `None` when the operator turned the toggle off (no send was
    /// attempted). The SPA surfaces this inline on the issue success
    /// flash.
    #[serde(skip_serializing_if = "Option::is_none")]
    email: Option<EmailRouteOutcomeBody>,
}

/// PR-92 — wire shape for the per-invoice email send outcome.
/// Mirrors the [`InvoiceEmailedSentPayload`] shape that lands in the
/// audit ledger (`outcome` + `error_class` + `error_detail`) without
/// the operator-decision idempotency_key (not interesting to the
/// SPA). Returned by both the auto-send-after-issue route and the
/// manual `POST /api/invoices/:id/email` route so the SPA renders
/// the two paths with one component.
#[derive(Debug, Clone, Serialize)]
pub struct EmailRouteOutcomeBody {
    /// `"succeeded"` | `"failed"` — closed vocab; deserialise via the
    /// SPA's string-union mirror.
    pub outcome: String,
    /// Recipient address actually used (or attempted). Operator-visible.
    pub recipient: String,
    /// Closed-vocab error class on failure; `None` on success.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error_class: Option<String>,
    /// Operator-readable detail on failure; `None` on success.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error_detail: Option<String>,
    /// `true` when the auto-send-after-issue path fired; `false` for
    /// the manual send button.
    pub auto: bool,
    /// `true` iff the NAV XML rode alongside the PDF.
    pub attached_xml: bool,
}

/// `400 Bad Request` body emitted for validation failures (empty
/// payload, missing required field, invalid currency string, etc.).
/// Same shape as [`ErrorBody`] above so the SPA's error renderer can
/// consume both 4xx and 5xx surfaces with one parser.
const DEFAULT_SERIES_CODE: &str = "INV-default";

/// PR-50 / session-70 — typed `400 Bad Request` body for the
/// supplier-config validation gate. Sibling of [`ErrorBody`] with an
/// `error_code` discriminant + the operator-actionable hints
/// (`config_path` + `sample_path`) the SPA's inline-error renderer
/// surfaces when the operator's form-typed tax number fails the
/// shape check.
///
/// Wire shape:
///
/// ```json
/// {
///   "error": "missing_seller_config",
///   "message": "supplier tax number `24904362` ... `xxxxxxxx-y-zz`",
///   "config_path": "/Users/aben/.aberp/test/seller.toml",
///   "sample_path": "/path/to/repo/samples/seller.toml.example"
/// }
/// ```
///
/// The discriminant `"missing_seller_config"` anticipates PR-51
/// (the SetupWizard's seller-config persistence) — today the
/// proximate fix is the form field, but the eventual fix is the
/// per-tenant seller.toml, and the SPA renders the
/// `config_path` + `sample_path` hint regardless. Mirrors A157's
/// inline-error posture for the issuance modal.
#[derive(Serialize)]
struct TypedErrorBody {
    error: &'static str,
    message: String,
    config_path: String,
    sample_path: String,
}

/// PR-50 / session-70 — sentinel string for the
/// `missing_seller_config` discriminant. Hard-coded both here and in
/// the SPA's error renderer (`apps/aberp-ui/ui/src/lib/issue-invoice.ts`)
/// — a regression that drifts one without the other surfaces at
/// `issue-invoice.test.ts`'s pin per CLAUDE.md rule 12.
const ERR_MISSING_SELLER_CONFIG: &str = "missing_seller_config";

/// PR-69 / session-91 — typed `400 Bad Request` body for the
/// pre-issuance preflight validator (ADR-0038). Sibling of
/// [`TypedErrorBody`] with an `errors` array instead of a single
/// message — the operator sees every problem at once instead of
/// one-per-resubmit.
///
/// Wire shape:
///
/// ```json
/// {
///   "error": "invoice_preflight_failed",
///   "errors": [
///     {
///       "kind": "CustomerTaxNumberMalformed",
///       "field_path": "customer.taxNumber",
///       "message_hu": "Az ügyfél adószáma (`1234`) hibás formátum …",
///       "message_en": "Customer ADÓSZÁM `1234` is not a valid Hungarian …"
///     }
///   ]
/// }
/// ```
///
/// The SPA's `parseInvoicePreflightErrors` discriminates on the outer
/// `error` field and routes each inner error to the matching input by
/// `field_path`.
#[derive(Serialize)]
struct PreflightErrorBody {
    error: &'static str,
    errors: Vec<PreflightErrorItem>,
}

#[derive(Serialize)]
struct PreflightErrorItem {
    kind: &'static str,
    field_path: String,
    message_hu: String,
    message_en: String,
}

impl PreflightErrorItem {
    fn from_preflight_error(e: &InvoicePreflightError) -> Self {
        PreflightErrorItem {
            kind: e.kind(),
            field_path: e.field_path(),
            message_hu: e.message_hu(),
            message_en: e.message_en(),
        }
    }
}

/// PR-50 / session-70 — build the per-tenant `seller.toml` path the
/// operator should populate when the SetupWizard (PR-51) lands.
/// Today the supplier identity flows via the SPA form; this path is
/// the forward-looking destination the typed error names so
/// operators have one config home to anchor on.
fn seller_toml_path_for_tenant(tenant: &str) -> String {
    let home = std::env::var("HOME").unwrap_or_else(|_| "/Users/operator".to_string());
    format!(
        "{home}/{root}/{tenant}/seller.toml",
        root = crate::build_profile::edition_data_dirname()
    )
}

/// PR-53 / session-73 — read the per-tenant `seller.toml` identity
/// block and synthesise the `SupplierJson` shape the issuance core
/// expects. Used by `issue_invoice_request` + `modification_invoice_request`
/// after PR-53 removed supplier from both wire shapes (cross-cutting
/// fix per Ervin's "obsolete to retype seller on invoice form").
///
/// Returns the typed [`SupplierConfigError`] (matching the existing
/// PR-50 surface) when:
///   - the file is missing or unreadable → `MissingTaxNumber`
///   - the identity block is incomplete → `MissingTaxNumber`
///   - the persisted tax number fails the ADÓSZÁM shape gate →
///     `MalformedTaxNumber`
///
/// The route handler maps the error to the typed
/// `missing_seller_config` 400 body via the existing PR-50
/// `IssueRequestValidationError::SupplierConfig` arm so the SPA's
/// `parseMissingSellerConfigError` renders the config_path +
/// sample_path hints inline.
pub fn supplier_from_seller_toml(
    tenant: &str,
) -> std::result::Result<issue_invoice::SupplierJson, SupplierConfigError> {
    let path = setup_seller_info::seller_toml_path_for_tenant(tenant)
        .map_err(|_| SupplierConfigError::MissingTaxNumber)?;
    // S434 — resolve the tenant's NAV mode so the HU §169 supplier-tax
    // shape check is skipped for a NAV-off (international) tenant. A
    // registry read error falls back to NAV-on (preserves HU validation).
    let nav_enabled = crate::tenant_registry::tenant_nav_enabled(tenant).unwrap_or(true);
    supplier_from_seller_toml_path(&path, nav_enabled)
}

/// PR-53 / session-73 — path-explicit sibling of
/// [`supplier_from_seller_toml`]. Used by the integration tests
/// (which can't safely mutate HOME under cargo's parallel test
/// runner) per the session-58 `get_invoice_pdf(seller_toml_override)`
/// precedent.
///
/// S434 — `nav_enabled` gates the HU supplier-tax validation: a NAV-off
/// tenant's seller tax is opaque (international format / not submitted to
/// NAV), so the `xxxxxxxx-y-zz` shape check is skipped. The identity must
/// still carry a (non-empty) tax_number — the international operator enters
/// their local registration number; it rides into the (never-sent) NAV XML
/// + the PDF verbatim.
pub fn supplier_from_seller_toml_path(
    path: &std::path::Path,
    nav_enabled: bool,
) -> std::result::Result<issue_invoice::SupplierJson, SupplierConfigError> {
    let identity: SellerIdentity = setup_seller_info::read_seller_identity(path)
        .map_err(|_| SupplierConfigError::MissingTaxNumber)?
        .ok_or(SupplierConfigError::MissingTaxNumber)?;
    let supplier_info = SupplierInfo {
        tax_number: identity.tax_number.clone(),
        name: identity.legal_name.clone(),
        address_country_code: identity.address_country_code.clone(),
        address_postal_code: identity.address_postal_code.clone(),
        address_city: identity.address_city.clone(),
        address_street: identity.address_street.clone(),
    };
    // Re-validate the persisted tax-number shape — a hand-edited
    // seller.toml could carry a malformed value the wizard never
    // wrote (the file is operator-editable after the wizard run). S434:
    // only for NAV-on tenants (HU §169); a NAV-off tenant's tax is opaque.
    if nav_enabled {
        nav_xml::validate_supplier_info(&supplier_info)?;
    }
    Ok(issue_invoice::SupplierJson {
        tax_number: identity.tax_number,
        name: identity.legal_name,
        address: issue_invoice::AddressJson {
            country_code: identity.address_country_code,
            postal_code: identity.address_postal_code,
            city: identity.address_city,
            street: identity.address_street,
        },
    })
}

/// PR-50 / session-70 — repo-relative sample-template path the typed
/// error names. Constructed from `CARGO_MANIFEST_DIR` at compile
/// time so the operator-facing hint is correct in dev runs from any
/// working directory; the path is `<workspace_root>/samples/seller.toml.example`.
fn seller_toml_sample_path() -> String {
    // `apps/aberp/Cargo.toml` lives two levels under the workspace
    // root; the sample sits at `<root>/samples/seller.toml.example`.
    // env! is compile-time so this path bakes into the binary; the
    // operator-facing hint stays accurate for the dev tree the
    // binary was built in.
    let manifest = env!("CARGO_MANIFEST_DIR");
    let path = std::path::PathBuf::from(manifest)
        .join("..")
        .join("..")
        .join("samples")
        .join("seller.toml.example");
    // Canonicalize at runtime when possible so the message renders
    // a clean absolute path; fall back to the join'd string on
    // filesystem unavailability (CI, sandboxed runs).
    match std::fs::canonicalize(&path) {
        Ok(p) => p.display().to_string(),
        Err(_) => path.display().to_string(),
    }
}

/// PR-73 / ADR-0040 §addendum — outcome of the bank-account resolver.
/// Either a typed snapshot for the issuance path to thread, or one
/// of three loud-fail classes the route layer maps to its respective
/// HTTP status:
///
/// - [`Self::Preflight`] → 400 with the `invoice_preflight_failed`
///   typed body (`SellerBankMissingForCurrency` /
///   `SellerBankCurrencyMismatch`). Operator-correctable.
/// - [`Self::NotFound`] → 404. The selected `bank_account_id` does
///   not exist in the current `seller.toml`. Defence in depth — the
///   SPA's dropdown is populated from the same endpoint
///   (`GET /api/seller/banks`) so this surface should not fire under
///   correct SPA operation; a stale operator click or a curl bypass
///   surfaces here.
/// - [`Self::Other`] → 500 (delegated to `internal_error`). I/O,
///   parser, or unexpected error reading `seller.toml`.
enum BankResolveOutcome {
    Snapshot(aberp_billing::BankAccountSnapshot),
    Preflight(InvoicePreflightError),
    NotFound,
    Other(anyhow::Error),
}

/// PR-73 / ADR-0040 §addendum — resolve the operator's bank-account
/// selection (or the per-currency default) into a typed
/// [`aberp_billing::BankAccountSnapshot`] suitable for stamping onto
/// the issued invoice row.
///
/// Resolution rules (per the session-95 brief):
///
/// 1. `bank_account_id == None` (or empty) → look up
///    `default_bank_for(currency)`. Missing →
///    `SellerBankMissingForCurrency` preflight.
/// 2. `bank_account_id == Some(id)` → look up by id.
///    - Missing → `NotFound` (404).
///    - Currency mismatch → `SellerBankCurrencyMismatch` preflight.
///    - Match → `Snapshot(BankAccountSnapshot { ... })`.
///
/// Reads `seller.toml` via [`seller_banks::read_seller_banks`]; any
/// I/O / parse failure becomes `Other(anyhow::Error)` so the route
/// layer surfaces it as 500.
fn resolve_bank_snapshot(tenant: &str, request: &IssueInvoiceRequest) -> BankResolveOutcome {
    let path = match setup_seller_info::seller_toml_path_for_tenant(tenant) {
        Ok(p) => p,
        Err(e) => return BankResolveOutcome::Other(e),
    };
    let banks = match seller_banks::read_seller_banks(&path) {
        Ok(b) => b,
        Err(SellerBanksError::Io(e)) => {
            return BankResolveOutcome::Other(anyhow!("read seller.toml: {e}"))
        }
        Err(e) => return BankResolveOutcome::Other(anyhow!("{e}")),
    };

    let entry = match request.bank_account_id.as_deref().map(str::trim) {
        None | Some("") => match banks.default_bank_for(request.currency) {
            Some(e) => e,
            None => {
                return BankResolveOutcome::Preflight(
                    InvoicePreflightError::SellerBankMissingForCurrency {
                        currency: request.currency,
                    },
                )
            }
        },
        Some(id) => match banks.bank_by_id(id) {
            None => return BankResolveOutcome::NotFound,
            Some(e) if e.currency != request.currency => {
                return BankResolveOutcome::Preflight(
                    InvoicePreflightError::SellerBankCurrencyMismatch {
                        selected_id: e.id.clone(),
                        selected_currency: e.currency,
                        invoice_currency: request.currency,
                    },
                )
            }
            Some(e) => e,
        },
    };

    BankResolveOutcome::Snapshot(bank_snapshot_from_entry(entry))
}

/// PR-73 / ADR-0040 §addendum — convert a `SellerBankEntry` (the
/// in-memory read-side type from `seller_banks.rs`) into the typed
/// `BankAccountSnapshot` (the billing-crate denormalized stamp).
/// Mirror of `SellerBankResponse` from PR-72 with the snapshot fields
/// — same name set, narrower domain.
fn bank_snapshot_from_entry(entry: &SellerBankEntry) -> aberp_billing::BankAccountSnapshot {
    aberp_billing::BankAccountSnapshot {
        id: entry.id.clone(),
        currency: entry.currency.iso_code().to_string(),
        account_number: entry.account_number.clone(),
        bank_name: entry.bank_name.clone(),
        swift_bic: entry.swift_bic.clone(),
    }
}

/// PR-44ζ / session-59 — `POST /invoices/issue` route handler. The
/// SPA's "New Invoice" form posts here; the handler:
///
///   1. Checks the bearer token (same posture as every other
///      authenticated route).
///   2. Validates the request body shape (4xx on validation failure
///      vs 5xx on propagated issuance errors).
///   3. Mints a server-side `nav_xml_path` under
///      `~/.aberp/serve/<tenant>/issued/<ulid>.xml` — the CLI threads
///      an operator-supplied `--out`; the route is operator-pathless
///      so the SPA never has to surface a path picker.
///   4. Builds the `Actor` from the startup-loaded operator login.
///   5. Dispatches into `issue_invoice::issue_from_parsed` via the
///      `issue_invoice_request` library helper (which the integration
///      test hits directly with a fake `MnbRatesProvider`).
///
/// Failure modes:
///   - `400 Bad Request` on validation failure (empty lines, etc.).
///   - `500 Internal Server Error` on any other propagated error
///     (MNB fetch, DB write, XSD validate, NAV XML write).
async fn handle_issue_invoice(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<IssueInvoiceRequest>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(login) => login,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    // S261 / PR-250 — refuse to issue while a restore from NAV is in
    // progress (or a crashed restore lock is still held). Per
    // [[trust-code-not-operator]] the code blocks the parallel write
    // rather than relying on the disabled SPA button alone.
    if let Some(resp) = restore_lock_block(&state).await {
        return resp;
    }
    // PR-69 / session-91 — pre-issuance preflight validator (ADR-0038)
    // runs FIRST so operator-correctable per-invoice errors (empty
    // customer name, malformed ADÓSZÁM, off-vocab VAT rate, …)
    // surface as a typed 400 the SPA renders inline per field, BEFORE
    // the legacy string-shape gate / the seller.toml read / the
    // issuance pipeline. Nothing downstream runs if preflight rejects;
    // no DB write, no audit entry, no NAV XML render.
    let preflight = validate_invoice_preflight(&request);
    if !preflight.is_empty() {
        let body = PreflightErrorBody {
            error: ERR_INVOICE_PREFLIGHT_FAILED,
            errors: preflight
                .iter()
                .map(PreflightErrorItem::from_preflight_error)
                .collect(),
        };
        return (StatusCode::BAD_REQUEST, Json(body)).into_response();
    }
    // Pre-issuance validation. Loud-fail per CLAUDE.md rule 12 with a
    // 400 + a typed error body so the SPA's inline-error surface can
    // distinguish operator-correctable input from server-side faults.
    //
    // PR-69 retains this defence-in-depth surface (ADR-0038
    // §"Adversarial review" #3) — the preflight strictly covers it,
    // but a future drift on the preflight surface would still fail
    // loud here rather than reaching the issuance pipeline.
    match validate_issue_request(&request) {
        Ok(()) => {}
        Err(IssueRequestValidationError::Plain(msg)) => {
            return (StatusCode::BAD_REQUEST, Json(error_body(msg))).into_response();
        }
    }

    // PR-53 / session-73 — supplier read from seller.toml server-side
    // instead of from the wire body. Any missing-file / malformed
    // identity surfaces via the same typed 400 body the operator-
    // typed shape gate emits, so the SPA's inline-error renderer
    // shows the existing `config_path` + `sample_path` hints.
    let supplier = match supplier_from_seller_toml(state.tenant.as_str()) {
        Ok(s) => s,
        Err(supplier_err) => {
            let body = TypedErrorBody {
                error: ERR_MISSING_SELLER_CONFIG,
                message: supplier_err.to_string(),
                config_path: seller_toml_path_for_tenant(state.tenant.as_str()),
                sample_path: seller_toml_sample_path(),
            };
            return (StatusCode::BAD_REQUEST, Json(body)).into_response();
        }
    };

    // PR-73 / ADR-0040 §addendum — resolve the operator's bank-account
    // selection (or the per-currency default) BEFORE the issuance
    // pipeline. Three loud-fail surfaces:
    //   - Preflight (typed 400 `invoice_preflight_failed`): the same
    //     wire body PR-69 emits for the per-field preflight errors,
    //     so the SPA's inline-error renderer surfaces the bank-picker
    //     dropdown errors at the same `bankAccountId` field path.
    //   - NotFound (404): the operator passed an id that does not
    //     exist in the current `seller.toml`. Defence in depth — the
    //     SPA's dropdown is populated from `GET /api/seller/banks`,
    //     so this surface fires only on stale clicks or curl bypass.
    //   - Other (500): I/O or parse error reading `seller.toml`.
    let bank_snapshot = match resolve_bank_snapshot(state.tenant.as_str(), &request) {
        BankResolveOutcome::Snapshot(s) => s,
        BankResolveOutcome::Preflight(err) => {
            let body = PreflightErrorBody {
                error: ERR_INVOICE_PREFLIGHT_FAILED,
                errors: vec![PreflightErrorItem::from_preflight_error(&err)],
            };
            return (StatusCode::BAD_REQUEST, Json(body)).into_response();
        }
        BankResolveOutcome::NotFound => {
            return (
                StatusCode::NOT_FOUND,
                Json(error_body(format!(
                    "bank_account_id `{}` not found in seller.toml",
                    request.bank_account_id.as_deref().unwrap_or("(none)")
                ))),
            )
                .into_response();
        }
        BankResolveOutcome::Other(e) => return internal_error("resolve_bank_snapshot", e),
    };

    let provider = match build_live_provider_for_currency(request.currency) {
        Ok(p) => p,
        Err(e) => return internal_error("build_live_provider", e),
    };

    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);

    // PR-92 — capture the operator's email-buyer toggle BEFORE the
    // request moves into `issue_invoice_request`. Defaults to `true`
    // (default-on) per ADR-0047 §2 — silence-by-omission is the wrong
    // default for a buyer-comms product.
    let email_buyer_flag = request.email_buyer_on_issue.unwrap_or(true);
    // PR-99 Item 4 Part B — same posture for auto-submit-to-NAV.
    // Default-on so the dominant path (issue + submit + see SAVED
    // inside the same minute) doesn't require a second operator click.
    let submit_to_nav_flag = request.submit_to_nav_on_issue.unwrap_or(true);
    // Snapshot the customer's identity for the post-issue email lookup —
    // `request` is consumed by `issue_invoice_request`. S164 — the
    // partner_id is the durable lookup key (PrivatePerson buyers carry
    // no tax_number, so the tax-number-only lookup never found them).
    let customer_partner_id_for_email = request.customer.partner_id.clone();
    let customer_tax_number_for_email = request.customer.tax_number.clone();

    match issue_invoice_request(
        &state,
        request,
        supplier,
        provider.as_ref(),
        actor,
        Some(bank_snapshot),
    )
    .await
    {
        Ok(summary) => {
            // ADR-0095 §3 — a regulated write just committed durably; nudge the
            // debounced post-write durable checkpoint (off the request path).
            crate::live_checkpoint::trigger();
            // [[post-issue-async]] (session 158) — the post-issue tail
            // (default-on auto-send-to-buyer email + default-on
            // auto-submit-to-NAV + bounded poll) used to run HERE,
            // synchronously, BEFORE this response returned. The bounded
            // poll alone can take up to 31s (ADR-0009 §5) and the SMTP
            // send adds seconds on top, so the SPA's `await issueInvoice`
            // — and therefore the operator's Issue-invoice form — sat
            // frozen for the entire tail. Ervin's session-158 ask:
            // navigate to the invoice's detail view IMMEDIATELY on issue
            // and watch the NAV pictogram + email status progress LIVE.
            // That requires the response to return as soon as the
            // issuance is durable, so the slow externals move to a
            // detached background task on the same tokio runtime axum
            // already owns (it lives for the desktop app's whole
            // lifetime — the task always outlives the request).
            //
            // The task writes exactly the same audit-ledger entries it
            // always did — `auto_send_after_issue` → InvoiceEmailedSent;
            // `submit_invoice_request` → InvoiceSubmission*;
            // `poll_ack_request` → InvoiceAckStatus — only from the
            // background task rather than inline. The SPA's InvoiceDetail
            // view live-polls `getInvoice` (PR-95 pictogram + PR-99 email
            // status both already derive reactively from the audit
            // entries) and surfaces each transition as it lands. The tail
            // stays best-effort and fire-and-forget: a NAV/SMTP failure
            // is logged + recorded on the audit ledger (same toleration
            // posture as before) and leaves the pictogram actionable for
            // a manual retry from the detail surface. The email outcome
            // is no longer known at response time, so the response's
            // `email` field is `None` — the SPA never read it on this
            // path (it derives email status from the live-polled audit
            // entries), so dropping it is observationally inert.
            let task_invoice_id = summary.invoice_id.clone();
            let task_invoice_number = summary.invoice_number.clone();
            let task_state = state.clone();
            let task_login = operator_login.clone();
            let task_customer_partner_id = customer_partner_id_for_email;
            let task_customer_tax = customer_tax_number_for_email;
            tokio::spawn(async move {
                if email_buyer_flag {
                    // Audit-ledger entry is written inside regardless of
                    // outcome; the returned body is unused now that the
                    // response no longer carries it.
                    let _ = auto_send_after_issue(
                        &task_state,
                        &task_invoice_id,
                        &task_invoice_number,
                        task_customer_partner_id.as_deref(),
                        &task_customer_tax,
                        &task_login,
                    )
                    .await;
                }
                if submit_to_nav_flag {
                    match submit_invoice_request(&task_state, &task_invoice_id).await {
                        Ok(_) => {
                            // Session-161 — hand off to the indefinite
                            // two-phase poll daemon instead of the bounded
                            // ~31s `poll_ack_request`. The daemon runs to
                            // terminal (or process shutdown); if NAV takes
                            // minutes-to-hours the pictogram still flips on
                            // its own with no operator click. Spawned as its
                            // own task so this post-issue tail returns once
                            // submit lands rather than living for the
                            // daemon's whole lifetime.
                            match build_poll_daemon_inputs(&task_state, &task_invoice_id).await {
                                Ok(inputs) => {
                                    let sem = task_state.nav_poll_semaphore.clone();
                                    let cancel = task_state.shutdown_token.clone();
                                    tokio::spawn(async move {
                                        if let Err(e) =
                                            poll_ack::run_nav_poll_daemon(inputs, sem, cancel).await
                                        {
                                            tracing::warn!(
                                                error = ?e,
                                                "post-issue NAV poll daemon failed"
                                            );
                                        }
                                    });
                                }
                                Err(e) => tracing::warn!(
                                    invoice_id = %task_invoice_id,
                                    error = ?e,
                                    "post-issue could not build poll daemon inputs; \
                                     pictogram stays actionable for a manual poll"
                                ),
                            }
                        }
                        Err(e) => {
                            tracing::warn!(
                                invoice_id = %task_invoice_id,
                                error = ?e,
                                "post-issue auto-submit failed; invoice remains Ready, \
                                 operator can submit manually from InvoiceDetail"
                            );
                        }
                    }
                }
            });
            Json(IssueInvoiceResponse {
                invoice_id: summary.invoice_id,
                invoice_number: summary.invoice_number,
                state: InvoiceState::Ready,
                email: None,
            })
            .into_response()
        }
        Err(e) => internal_error("issue_invoice_request", e),
    }
}

/// S184 — post-issue tail for STORNO and MODIFICATION chains. Mirrors
/// the [[post-issue-async]] block in `handle_issue_invoice` (PR-99 /
/// session-158) verbatim, with two chain-specific seams:
///
/// 1. The buyer identity is resolved from the BASE invoice's side-
///    stored `input.json` (via `resolve_customer_identity` on
///    `base_invoice_id`) — chain children inherit the buyer from the
///    base by definition (ADR-0024 §6, ADR-0023 §4 chain inheritance).
///    The storno / modification's own ULID has no `.input.json` side-
///    store written, so a direct lookup keyed on the chain child's id
///    would fail; the chain link's `base_invoice_id` is the recovery
///    bridge.
/// 2. The auto-submit + poll daemon target the CHAIN CHILD's invoice
///    id (the storno / modification has its own NAV XML on disk via
///    `InvoiceDraftCreated.nav_xml_path`, its own pending sequence
///    backlog row, and submits as a fresh `manageInvoice` operation
///    per ADR-0023 §3 / ADR-0024 §3).
///
/// Pre-S184 both routes returned the response immediately and the
/// operator had to click Submit + Email manually. The Issue path had
/// the auto-tail since PR-99; this closes the chain-paths' gap.
///
/// Best-effort fire-and-forget: NAV / SMTP failures are logged and
/// recorded on the audit ledger; the pictogram stays actionable for a
/// manual retry from the InvoiceDetail surface (PR-95).
async fn run_chain_post_issue_tail(
    state: &AppState,
    chain_invoice_id: &str,
    chain_invoice_number: &str,
    base_invoice_id: &str,
    operator_login: &str,
    email_buyer_flag: bool,
    submit_to_nav_flag: bool,
) {
    if email_buyer_flag {
        // Resolve buyer identity from the BASE's side-stored input.json
        // (the only place that holds the operator-typed
        // partner_id+tax_number pair durably for SPA-issued invoices).
        // Failure is loud-logged but non-fatal — the auto-send writes
        // an `InvoiceEmailedSent` entry for the MissingRecipient case
        // so the email-status pictogram surfaces actionable error
        // state on the storno detail view (per S163).
        match resolve_customer_identity(state, base_invoice_id) {
            Ok((partner_id, tax_number)) => {
                let _ = auto_send_after_issue(
                    state,
                    chain_invoice_id,
                    chain_invoice_number,
                    partner_id.as_deref(),
                    &tax_number,
                    operator_login,
                )
                .await;
            }
            Err(e) => {
                tracing::warn!(
                    chain_invoice_id = %chain_invoice_id,
                    base_invoice_id = %base_invoice_id,
                    error = ?e,
                    "post-issue chain auto-email could not resolve buyer identity \
                     from base's input.json; operator can retry via the manual \
                     Email button on the chain child's detail view"
                );
            }
        }
    }
    if submit_to_nav_flag {
        match submit_invoice_request(state, chain_invoice_id).await {
            Ok(_) => match build_poll_daemon_inputs(state, chain_invoice_id).await {
                Ok(inputs) => {
                    let sem = state.nav_poll_semaphore.clone();
                    let cancel = state.shutdown_token.clone();
                    tokio::spawn(async move {
                        if let Err(e) = poll_ack::run_nav_poll_daemon(inputs, sem, cancel).await {
                            tracing::warn!(
                                error = ?e,
                                "post-issue chain NAV poll daemon failed"
                            );
                        }
                    });
                }
                Err(e) => tracing::warn!(
                    chain_invoice_id = %chain_invoice_id,
                    error = ?e,
                    "post-issue chain could not build poll daemon inputs; \
                     pictogram stays actionable for a manual poll"
                ),
            },
            Err(e) => {
                tracing::warn!(
                    chain_invoice_id = %chain_invoice_id,
                    error = ?e,
                    "post-issue chain auto-submit failed; chain child remains in Ready / \
                     pre-Submitted state — operator can retry via the manual Submit button"
                );
            }
        }
    }
}

/// PR-92 — render the email send for the post-issue auto-send path.
/// Always writes an audit-ledger `InvoiceEmailedSent` entry (success
/// OR failure) so the operator-twin record never has gaps. Returns
/// an [`EmailRouteOutcomeBody`] body the SPA can surface inline on
/// the success flash.
async fn auto_send_after_issue(
    state: &AppState,
    invoice_id: &str,
    invoice_number: &str,
    customer_partner_id: Option<&str>,
    customer_tax_number: &str,
    operator_login: &str,
) -> EmailRouteOutcomeBody {
    send_invoice_email_route(
        state,
        invoice_id,
        invoice_number,
        customer_partner_id,
        customer_tax_number,
        operator_login,
        SendTrigger::AutoOnIssue,
    )
    .await
}

/// PR-44ζ / session-59 — input validation that maps to `400 Bad
/// Request` rather than `500`. Mirrors the CLI's first-pass shape
/// checks at the route layer so the SPA renders an operator-actionable
/// inline error instead of an opaque "internal error" string.
///
/// Per CLAUDE.md rule 9: per-rule coverage — each branch pins a
/// distinct field-level rule so a regression that drops one check
/// surfaces at the route_validation_rejects_* test rather than at a
/// silent 500.
///
/// PR-50 / session-70 — return type widened to distinguish the
/// supplier-config shape failure (which maps to the typed
/// `missing_seller_config` 400 body the SPA renders with
/// `config_path` + `sample_path` hints) from the generic string-
/// shape failures (empty fields, missing tax number entirely).
fn validate_issue_request(
    request: &IssueInvoiceRequest,
) -> std::result::Result<(), IssueRequestValidationError> {
    if request.lines.is_empty() {
        return Err(IssueRequestValidationError::Plain(
            "at least one line item is required".to_string(),
        ));
    }
    if request.customer.name.trim().is_empty() {
        return Err(IssueRequestValidationError::Plain(
            "customer name is required".to_string(),
        ));
    }
    // Session-148 — the customer tax-number requirement is NOT
    // unconditional: PRIVATE_PERSON buyers legitimately carry no
    // ADÓSZÁM (and OTHER is v1-deferred). The vat-status-aware
    // `validate_invoice_preflight` (which runs FIRST, above) owns the
    // per-status tax-number rule — Domestic requires a well-formed
    // number, PrivatePerson requires its absence. This stale gate
    // (pre-PR-97, when every buyer was Domestic) blocked all
    // PrivatePerson issuance; the check is dropped here so the canonical
    // preflight is the single source of truth for the tax-number rule.
    // PR-53 / session-73 — supplier validation moved off the wire
    // shape. The synthesiser inside `issue_invoice_request` reads
    // seller.toml and dispatches the same typed
    // `missing_seller_config` 400 if the file is missing OR the tax
    // number's shape fails.
    // PR-203 / S203 — per-invoice email recipient override. When the
    // operator supplied a value, parse + validate every comma-segment
    // (reuses `partners::parse_and_validate_emails`: same RFC-5322 shape
    // gate and the same comma/semicolon/whitespace tolerance as
    // `partners.contact_email`). Reject as 400 with the offender named
    // so the SPA's inline-error renderer can highlight the input;
    // pre-PR-203 callers / CLI omit the field → no validation runs.
    if let Some(raw) = request.email_recipient_override.as_deref() {
        if !raw.trim().is_empty() {
            if let Err(msg) = partners::parse_and_validate_emails(raw) {
                return Err(IssueRequestValidationError::Plain(format!(
                    "email recipient override is malformed: {msg}"
                )));
            }
        }
    }
    Ok(())
}

/// PR-203 / S203 — public closed-vocab mirror of
/// [`IssueRequestValidationError`] for integration tests. The internal
/// enum stays private (the route layer is the only production consumer);
/// this mirror lets the `tests/email_recipient_override.rs` pin check
/// the validator's classification without exposing the enum's body.
#[derive(Debug)]
pub enum IssueRequestValidationOutcome {
    /// The request passed every gate; the issuance pipeline can proceed.
    Ok,
    /// A plain string-shape rule rejected the request. Carries the
    /// operator-readable message the route layer renders inline.
    Plain(String),
}

/// PR-203 / S203 — test-only re-entry into [`validate_issue_request`].
/// `pub` so the integration test in `tests/email_recipient_override.rs`
/// can exercise the validator directly. The function body delegates
/// verbatim — keeps the test surface and production surface byte-for-
/// byte identical (a future contributor who edits the validator sees
/// the test fail on the same line).
pub fn validate_issue_request_for_test(
    request: &IssueInvoiceRequest,
) -> IssueRequestValidationOutcome {
    match validate_issue_request(request) {
        Ok(()) => IssueRequestValidationOutcome::Ok,
        Err(IssueRequestValidationError::Plain(msg)) => IssueRequestValidationOutcome::Plain(msg),
    }
}

/// PR-50 / session-70 — typed validation error for the issue route.
///
/// PR-53 / session-73 — narrowed to one variant after supplier moved
/// off the wire shape. The supplier-config gate now fires inside
/// [`supplier_from_seller_toml`] in the handler and surfaces the
/// typed `missing_seller_config` 400 body directly, so the
/// validation surface here is just the plain string-shape failures
/// (empty lines / customer name / tax number).
enum IssueRequestValidationError {
    Plain(String),
}

/// PR-44ζ / session-59 — build the production `MnbRatesProvider` for
/// the request's currency. The HUF branch returns the `NeverProvider`
/// sentinel (any consult is a bug — the HUF issuance branch is
/// rate-free per ADR-0037 §1); the EUR branch builds a
/// `LiveMnbRatesProvider`.
///
/// Returns `Box<dyn MnbRatesProvider>` so the call site can pass it to
/// `issue_from_parsed`'s generic-over-`P` surface without duplicating
/// the issuance-path code for the two currency branches.
///
/// PR-60 / session-80 — `LiveMnbRatesProvider::new` no longer builds a
/// per-instance tokio runtime; the issuance pipeline is now async-
/// native and `.await`s the underlying `MnbClient::fetch_official_rate`
/// directly on the runtime owned by axum's request executor.
fn build_live_provider_for_currency(currency: Currency) -> Result<Box<dyn MnbRatesProvider>> {
    match currency {
        Currency::Huf => Ok(Box::new(NeverProvider)),
        _ => Ok(Box::new(LiveMnbRatesProvider::new().context(
            "build MNB rates provider for non-HUF issuance via serve route",
        )?)),
    }
}

/// Stand-in `MnbRatesProvider` for the HUF route path — never expected
/// to be consulted (the HUF branch of `issue_from_parsed` does not
/// reach for the rate). Mirrors the same sentinel in
/// `issue_invoice::NeverProvider` (private there) so a wrongful EUR
/// regression on the HUF branch panics rather than silently returns a
/// placeholder rate.
struct NeverProvider;

#[async_trait]
impl MnbRatesProvider for NeverProvider {
    async fn fetch_official_rate(
        &self,
        _currency: Currency,
        _date: time::Date,
    ) -> std::result::Result<aberp_mnb_rates::MnbRate, aberp_mnb_rates::MnbError> {
        unreachable!(
            "serve.rs::NeverProvider must not be consulted — \
             the HUF issuance path is rate-free per ADR-0037 §1"
        )
    }
}

/// PR-44ζ / session-59 — library helper that wires
/// `issue_invoice::issue_from_parsed` over the [`AppState`]'s
/// db_path + tenant + operator login. `pub` so the integration test
/// (`tests/serve_issue_route.rs`) can hit it with a fake
/// `MnbRatesProvider` and a fixture `Actor` without spinning the
/// HTTPS listener (same posture as `get_invoice_pdf` per A158).
pub async fn issue_invoice_request<P: MnbRatesProvider + ?Sized>(
    state: &AppState,
    request: IssueInvoiceRequest,
    supplier: issue_invoice::SupplierJson,
    provider: &P,
    actor: Actor,
    // PR-73 / ADR-0040 §addendum — typed bank-account snapshot
    // already resolved by the route handler via
    // `resolve_bank_snapshot` (or `None` from the integration test
    // path / future library callers that do not exercise the bank
    // picker). Threaded down into `issue_from_parsed` so the five
    // `bank_account_*` invoice columns are populated at INSERT time.
    bank_snapshot: Option<aberp_billing::BankAccountSnapshot>,
) -> Result<issue_invoice::IssuedInvoiceSummary> {
    let xml_path = mint_issued_xml_path(state.tenant.as_str())
        .context("mint server-side NAV-XML output path for issuance")?;
    let input = InvoiceInputJson {
        supplier,
        customer: request.customer,
        lines: request.lines,
        // PR-82 — thread the operator-typed global note ("Megjegyzés")
        // straight from the SPA wire body into the issuance pipeline.
        // Stored on `invoice.invoice_note`, stamped on the audit payload,
        // rendered on the printed PDF — NEVER reaches the NAV XML.
        invoice_note: request.invoice_note,
        // PR-84 — three invoice-date fields thread the operator's SPA
        // form choices straight to the issuance pipeline. `payment_deadline`
        // + `delivery_date` are canonical YYYY-MM-DD strings parsed by
        // `issue_from_parsed`; `delivery_date_override` is the comfort-zone
        // audit discriminant stamped onto the `InvoiceDraftCreated`
        // payload verbatim.
        payment_deadline: request.payment_deadline,
        delivery_date: request.delivery_date,
        delivery_date_override: request.delivery_date_override,
        // S160 — operator's payment-method dropdown choice (Fizetési mód),
        // defaulting to `Transfer` when the wire body omits it.
        payment_method: request.payment_method,
        // PR-203 / S203 — operator-typed per-invoice email recipient
        // override. Normalised here (trim → empty-as-None) so the
        // downstream resolver doesn't have to filter blanks. The wire
        // shape already passed `validate_issue_request`'s parse gate,
        // so a `Some(_)` survives as a validated comma-separated list.
        email_recipient_override: request.email_recipient_override.and_then(|s| {
            let t = s.trim();
            if t.is_empty() {
                None
            } else {
                Some(t.to_string())
            }
        }),
    };
    // PR-47α / session-64 — side-store the InvoiceInputJson alongside
    // the NAV-XML output path so the SPA storno route can reconstruct
    // the storno's own body content (lines + parties) without parsing
    // the rendered NAV XML back out (the renderer's flat-string
    // supplierTaxNumber emit and the nested-taxpayerId customer emit
    // diverge, so an XML-back parser would be the wrong abstraction).
    // The sibling-path convention matches `sibling_input_json_path`
    // both at write (here) and at read (the storno route).
    //
    // Write the input.json BEFORE `issue_from_parsed` so a failed write
    // aborts the issuance entirely — better than half-issued state
    // where the NAV XML lands on disk but the storno path can't find
    // its companion (CLAUDE.md rule 12, fail loud).
    let input_json_path = sibling_input_json_path(&xml_path);
    let input_json_bytes = serde_json::to_vec(&input)
        .context("serialize side-stored InvoiceInputJson (PR-47α / A174)")?;
    std::fs::write(&input_json_path, &input_json_bytes).with_context(|| {
        format!(
            "side-store InvoiceInputJson at {} (PR-47α)",
            input_json_path.display()
        )
    })?;
    let series = request.series.as_deref().unwrap_or(DEFAULT_SERIES_CODE);
    // S392 — dev/test NAV invoice-number pre-flight (None on production
    // builds). The probe owns freshly-loaded NAV credentials; on prod or a
    // keychain miss we proceed without it (the pre-flight is a convenience,
    // never a gate on issuance). This is the SPA path the operator hit the
    // INVOICE_NUMBER_NOT_UNIQUE collision on.
    let nav_probe: Option<Box<dyn crate::nav_number_probe::NavInvoiceNumberProbe>> =
        if crate::build_profile::IS_PRODUCTION_BUILD {
            None
        } else {
            match NavCredentials::load_from_keychain(state.tenant.as_str()) {
                Ok(creds) => {
                    crate::nav_number_probe::build_issue_probe(creds, &input.supplier.tax_number)
                }
                Err(e) => {
                    tracing::warn!(
                        err = %e,
                        "S392 NAV number pre-flight skipped (no NAV credentials); \
                         issuance proceeds without it"
                    );
                    None
                }
            }
        };
    issue_invoice::issue_from_parsed(
        input,
        &state.db,
        state.tenant.as_str(),
        series,
        request.currency,
        xml_path,
        actor,
        provider,
        nav_probe.as_deref(),
        // PR-73 / ADR-0040 §addendum — the route handler resolved the
        // operator's `bank_account_id` (or per-currency default) via
        // `resolve_bank_snapshot` BEFORE invoking this helper and
        // passed the typed snapshot here. Persisted by `allocate_in_tx`
        // to the five `bank_account_*` invoice columns; surfaced on
        // the list + detail wire shape via `load_invoice_bank_snapshot_in_tx`.
        bank_snapshot,
    )
    .await
}

/// PR-47α / session-64 — given an issued NAV-XML path, return the
/// sibling `<ULID>.input.json` path the SPA-issue route side-stores
/// the operator's `InvoiceInputJson` to. The storno route reads back
/// from the same sibling computation so a renamed/moved XML carries
/// its companion in lockstep.
///
/// Replaces the trailing `.xml` extension with `.input.json`. If the
/// path has no `.xml` extension (impossible via `mint_issued_xml_path`
/// but documented for the test path), falls back to appending the
/// suffix — the result is still deterministic + recoverable.
pub fn sibling_input_json_path(xml_path: &std::path::Path) -> std::path::PathBuf {
    if xml_path
        .extension()
        .and_then(|e| e.to_str())
        .map(|s| s.eq_ignore_ascii_case("xml"))
        .unwrap_or(false)
    {
        xml_path.with_extension("input.json")
    } else {
        let mut s = xml_path.as_os_str().to_owned();
        s.push(".input.json");
        std::path::PathBuf::from(s)
    }
}

/// PR-44ζ / session-59 — mint a per-issuance NAV-XML on-disk path
/// under `~/.aberp/serve/<tenant>/issued/<ULID>.xml`. The CLI's
/// `aberp issue-invoice --out <PATH>` lets the operator pick the
/// filename; the SPA route is operator-pathless so the server picks a
/// deterministic ULID-keyed slug. The path is recorded on the
/// `InvoiceDraftCreated` payload (per ADR-0031 §2) so downstream
/// readers (drain worker, print-invoice) find it regardless of the
/// filename shape.
///
/// Same `~/.aberp/serve/<tenant>/` parent dir as the cert + session
/// token persistence per A158 — "operator-invisible artifacts live
/// next to the keychain material" posture from PR-9-1.
fn mint_issued_xml_path(tenant: &str) -> Result<std::path::PathBuf> {
    let dir = serve_artifacts_dir(tenant)?.join("issued");
    std::fs::create_dir_all(&dir)
        .with_context(|| format!("create issued-XML directory at {}", dir.display()))?;
    Ok(dir.join(format!("{}.xml", Ulid::new())))
}

// ── PR-44η / session-60 — POST /invoices/:id/submit + /poll-ack ──────

/// PR-44η / session-60 — wire response body for
/// `POST /invoices/:id/submit`. Surfaces the NAV-assigned
/// `transaction_id` so the SPA's detail-modal renderer can display
/// it immediately AND the new typestate label so the SPA's state
/// chip flips without an extra `getInvoice` roundtrip.
#[derive(Debug, Serialize)]
struct SubmitInvoiceResponse {
    invoice_id: String,
    transaction_id: String,
    state: InvoiceState,
    entries_verified: u64,
}

/// PR-44η / session-60 — wire response body for
/// `POST /invoices/:id/poll-ack`. Carries the terminal classification
/// (`Finalized` / `Rejected` / `Submitted` with stuck variants) the
/// poll loop reached + the attempt count that actually fired so the
/// SPA can render the operator-visible "loop completed after N
/// attempts" line without re-parsing audit entries.
#[derive(Debug, Serialize)]
struct PollAckResponse {
    invoice_id: String,
    state: InvoiceState,
    attempts_made: u32,
    transaction_id: String,
    /// On terminal `Rejected` / stuck-loop terminuses the SPA renders
    /// the diagnostic inline; `None` on the clean `Finalized` arm.
    diagnostic: Option<String>,
    entries_verified: u64,
}

/// PR-44η / session-60 — `POST /invoices/:id/submit` handler.
///
/// 1. Bearer-auth check.
/// 2. Precondition: derive the invoice's state from the audit-ledger
///    trace; loud-fail 409 if not `Ready`. Issued-but-already-
///    submitted invoices, terminal invoices, and unknown ids all
///    bounce here.
/// 3. Resolve the NAV-body on-disk path from the most-recent
///    `InvoiceDraftCreated` audit entry per ADR-0031 §2.
/// 4. Read the on-disk XML; extract the supplier 8-digit tax number
///    from the body (same source the CLI parses from `--tax-number`,
///    but server-derived so the SPA does not need to surface it).
/// 5. Load NAV credentials fresh per request (mirrors the CLI's
///    `submit-invoice` posture; the startup-cached `operator_login`
///    on `AppState` is non-secret and not sufficient for signing).
/// 6. Mint the per-request `Actor` from the startup-loaded
///    `operator_login` (A159 boilerplate).
/// 7. Dispatch into `submit_invoice::submit_from_inputs` (the
///    library helper extracted at this PR).
///
/// Failure modes:
///   - `401 Unauthorized` — bearer missing or wrong.
///   - `409 Conflict` — invoice is not in `Ready` state (loud-fail
///     per CLAUDE.md rule 12; the SPA renders the typed error body
///     inline).
///   - `500 Internal Server Error` — any propagated error (NAV
///     transport, audit-write, DB error, etc.). The TX2
///     AttemptFailed audit is committed BEFORE the 500 is surfaced
///     per ADR-0032 §1 so the invoice's state transitions to
///     `Pending` even on wire failure.
async fn handle_submit_invoice(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match submit_invoice_request(&state, &invoice_id).await {
        Ok(outcome) => Json(SubmitInvoiceResponse {
            invoice_id: outcome.invoice_id,
            transaction_id: outcome.transaction_id,
            // S434 — NAV-off issuance lands LocalOnly; the normal NAV wire
            // path lands Submitted.
            state: if outcome.local_only {
                InvoiceState::LocalOnly
            } else {
                InvoiceState::Submitted
            },
            entries_verified: outcome.entries_verified,
        })
        .into_response(),
        Err(SubmitRouteError::PreconditionMismatch {
            current_state,
            message,
        }) => (
            StatusCode::CONFLICT,
            Json(error_body(format!(
                "{message} (current state: {current_state})"
            ))),
        )
            .into_response(),
        Err(SubmitRouteError::NotFound(message)) => {
            (StatusCode::NOT_FOUND, Json(error_body(message))).into_response()
        }
        Err(SubmitRouteError::NavUpstreamFault {
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        }) => nav_upstream_fault_response(
            "submit_invoice_request",
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        ),
        Err(SubmitRouteError::Other(e)) => internal_error("submit_invoice_request", e),
    }
}

/// PR-44η / session-60 — `POST /invoices/:id/poll-ack` handler.
///
/// 1. Bearer-auth check.
/// 2. Precondition: derive the invoice's state; loud-fail 409 if
///    not `Submitted` or `PendingNavExists`. Only those two states
///    are poll-meaningful — Pending without NAV-side evidence has
///    no transactionId to poll yet (operator should `submit`
///    first); terminal states are done.
/// 3. Load NAV credentials fresh per request.
/// 4. Mint per-request `Actor`.
/// 5. Dispatch into `poll_ack::poll_ack_from_inputs`.
async fn handle_poll_ack(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match poll_ack_request(&state, &invoice_id).await {
        Ok(outcome) => Json(PollAckResponse {
            invoice_id: outcome.invoice_id,
            state: poll_terminal_to_state(&outcome.terminal),
            attempts_made: outcome.attempts_made,
            transaction_id: outcome.transaction_id,
            diagnostic: poll_terminal_diagnostic(&outcome.terminal),
            entries_verified: outcome.entries_verified,
        })
        .into_response(),
        Err(SubmitRouteError::PreconditionMismatch {
            current_state,
            message,
        }) => (
            StatusCode::CONFLICT,
            Json(error_body(format!(
                "{message} (current state: {current_state})"
            ))),
        )
            .into_response(),
        Err(SubmitRouteError::NotFound(message)) => {
            (StatusCode::NOT_FOUND, Json(error_body(message))).into_response()
        }
        // PR-58 / session-78 — poll_ack does not currently produce a
        // NavUpstreamFault (it runs after tokenExchange already
        // succeeded for the prior submit), but the variant is on the
        // shared SubmitRouteError surface; route it through the same
        // typed 502 helper for symmetry.
        Err(SubmitRouteError::NavUpstreamFault {
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        }) => nav_upstream_fault_response(
            "poll_ack_request",
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        ),
        Err(SubmitRouteError::Other(e)) => internal_error("poll_ack_request", e),
    }
}

/// PR-44η / session-60 — typed error returned by the two mutation
/// helpers below. `PreconditionMismatch` maps to 409; `NotFound`
/// maps to 404; `Other` maps to 500 via the existing
/// [`internal_error`] helper.
///
/// PR-58 / session-78 — `NavUpstreamFault` carries NAV's HTTP-layer
/// rejection of `tokenExchange` and maps to 502 with a typed JSON
/// body so the SPA can render the parsed `fault_code` +
/// `fault_message` instead of a generic "internal error". Operator-
/// actionable diagnostics (IP whitelist, expired technical-user
/// password, signature drift) flow through this surface verbatim.
#[derive(Debug)]
pub enum SubmitRouteError {
    PreconditionMismatch {
        /// PascalCase wire form of the current `InvoiceState` (the
        /// label the SPA reads). Kept as `String` rather than the
        /// typed enum so this error type stays composable across the
        /// pub crate surface without lifting `InvoiceState` itself
        /// to `pub` (it remains an implementation detail of the
        /// wire shape).
        current_state: String,
        message: String,
    },
    NotFound(String),
    NavUpstreamFault {
        status: u16,
        fault_code: Option<String>,
        fault_message: Option<String>,
        technical_validations: Vec<TechnicalValidation>,
        body_preview: String,
    },
    Other(anyhow::Error),
}

impl From<anyhow::Error> for SubmitRouteError {
    fn from(e: anyhow::Error) -> Self {
        SubmitRouteError::Other(e)
    }
}

/// S378 / F44 — pre-flight dedupe verdict for an operator-triggered
/// NAV submission. `None` means "state is `Ready`, proceed with the
/// manageInvoice send". `Some(message)` is the operator-facing body
/// for a `409 Conflict`: the invoice is not in a state where a fresh
/// `manageInvoice` may be sent, so we refuse in code rather than let
/// NAV reject it.
///
/// # Why this gate exists
///
/// NAV keys its invoice store on `InvoiceData/invoiceNumber` and
/// rejects any second submission of a number it has already seen with
/// `INVOICE_NUMBER_NOT_UNIQUE` ("A megadott számla sorszámmal már
/// történt adatszolgáltatás"). Every submission also counts toward the
/// taxpayer's ÁFA reporting, so a duplicate is not a harmless retry.
/// The safety property therefore lives in code — we refuse a re-send
/// whenever the audit ledger already records a submission for this
/// invoice (per the no-smoke-test-in-prod / trust-code-not-operator
/// posture), instead of trusting the operator to notice.
///
/// # invoice_number vs invoice_id
///
/// We key on the ABERP `invoice_id` (the ULID), not the NAV
/// `invoiceNumber` string. For ABERP-issued ("Own") invoices the two
/// are 1:1: the number is `series + sequence_number`, allocated
/// exactly once at issuance behind a gap-free, `UNIQUE`-keyed
/// allocator, and never re-bound to a different id. So "any prior
/// submission for this invoice_number" ≡ "any prior submission for
/// this invoice_id". Keying on the id is correct and avoids parsing
/// `invoiceNumber` out of the opaque `request_xml` bytes the audit
/// payloads carry (the number is not a queryable field).
fn submission_dedupe_message(state: InvoiceState, transaction_id: Option<&str>) -> Option<String> {
    let txn = match transaction_id {
        Some(t) if !t.is_empty() => format!(", NAV transactionId={t}"),
        _ => String::new(),
    };
    match state {
        // The only state from which a fresh submission is allowed.
        InvoiceState::Ready => None,
        // State-2: Attempt committed, no Response yet. NAV may or may
        // not already hold the submission (the wire leg is exactly the
        // ambiguous window F44 describes); either way a blind re-send
        // risks INVOICE_NUMBER_NOT_UNIQUE. Refuse and point at recovery.
        InvoiceState::Pending => Some(format!(
            "submission already in progress for this invoice{txn}; refusing a \
             duplicate manageInvoice send. Poll the acknowledgement (poll-ack) \
             or refresh from NAV to learn the current status."
        )),
        InvoiceState::PendingNavExists => Some(format!(
            "NAV already holds a submission for this invoice{txn}; refusing a \
             duplicate manageInvoice send. Poll-ack to fetch the \
             acknowledgement status."
        )),
        // State-3: Response on the ledger — NAV has definitely seen it.
        InvoiceState::Submitted | InvoiceState::Recovered => Some(format!(
            "invoice already submitted to NAV{txn}; refusing a duplicate \
             manageInvoice send. Poll-ack to fetch the acknowledgement status."
        )),
        // Terminal-by-NAV.
        InvoiceState::Finalized => Some(format!(
            "invoice already accepted by NAV (SAVED){txn}; no further \
             submission is possible."
        )),
        InvoiceState::Rejected => Some(format!(
            "invoice was already submitted and rejected by NAV (ABORTED){txn}; \
             NAV will not accept a re-submission of this invoiceNumber — issue \
             a fresh invoice with a new number."
        )),
        // Structurally not submittable — keep the pre-S378 precondition
        // framing (stale UI / wrong affordance) rather than a dedupe story.
        InvoiceState::Unknown
        | InvoiceState::Draft
        | InvoiceState::Storno
        | InvoiceState::Amended
        | InvoiceState::Abandoned
        // S434 — LocalOnly is terminal from ABERP's side (NAV-off). It
        // never reaches this dedupe gate on a NAV-on tenant; the arm
        // exists for exhaustiveness + the NAV-off idempotency short-circuit
        // in `submit_invoice_request` handles the real path.
        | InvoiceState::LocalOnly => Some(format!(
            "POST /invoices/.../submit requires state `Ready`; current state is \
             `{state:?}`. Re-fetch the invoice detail and retry."
        )),
    }
}

/// S378 / F44 — process-wide, per-invoice submission gate.
///
/// Returns the async `Mutex` that serialises every
/// [`submit_invoice_request`] for a given `(tenant, invoice_id)`. The
/// caller holds it across the read-state → TX1-Attempt-commit → wire-
/// send window so two concurrent submissions of the same invoice can
/// no longer both observe `Ready` and both POST to NAV — the second
/// waiter re-derives state *after* the first's Attempt commit, sees
/// `Pending`/`Submitted`, and is refused by [`submission_dedupe_message`].
///
/// This closes the F44 double-submit (the invoice-0047 incident): the
/// race is real because `submit_invoice_request` runs both from the
/// auto-submit-on-issue background task and from the manual
/// `POST /invoices/:id/submit` route, which can fire concurrently on a
/// still-`Ready` invoice.
///
/// In-process only. Cross-process double-submit (two `aberp serve`
/// instances on one tenant) is NOT covered here — that needs the
/// flock/pidfile single-instance guard tracked separately (S386 per
/// `docs/findings/s382-concurrency-db-lock-hardening.md`). The map
/// retains one small entry per invoice ever submitted in this process;
/// for the deployment's invoice volumes (and upgrade-time restarts)
/// that is negligible and not pruned.
fn submission_gate(tenant: &str, invoice_id: &str) -> Arc<tokio::sync::Mutex<()>> {
    static GATES: std::sync::OnceLock<
        std::sync::Mutex<std::collections::HashMap<(String, String), Arc<tokio::sync::Mutex<()>>>>,
    > = std::sync::OnceLock::new();
    let registry = GATES.get_or_init(|| std::sync::Mutex::new(std::collections::HashMap::new()));
    // Tuple key — no string concat, so no tenant / invoice_id pair can
    // ever alias another regardless of the bytes either contains.
    let key = (tenant.to_string(), invoice_id.to_string());
    let mut guard = registry
        .lock()
        .expect("submission-gate registry mutex poisoned");
    guard
        .entry(key)
        .or_insert_with(|| Arc::new(tokio::sync::Mutex::new(())))
        .clone()
}

/// S434 — append one `InvoiceLocalOnlyEmitted` row into the tenant's
/// ledger, marking an invoice issued under a NAV-disabled tenant as
/// stored local-only. Mirrors the `tenant_registry::emit_tenant_event`
/// open-by-path + append discipline. The cross-invoice contamination
/// guard lives in `InvoiceTrace::merge_entry` (it matches the payload's
/// `invoice_id`).
fn emit_invoice_local_only(
    state: &AppState,
    invoice_id: &str,
    operator_login: &str,
) -> std::result::Result<(), SubmitRouteError> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash for local-only emit")?;
    let mut ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger to record InvoiceLocalOnlyEmitted")?;
    let payload = audit_payloads::InvoiceLocalOnlyEmittedPayload {
        invoice_id: invoice_id.to_string(),
        operator_login: operator_login.to_string(),
    };
    let actor = Actor::from_local_cli(Ulid::new().to_string(), operator_login);
    ledger
        .append(
            EventKind::InvoiceLocalOnlyEmitted,
            payload.to_bytes(),
            actor,
            None,
        )
        .context("append InvoiceLocalOnlyEmitted audit entry")?;
    tracing::info!(
        invoice_id = %invoice_id,
        tenant = %state.tenant.as_str(),
        "invoice marked LOCAL ONLY (NAV synchron disabled for this tenant)"
    );
    Ok(())
}

/// PR-44η / session-60 — library helper that wires
/// `submit_invoice::submit_from_inputs` over the [`AppState`]'s
/// db_path + tenant + operator login. `pub` so the integration test
/// can hit it for precondition pin tests without spinning the HTTPS
/// listener (same posture as `get_invoice_pdf` per A158 and
/// `issue_invoice_request` per A159).
pub async fn submit_invoice_request(
    state: &AppState,
    invoice_id: &str,
) -> std::result::Result<submit_invoice::SubmitInvoiceOutcome, SubmitRouteError> {
    // PR-46α / session-62 — pull operator_login from the Ready
    // boot-state. The route-level `require_ready` guard runs first,
    // so this read should always succeed; the NeedsSetup arm here is
    // defence in depth (e.g., the integration test driving this
    // helper without spinning the listener still has to construct a
    // Ready AppState).
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSetup => {
                return Err(SubmitRouteError::Other(anyhow!(
                    "submit_invoice_request called in NeedsSetup state — \
                     /api/setup-nav-credentials must run first"
                )));
            }
            ServeBootState::NeedsSellerConfig { .. } => {
                return Err(SubmitRouteError::Other(anyhow!(
                    "submit_invoice_request called in NeedsSellerConfig state — \
                     /api/setup-seller-info must run first"
                )));
            }
        },
        Err(e) => {
            return Err(SubmitRouteError::Other(anyhow!(
                "boot_state RwLock poisoned: {e}"
            )));
        }
    };

    // S378 / F44 — acquire the per-invoice submission gate BEFORE
    // deriving state and hold it across the wire send. This serialises
    // concurrent submissions of the same invoice (auto-submit-on-issue
    // background task vs. a manual Submit click) so the second waiter
    // re-derives state after the first's TX1 Attempt commit and is
    // refused below instead of POSTing a duplicate manageInvoice that
    // NAV rejects INVOICE_NUMBER_NOT_UNIQUE (the invoice-0047 incident).
    let gate = submission_gate(state.tenant.as_str(), invoice_id);
    let _gate = gate.lock().await;

    // 1. Precondition + dedupe gate — derive current state from the
    //    audit trace. Only `Ready` proceeds; every other state is a
    //    409 Conflict naming the existing status (and NAV transactionId
    //    when known) per `submission_dedupe_message`.
    let derived = derive_state_for(state, invoice_id)?;

    // S434 — NAV-off chokepoint. A NAV-disabled tenant never POSTs to
    // NAV: instead the invoice is recorded LOCAL ONLY (one
    // `InvoiceLocalOnlyEmitted` ledger row → `derive_state` returns
    // `LocalOnly`). Idempotent: a re-submit of an already-LocalOnly
    // invoice short-circuits without a second row. The PDF + audit trail
    // are produced by the normal issuance path; only the NAV wire send is
    // skipped. ([[trust-code-not-operator]] — read at the chokepoint.)
    if !state.nav_enabled {
        if derived.state == InvoiceState::LocalOnly {
            return Ok(submit_invoice::SubmitInvoiceOutcome {
                invoice_id: invoice_id.to_string(),
                sequence_number: 0,
                transaction_id: String::new(),
                entries_verified: 0,
                local_only: true,
            });
        }
        if derived.state != InvoiceState::Ready {
            return Err(SubmitRouteError::PreconditionMismatch {
                current_state: format!("{:?}", derived.state),
                message: format!(
                    "invoice {invoice_id} cannot be marked local-only from state {:?}",
                    derived.state
                ),
            });
        }
        emit_invoice_local_only(state, invoice_id, &operator_login)?;
        return Ok(submit_invoice::SubmitInvoiceOutcome {
            invoice_id: invoice_id.to_string(),
            sequence_number: 0,
            transaction_id: String::new(),
            entries_verified: 0,
            local_only: true,
        });
    }

    if let Some(message) =
        submission_dedupe_message(derived.state, derived.transaction_id.as_deref())
    {
        return Err(SubmitRouteError::PreconditionMismatch {
            current_state: format!("{:?}", derived.state),
            message,
        });
    }

    // 2. Resolve nav_xml_path from the most-recent
    //    InvoiceDraftCreated entry per ADR-0031 §2.
    let nav_xml_path = derived.nav_xml_path.ok_or_else(|| {
        SubmitRouteError::Other(anyhow!(
            "invoice {invoice_id} is Ready but no `nav_xml_path` recorded on the \
                 InvoiceDraftCreated audit entry — pre-PR-18 entry; \
                 fall back to `aberp submit-invoice --invoice-xml <path>`"
        ))
    })?;

    // 3. Read the on-disk XML.
    let invoice_xml = std::fs::read(&nav_xml_path).with_context(|| {
        format!(
            "read NAV InvoiceData XML from {} (server-resolved from audit ledger)",
            nav_xml_path.display()
        )
    })?;
    if invoice_xml.is_empty() {
        return Err(SubmitRouteError::Other(anyhow!(
            "NAV InvoiceData XML at {} is empty",
            nav_xml_path.display()
        )));
    }

    // 4. Extract the supplier 8-digit tax number from the XML body.
    let tax_number_8 = parse_supplier_tax_number_from_xml(&invoice_xml)?;

    // 5. Load NAV credentials fresh per request (per A159 — secrets
    //    are not stashed on AppState; only the non-secret
    //    `operator_login` is).
    let credentials =
        NavCredentials::load_from_keychain(state.tenant.as_str()).with_context(|| {
            format!(
                "load NAV credentials from OS keychain for tenant `{}` \
                 (run `aberp setup-nav-credentials` if missing)",
                state.tenant.as_str()
            )
        })?;

    // 6. Mint per-request Actor from startup-loaded operator login.
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);

    // 7. Dispatch into the library helper. S165 — the endpoint is now
    //    the compile-time build-profile choice (prod build → real NAV,
    //    dev/test build → NAV test). The defence-in-depth gate refuses a
    //    prod endpoint from a dev binary no matter what.
    let endpoint = build_profile::nav_endpoint();
    build_profile::assert_endpoint_allowed(endpoint).map_err(SubmitRouteError::Other)?;
    submit_invoice::submit_from_inputs(submit_invoice::SubmitFromInputs {
        db: &state.db,
        tenant_str: state.tenant.as_str(),
        invoice_id_str: invoice_id,
        invoice_xml_origin: nav_xml_path.display().to_string(),
        invoice_xml,
        tax_number_raw: &tax_number_8,
        nav_endpoint: endpoint,
        endpoint_audit_label: build_profile::nav_endpoint_audit_label(),
        credentials: &credentials,
        actor,
    })
    .await
    .map_err(|e| match e {
        submit_invoice::SubmitFromInputsError::WireFailed { error_message, .. } => {
            SubmitRouteError::Other(anyhow!("manageInvoice wire send failed: {error_message}"))
        }
        // PR-58 / session-78 — propagate the typed NAV-upstream fault
        // verbatim through the route surface so the SPA receives the
        // parsed fault_code / fault_message instead of a generic
        // "internal error" body.
        submit_invoice::SubmitFromInputsError::NavUpstreamFault {
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        } => SubmitRouteError::NavUpstreamFault {
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        },
        // S390/E — another PROCESS (a CLI drain / retry / second app
        // instance) holds the cross-process submission lock for this
        // invoice. Mirror the in-process dedupe gate's 409 verdict: the
        // submission is in progress elsewhere, so refuse rather than
        // double-POST. (The in-process gate, S378, handles same-process
        // races; this is its cross-process twin.)
        submit_invoice::SubmitFromInputsError::SubmissionInProgress { invoice_id } => {
            SubmitRouteError::PreconditionMismatch {
                current_state: "SubmissionInProgress".to_string(),
                message: format!(
                    "a NAV submission for {invoice_id} is already in progress in another \
                     process; not double-submitting"
                ),
            }
        }
        submit_invoice::SubmitFromInputsError::Other(inner) => SubmitRouteError::Other(inner),
    })
}

/// PR-44η / session-60 — library helper that wires
/// `poll_ack::poll_ack_from_inputs` over the [`AppState`]'s db_path
/// + tenant + operator login. `pub` so the integration test can hit
/// it for precondition pin tests without spinning the HTTPS
/// listener.
pub async fn poll_ack_request(
    state: &AppState,
    invoice_id: &str,
) -> std::result::Result<poll_ack::PollAckOutcome, SubmitRouteError> {
    // PR-46α / session-62 — operator login read from Ready boot-state
    // (same posture as `submit_invoice_request`). Loud-fail in
    // NeedsSetup as defence in depth past the route-level gate.
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSetup => {
                return Err(SubmitRouteError::Other(anyhow!(
                    "poll_ack_request called in NeedsSetup state — \
                     /api/setup-nav-credentials must run first"
                )));
            }
            ServeBootState::NeedsSellerConfig { .. } => {
                return Err(SubmitRouteError::Other(anyhow!(
                    "poll_ack_request called in NeedsSellerConfig state — \
                     /api/setup-seller-info must run first"
                )));
            }
        },
        Err(e) => {
            return Err(SubmitRouteError::Other(anyhow!(
                "boot_state RwLock poisoned: {e}"
            )));
        }
    };

    // 1. Precondition check.
    let derived = derive_state_for(state, invoice_id)?;
    let poll_eligible = matches!(
        derived.state,
        InvoiceState::Submitted | InvoiceState::PendingNavExists
    );
    if !poll_eligible {
        return Err(SubmitRouteError::PreconditionMismatch {
            current_state: format!("{:?}", derived.state),
            message: format!(
                "POST /invoices/{invoice_id}/poll-ack requires state \
                 `Submitted` or `PendingNavExists`; re-fetch detail and retry"
            ),
        });
    }

    // 2. Resolve supplier tax number from the on-disk XML.
    let nav_xml_path = derived.nav_xml_path.ok_or_else(|| {
        SubmitRouteError::Other(anyhow!(
            "invoice {invoice_id} has no `nav_xml_path` on the audit ledger; \
             fall back to `aberp poll-ack --tax-number <n>`"
        ))
    })?;
    let invoice_xml = std::fs::read(&nav_xml_path).with_context(|| {
        format!(
            "read NAV InvoiceData XML from {} (server-resolved from audit ledger)",
            nav_xml_path.display()
        )
    })?;
    let tax_number_8 = parse_supplier_tax_number_from_xml(&invoice_xml)?;

    // 3. Load NAV credentials fresh per request.
    let credentials =
        NavCredentials::load_from_keychain(state.tenant.as_str()).with_context(|| {
            format!(
                "load NAV credentials from OS keychain for tenant `{}`",
                state.tenant.as_str()
            )
        })?;

    // 4. Mint per-request Actor.
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);

    // 5. Dispatch into the library helper. S165 — endpoint is the
    //    compile-time build-profile choice; the gate refuses a prod
    //    endpoint from a dev binary.
    let endpoint = build_profile::nav_endpoint();
    build_profile::assert_endpoint_allowed(endpoint).map_err(SubmitRouteError::Other)?;
    poll_ack::poll_ack_from_inputs(
        &state.db,
        state.tenant.as_str(),
        invoice_id,
        &tax_number_8,
        endpoint,
        &credentials,
        actor,
    )
    .await
    .map_err(SubmitRouteError::Other)
}

// ── PR-47α / session-64 — POST /api/invoices/:id/storno ──────────────

/// PR-83 — wire request body for `POST /api/invoices/:id/storno`. The
/// pre-PR-83 route accepted no body (the storno's content is
/// reconstructed server-side from the base's side-stored
/// `<ULID>.input.json`). PR-83 adds the optional buyer-facing
/// "Sztornó indoka / Storno reason" — a free-text note the operator
/// types in the SPA's inline storno confirm panel so the buyer sees
/// WHY the invoice was cancelled on the printed PDF / email body.
///
/// Recipient-facing only. NEVER carried into the NAV InvoiceData XML
/// wire body — the storno emitter (`render_storno_data`) does not read
/// this field and the never-leak pin extends to storno-emit cases.
/// See `adr/0042-invoice-notes-never-in-nav-xml.md`.
///
/// Optional on the wire — pre-PR-83 SPA / curl callers that do not
/// send a body OR send `{}` continue to work (the field defaults to
/// `None`).
#[derive(Debug, Default, Deserialize)]
pub struct StornoInvoiceRequest {
    #[serde(default, rename = "stornoReason")]
    pub storno_reason: Option<String>,
    /// S184 — operator's per-storno opt-out of the default-on auto-
    /// email-buyer tail. Mirrors `IssueInvoiceRequest::email_buyer_on_issue`
    /// shape + posture: optional on the wire so pre-S184 SPA / curl
    /// callers still type-check; absent → defaults to `true` server-
    /// side at the `email_buyer_on_storno.unwrap_or(true)` seam in
    /// `handle_storno_invoice`. Default-on per the same posture as the
    /// issue path — storno IS the legal-correction mechanism and the
    /// buyer should receive the corrected paper trail without a second
    /// operator click.
    #[serde(default, rename = "emailBuyerOnStorno")]
    pub email_buyer_on_storno: Option<bool>,
    /// S184 — operator's per-storno opt-out of the default-on auto-
    /// submit-to-NAV tail. Mirrors `IssueInvoiceRequest::submit_to_nav_on_issue`
    /// shape + posture. Default-on so the dominant operator flow
    /// (storno → submit → SAVED inside the same minute) matches the
    /// issue path's UX without a second click. Failures are tolerated
    /// (the storno stays in `Ready`) so a transient NAV outage doesn't
    /// undo the storno commit.
    #[serde(default, rename = "submitToNavOnStorno")]
    pub submit_to_nav_on_storno: Option<bool>,
}

/// PR-47α / session-64 — wire response body for
/// `POST /api/invoices/:id/storno`. Mirrors the submit / poll-ack
/// response shape — the SPA reads `invoice_id` + `invoice_number` for
/// the new storno (NOT the base, which the operator already has open
/// in the detail modal) so it can render the new chain-child row
/// inline; `state` is always `Storno` on the BASE invoice after this
/// route succeeds (the base flips from `Finalized` → `Storno` via
/// `derive_state`'s `is_storno_base` arm), so the SPA can flip the
/// chip without a separate `getInvoice` roundtrip; `entries_verified`
/// is the post-commit `Ledger::verify_chain` count, surfaced for
/// parity with the existing mutation routes.
#[derive(Debug, Serialize)]
struct StornoInvoiceResponse {
    invoice_id: String,
    invoice_number: String,
    /// The base invoice's NEW state after this route succeeds. Always
    /// `Storno` per ADR-0036 §3 — the `is_storno_base` arm of
    /// `derive_state`'s priority ladder fires once an
    /// `InvoiceStornoIssued` audit row exists for the base.
    state: InvoiceState,
    modification_index: u32,
    entries_verified: u64,
}

/// PR-47α / session-64 — `POST /api/invoices/:id/storno` handler.
///
/// Operator-pathless mutation route that wraps the existing
/// `issue_storno::storno_from_inputs` library helper. The SPA renders
/// a "Cancel invoice (storno)" button on the invoice-detail modal
/// when the base is in `Finalized` state; this route is the end-to-
/// end backend leg.
///
/// 1. Bearer-auth check (post-Ready); 503 in NeedsSetup.
/// 2. Precondition: derive base's state; loud-fail 409 unless
///    `Finalized` (the only state where a fresh storno is legal per
///    ADR-0023 §1 and `check_base_is_finalized`'s named-reason
///    classifier).
/// 3. Resolve the base's `nav_xml_path` from its most-recent
///    `InvoiceDraftCreated` audit entry (per ADR-0031 §2). Loud-fail
///    if absent — surfaces the pre-PR-18 invoice case.
/// 4. Read the sibling `<ULID>.input.json` written by
///    `issue_invoice_request` at issuance time (PR-47α / A174). Loud-
///    fail if absent — surfaces the pre-PR-47α SPA-issued invoice OR
///    a CLI-issued invoice case, with a message steering the operator
///    to the CLI's `aberp issue-storno` fallback. NAV creds are NOT
///    loaded here (storno does not call NAV per ADR-0023 §1, so the
///    submit/poll-route fresh-creds posture is unnecessary).
/// 5. Mint a fresh server-side output path for the storno's NAV XML.
/// 6. Mint per-request `Actor` from startup-cached `operator_login`.
/// 7. Dispatch into `issue_storno::storno_from_inputs`.
///
/// Failure modes:
///   - `401 Unauthorized` — bearer missing or wrong.
///   - `503 Service Unavailable` — NeedsSetup boot state.
///   - `404 Not Found` — unknown invoice id.
///   - `409 Conflict` — base not in `Finalized`. Operator-actionable
///     message names the current state.
///   - `500 Internal Server Error` — any propagated error (audit-write,
///     DB error, missing sibling input.json, etc.).
async fn handle_storno_invoice(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
    // PR-83 — `Option<Json<...>>` so a pre-PR-83 caller that POSTs no
    // body OR an empty body still works. Axum's `Option<Json<T>>`
    // extractor returns `None` when the request has no body OR the
    // Content-Type header is missing; the unit-default of
    // `StornoInvoiceRequest` (all-`None`) covers both shapes.
    body: Option<Json<StornoInvoiceRequest>>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(login) => login,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let request = body.map(|Json(r)| r).unwrap_or_default();
    // S184 — capture the operator's auto-pipeline flags BEFORE the
    // request moves into `storno_invoice_request`. Same default-on
    // posture as the issue path (PR-92 / PR-99 Item 4 Part B): absent →
    // `true`. The SPA's storno confirm panel pre-S184 does not surface
    // a checkbox, so every storno today triggers the full tail; the
    // wire field is forward-compat so a future SPA can flip it OFF.
    let email_buyer_flag = request.email_buyer_on_storno.unwrap_or(true);
    let submit_to_nav_flag = request.submit_to_nav_on_storno.unwrap_or(true);
    // S184 — capture the BASE invoice id (this storno's parent) before
    // the route helper consumes the path. The post-issue email lookup
    // resolves the buyer identity from the BASE's side-stored
    // input.json (storno inherits buyer from base by definition; the
    // storno's own ULID has no input.json — only the base does — and
    // the chain link `InvoiceStornoIssued.base_invoice_id` is the
    // operator-visible bridge to recover identity).
    let base_invoice_id_for_tail = invoice_id.clone();
    match storno_invoice_request(&state, &invoice_id, request) {
        Ok(summary) => {
            // ADR-0095 §3 — debounced post-write durable checkpoint nudge.
            crate::live_checkpoint::trigger();
            // S184 — post-issue tail mirrors `handle_issue_invoice`'s
            // [[post-issue-async]] pattern: a detached `tokio::spawn`
            // runs the default-on auto-email + auto-submit-to-NAV +
            // bounded poll AFTER the route response returns. The SPA's
            // InvoiceDetail view live-polls `getInvoice` so each
            // transition (NAV pictogram, email status) lands on screen
            // as the audit ledger records it. Best-effort fire-and-
            // forget: a NAV/SMTP failure is logged and recorded on the
            // audit ledger; the pictogram stays actionable for a manual
            // retry from the detail surface. Pre-S184 (PR-47α through
            // S183) the operator had to click Submit AND Email manually
            // after every storno — the parallel to the issue path was
            // never wired; this closes the gap.
            let task_storno_invoice_id = summary.invoice_id.clone();
            let task_storno_invoice_number = summary.invoice_number.clone();
            let task_state = state.clone();
            let task_login = operator_login.clone();
            let task_base_invoice_id = base_invoice_id_for_tail;
            tokio::spawn(async move {
                run_chain_post_issue_tail(
                    &task_state,
                    &task_storno_invoice_id,
                    &task_storno_invoice_number,
                    &task_base_invoice_id,
                    &task_login,
                    email_buyer_flag,
                    submit_to_nav_flag,
                )
                .await;
            });
            Json(StornoInvoiceResponse {
                invoice_id: summary.invoice_id,
                invoice_number: summary.invoice_number,
                state: InvoiceState::Storno,
                modification_index: summary.modification_index,
                entries_verified: summary.entries_verified,
            })
            .into_response()
        }
        Err(SubmitRouteError::PreconditionMismatch {
            current_state,
            message,
        }) => (
            StatusCode::CONFLICT,
            Json(error_body(format!(
                "{message} (current state: {current_state})"
            ))),
        )
            .into_response(),
        Err(SubmitRouteError::NotFound(message)) => {
            (StatusCode::NOT_FOUND, Json(error_body(message))).into_response()
        }
        // PR-58 / session-78 — storno_invoice_request does not call NAV
        // tokenExchange (it issues a storno locally and lets the
        // operator drive the subsequent submit), so this variant is
        // unreachable here. Wired through symmetrically so a future
        // refactor that lifts NAV-tokenExchange into storno issuance
        // does not silently degrade to "internal error". CLAUDE.md
        // rule 12.
        Err(SubmitRouteError::NavUpstreamFault {
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        }) => nav_upstream_fault_response(
            "storno_invoice_request",
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        ),
        Err(SubmitRouteError::Other(e)) => internal_error("storno_invoice_request", e),
    }
}

/// PR-47α / session-64 — library helper that wires
/// `issue_storno::storno_from_inputs` over the [`AppState`]'s
/// db_path + tenant + operator login. `pub` so the integration test
/// (`tests/serve_storno_route.rs`) can hit it for precondition pin
/// tests without spinning the HTTPS listener (same posture as
/// `submit_invoice_request` per A159).
pub fn storno_invoice_request(
    state: &AppState,
    invoice_id: &str,
    // PR-83 — typed request body carrying the buyer-facing storno
    // reason. `Default::default()` (all-`None`) covers the no-body /
    // pre-PR-83 wire case so existing tests and CLI fallbacks continue
    // to work without churn.
    request: StornoInvoiceRequest,
) -> std::result::Result<issue_storno::StornoIssuedSummary, SubmitRouteError> {
    // PR-46α / session-62 — operator login read from Ready boot-state
    // (same posture as `submit_invoice_request`). Loud-fail in
    // NeedsSetup as defence in depth past the route-level gate.
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSetup => {
                return Err(SubmitRouteError::Other(anyhow!(
                    "storno_invoice_request called in NeedsSetup state — \
                     /api/setup-nav-credentials must run first"
                )));
            }
            ServeBootState::NeedsSellerConfig { .. } => {
                return Err(SubmitRouteError::Other(anyhow!(
                    "storno_invoice_request called in NeedsSellerConfig state — \
                     /api/setup-seller-info must run first"
                )));
            }
        },
        Err(e) => {
            return Err(SubmitRouteError::Other(anyhow!(
                "boot_state RwLock poisoned: {e}"
            )));
        }
    };

    // 1. Precondition check — base must be Finalized. Any other state
    //    surfaces as 409 with the current state named in the message
    //    (same shape as submit/poll). `Storno` itself (already-stornoed)
    //    bounces here too — the operator cannot storno the same base
    //    twice via the SPA (the CLI's `aberp issue-storno` would
    //    allocate `modification_index = 2` and write a second chain
    //    entry; the brief explicitly scopes PR-47α to the operator-
    //    expected single-storno path).
    let derived = derive_state_for(state, invoice_id)?;
    if !matches!(derived.state, InvoiceState::Finalized) {
        return Err(SubmitRouteError::PreconditionMismatch {
            current_state: format!("{:?}", derived.state),
            message: format!(
                "POST /api/invoices/{invoice_id}/storno requires state `Finalized`; \
                 re-fetch detail and retry"
            ),
        });
    }

    // 2. Resolve the base's nav_xml_path from the most-recent
    //    InvoiceDraftCreated audit entry (per ADR-0031 §2). Loud-fail
    //    if absent.
    let base_xml_path = derived.nav_xml_path.ok_or_else(|| {
        SubmitRouteError::Other(anyhow!(
            "invoice {invoice_id} is Finalized but no `nav_xml_path` recorded on the \
             InvoiceDraftCreated audit entry — pre-PR-18 entry; \
             fall back to `aberp issue-storno --references {invoice_id} --in <PATH>`"
        ))
    })?;

    // 3. Read the sibling InvoiceInputJson side-stored at issuance
    //    time. Loud-fail if absent — pre-PR-47α SPA-issued invoice OR
    //    CLI-issued invoice; the message steers to CLI fallback per
    //    CLAUDE.md rule 12.
    let input_json_path = sibling_input_json_path(&base_xml_path);
    let input_json_bytes = std::fs::read(&input_json_path).map_err(|e| {
        SubmitRouteError::Other(anyhow!(
            "invoice {invoice_id} has no side-stored InvoiceInputJson at {} ({}); \
             the SPA storno path requires the input.json side-store added at PR-47α — \
             fall back to `aberp issue-storno --references {invoice_id} --in <PATH>` \
             with the operator's original issuance JSON",
            input_json_path.display(),
            e
        ))
    })?;
    let input: InvoiceInputJson = serde_json::from_slice(&input_json_bytes).map_err(|e| {
        SubmitRouteError::Other(anyhow!(
            "parse side-stored InvoiceInputJson at {}: {e} — \
             the file appears corrupted or hand-edited",
            input_json_path.display()
        ))
    })?;

    // 4. Mint a fresh server-side output path for the storno's XML.
    let storno_xml_path = mint_issued_xml_path(state.tenant.as_str())
        .context("mint server-side NAV-XML output path for storno")?;

    // 5. Mint per-request Actor from startup-loaded operator login
    //    (same posture as submit/poll routes — A159 boilerplate).
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);

    // 6. Dispatch into the library helper. Default series unchanged —
    //    the CLI's `--series` flag carries the storno's own
    //    sequence-burning series; the SPA route uses the default per
    //    the operator-pathless posture. The same-series-as-base case
    //    is the documented default per ADR-0023 §1.
    // PR-83 — normalise the storno reason: trim, then treat empty-
    // after-trim as `None`. Matches PR-82's `blankToNull` posture for
    // the issue path's note channels (single rule across both
    // buyer-facing note surfaces).
    let storno_reason = request.storno_reason.and_then(|s| {
        let trimmed = s.trim();
        if trimmed.is_empty() {
            None
        } else {
            Some(trimmed.to_string())
        }
    });

    issue_storno::storno_from_inputs(
        input,
        &state.db,
        state.tenant.as_str(),
        DEFAULT_SERIES_CODE,
        invoice_id,
        storno_xml_path,
        actor,
        storno_reason,
    )
    .map_err(SubmitRouteError::Other)
}

// ── PR-47β / session-65 — POST /api/invoices/:id/modification ────────

/// PR-47β / session-65 — wire request body for
/// `POST /api/invoices/:id/modification`. Mirrors
/// [`IssueInvoiceRequest`] field-for-field plus the operator-supplied
/// `modification_date` per ADR-0024 §1 (no silent today-default; the
/// operator owns the audit-payload-frozen date string).
///
/// The `currency` field MUST match the base invoice's stored currency
/// per ADR-0037 §4 invariant C6 (chain-currency-match by inheritance);
/// the route layer enforces this loudly with a `400 Bad Request` rather
/// than silently overriding inside `run_single_tx`. The SPA's form
/// pre-locks the dropdown to the base's currency, so the 400 is
/// defence-in-depth against a curl bypass.
#[derive(Debug, Deserialize)]
pub struct ModificationInvoiceRequest {
    pub customer: issue_invoice::CustomerJson,
    pub lines: Vec<issue_invoice::LineJson>,
    pub currency: Currency,
    #[serde(rename = "modificationDate")]
    pub modification_date: String,
    #[serde(default)]
    pub series: Option<String>,
    /// S184 — operator's per-modification opt-out of the default-on
    /// auto-email-buyer tail. Same shape + posture as
    /// `StornoInvoiceRequest::email_buyer_on_storno`; absent → `true`.
    #[serde(default, rename = "emailBuyerOnModification")]
    pub email_buyer_on_modification: Option<bool>,
    /// S184 — operator's per-modification opt-out of the default-on
    /// auto-submit-to-NAV tail. Same shape + posture as
    /// `StornoInvoiceRequest::submit_to_nav_on_storno`; absent → `true`.
    #[serde(default, rename = "submitToNavOnModification")]
    pub submit_to_nav_on_modification: Option<bool>,
    /// PR-203 / S203 — operator-typed per-invoice email recipient
    /// override for THIS modification (Fizetési mód's sibling field on
    /// the SPA's modification form pre-fills from the base's stored
    /// override but is editable per-invoice). Same camelCase / posture
    /// as `IssueInvoiceRequest::email_recipient_override`; absent / blank
    /// → the send-path resolver falls back to the partner master's
    /// `contact_email`. Validated at request-build time below; the
    /// modification's own `invoice.email_recipient_override` row carries
    /// the operator's edit independent of the base's value.
    #[serde(default, rename = "emailRecipientOverride")]
    pub email_recipient_override: Option<String>,
}

/// PR-47β / session-65 — wire response body for
/// `POST /api/invoices/:id/modification`. Mirrors
/// [`StornoInvoiceResponse`] field-for-field; the only difference is
/// `state` flips to `Amended` (the `is_amended_base` arm of
/// `derive_state`'s ladder) once an `InvoiceModificationIssued` audit
/// row exists for the base.
#[derive(Debug, Serialize)]
struct ModificationInvoiceResponse {
    invoice_id: String,
    invoice_number: String,
    /// The BASE invoice's new state after this route succeeds. Always
    /// `Amended` per ADR-0036 §3 — the `is_amended_base` arm of
    /// `derive_state`'s priority ladder fires once an
    /// `InvoiceModificationIssued` audit row exists for the base.
    state: InvoiceState,
    modification_index: u32,
    entries_verified: u64,
}

/// PR-47β / session-65 — typed error returned by
/// [`modification_invoice_request`]. Mirrors [`SubmitRouteError`]'s
/// three existing variants and adds `BadRequest` for the C6 currency-
/// mismatch case so the handler can map it to `400` cleanly. A
/// separate enum (rather than extending [`SubmitRouteError`]) keeps the
/// storno / submit / poll handlers byte-for-byte unchanged — surgical
/// per CLAUDE.md rule 3.
#[derive(Debug)]
pub enum ModificationRouteError {
    PreconditionMismatch {
        current_state: String,
        message: String,
    },
    NotFound(String),
    /// `400 Bad Request` — operator-correctable input shape error
    /// (today: C6 chain-currency mismatch).
    BadRequest(String),
    /// PR-58 / session-78 — propagated NAV upstream-fault. Modification
    /// issuance does not call tokenExchange directly today, but the
    /// shared [`SubmitRouteError::NavUpstreamFault`] surface means the
    /// `From<SubmitRouteError>` conversion must remain total.
    NavUpstreamFault {
        status: u16,
        fault_code: Option<String>,
        fault_message: Option<String>,
        technical_validations: Vec<TechnicalValidation>,
        body_preview: String,
    },
    Other(anyhow::Error),
}

impl From<anyhow::Error> for ModificationRouteError {
    fn from(e: anyhow::Error) -> Self {
        ModificationRouteError::Other(e)
    }
}

impl From<SubmitRouteError> for ModificationRouteError {
    fn from(e: SubmitRouteError) -> Self {
        match e {
            SubmitRouteError::PreconditionMismatch {
                current_state,
                message,
            } => ModificationRouteError::PreconditionMismatch {
                current_state,
                message,
            },
            SubmitRouteError::NotFound(m) => ModificationRouteError::NotFound(m),
            SubmitRouteError::NavUpstreamFault {
                status,
                fault_code,
                fault_message,
                technical_validations,
                body_preview,
            } => ModificationRouteError::NavUpstreamFault {
                status,
                fault_code,
                fault_message,
                technical_validations,
                body_preview,
            },
            SubmitRouteError::Other(inner) => ModificationRouteError::Other(inner),
        }
    }
}

/// PR-47β / session-65 — `POST /api/invoices/:id/modification` handler.
///
/// Operator-edited mutation route wrapping
/// [`issue_modification::modification_from_inputs`]. The SPA's
/// "Amend invoice (modification)" button on the invoice-detail modal
/// posts the operator-edited body here.
///
/// 1. Bearer-auth + Ready gate (503 in NeedsSetup).
/// 2. Precondition: base derives to `Finalized` OR `Amended` per
///    ADR-0024 §6; loud-fail 409 otherwise.
/// 3. C6 chain-currency invariant: `request.currency` MUST equal the
///    base's stored currency. Loud-fail 400 on mismatch.
/// 4. Mint a fresh server-side output path for the modification XML.
/// 5. Mint per-request `Actor` from startup-cached `operator_login`.
/// 6. Dispatch into the library helper.
///
/// Failure modes:
///   - `400 Bad Request` — C6 currency mismatch (the body's currency
///     differs from the base's stored currency).
///   - `401 Unauthorized` — bearer missing or wrong.
///   - `503 Service Unavailable` — NeedsSetup boot state.
///   - `404 Not Found` — unknown base invoice id.
///   - `409 Conflict` — base not in `Finalized` or `Amended`.
///   - `500 Internal Server Error` — any propagated error.
async fn handle_modification_invoice(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
    Json(request): Json<ModificationInvoiceRequest>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(login) => login,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    // S184 — capture the operator's auto-pipeline flags BEFORE the
    // request moves into `modification_invoice_request`. Same default-
    // on posture as the issue + storno paths: absent → `true`. The
    // SPA's modification confirm panel pre-S184 does not surface a
    // checkbox, so every modification today triggers the full tail.
    let email_buyer_flag = request.email_buyer_on_modification.unwrap_or(true);
    let submit_to_nav_flag = request.submit_to_nav_on_modification.unwrap_or(true);
    // S184 — capture the BASE invoice id (this modification's parent)
    // before the route helper consumes the path. Same chain-identity-
    // recovery pattern as the storno tail.
    let base_invoice_id_for_tail = invoice_id.clone();
    match modification_invoice_request(&state, &invoice_id, request) {
        Ok(summary) => {
            // ADR-0095 §3 — debounced post-write durable checkpoint nudge.
            crate::live_checkpoint::trigger();
            // S184 — post-issue tail. See `handle_storno_invoice` +
            // `run_chain_post_issue_tail` doc-comments for the
            // [[post-issue-async]] parallel.
            let task_modification_invoice_id = summary.invoice_id.clone();
            let task_modification_invoice_number = summary.invoice_number.clone();
            let task_state = state.clone();
            let task_login = operator_login.clone();
            let task_base_invoice_id = base_invoice_id_for_tail;
            tokio::spawn(async move {
                run_chain_post_issue_tail(
                    &task_state,
                    &task_modification_invoice_id,
                    &task_modification_invoice_number,
                    &task_base_invoice_id,
                    &task_login,
                    email_buyer_flag,
                    submit_to_nav_flag,
                )
                .await;
            });
            Json(ModificationInvoiceResponse {
                invoice_id: summary.invoice_id,
                invoice_number: summary.invoice_number,
                state: InvoiceState::Amended,
                modification_index: summary.modification_index,
                entries_verified: summary.entries_verified,
            })
            .into_response()
        }
        Err(ModificationRouteError::PreconditionMismatch {
            current_state,
            message,
        }) => (
            StatusCode::CONFLICT,
            Json(error_body(format!(
                "{message} (current state: {current_state})"
            ))),
        )
            .into_response(),
        Err(ModificationRouteError::NotFound(message)) => {
            (StatusCode::NOT_FOUND, Json(error_body(message))).into_response()
        }
        Err(ModificationRouteError::BadRequest(message)) => {
            (StatusCode::BAD_REQUEST, Json(error_body(message))).into_response()
        }
        // PR-58 / session-78 — see notes on the storno handler. Not
        // reachable from today's modification path but kept symmetric
        // through the typed surface.
        Err(ModificationRouteError::NavUpstreamFault {
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        }) => nav_upstream_fault_response(
            "modification_invoice_request",
            status,
            fault_code,
            fault_message,
            technical_validations,
            body_preview,
        ),
        Err(ModificationRouteError::Other(e)) => internal_error("modification_invoice_request", e),
    }
}

/// PR-47β / session-65 — library helper that wires
/// [`issue_modification::modification_from_inputs`] over the
/// [`AppState`]'s db_path + tenant + operator login. `pub` so the
/// integration test (`tests/serve_modification_route.rs`) drives it
/// without spinning the HTTPS listener (same posture as
/// [`storno_invoice_request`] / [`submit_invoice_request`] per A159).
pub fn modification_invoice_request(
    state: &AppState,
    invoice_id: &str,
    request: ModificationInvoiceRequest,
) -> std::result::Result<issue_modification::ModificationIssuedSummary, ModificationRouteError> {
    // Operator login from Ready boot-state (same posture as the other
    // mutation helpers). Defence in depth past the route-level gate.
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSetup => {
                return Err(ModificationRouteError::Other(anyhow!(
                    "modification_invoice_request called in NeedsSetup state — \
                     /api/setup-nav-credentials must run first"
                )));
            }
            ServeBootState::NeedsSellerConfig { .. } => {
                return Err(ModificationRouteError::Other(anyhow!(
                    "modification_invoice_request called in NeedsSellerConfig state — \
                     /api/setup-seller-info must run first"
                )));
            }
        },
        Err(e) => {
            return Err(ModificationRouteError::Other(anyhow!(
                "boot_state RwLock poisoned: {e}"
            )));
        }
    };

    // 1. Precondition check — base must be Finalized OR Amended per
    //    ADR-0024 §6. Other states (Storno, Rejected, Pending,
    //    Submitted, etc.) bounce with 409 + the current state named.
    let derived = derive_state_for(state, invoice_id)?;
    let modify_eligible = matches!(
        derived.state,
        InvoiceState::Finalized | InvoiceState::Amended
    );
    if !modify_eligible {
        return Err(ModificationRouteError::PreconditionMismatch {
            current_state: format!("{:?}", derived.state),
            message: format!(
                "POST /api/invoices/{invoice_id}/modification requires state \
                 `Finalized` or `Amended`; re-fetch detail and retry"
            ),
        });
    }

    // 2. C6 chain-currency invariant check (ADR-0037 §4). Load the
    //    base's stored currency and reject 400 if the body's currency
    //    differs. The SPA's modification form locks the currency
    //    dropdown to the base's currency, so the 400 is operator-
    //    actionable defence against a curl bypass. Inside
    //    `run_single_tx` the core would silently override the
    //    operator-supplied currency via `inherit_rate_metadata_for_chain`;
    //    surfacing the mismatch loud here keeps the wire shape honest
    //    per CLAUDE.md rule 12.
    let base_currency =
        read_base_currency(&state.db, invoice_id).map_err(ModificationRouteError::Other)?;
    if base_currency != request.currency {
        return Err(ModificationRouteError::BadRequest(format!(
            "modification body currency {} differs from base invoice {} \
             currency {} — ADR-0037 §4 invariant C6 requires chain children to \
             inherit the base's currency (rate metadata is frozen at base \
             issuance time and re-fetching at chain-child time would risk a \
             different rate for the same referenced invoice)",
            request.currency.iso_code(),
            invoice_id,
            base_currency.iso_code(),
        )));
    }

    // 3. Mint a fresh server-side output path for the modification's
    //    XML (operator-pathless route posture, same as issue / storno).
    let modification_xml_path = mint_issued_xml_path(state.tenant.as_str())
        .context("mint server-side NAV-XML output path for modification")?;

    // 4. Mint per-request Actor from startup-loaded operator login
    //    (A159 boilerplate).
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);

    // 5. Build the parsed input shape the library helper expects.
    //
    //    PR-53 / session-73 — supplier resolved from the per-tenant
    //    seller.toml instead of the wire body (cross-cutting fix for
    //    the SPA's modification form which no longer surfaces seller
    //    inputs). The seller.toml read failures bounce back as a
    //    typed 400 via `ModificationRouteError::BadRequest` rather
    //    than a 500 so the SPA's inline-error renderer stays
    //    operator-actionable.
    let supplier = supplier_from_seller_toml(state.tenant.as_str()).map_err(|e| {
        ModificationRouteError::BadRequest(format!(
            "seller.toml identity unavailable for modification: {e}"
        ))
    })?;
    let input = InvoiceInputJson {
        supplier,
        customer: request.customer,
        lines: request.lines,
        // PR-82 — modification-route does not yet surface an operator
        // note input on the SPA form; pass `None`. PR-83 wires the
        // chain-level note (storno reason); the modification surface
        // can follow when an operational need surfaces.
        invoice_note: None,
        // PR-84 — modification chains do not yet surface operator
        // date pickers (out of scope per the PR-84 brief: "keep PR-84
        // to the issue path"). All three fields stay `None`; the
        // modification's allocator (`issue_modification.rs`) defaults
        // payment_deadline + delivery_date to its own server-stamped
        // issue date, preserving pre-PR-84 wire behaviour for chain
        // children.
        payment_deadline: None,
        delivery_date: None,
        delivery_date_override: None,
        // S160 — the SPA modification route does not surface a payment-
        // method picker and does not reload the base's side-stored
        // `input.json` here (same posture as `invoice_note` / dates above,
        // which also default rather than inherit). Defaults to `Transfer`.
        // The CLI modification path (`issue_modification::run`) DOES
        // inherit, because it parses the base's `input.json` (whose
        // `payment_method` round-trips via `#[serde(default)]`). Full
        // base-inheritance for the SPA route is a follow-up (see ADR-0050).
        payment_method: aberp_billing::PaymentMethod::default(),
        // PR-203 / S203 — operator-typed per-modification email recipient
        // override. The SPA's modification form pre-fills it from the
        // base's stored value (via `GET /issuance-input` → base's
        // `input.json`); the operator's edit on THIS form lands here.
        // Validated below before reaching `issue_modification`.
        email_recipient_override: request.email_recipient_override.and_then(|s| {
            let t = s.trim();
            if t.is_empty() {
                None
            } else {
                Some(t.to_string())
            }
        }),
    };
    if let Some(raw) = input.email_recipient_override.as_deref() {
        if let Err(msg) = partners::parse_and_validate_emails(raw) {
            return Err(ModificationRouteError::BadRequest(format!(
                "email recipient override is malformed: {msg}"
            )));
        }
    }
    let series = request.series.as_deref().unwrap_or(DEFAULT_SERIES_CODE);

    // 6. Dispatch into the library helper.
    issue_modification::modification_from_inputs(
        input,
        &state.db,
        state.tenant.as_str(),
        series,
        invoice_id,
        &request.modification_date,
        modification_xml_path,
        actor,
    )
    .map_err(ModificationRouteError::Other)
}

/// PR-47β / session-65 — open a quick read-only DuckDB transaction and
/// return the base invoice's stored `Currency` per ADR-0037 §3. Wraps
/// [`load_invoice_currency_metadata_in_tx`] for the route-layer C6
/// invariant guard so the modification handler does not have to open
/// the tx itself.
///
/// Returns the typed `Currency` value (NOT the full
/// [`InvoiceCurrencyMetadata`] bundle) — the route only needs the
/// currency for the equality check; reading the rate columns here would
/// be speculative work the core re-reads anyway inside its own write tx.
fn read_base_currency(db: &aberp_db::HandleArc, invoice_id: &str) -> Result<Currency> {
    let mut conn = db
        .read()
        .context("shared read: base-currency lookup (ADR-0098 Gap 1a Session C)")?;
    let tx = conn
        .transaction()
        .context("begin read transaction for base-currency lookup (modification route)")?;
    let metadata = load_invoice_currency_metadata_in_tx(&tx, invoice_id).with_context(|| {
        format!(
            "read base invoice {} currency metadata for modification route C6 check",
            invoice_id
        )
    })?;
    tx.commit()
        .context("commit read transaction for base-currency lookup")?;
    Ok(metadata.currency)
}

// ── PR-47β / session-65 — GET /api/invoices/:id/issuance-input ───────

/// PR-47β / session-65 — `GET /api/invoices/:id/issuance-input` handler.
///
/// Returns the operator's original [`InvoiceInputJson`] side-stored
/// alongside the NAV XML at issuance time (per A174). The SPA's
/// modification modal pre-fills its form fields from this so the
/// operator edits in place rather than retyping the entire invoice.
///
/// Failure modes:
///   - `401 Unauthorized` — bearer missing or wrong.
///   - `503 Service Unavailable` — NeedsSetup boot state.
///   - `404 Not Found` — no side-stored input.json for this invoice
///     (CLI-issued OR pre-PR-47α SPA-issued). The SPA falls back to a
///     fresh form with an explanatory banner.
///   - `500 Internal Server Error` — propagated parse / read error.
async fn handle_get_issuance_input(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let invoice_id_for_task = invoice_id.clone();
    let result = tokio::task::spawn_blocking(move || {
        get_issuance_input(&state_for_task, &invoice_id_for_task)
    })
    .await;
    match result {
        Ok(Ok(Some(input))) => Json(input).into_response(),
        Ok(Ok(None)) => (
            StatusCode::NOT_FOUND,
            Json(error_body(format!(
                "no side-stored issuance input for invoice {invoice_id} \
                 (CLI-issued or pre-PR-47α SPA-issued); the modification form \
                 will open empty"
            ))),
        )
            .into_response(),
        Ok(Err(e)) => internal_error("get_issuance_input", e),
        Err(join_err) => internal_error(
            "get_issuance_input:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

/// PR-47β / session-65 — library helper for the issuance-input read.
/// `pub` for symmetry with the other route helpers; surfaces `Ok(None)`
/// for the missing-sibling case so the handler can map it to 404
/// without an anyhow error string round-trip.
pub fn get_issuance_input(state: &AppState, invoice_id: &str) -> Result<Option<InvoiceInputJson>> {
    let derived = match derive_state_for(state, invoice_id) {
        Ok(d) => d,
        Err(SubmitRouteError::NotFound(_)) => return Ok(None),
        Err(SubmitRouteError::Other(e)) => return Err(e),
        Err(SubmitRouteError::PreconditionMismatch { message, .. }) => {
            return Err(anyhow!(message))
        }
        // PR-58 / session-78 — derive_state_for does not call NAV, so
        // this variant is structurally unreachable here. The arm
        // exists so the match stays exhaustive when the typed surface
        // grows; the anyhow-wrap is the loud-fail per CLAUDE.md rule 12.
        Err(SubmitRouteError::NavUpstreamFault {
            status,
            fault_code,
            fault_message,
            ..
        }) => {
            return Err(anyhow!(
                "derive_state_for surfaced an unexpected NavUpstreamFault \
                 (status={status}, fault_code={fault_code:?}, \
                 fault_message={fault_message:?}) — this code path does not \
                 call NAV; investigate"
            ));
        }
    };
    let xml_path = match derived.nav_xml_path {
        Some(p) => p,
        None => return Ok(None),
    };
    let input_json_path = sibling_input_json_path(&xml_path);
    let bytes = match std::fs::read(&input_json_path) {
        Ok(b) => b,
        Err(e) if e.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(e) => {
            return Err(anyhow!(
                "read side-stored InvoiceInputJson at {}: {e}",
                input_json_path.display()
            ))
        }
    };
    let parsed: InvoiceInputJson = serde_json::from_slice(&bytes).with_context(|| {
        format!(
            "parse side-stored InvoiceInputJson at {}",
            input_json_path.display()
        )
    })?;
    Ok(Some(parsed))
}

// ── PR-70 / ADR-0039 — POST /api/invoices/:id/mark-paid ──────────────

/// PR-70 / ADR-0039 — wire request body for
/// `POST /api/invoices/:id/mark-paid`. Mirrors the
/// `MarkPaidInput` shape minus the `invoice_id` field (URL path
/// segment). `currency` MUST match the invoice's stored currency
/// per ADR-0039 §3; the route layer enforces this with a 400.
#[derive(Debug, Deserialize)]
pub struct MarkPaidRequest {
    pub paid_at: String,
    pub amount_minor: i64,
    pub currency: Currency,
    pub method: PaymentMethod,
    #[serde(default)]
    pub reference: Option<String>,
}

/// PR-70 / ADR-0039 — wire response body for
/// `POST /api/invoices/:id/mark-paid` on the success path.
/// `payment` carries the just-appended audit-payload echo (the SPA
/// re-uses this to render the Paid chip + payment detail immediately
/// without a follow-up `GET /invoices/:id` round-trip);
/// `entries_verified` is the post-commit `Ledger::verify_chain`
/// count, surfaced for parity with the existing mutation routes.
#[derive(Debug, Serialize)]
struct MarkPaidResponse {
    invoice_id: String,
    payment: PaymentRecordSummary,
    entries_verified: u64,
}

/// PR-70 / ADR-0039 — wire-shape mirror of
/// [`audit_query::PaymentRecord`]. A separate struct (vs. deriving
/// `Serialize` on the audit-query type) keeps the wire field names
/// controlled here (snake_case to match the SPA's TS interface
/// `PaymentRecordSummary`) and lets the wire shape evolve
/// independently of the read-side accessor's Rust types.
#[derive(Debug, Serialize)]
struct PaymentRecordSummary {
    paid_at: String,
    amount_minor: i64,
    currency: String,
    method: PaymentMethod,
    reference: Option<String>,
}

impl From<PaymentRecord> for PaymentRecordSummary {
    fn from(p: PaymentRecord) -> Self {
        Self {
            paid_at: p.paid_at,
            amount_minor: p.amount_minor,
            currency: p.currency,
            method: p.method,
            reference: p.reference,
        }
    }
}

/// PR-70 / ADR-0039 — wire response body for the `409 Conflict`
/// already-paid arm. Carries the existing payment record verbatim
/// so the SPA can render "this invoice was already paid on
/// 2026-05-26 by BankTransfer for HUF 12,500" inline rather than
/// surfacing a generic conflict.
#[derive(Debug, Serialize)]
struct AlreadyPaidBody {
    error: &'static str,
    message: String,
    payment: PaymentRecordSummary,
}

/// S397 — structured `400` refusal body for the two mark-paid
/// non-payable classes (storno / negative total). Mirrors the
/// `error`-code-plus-`message` shape of [`AlreadyPaidBody`] so the SPA
/// can branch on the stable `error` discriminator
/// (`cannot_mark_paid_storno` / `cannot_mark_paid_negative`) rather
/// than parsing free text.
#[derive(Serialize)]
struct MarkPaidRefusalBody {
    error: &'static str,
    message: String,
}

/// PR-70 / ADR-0039 — `POST /api/invoices/:id/mark-paid` handler.
///
/// 1. Bearer-auth check (post-Ready); 503 in NeedsSetup.
/// 2. Precondition: derive the invoice's state; loud-fail with 409
///    Conflict unless `Finalized`. Operational metadata only — the
///    NAV regulatory state ladder is unchanged.
/// 3. Currency-match check: the request's `currency` MUST equal the
///    invoice's stored currency; otherwise 400 Bad Request.
/// 4. Dispatch into [`mark_invoice_paid::mark_paid`] (which handles
///    the date-format check, idempotency gate, audit-write, and
///    chain verify).
///
/// Failure modes:
///   - `401 Unauthorized` — bearer missing or wrong.
///   - `503 Service Unavailable` — NeedsSetup boot state.
///   - `404 Not Found` — unknown invoice id.
///   - `409 Conflict` — base not in `Finalized`, OR an
///     `InvoicePaymentRecorded` entry already exists. The
///     already-paid response body carries the existing payment
///     record so the SPA can render the duplicate gracefully.
///   - `400 Bad Request` — currency mismatch OR malformed `paid_at`.
///   - `500 Internal Server Error` — any propagated error
///     (audit-write, DB error, chain verify failure).
async fn handle_mark_invoice_paid(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
    Json(body): Json<MarkPaidRequest>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let invoice_id_for_task = invoice_id.clone();
    let result = tokio::task::spawn_blocking(move || {
        mark_paid_request(&state_for_task, &invoice_id_for_task, body)
    })
    .await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "mark_paid_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };
    match outcome {
        Ok(outcome) => Json(MarkPaidResponse {
            invoice_id,
            payment: outcome.payment.into(),
            entries_verified: outcome.entries_verified,
        })
        .into_response(),
        Err(MarkPaidRouteError::PreconditionMismatch {
            current_state,
            message,
        }) => (
            StatusCode::CONFLICT,
            Json(error_body(format!(
                "{message} (current state: {current_state})"
            ))),
        )
            .into_response(),
        Err(MarkPaidRouteError::NotFound(message)) => {
            (StatusCode::NOT_FOUND, Json(error_body(message))).into_response()
        }
        Err(MarkPaidRouteError::AlreadyPaid(existing)) => (
            StatusCode::CONFLICT,
            Json(AlreadyPaidBody {
                error: "already_paid",
                message: format!(
                    "invoice {invoice_id} already has a recorded payment \
                     (paid_at {}, amount_minor {}, currency {})",
                    existing.paid_at, existing.amount_minor, existing.currency
                ),
                payment: existing.into(),
            }),
        )
            .into_response(),
        Err(MarkPaidRouteError::CurrencyMismatch {
            invoice_currency,
            body_currency,
        }) => (
            StatusCode::BAD_REQUEST,
            Json(error_body(format!(
                "payment currency {body_currency} does not match invoice currency \
                 {invoice_currency}; a mark-paid request must record the payment in \
                 the invoice's own currency"
            ))),
        )
            .into_response(),
        Err(MarkPaidRouteError::InvalidPaidAt(message)) => {
            (StatusCode::BAD_REQUEST, Json(error_body(message))).into_response()
        }
        Err(MarkPaidRouteError::CannotMarkPaidStorno) => (
            StatusCode::BAD_REQUEST,
            Json(MarkPaidRefusalBody {
                error: "cannot_mark_paid_storno",
                message: format!(
                    "invoice {invoice_id} is a storno (credit note); a storno cancels its \
                     base invoice and cannot itself be marked paid"
                ),
            }),
        )
            .into_response(),
        Err(MarkPaidRouteError::CannotMarkPaidNegative { total_gross }) => (
            StatusCode::BAD_REQUEST,
            Json(MarkPaidRefusalBody {
                error: "cannot_mark_paid_negative",
                message: format!(
                    "invoice {invoice_id} has a negative total ({total_gross}); a credit \
                     balance has inverted payment semantics and cannot be marked paid"
                ),
            }),
        )
            .into_response(),
        Err(MarkPaidRouteError::Other(e)) => internal_error("mark_paid_request", e),
    }
}

/// PR-217 / S220 — request body for `POST /api/restored-invoices/:id/partner`.
///
/// `partner_id: None` is the explicit "clear / no partner" path —
/// distinct from absent-field (serde rejects unknown JSON shapes via
/// the strict route layer, but a missing key in this struct would
/// deserialize to `None` and be indistinguishable from an explicit
/// null). The SPA always sends an explicit `null` or `string` for
/// clarity.
#[derive(Debug, Deserialize)]
pub struct SetRestoredPartnerRequest {
    /// `prt_<ULID>` partner pointer to link, or `null` to clear an
    /// existing link. The handler validates that a non-null id resolves
    /// to a live partner row before writing.
    pub partner_id: Option<String>,
}

/// PR-217 / S220 — response body for the manual-link route. Echoes the
/// post-write denormalized buyer snapshot so the SPA can refresh the
/// row without a second list-restored fetch.
#[derive(Debug, Serialize)]
pub struct SetRestoredPartnerResponse {
    pub partner_id: Option<String>,
    pub customer_name: Option<String>,
    pub customer_tax_number: Option<String>,
    pub customer_vat_status: Option<String>,
}

/// PR-217 / S220 — typed errors for the manual-link route.
#[derive(Debug)]
enum SetRestoredPartnerError {
    RestoredNotFound(String),
    PartnerNotFound(String),
    Other(anyhow::Error),
}

impl From<anyhow::Error> for SetRestoredPartnerError {
    fn from(e: anyhow::Error) -> Self {
        SetRestoredPartnerError::Other(e)
    }
}

/// PR-217 / S220 — operator-paced manual partner link on a restored
/// ExtNav row. Per [[aberp-extnav-partner-nav-gap]] NAV does not expose
/// buyer info for invoices submitted via other software; this route is
/// the operator's escape hatch for those rows.
///
/// **State transitions**:
///   - `partner_id: Some(id)` → fetch partner, denormalize
///     `customer_name`/`customer_tax_number`/`customer_vat_status`
///     onto the row, write `partner_id` pointer, emit audit
///     `ExtNavPartnerManualLink` (action `"link"`).
///   - `partner_id: None` → clear all four fields, emit audit
///     (action `"clear"`).
///
/// **HTTP status codes**:
///   - `200 OK` + [`SetRestoredPartnerResponse`] on success.
///   - `404 Not Found` — restored row id is unknown OR belongs to a
///     different tenant OR the target partner_id is unknown.
///   - `503 Service Unavailable` — backend not in `Ready` state.
///   - `500 Internal Server Error` — DB / audit-ledger error.
async fn handle_set_restored_partner(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(restored_id): AxumPath<String>,
    Json(body): Json<SetRestoredPartnerRequest>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let restored_id_for_task = restored_id.clone();
    let result = tokio::task::spawn_blocking(move || {
        set_restored_partner_request(&state_for_task, &restored_id_for_task, body)
    })
    .await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "set_restored_partner_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };
    match outcome {
        Ok(snapshot) => Json(SetRestoredPartnerResponse {
            partner_id: snapshot.partner_id,
            customer_name: snapshot.customer_name,
            customer_tax_number: snapshot.customer_tax_number,
            customer_vat_status: snapshot.customer_vat_status,
        })
        .into_response(),
        Err(SetRestoredPartnerError::RestoredNotFound(msg)) => {
            (StatusCode::NOT_FOUND, Json(error_body(msg))).into_response()
        }
        Err(SetRestoredPartnerError::PartnerNotFound(msg)) => {
            (StatusCode::NOT_FOUND, Json(error_body(msg))).into_response()
        }
        Err(SetRestoredPartnerError::Other(e)) => internal_error("set_restored_partner_request", e),
    }
}

/// PR-217 / S220 — sync implementation of the manual-link route. Runs
/// inside `spawn_blocking`. Holds ONE DB transaction across:
///   1. `read_restored_buyer_snapshot` — capture `*_before`.
///   2. `read_restored_source_number` — needed for the audit payload.
///   3. Resolve target partner snapshot (or `None` for clear).
///   4. `update_partner_for_restored` — write 4 denorm fields.
///   5. `audit_ledger::append_in_tx` — `ExtNavPartnerManualLink`.
/// All-or-nothing per the audit-ledger discipline (a write that
/// commits without its audit entry is the silent-omission failure
/// mode CLAUDE.md rule 12 names).
fn set_restored_partner_request(
    state: &AppState,
    restored_id: &str,
    body: SetRestoredPartnerRequest,
) -> std::result::Result<restore_outgoing::RestoredBuyerSnapshot, SetRestoredPartnerError> {
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSetup | ServeBootState::NeedsSellerConfig { .. } => {
                return Err(SetRestoredPartnerError::Other(anyhow!(
                    "set_restored_partner_request called outside Ready state"
                )));
            }
        },
        Err(e) => {
            return Err(SetRestoredPartnerError::Other(anyhow!(
                "boot_state RwLock poisoned: {e}"
            )));
        }
    };

    let binary_hash = state
        .binary_hash
        .wait()
        .map_err(|e| SetRestoredPartnerError::Other(anyhow!("await binary hash: {e}")))?;
    let tenant = state.tenant.clone();
    let db_path = state.db_path.as_ref().clone();

    let mut conn = state
        .db
        .write()
        .context("shared writer: ExtNavPartnerManualLink (ADR-0098 Gap 1a Session C)")?;
    aberp_audit_ledger::ensure_schema(&conn)
        .context("ensure audit-ledger schema for ExtNavPartnerManualLink")?;
    partners::ensure_schema(&conn).context("ensure partners schema for ExtNavPartnerManualLink")?;

    let before = match restore_outgoing::read_restored_buyer_snapshot(
        &conn,
        tenant.as_str(),
        restored_id,
    )? {
        Some(s) => s,
        None => {
            return Err(SetRestoredPartnerError::RestoredNotFound(format!(
                "no restored_invoice row matches id `{restored_id}` for this tenant"
            )));
        }
    };
    let source_nav_invoice_number =
        restore_outgoing::read_restored_source_number(&conn, tenant.as_str(), restored_id)?
            .ok_or_else(|| {
                SetRestoredPartnerError::RestoredNotFound(format!(
                    "no restored_invoice row matches id `{restored_id}` for this tenant"
                ))
            })?;

    // Resolve the target partner snapshot (None on a clear action).
    let after = match body.partner_id.as_deref().map(str::trim) {
        Some(pid) if !pid.is_empty() => {
            let partner = match partners::get_partner(&conn, tenant.as_str(), pid)? {
                Some(p) => p,
                None => {
                    return Err(SetRestoredPartnerError::PartnerNotFound(format!(
                        "no partner row matches id `{pid}` for this tenant"
                    )));
                }
            };
            // Snapshot the partner's denormalized fields onto the
            // restored row. Mirrors how the side-store `<ULID>.input.json`
            // path captures buyer info at issue time — the row carries
            // a frozen view; a later partner rename does not retroactively
            // change the audit-trail view.
            restore_outgoing::RestoredBuyerSnapshot {
                partner_id: Some(partner.id.clone()),
                customer_name: Some(partner.display_name.clone()),
                customer_tax_number: partner.tax_number.clone(),
                customer_vat_status: Some(partner.customer_vat_status.as_db_str().to_string()),
            }
        }
        _ => restore_outgoing::RestoredBuyerSnapshot {
            partner_id: None,
            customer_name: None,
            customer_tax_number: None,
            customer_vat_status: None,
        },
    };

    let action = if after.partner_id.is_some() {
        "link"
    } else {
        "clear"
    };
    let idempotency_key = Ulid::new().to_string();
    let payload = audit_payloads::ExtNavPartnerManualLinkPayload {
        idempotency_key: idempotency_key.clone(),
        restored_invoice_id: restored_id.to_string(),
        source_nav_invoice_number,
        action: action.to_string(),
        partner_id_before: before.partner_id.clone(),
        partner_id_after: after.partner_id.clone(),
        customer_name_before: before.customer_name.clone(),
        customer_name_after: after.customer_name.clone(),
    };

    let tx = conn
        .transaction()
        .context("begin DuckDB transaction (ExtNavPartnerManualLink)")?;
    let affected = restore_outgoing::update_partner_for_restored(
        &tx,
        tenant.as_str(),
        restored_id,
        after.partner_id.as_deref(),
        after.customer_name.as_deref(),
        after.customer_tax_number.as_deref(),
        after.customer_vat_status.as_deref(),
    )?;
    if affected != 1 {
        return Err(SetRestoredPartnerError::RestoredNotFound(format!(
            "restored_invoice row `{restored_id}` disappeared between read and write"
        )));
    }
    let session_id = Ulid::new().to_string();
    let actor = Actor::from_local_cli(session_id, &operator_login);
    let ledger_meta = aberp_audit_ledger::LedgerMeta::new(tenant.clone(), binary_hash);
    aberp_audit_ledger::append_in_tx(
        &tx,
        &ledger_meta,
        EventKind::ExtNavPartnerManualLink,
        payload.to_bytes(),
        actor,
        Some(idempotency_key),
    )
    .map_err(|e| anyhow!("audit_ledger::append_in_tx ExtNavPartnerManualLink: {e}"))?;
    tx.commit()
        .context("commit DuckDB transaction (ExtNavPartnerManualLink)")?;
    drop(conn);

    let ledger = Ledger::open(&db_path, tenant.clone(), binary_hash)
        .context("open audit ledger to sync mirror after manual-link entry")?;
    let mirror_path = aberp_audit_ledger::mirror_path_for(&db_path);
    ledger
        .sync_mirror(&mirror_path)
        .context("sync audit-ledger mirror file after manual-link entry")?;

    Ok(after)
}

/// PR-70 / ADR-0039 — typed error returned by [`mark_paid_request`].
/// Mirrors the closed-vocab posture of [`SubmitRouteError`] and adds
/// two PR-70-specific arms (`AlreadyPaid` + `CurrencyMismatch`).
#[derive(Debug)]
pub enum MarkPaidRouteError {
    PreconditionMismatch {
        current_state: String,
        message: String,
    },
    NotFound(String),
    AlreadyPaid(PaymentRecord),
    CurrencyMismatch {
        invoice_currency: String,
        body_currency: String,
    },
    InvalidPaidAt(String),
    /// S397 — the invoice IS a storno (credit note); it cancels its
    /// base and cannot itself be marked paid. Maps to a structured
    /// `400 cannot_mark_paid_storno`.
    CannotMarkPaidStorno,
    /// S397 — the invoice has a negative stored total; a credit
    /// balance has inverted payment semantics. Maps to a structured
    /// `400 cannot_mark_paid_negative`. Carries the offending total so
    /// the refusal names the value per CLAUDE.md rule 12.
    CannotMarkPaidNegative {
        total_gross: i64,
    },
    Other(anyhow::Error),
}

impl From<anyhow::Error> for MarkPaidRouteError {
    fn from(e: anyhow::Error) -> Self {
        MarkPaidRouteError::Other(e)
    }
}

impl From<SubmitRouteError> for MarkPaidRouteError {
    fn from(e: SubmitRouteError) -> Self {
        match e {
            SubmitRouteError::PreconditionMismatch {
                current_state,
                message,
            } => MarkPaidRouteError::PreconditionMismatch {
                current_state,
                message,
            },
            SubmitRouteError::NotFound(s) => MarkPaidRouteError::NotFound(s),
            SubmitRouteError::Other(e) => MarkPaidRouteError::Other(e),
            // mark-paid never calls NAV; this arm is unreachable in
            // practice. Wired through symmetrically so a future
            // refactor that lifts NAV calls into the mark-paid surface
            // does not silently degrade per CLAUDE.md rule 12.
            SubmitRouteError::NavUpstreamFault {
                status,
                fault_code,
                fault_message,
                ..
            } => MarkPaidRouteError::Other(anyhow!(
                "mark_paid_request received an unexpected NavUpstreamFault \
                 (status={status}, fault_code={fault_code:?}, \
                 fault_message={fault_message:?}) — this surface does not call NAV"
            )),
        }
    }
}

/// S397 — operational mark-paid eligibility verdict. A storno (credit
/// note that nets its base to zero) and any negative-total invoice
/// cannot be "paid"; the route refuses both classes BEFORE the audit
/// append so no phantom payment row is written on refusal. Pure so the
/// decision is unit-testable independent of a live ledger + billing
/// fixture (CLAUDE.md rule 9).
#[derive(Debug, PartialEq, Eq)]
enum MarkPaidEligibility {
    Eligible,
    Storno,
    Negative(i64),
}

/// S397 — decide mark-paid eligibility from the two refusal signals.
/// `is_storno_self` comes from the audit-ledger chain walk
/// (`DerivedStateForInvoice`); `total_gross` is the billing row's
/// stored gross (always POSITIVE in practice — the `Negative` arm is
/// defence-in-depth against signed-storage drift / a hand-edited DB).
/// Storno is checked first so a storno credit note refuses with the
/// more specific verdict even if its stored total were also negative.
fn mark_paid_eligibility(is_storno_self: bool, total_gross: Option<i64>) -> MarkPaidEligibility {
    if is_storno_self {
        return MarkPaidEligibility::Storno;
    }
    match total_gross {
        Some(g) if g < 0 => MarkPaidEligibility::Negative(g),
        _ => MarkPaidEligibility::Eligible,
    }
}

/// PR-70 / ADR-0039 — library helper that drives the mark-paid
/// orchestration end-to-end. `pub` so the integration test can hit
/// it for precondition pin tests without spinning the HTTPS listener
/// (same posture as `storno_invoice_request` per A159).
pub fn mark_paid_request(
    state: &AppState,
    invoice_id: &str,
    body: MarkPaidRequest,
) -> std::result::Result<mark_invoice_paid::MarkPaidOutcome, MarkPaidRouteError> {
    // 1. Operator login from Ready boot-state.
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSetup => {
                return Err(MarkPaidRouteError::Other(anyhow!(
                    "mark_paid_request called in NeedsSetup state — \
                     /api/setup-nav-credentials must run first"
                )));
            }
            ServeBootState::NeedsSellerConfig { .. } => {
                return Err(MarkPaidRouteError::Other(anyhow!(
                    "mark_paid_request called in NeedsSellerConfig state — \
                     /api/setup-seller-info must run first"
                )));
            }
        },
        Err(e) => {
            return Err(MarkPaidRouteError::Other(anyhow!(
                "boot_state RwLock poisoned: {e}"
            )));
        }
    };

    // 2. Precondition: derive the invoice's state. Mark-paid is
    //    legal only on Finalized invoices per ADR-0039 §3 — the
    //    NAV-side regulatory ladder must have reached terminal
    //    SAVED before the operator records a payment. Storno /
    //    Modified / Abandoned / Pending / etc. all 409 here.
    let derived = derive_state_for(state, invoice_id)?;
    if !matches!(derived.state, InvoiceState::Finalized) {
        return Err(MarkPaidRouteError::PreconditionMismatch {
            current_state: format!("{:?}", derived.state),
            message: format!(
                "POST /api/invoices/{invoice_id}/mark-paid requires state `Finalized`; \
                 the invoice must be terminally accepted at NAV (SAVED) before a \
                 payment can be recorded"
            ),
        });
    }

    // 2b. S397 — refuse mark-paid on a storno (credit note that nets
    //    its base to zero) OR a negative-total invoice. The SPA already
    //    hides the affordance (`isMarkPayable`), but the route refuses
    //    regardless ([[trust-code-not-operator]] / [[hulye-biztos]]) so
    //    a curl bypass cannot record a phantom payment against a
    //    reversal. This runs BEFORE the audit append below, so a refusal
    //    writes no InvoicePaymentRecorded row.
    //
    //    The storno verdict is purely ledger-derived (`is_storno_self`),
    //    so skip the billing read entirely for a storno — its refusal
    //    must not hinge on a billing-store round-trip. For a non-storno
    //    we read the billing row's stored gross (positive in practice;
    //    the negative arm is defence-in-depth against signed-storage
    //    drift) and let the pure verdict decide.
    let total_gross = if derived.is_storno_self {
        None
    } else {
        read_invoice_total_gross_minor(&state.db, invoice_id).map_err(|e| {
            MarkPaidRouteError::Other(anyhow!(
                "read invoice total_gross for mark-paid eligibility gate: {e}"
            ))
        })?
    };
    match mark_paid_eligibility(derived.is_storno_self, total_gross) {
        MarkPaidEligibility::Eligible => {}
        MarkPaidEligibility::Storno => return Err(MarkPaidRouteError::CannotMarkPaidStorno),
        MarkPaidEligibility::Negative(g) => {
            return Err(MarkPaidRouteError::CannotMarkPaidNegative { total_gross: g })
        }
    }

    // 3. Currency-match check — defence-in-depth against a curl
    //    bypass (the SPA pre-locks the dropdown to the invoice's
    //    currency). Read the invoice's currency from the billing
    //    store using the same scoped-read-tx posture as
    //    `read_base_currency`.
    let invoice_currency = read_invoice_currency(&state.db, invoice_id).map_err(|e| {
        MarkPaidRouteError::Other(anyhow!(
            "read invoice currency for mark-paid currency-match check: {e}"
        ))
    })?;
    if body.currency != invoice_currency {
        return Err(MarkPaidRouteError::CurrencyMismatch {
            invoice_currency: invoice_currency.iso_code().to_string(),
            body_currency: body.currency.iso_code().to_string(),
        });
    }

    // 4. Dispatch into the library helper.
    let binary_hash = state
        .binary_hash
        .wait()
        .map_err(|e| MarkPaidRouteError::Other(anyhow!("await binary hash: {e}")))?;
    let input = MarkPaidInput {
        invoice_id: invoice_id.to_string(),
        paid_at: body.paid_at,
        amount_minor: body.amount_minor,
        currency: body.currency.iso_code().to_string(),
        method: body.method,
        reference: body.reference.and_then(|s| {
            let trimmed = s.trim();
            if trimmed.is_empty() {
                None
            } else {
                Some(trimmed.to_string())
            }
        }),
    };
    match mark_invoice_paid::mark_paid(
        &state.db,
        state.tenant.clone(),
        binary_hash,
        &operator_login,
        input,
    ) {
        Ok(outcome) => Ok(outcome),
        Err(MarkPaidError::AlreadyPaid(existing)) => Err(MarkPaidRouteError::AlreadyPaid(existing)),
        Err(MarkPaidError::InvalidPaidAt(message)) => {
            Err(MarkPaidRouteError::InvalidPaidAt(message))
        }
        Err(MarkPaidError::Other(e)) => Err(MarkPaidRouteError::Other(e)),
    }
}

/// PR-70 / ADR-0039 — read the invoice's stored currency from the
/// billing store. Same scoped-read-tx posture as
/// [`read_base_currency`] but does not require the invoice to be
/// the base of a chain — works for any invoice id that exists in
/// the billing table.
fn read_invoice_currency(db: &aberp_db::HandleArc, invoice_id: &str) -> Result<Currency> {
    let mut conn = db
        .read()
        .context("shared read: invoice-currency lookup (ADR-0098 Gap 1a Session C)")?;
    let tx = conn
        .transaction()
        .context("begin read transaction for invoice-currency lookup")?;
    let metadata = load_invoice_currency_metadata_in_tx(&tx, invoice_id)
        .with_context(|| format!("load invoice_currency_metadata for invoice {invoice_id}"))?;
    tx.commit()
        .context("commit read transaction for invoice-currency lookup")?;
    Ok(metadata.currency)
}

/// S397 — read the invoice's stored gross total (minor units: whole
/// forints for HUF, EUR cents for EUR) from the billing store. Same
/// scoped-read-tx posture as [`read_invoice_currency`]. `None` when
/// the id has no allocated billing row yet (a draft) — the mark-paid
/// gate treats `None` as non-negative (the Finalized precondition has
/// already excluded drafts by the time this runs). Reuses
/// `billing::load_ready_invoice_by_id` so the gross read shares the
/// list/detail read path's source of truth (CLAUDE.md rule 8).
fn read_invoice_total_gross_minor(
    db: &aberp_db::HandleArc,
    invoice_id: &str,
) -> Result<Option<i64>> {
    let mut conn = db
        .read()
        .context("shared read: invoice total_gross lookup (ADR-0098 Gap 1a Session C)")?;
    let tx = conn
        .transaction()
        .context("begin read transaction for invoice total_gross lookup")?;
    let pair = billing::load_ready_invoice_by_id(&tx, invoice_id)
        .with_context(|| format!("load_ready_invoice_by_id for invoice {invoice_id}"))?;
    tx.commit()
        .context("commit read transaction for invoice total_gross lookup")?;
    Ok(pair.and_then(|p| p.0.total_gross()).map(|h| h.as_i64()))
}

// ── PR-48α / session-68 — partner CRUD ───────────────────────────────
//
// Five routes (list + create on the collection; get + update + delete
// on the resource) over the per-tenant DuckDB `partners` table.
// `aberp::partners` owns the schema + the CRUD body; this section is
// the HTTP boundary that maps validation / not-found / 5xx errors
// onto the standard status codes.

/// PR-48α — typed error for the partner route helpers. `Validation`
/// → 400, `NotFound` → 404, `Other` → 500 (via the standard
/// [`internal_error`] helper).
#[derive(Debug)]
pub enum PartnerRouteError {
    Validation(Vec<PartnerValidationError>),
    NotFound,
    Other(anyhow::Error),
}

impl From<anyhow::Error> for PartnerRouteError {
    fn from(e: anyhow::Error) -> Self {
        PartnerRouteError::Other(e)
    }
}

/// PR-48α — query-string carrier for `GET /api/partners?search=<needle>`.
/// `search` is case-insensitive prefix match on `display_name` OR
/// `legal_name` per the typeahead UX. Absence ⇒ list every active
/// partner.
#[derive(Debug, Deserialize)]
pub struct ListPartnersQuery {
    #[serde(default)]
    pub search: Option<String>,
}

/// Wire body shape for the validation-failure response. `error` is a
/// fixed sentinel string the SPA can pattern-match on; `fields` is the
/// per-field array the inline-error renderer (A157) consumes.
#[derive(Serialize)]
struct PartnerValidationBody {
    error: &'static str,
    fields: Vec<PartnerValidationError>,
}

fn partner_validation_response(errors: Vec<PartnerValidationError>) -> Response {
    (
        StatusCode::BAD_REQUEST,
        Json(PartnerValidationBody {
            error: "validation_failed",
            fields: errors,
        }),
    )
        .into_response()
}

fn partner_not_found_response() -> Response {
    (
        StatusCode::NOT_FOUND,
        Json(error_body("partner not found".to_string())),
    )
        .into_response()
}

// ── GET /api/partners ─────────────────────────────────────────────────

async fn handle_list_partners(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListPartnersQuery>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let search = query.search;
    let result = tokio::task::spawn_blocking(move || {
        list_partners_request(&state_for_task, search.as_deref())
    })
    .await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "list_partners_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };
    match outcome {
        Ok(partners) => Json(partners).into_response(),
        Err(PartnerRouteError::Other(e)) => internal_error("list_partners_request", e),
        Err(PartnerRouteError::Validation(_)) | Err(PartnerRouteError::NotFound) => {
            // Unreachable — the list helper does not validate or
            // surface NotFound. Bug-defensive arm so a future
            // refactor that adds either path surfaces loud rather
            // than a status-code-dropped silent 500.
            internal_error(
                "list_partners_request",
                anyhow!("list_partners_request surfaced unexpected Validation/NotFound"),
            )
        }
    }
}

/// PR-48α — library helper backing `GET /api/partners`. `pub` so the
/// integration test can hit it without spinning the HTTPS listener
/// (same posture as `issue_invoice_request` per A159).
pub fn list_partners_request(
    state: &AppState,
    search: Option<&str>,
) -> std::result::Result<Vec<Partner>, PartnerRouteError> {
    let conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let partners = partners::list_partners(&conn, state.tenant.as_str(), search)?;
    Ok(partners)
}

// ── GET /api/partners/:id ────────────────────────────────────────────

async fn handle_get_partner(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match get_partner_request(&state, &id) {
        Ok(partner) => Json(partner).into_response(),
        Err(PartnerRouteError::NotFound) => partner_not_found_response(),
        Err(PartnerRouteError::Other(e)) => internal_error("get_partner_request", e),
        Err(PartnerRouteError::Validation(_)) => internal_error(
            "get_partner_request",
            anyhow!("get_partner_request surfaced unexpected Validation"),
        ),
    }
}

pub fn get_partner_request(
    state: &AppState,
    id: &str,
) -> std::result::Result<Partner, PartnerRouteError> {
    let conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    match partners::get_partner(&conn, state.tenant.as_str(), id)? {
        Some(p) => Ok(p),
        None => Err(PartnerRouteError::NotFound),
    }
}

// ── POST /api/partners ───────────────────────────────────────────────

async fn handle_create_partner(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(inputs): Json<PartnerInputs>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let result =
        tokio::task::spawn_blocking(move || create_partner_request(&state_for_task, &inputs)).await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "create_partner_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };
    match outcome {
        Ok(partner) => (StatusCode::CREATED, Json(partner)).into_response(),
        Err(PartnerRouteError::Validation(errors)) => partner_validation_response(errors),
        Err(PartnerRouteError::Other(e)) => internal_error("create_partner_request", e),
        Err(PartnerRouteError::NotFound) => internal_error(
            "create_partner_request",
            anyhow!("create_partner_request surfaced unexpected NotFound"),
        ),
    }
}

pub fn create_partner_request(
    state: &AppState,
    inputs: &PartnerInputs,
) -> std::result::Result<Partner, PartnerRouteError> {
    if let Err(errors) = partners::validate_partner_inputs(inputs) {
        return Err(PartnerRouteError::Validation(errors));
    }
    let conn = state
        .db
        .write()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let partner = partners::create_partner(&conn, state.tenant.as_str(), inputs)?;
    Ok(partner)
}

// ── PUT /api/partners/:id ────────────────────────────────────────────

async fn handle_update_partner(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(id): AxumPath<String>,
    Json(inputs): Json<PartnerInputs>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(login) => login,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    // S428 — a customer_type change fires an audit row, so the binary
    // hash must be resolvable (mirrors the machine-CRUD posture).
    let binary_hash = match resolve_binary_hash(&state) {
        Ok(h) => h,
        Err(resp) => return resp,
    };
    let state_for_task = state.clone();
    let result = tokio::task::spawn_blocking(move || {
        update_partner_request(&state_for_task, &id, &inputs, &operator_login, binary_hash)
    })
    .await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "update_partner_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };
    match outcome {
        Ok(partner) => Json(partner).into_response(),
        Err(PartnerRouteError::Validation(errors)) => partner_validation_response(errors),
        Err(PartnerRouteError::NotFound) => partner_not_found_response(),
        Err(PartnerRouteError::Other(e)) => internal_error("update_partner_request", e),
    }
}

pub fn update_partner_request(
    state: &AppState,
    id: &str,
    inputs: &PartnerInputs,
    operator_login: &str,
    binary_hash: BinaryHash,
) -> std::result::Result<Partner, PartnerRouteError> {
    if let Err(errors) = partners::validate_partner_inputs(inputs) {
        return Err(PartnerRouteError::Validation(errors));
    }
    // S428 — capture the old customer_type before the write so we can
    // detect a change and fire `PartnerCustomerTypeChanged`. The write
    // connection is scoped/dropped before the audit append opens its own
    // ledger connection (the S427 single-writer-lock posture).
    let (partner, old_customer_type) = {
        let conn = state
            .db
            .write()
            .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
        let old_customer_type =
            partners::get_partner(&conn, state.tenant.as_str(), id)?.map(|p| p.customer_type);
        let updated = match partners::update_partner(&conn, state.tenant.as_str(), id, inputs)? {
            Some(p) => p,
            None => return Err(PartnerRouteError::NotFound),
        };
        (updated, old_customer_type)
    };

    if old_customer_type != Some(partner.customer_type) {
        let payload = crate::audit_payloads::PartnerCustomerTypeChangedPayload {
            partner_id: partner.id.clone(),
            old_customer_type: old_customer_type
                .map(|t| t.as_db_str().to_string())
                .unwrap_or_else(|| "unset".to_string()),
            new_customer_type: partner.customer_type.as_db_str().to_string(),
        };
        let tenant = TenantId::new(state.tenant.as_str())
            .with_context(|| format!("tenant id {}", state.tenant.as_str()))?;
        crate::quoting_machines::append_machine_event(
            &state.db_path,
            tenant,
            binary_hash,
            operator_login,
            EventKind::PartnerCustomerTypeChanged,
            payload.to_bytes(),
        )?;
    }
    Ok(partner)
}

