// ── PR-172 — GET /api/notes-history ──────────────────────────────────
//
// Buyer-facing notes typeahead source. Three textareas in the SPA
// (per-line note, per-invoice note, storno reason) feed off this
// endpoint as the operator types. The scope discriminator routes
// each typeahead to its own history bucket so the per-line typeahead
// never surfaces an invoice-level note (and vice versa).
//
// The handler is a thin shell around `notes_history::list_notes_history`;
// the per-tenant ledger walk + dedup + ordering live there.

/// PR-172 — query-string carrier for `GET /api/notes-history`.
/// `scope` is required and one of `line` / `invoice` / `storno`;
/// unknown values produce a 400 rather than a silent default.
/// `limit` is optional and defaults to [`crate::notes_history::DEFAULT_LIMIT`].
#[derive(Debug, Deserialize)]
pub struct NotesHistoryQuery {
    pub scope: String,
    #[serde(default)]
    pub limit: Option<usize>,
}

async fn handle_get_notes_history(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<NotesHistoryQuery>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let scope = match crate::notes_history::NotesHistoryScope::from_storage_str(&query.scope) {
        Some(s) => s,
        None => {
            return (
                StatusCode::BAD_REQUEST,
                Json(error_body(format!(
                    "unknown scope {:?}: expected one of \"line\", \"invoice\", \"storno\"",
                    query.scope
                ))),
            )
                .into_response();
        }
    };
    let limit = query.limit.unwrap_or(crate::notes_history::DEFAULT_LIMIT);
    let state_for_task = state.clone();
    let result = tokio::task::spawn_blocking(move || {
        list_notes_history_request(&state_for_task, scope, limit)
    })
    .await;
    match result {
        Ok(Ok(notes)) => Json(notes).into_response(),
        Ok(Err(e)) => internal_error("list_notes_history_request", e),
        Err(join_err) => internal_error(
            "list_notes_history_request:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

/// PR-172 — library helper backing `GET /api/notes-history`. `pub`
/// so an integration test can hit it without spinning the HTTPS
/// listener (same posture as `list_partners_request` per A159).
pub fn list_notes_history_request(
    state: &AppState,
    scope: crate::notes_history::NotesHistoryScope,
    limit: usize,
) -> Result<Vec<String>> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for notes-history scan")?;
    crate::notes_history::list_notes_history(&ledger, scope, limit)
}

// ── PR-91 — products master-data routes ──────────────────────────────
//
// Five routes (list + create on the collection; get + update + delete
// on the resource) over the per-tenant DuckDB `products` table.
// `aberp::products` owns the schema + the CRUD body; this section is
// the HTTP boundary that maps validation / not-found / 5xx onto status
// codes. Shape mirrors the partners routes by intent — the SPA's
// inline-error renderer (A157) consumes the same validation envelope.

/// PR-91 — typed error for the product route helpers. Mirrors
/// [`PartnerRouteError`].
#[derive(Debug)]
pub enum ProductRouteError {
    Validation(Vec<ProductValidationError>),
    NotFound,
    Other(anyhow::Error),
}

impl From<anyhow::Error> for ProductRouteError {
    fn from(e: anyhow::Error) -> Self {
        ProductRouteError::Other(e)
    }
}

/// PR-91 — query-string carrier for `GET /api/products?search=<needle>`.
#[derive(Debug, Deserialize)]
pub struct ListProductsQuery {
    #[serde(default)]
    pub search: Option<String>,
}

#[derive(Serialize)]
struct ProductValidationBody {
    error: &'static str,
    fields: Vec<ProductValidationError>,
}

fn product_validation_response(errors: Vec<ProductValidationError>) -> Response {
    (
        StatusCode::BAD_REQUEST,
        Json(ProductValidationBody {
            error: "validation_failed",
            fields: errors,
        }),
    )
        .into_response()
}

fn product_not_found_response() -> Response {
    (
        StatusCode::NOT_FOUND,
        Json(error_body("product not found".to_string())),
    )
        .into_response()
}

// ── GET /api/products ────────────────────────────────────────────────

/// S231 / PR-227 / ADR-0061 §6 — wire shape for the products list +
/// detail responses. Wraps [`products::Product`] with the inventory
/// cache fields per ADR-0061 §3. The chip in the SPA reads
/// `is_low_stock` straight off the wire rather than recomputing
/// client-side per CLAUDE.md rule 5.
#[derive(Serialize, Debug)]
pub struct ProductWithInventory {
    #[serde(flatten)]
    pub product: Product,
    pub stock_qty: rust_decimal::Decimal,
    pub min_stock: rust_decimal::Decimal,
    pub bin_location: Option<String>,
    pub last_movement_at: Option<String>,
    pub is_low_stock: bool,
}

fn product_with_inventory(
    product: Product,
    fields: Option<aberp_inventory::InventoryFields>,
) -> ProductWithInventory {
    let f = fields.unwrap_or(aberp_inventory::InventoryFields {
        stock_qty: rust_decimal::Decimal::ZERO,
        min_stock: rust_decimal::Decimal::ZERO,
        bin_location: None,
        last_movement_at: None,
        is_low_stock: false,
    });
    ProductWithInventory {
        product,
        stock_qty: f.stock_qty,
        min_stock: f.min_stock,
        bin_location: f.bin_location,
        last_movement_at: f.last_movement_at,
        is_low_stock: f.is_low_stock,
    }
}

async fn handle_list_products(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListProductsQuery>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let search = query.search;
    let result = tokio::task::spawn_blocking(move || {
        list_products_with_inventory_request(&state_for_task, search.as_deref())
    })
    .await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "list_products_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };
    match outcome {
        Ok(items) => Json(items).into_response(),
        Err(ProductRouteError::Other(e)) => internal_error("list_products_request", e),
        Err(ProductRouteError::Validation(_)) | Err(ProductRouteError::NotFound) => internal_error(
            "list_products_request",
            anyhow!("list_products_request surfaced unexpected Validation/NotFound"),
        ),
    }
}

pub fn list_products_request(
    state: &AppState,
    search: Option<&str>,
) -> std::result::Result<Vec<Product>, ProductRouteError> {
    let conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let items = products::list_products(&conn, state.tenant.as_str(), search)?;
    Ok(items)
}

/// S231 / PR-227 — list-products helper that merges inventory cache
/// fields into each row for the HTTP response. The pre-existing
/// [`list_products_request`] retains its `Vec<Product>` shape so the
/// PR-91 unit tests in `tests/serve_products_route.rs` continue to
/// exercise the unmodified product surface.
pub fn list_products_with_inventory_request(
    state: &AppState,
    search: Option<&str>,
) -> std::result::Result<Vec<ProductWithInventory>, ProductRouteError> {
    let conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let items = products::list_products(&conn, state.tenant.as_str(), search)?;
    let fields = aberp_inventory::inventory_fields_for_tenant(&conn, state.tenant.as_str())
        .map_err(ProductRouteError::Other)?;
    Ok(items
        .into_iter()
        .map(|p| {
            let f = fields.get(&p.id).cloned();
            product_with_inventory(p, f)
        })
        .collect())
}

// ── GET /api/products/:id ────────────────────────────────────────────

async fn handle_get_product(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(id): AxumPath<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match get_product_with_inventory_request(&state, &id) {
        Ok(p) => Json(p).into_response(),
        Err(ProductRouteError::NotFound) => product_not_found_response(),
        Err(ProductRouteError::Other(e)) => internal_error("get_product_request", e),
        Err(ProductRouteError::Validation(_)) => internal_error(
            "get_product_request",
            anyhow!("get_product_request surfaced unexpected Validation"),
        ),
    }
}

pub fn get_product_request(
    state: &AppState,
    id: &str,
) -> std::result::Result<Product, ProductRouteError> {
    let conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    match products::get_product(&conn, state.tenant.as_str(), id)? {
        Some(p) => Ok(p),
        None => Err(ProductRouteError::NotFound),
    }
}

/// S231 / PR-227 — get-product helper that merges inventory cache
/// fields for the HTTP detail response. The pre-existing
/// [`get_product_request`] retains its bare-`Product` shape so the
/// PR-91 unit tests in `tests/serve_products_route.rs` continue to
/// exercise the unmodified product surface.
pub fn get_product_with_inventory_request(
    state: &AppState,
    id: &str,
) -> std::result::Result<ProductWithInventory, ProductRouteError> {
    let conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let product = match products::get_product(&conn, state.tenant.as_str(), id)? {
        Some(p) => p,
        None => return Err(ProductRouteError::NotFound),
    };
    let fields = aberp_inventory::inventory_fields_for_product(&conn, state.tenant.as_str(), id)
        .map_err(ProductRouteError::Other)?;
    Ok(product_with_inventory(product, fields))
}

