// ── S272 / PR-261 — DEAL saga route ──────────────────────────────────

/// Inbound JSON body for `POST /api/quote-intake/:quote_id/deal`. The
/// SPA submits `deal_token` (the BIG/RED single-use input) and
/// `refresh_ack` (the typed REFRESH token, present only when the row's
/// `stock_alert` is TRUE). The server-side gate is defense-in-depth —
/// the SPA already disables the DEAL button until both fields are
/// satisfied, but this route validates again per
/// [[trust-code-not-operator]].
#[derive(Debug, serde::Deserialize)]
struct DealSagaRequest {
    deal_token: String,
    refresh_ack: Option<String>,
}

/// 409 response body shape — `code` is the machine code the SPA toast
/// routes on, `message` the operator-readable fallback copy. Mirrors
/// the storno-route shape (`{code, message}`) so the SPA's error
/// handler treats both uniformly.
#[derive(Debug, serde::Serialize)]
struct DealSagaErrorBody {
    code: &'static str,
    message: String,
}

/// `POST /api/quote-intake/:quote_id/deal` — operator clicked DEAL on
/// a quote intake row. Delegates to [`crate::quote_deal::run_deal_saga`]
/// inside a blocking task (DuckDB writes are sync) and translates the
/// typed [`crate::quote_deal::DealSagaError`] into the right 4xx
/// machine code.
async fn handle_deal_saga(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(quote_id): AxumPath<String>,
    Json(body): Json<DealSagaRequest>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(l) => l,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let quote_id_for_task = quote_id.clone();
    let result = tokio::task::spawn_blocking(move || {
        run_deal_saga_request(
            &state_for_task,
            &operator_login,
            &quote_id_for_task,
            body.deal_token,
            body.refresh_ack,
        )
    })
    .await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "run_deal_saga_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };
    match outcome {
        Ok(o) => (StatusCode::OK, Json(o)).into_response(),
        Err(e) => {
            // Downcast to the typed saga error so we map to the right
            // 4xx machine code; an opaque `anyhow::Error` falls through
            // to 500. This is the bouncer that turns ADR-0067's
            // closed-vocab failure modes into HTTP without leaking
            // anyhow chains to the SPA.
            if let Some(saga) = e.downcast_ref::<crate::quote_deal::DealSagaError>() {
                use crate::quote_deal::DealSagaError;
                let (status, code, msg) = match saga {
                    DealSagaError::NotStaged { .. } => (
                        StatusCode::NOT_FOUND,
                        saga.machine_code(),
                        format!("quote {quote_id} not staged"),
                    ),
                    DealSagaError::NotActionable { state, .. } => (
                        StatusCode::CONFLICT,
                        saga.machine_code(),
                        format!("quote {quote_id} intake_state is {state:?}; only staged rows can be dealt"),
                    ),
                    DealSagaError::DealAlreadyIssued { .. } => (
                        StatusCode::CONFLICT,
                        saga.machine_code(),
                        format!("quote {quote_id} has already been dealt"),
                    ),
                    DealSagaError::StockAlertRefreshRequired { .. } => (
                        StatusCode::CONFLICT,
                        saga.machine_code(),
                        "stock_alert active — type REFRESH to acknowledge first".to_string(),
                    ),
                    DealSagaError::DealTokenMismatch { .. } => (
                        StatusCode::CONFLICT,
                        saga.machine_code(),
                        "DEAL token does not match — copy from the reference column".to_string(),
                    ),
                    // S273 / PR-262 / ADR-0069 — material-side capacity
                    // check failed. The numbers reach the SPA so the
                    // operator sees exactly why the DEAL was refused.
                    DealSagaError::InsufficientMaterial {
                        material_grade,
                        requested,
                        on_hand,
                        already_reserved,
                        already_committed,
                        ..
                    } => (
                        StatusCode::CONFLICT,
                        saga.machine_code(),
                        format!(
                            "insufficient material {material_grade}: requested {requested}, on hand {on_hand}, already reserved {already_reserved}, already committed {already_committed}. Open Inventory Balances to fix on_hand_qty, then retry."
                        ),
                    ),
                    // S275 / PR-264 / F32 — quote validity expired. The
                    // SPA toast surfaces the date so the operator can
                    // reissue / extend the quote storefront-side.
                    DealSagaError::QuoteExpired {
                        valid_until,
                        today,
                        ..
                    } => (
                        StatusCode::CONFLICT,
                        saga.machine_code(),
                        format!(
                            "quote validity expired on {valid_until} (today is {today}). Reissue or extend the quote and retry."
                        ),
                    ),
                    DealSagaError::BelowMarginFloor { .. } => (
                        StatusCode::CONFLICT,
                        saga.machine_code(),
                        "this quote is priced below the minimum margin floor; DEAL is blocked. Raise the margin (or fix the profile) and re-price first.".to_string(),
                    ),
                };
                return (status, Json(DealSagaErrorBody { code, message: msg })).into_response();
            }
            internal_error("run_deal_saga_request", e)
        }
    }
}

/// Sync wrapper invoked inside the blocking task: opens the DuckDB
/// connection, builds the ledger meta + actor, and runs the saga.
/// Surfaces the saga's typed `DealSagaError` (boxed inside the
/// `anyhow::Error`) so the HTTP layer can downcast.
pub fn run_deal_saga_request(
    state: &AppState,
    operator_login: &str,
    quote_id: &str,
    deal_token: String,
    refresh_ack: Option<String>,
) -> Result<crate::quote_deal::DealSagaOutcome> {
    let mut conn = state
        .db
        .write()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let binary_hash = state
        .binary_hash
        .wait()
        .context("binary hash unavailable")?;
    let ledger_meta = aberp_audit_ledger::LedgerMeta::new(state.tenant.clone(), binary_hash);
    let ledger_actor = Actor::from_local_cli(Ulid::new().to_string(), operator_login);

    crate::quote_deal::run_deal_saga(
        &mut conn,
        &ledger_meta,
        ledger_actor,
        crate::quote_deal::DealSagaInputs {
            tenant: state.tenant.as_str().to_string(),
            quote_id: quote_id.to_string(),
            actor: operator_login.to_string(),
            deal_token,
            refresh_ack,
        },
    )
}

// ── S403 — operator REFUSE-with-reason route ─────────────────────────

/// Inbound JSON body for `POST /api/quote-intake/:quote_id/refuse`. The
/// SPA submits the operator's free-text `reason`. Validated server-side
/// (≥5 chars after trim, ≤2000, no control chars) per
/// [[trust-code-not-operator]] — the SPA modal also validates, but the
/// route is the source of truth and 400s a missing / short / unsafe
/// reason regardless of what the SPA sent.
#[derive(Debug, serde::Deserialize)]
struct RefuseQuoteRequest {
    reason: String,
}

/// Upper bound on the reason text. Matches the storefront's `notes` cap
/// so the `rejected`-status writeback never exceeds what the portal
/// accepts.
const REFUSE_REASON_MAX_CHARS: usize = 2000;

/// Validate + normalize the operator reason. Returns the trimmed reason
/// on success, or an operator-readable rejection message. Control chars
/// (incl. CR/LF/NUL) are refused so the reason is safe both as the
/// storefront `notes` (which rejects header-injection bytes) and as an
/// e-mail subject/body line. Pure — unit-tested.
fn validate_refuse_reason(raw: &str) -> Result<String, String> {
    let trimmed = raw.trim();
    let n = trimmed.chars().count();
    if n < crate::quote_refuse::REASON_MIN_CHARS {
        return Err(format!(
            "a refusal reason of at least {} characters is required",
            crate::quote_refuse::REASON_MIN_CHARS
        ));
    }
    if n > REFUSE_REASON_MAX_CHARS {
        return Err(format!(
            "refusal reason too long (max {REFUSE_REASON_MAX_CHARS} characters)"
        ));
    }
    if trimmed.chars().any(|c| c.is_control()) {
        return Err("refusal reason must be a single line (no control characters)".to_string());
    }
    Ok(trimmed.to_string())
}

/// `POST /api/quote-intake/:quote_id/refuse` — operator declines to
/// fulfil an accepted auto-quote. Validates the reason, runs the refuse
/// saga (state flip + audit + customer e-mail, atomic) in a blocking
/// task, then best-effort writes the storefront `rejected` status so the
/// customer portal reflects the refusal. Returns 200 even when the
/// storefront sync fails — the local refusal + customer e-mail are the
/// committed source of truth; `storefront_synced` surfaces the sync
/// result loud per CLAUDE.md #12.
async fn handle_refuse_quote(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(quote_id): AxumPath<String>,
    Json(body): Json<RefuseQuoteRequest>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(l) => l,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }

    let reason = match validate_refuse_reason(&body.reason) {
        Ok(r) => r,
        Err(msg) => {
            return (
                StatusCode::BAD_REQUEST,
                Json(DealSagaErrorBody {
                    code: "invalid_reason",
                    message: msg,
                }),
            )
                .into_response();
        }
    };

    let state_for_task = state.clone();
    let quote_id_for_task = quote_id.clone();
    let reason_for_task = reason.clone();
    let result = tokio::task::spawn_blocking(move || {
        run_refuse_saga_request(
            &state_for_task,
            &operator_login,
            &quote_id_for_task,
            reason_for_task,
        )
    })
    .await;
    let outcome = match result {
        Ok(r) => r,
        Err(join_err) => {
            return internal_error(
                "run_refuse_saga_request:join",
                anyhow!("blocking task panicked: {join_err}"),
            );
        }
    };

    let outcome = match outcome {
        Ok(o) => o,
        Err(e) => {
            if let Some(refuse) = e.downcast_ref::<crate::quote_refuse::RefuseError>() {
                use crate::quote_refuse::RefuseError;
                let (status, msg) = match refuse {
                    RefuseError::NotStaged { .. } => (
                        StatusCode::NOT_FOUND,
                        format!("quote {quote_id} not staged"),
                    ),
                    RefuseError::NotActionable { state: s, .. } => (
                        StatusCode::CONFLICT,
                        format!(
                            "quote {quote_id} intake_state is {s:?}; only staged rows can be refused"
                        ),
                    ),
                    RefuseError::AlreadyDealt { .. } => (
                        StatusCode::CONFLICT,
                        format!("quote {quote_id} has already been dealt and cannot be refused"),
                    ),
                };
                return (
                    status,
                    Json(DealSagaErrorBody {
                        code: refuse.machine_code(),
                        message: msg,
                    }),
                )
                    .into_response();
            }
            return internal_error("run_refuse_saga_request", e);
        }
    };

    // Best-effort storefront writeback of the `rejected` status + reason
    // so the customer portal (/q/{id}) reflects the refusal. The local
    // refusal + customer e-mail are already committed; a failed sync is
    // surfaced (not fatal) so the operator/daemon can reconcile.
    let storefront_synced = match state.storefront_credential.snapshot() {
        Some(cred) => {
            // `post_operator_accept` is the body-agnostic POST to the
            // storefront `/status` endpoint (it just classifies the
            // response); here we send the `rejected` status + reason.
            let post_body = serde_json::json!({
                "status": "rejected",
                "notes": reason,
            });
            let wb =
                post_operator_accept(&cred.base_url, &quote_id, &cred.bearer, &post_body).await;
            if !wb.is_success() {
                tracing::warn!(
                    target: "quote_refuse",
                    quote_id = %quote_id,
                    outcome = wb.tag(),
                    "refuse: storefront `rejected` writeback failed (local refusal + e-mail committed)"
                );
            }
            wb.is_success()
        }
        None => {
            tracing::warn!(
                target: "quote_refuse",
                quote_id = %quote_id,
                "refuse: no storefront credential — portal status not updated (e-mail still queued)"
            );
            false
        }
    };

    (
        StatusCode::OK,
        Json(serde_json::json!({
            "refused_at": outcome.refused_at,
            "customer_email_notified": outcome.email_queued,
            "storefront_synced": storefront_synced,
        })),
    )
        .into_response()
}

/// Sync wrapper invoked inside the blocking task: opens the DuckDB
/// connection, builds the ledger meta + actor, and runs the refuse saga.
/// Surfaces the saga's typed [`crate::quote_refuse::RefuseError`] (boxed
/// inside the `anyhow::Error`) so the HTTP layer can downcast.
pub fn run_refuse_saga_request(
    state: &AppState,
    operator_login: &str,
    quote_id: &str,
    reason: String,
) -> Result<crate::quote_refuse::RefuseOutcome> {
    let mut conn = state
        .db
        .write()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let binary_hash = state
        .binary_hash
        .wait()
        .context("binary hash unavailable")?;
    let ledger_meta = aberp_audit_ledger::LedgerMeta::new(state.tenant.clone(), binary_hash);
    let ledger_actor = Actor::from_local_cli(Ulid::new().to_string(), operator_login);

    crate::quote_refuse::run_refuse_saga(
        &mut conn,
        &ledger_meta,
        ledger_actor,
        crate::quote_refuse::RefuseSagaInputs {
            tenant: state.tenant.as_str().to_string(),
            quote_id: quote_id.to_string(),
            reason,
            actor: operator_login.to_string(),
        },
    )
}

// ── Session-161 — NAV poll daemon orchestration ──────────────────────

/// If `entry` is the `InvoiceDraftCreated` for `invoice_id` and carries
/// a `nav_xml_path`, return it. Mirrors the `nav_xml_path` parse posture
/// in [`derive_state_for`] / [`list_invoices`] (a future ADR that
/// changes how the path is recorded must surface in all three).
fn draft_nav_xml_path_for(entry: &Entry, invoice_id: &str) -> Option<PathBuf> {
    if entry.kind != EventKind::InvoiceDraftCreated {
        return None;
    }
    if extract_invoice_id(entry).as_deref() != Some(invoice_id) {
        return None;
    }
    let parsed: audit_payloads::InvoiceDraftCreatedPayload =
        serde_json::from_slice(&entry.payload).ok()?;
    parsed.nav_xml_path.map(PathBuf::from)
}

/// Pure core of [`query_non_terminal_invoices`]: given every audit
/// entry, return the ids of invoices that are still `Submitted` (NAV
/// accepted, no terminal ack yet) AND carry a resolvable
/// `transaction_id`. These are exactly the invoices an app-boot NAV poll
/// daemon should chase. Factored out (no `AppState`, no ledger I/O) so
/// the recovery scan is pinned by a plain in-memory-ledger test.
///
/// `PendingNavExists` is intentionally excluded: it has no
/// `InvoiceSubmissionResponse` yet, hence no `transaction_id` to poll
/// against (the retry-submit drain owns that pre-Response state, not the
/// poll daemon). `Recovered`/terminal/abandoned states are excluded by
/// the `Submitted`-only predicate.
fn non_terminal_invoice_ids_from_entries(entries: &[Entry]) -> Vec<String> {
    use std::collections::{BTreeMap, BTreeSet};
    let mut by_invoice: BTreeMap<String, InvoiceTrace> = BTreeMap::new();
    let mut has_txid: BTreeSet<String> = BTreeSet::new();
    for entry in entries {
        if let Some(id) = extract_invoice_id(entry) {
            by_invoice
                .entry(id.clone())
                .or_default()
                .merge_entry(entry, &id);
            if poll_ack::extract_transaction_id(entry, &id).is_some() {
                has_txid.insert(id.clone());
            }
        }
        if let Some(link) = extract_chain_link(entry) {
            let trace = by_invoice.entry(link.base_invoice_id).or_default();
            match link.kind {
                EventKind::InvoiceStornoIssued => trace.is_storno_base = true,
                EventKind::InvoiceModificationIssued => trace.is_amended_base = true,
                _ => {}
            }
        }
    }
    by_invoice
        .into_iter()
        .filter(|(id, trace)| {
            matches!(trace.derive_state(), InvoiceState::Submitted) && has_txid.contains(id)
        })
        .map(|(id, _)| id)
        .collect()
}

/// App-boot recovery scan — open the audit ledger and return the
/// invoice ids whose NAV state is non-terminal (`Submitted`) and which
/// have a `transaction_id` to poll against. The caller re-spawns a poll
/// daemon per id.
fn query_non_terminal_invoices(state: &AppState) -> Result<Vec<String>> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute for boot-recovery scan")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for boot-recovery scan")?;
    let entries = ledger
        .entries()
        .context("read audit ledger entries for boot-recovery scan")?;
    Ok(non_terminal_invoice_ids_from_entries(&entries))
}

/// Build the [`poll_ack::PollDaemonInputs`] for `invoice_id` from the
/// audit ledger + the on-disk NAV XML + the keychain. Resolves the
/// `transaction_id` from the latest `InvoiceSubmissionResponse`, the
/// supplier tax number from the side-stored NAV XML, and a fresh
/// per-daemon [`Actor`]. Used by BOTH the post-issue handoff and the
/// app-boot recovery spawn so they share one resolution path.
async fn build_poll_daemon_inputs(
    state: &AppState,
    invoice_id: &str,
) -> Result<poll_ack::PollDaemonInputs> {
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            other => {
                return Err(anyhow!(
                    "build_poll_daemon_inputs called in non-Ready boot state ({}); \
                     NAV setup must complete first",
                    other.state_token()
                ));
            }
        },
        Err(e) => return Err(anyhow!("boot_state RwLock poisoned: {e}")),
    };

    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute for poll daemon inputs")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger to build poll daemon inputs")?;
    let entries = ledger
        .entries()
        .context("read audit ledger entries to build poll daemon inputs")?;

    let transaction_id = entries
        .iter()
        .rev()
        .find_map(|e| poll_ack::extract_transaction_id(e, invoice_id))
        .ok_or_else(|| {
            anyhow!(
                "invoice {invoice_id}: no InvoiceSubmissionResponse audit entry; \
                 cannot start NAV poll daemon"
            )
        })?;
    let nav_xml_path = entries
        .iter()
        .find_map(|e| draft_nav_xml_path_for(e, invoice_id))
        .ok_or_else(|| {
            anyhow!(
                "invoice {invoice_id}: no nav_xml_path on InvoiceDraftCreated; \
                 cannot resolve supplier tax number for the poll daemon"
            )
        })?;
    let invoice_xml = std::fs::read(&nav_xml_path).with_context(|| {
        format!(
            "read NAV InvoiceData XML from {} for poll daemon inputs",
            nav_xml_path.display()
        )
    })?;
    let tax_number_8 = parse_supplier_tax_number_from_xml(&invoice_xml)?;

    let credentials =
        NavCredentials::load_from_keychain(state.tenant.as_str()).with_context(|| {
            format!(
                "load NAV credentials from OS keychain for tenant `{}`",
                state.tenant.as_str()
            )
        })?;
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);

    // S165 — endpoint is the compile-time build-profile choice; the
    // gate refuses a prod endpoint from a dev binary. Mirrors
    // `poll_ack_request` + `submit_invoice_request`.
    let endpoint = build_profile::nav_endpoint();
    build_profile::assert_endpoint_allowed(endpoint)?;

    Ok(poll_ack::PollDaemonInputs {
        db: state.db.clone(),
        tenant: state.tenant.clone(),
        binary_hash,
        invoice_id: invoice_id.to_string(),
        transaction_id,
        tax_number_8,
        endpoint,
        credentials,
        actor,
    })
}

/// Inspect the request's `Authorization` header against the expected
/// bearer token. Returns `Some(response)` if the request must be
/// rejected (no token, malformed token, mismatched token); returns
/// `None` if the request may proceed.
///
/// The `Option`-on-rejection shape (rather than `Result<(), Response>`)
/// avoids clippy's `result_large_err` lint — `Response` is ~128 bytes
/// and `Result` carries it in both arms. Semantically clearer too:
/// `Some(resp)` reads as "here is the rejection response."
fn check_bearer_rejection(headers: &HeaderMap, expected: &str) -> Option<Response> {
    let auth = headers
        .get(axum::http::header::AUTHORIZATION)
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if let Some(token) = auth.strip_prefix("Bearer ") {
        if constant_time_eq(token, expected) {
            return None;
        }
    }
    Some(
        (
            StatusCode::UNAUTHORIZED,
            Json(error_body("missing or invalid Bearer token".to_string())),
        )
            .into_response(),
    )
}

/// Constant-time string compare. A small loop is fine here — the
/// strings are O(64) bytes. We never want to leak token length via a
/// fast `==` exit, so we walk the longer of the two and accumulate.
fn constant_time_eq(a: &str, b: &str) -> bool {
    let a = a.as_bytes();
    let b = b.as_bytes();
    if a.len() != b.len() {
        return false;
    }
    let mut diff = 0u8;
    for i in 0..a.len() {
        diff |= a[i] ^ b[i];
    }
    diff == 0
}

fn internal_error(context_label: &'static str, e: anyhow::Error) -> Response {
    tracing::error!(error = %format!("{e:#}"), "internal error in {}", context_label);
    (
        StatusCode::INTERNAL_SERVER_ERROR,
        Json(error_body("internal error".to_string())),
    )
        .into_response()
}

/// PR-58 / session-78 — typed JSON body for NAV upstream-fault rejection
/// (HTTP-layer non-2xx returned by NAV's `tokenExchange`). Mapped to
/// HTTP 502 (Bad Gateway): the local server processed the request fine,
/// but the upstream NAV API rejected it. The four top-level fields
/// surface the operator-actionable diagnostic verbatim; the SPA's
/// invoice-detail modal renders `fault_code` + `fault_message`
/// prominently.
///
/// PR-59 / session-79 — extended with `technical_validations`, the per-
/// rule list NAV emits inside repeated `<technicalValidationMessages>`
/// elements. For NAV's most common 400 (`fault_code=INVALID_REQUEST`)
/// this array is the ACTUAL diagnostic; the top-level is just the
/// generic wrapper. Wire shape is a flat array of typed
/// [`TechnicalValidationBody`] objects (snake_case fields match the
/// SPA's TS interface in `nav-upstream-fault.test.ts`).
#[derive(Serialize)]
struct NavUpstreamFaultBody {
    error: &'static str,
    status: u16,
    fault_code: Option<String>,
    fault_message: Option<String>,
    technical_validations: Vec<TechnicalValidationBody>,
    raw_body_preview: String,
}

/// PR-59 / session-79 — wire-shape mirror of
/// [`aberp_nav_transport::operations::TechnicalValidation`]. A separate
/// struct (vs. deriving `Serialize` on the crate type) keeps the
/// nav-transport crate free of `serde` and lets the wire field names
/// be controlled here (snake_case to match the SPA's TS interface
/// `NavUpstreamFault.technical_validations`).
#[derive(Serialize)]
struct TechnicalValidationBody {
    result_code: Option<String>,
    error_code: Option<String>,
    message: Option<String>,
    tag: Option<String>,
}

impl From<TechnicalValidation> for TechnicalValidationBody {
    fn from(v: TechnicalValidation) -> Self {
        Self {
            result_code: v.result_code,
            error_code: v.error_code,
            message: v.message,
            tag: v.tag,
        }
    }
}

fn nav_upstream_fault_response(
    context_label: &'static str,
    status: u16,
    fault_code: Option<String>,
    fault_message: Option<String>,
    technical_validations: Vec<TechnicalValidation>,
    body_preview: String,
) -> Response {
    tracing::error!(
        nav_status = status,
        fault_code = ?fault_code,
        fault_message = ?fault_message,
        technical_validations_len = technical_validations.len(),
        body_preview = %body_preview,
        "NAV upstream fault in {}",
        context_label,
    );
    let technical_validations: Vec<TechnicalValidationBody> = technical_validations
        .into_iter()
        .map(TechnicalValidationBody::from)
        .collect();
    (
        StatusCode::BAD_GATEWAY,
        Json(NavUpstreamFaultBody {
            error: "nav_upstream_fault",
            status,
            fault_code,
            fault_message,
            technical_validations,
            raw_body_preview: body_preview,
        }),
    )
        .into_response()
}

#[derive(Serialize)]
struct ErrorBody {
    error: String,
}

fn error_body(error: String) -> ErrorBody {
    ErrorBody { error }
}

// ── Read paths over billing DB + audit ledger ────────────────────────

fn list_invoices(state: &AppState) -> Result<Vec<InvoiceListItem>> {
    // The audit ledger is the source of truth for "what invoices
    // exist." Walk every entry once; group by invoice_id; derive
    // state.
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for serve list")?;
    let entries = ledger.entries().context("read audit ledger entries")?;

    // PR-65 / session-86 — sidecar map from invoice_id to the
    // `InvoiceDraftCreated` payload's `nav_xml_path`. Collected on
    // the same single walk so the items loop below can resolve each
    // invoice's side-store path (via `sibling_input_json_path`)
    // without a second ledger scan. Mirrors the parse posture in
    // `derive_state_for` so a future ADR that changes how nav_xml_path
    // is recorded surfaces in both places.
    let mut nav_xml_paths: std::collections::BTreeMap<String, std::path::PathBuf> =
        Default::default();
    let mut by_invoice: std::collections::BTreeMap<String, InvoiceTrace> = Default::default();
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            by_invoice
                .entry(id.clone())
                .or_default()
                .merge_entry(entry, &id);
            if entry.kind == EventKind::InvoiceDraftCreated {
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceDraftCreatedPayload,
                >(&entry.payload)
                {
                    if let Some(path_str) = parsed.nav_xml_path {
                        nav_xml_paths.insert(id.clone(), std::path::PathBuf::from(path_str));
                    }
                }
            }
        }
        // PR-23 / ADR-0036 §4 — chain-link entries do not carry a
        // top-level `invoice_id` field; they carry
        // `storno_invoice_id` / `modification_invoice_id` (the
        // chain invoice's own id, which already enters `by_invoice`
        // via its own InvoiceSequenceReserved + InvoiceDraftCreated
        // pair) AND `base_invoice_id` (the chain link's anchor,
        // which is what flips the BASE invoice's trace into Storno
        // / Amended). Probe extracts both ids so this base-side
        // trace flip and the PR-32 chain-children walker (in
        // `get_invoice_detail`) share one parse per chain entry.
        if let Some(link) = extract_chain_link(entry) {
            // ADR-0049 §Screen render — flag the storno CHILD's own row so
            // the SPA list negates its total. Do this before the base flip
            // so `child_invoice_id` is read before the move below.
            if link.kind == EventKind::InvoiceStornoIssued {
                by_invoice
                    .entry(link.child_invoice_id)
                    .or_default()
                    .is_storno_self = true;
            }
            let trace = by_invoice.entry(link.base_invoice_id).or_default();
            match link.kind {
                EventKind::InvoiceStornoIssued => trace.is_storno_base = true,
                EventKind::InvoiceModificationIssued => trace.is_amended_base = true,
                _ => {}
            }
        }
    }

    // Load billing details for each invoice id.
    let mut items: Vec<InvoiceListItem> = Vec::new();
    let mut conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    // S242 / PR-236 — same `YYYY-MM-DD` format the detail-modal
    // path emits (`get_invoice_detail` uses an identical descriptor);
    // both surfaces feed the SPA's `formatInvoiceDate` HU display
    // form. Declared once outside the loop so the per-row format()
    // call reuses the descriptor.
    let date_fmt = ::time::macros::format_description!("[year]-[month]-[day]");
    for (id, trace) in by_invoice {
        let row = match read_invoice_row(&mut conn, &id)? {
            Some(row) => row,
            None => continue, // ledger has it but billing row gone — skip silently
        };
        let buyer_name = nav_xml_paths
            .get(&id)
            .and_then(|p| read_buyer_name_from_side_store(p));
        let payment = trace.payment.clone().map(PaymentRecordSummary::from);
        let issue_date = row.ready_invoice.issue_date.date().format(date_fmt).ok();
        // S262 / PR-251 — resolved payment deadline (NULL→issue_date per
        // PR-84) for the AR-aging click-through. Same descriptor as
        // issue_date so both surface identical YYYY-MM-DD strings.
        let payment_deadline = row.ready_invoice.payment_deadline.format(date_fmt).ok();
        items.push(InvoiceListItem {
            invoice_id: id,
            sequence_number: row.ready_invoice.sequence_number,
            fiscal_year: row.ready_invoice.fiscal_year,
            state: trace.derive_state(),
            total_gross: row.ready_invoice.total_gross().map(|h| h.as_i64()),
            has_chain_children: trace.is_storno_base || trace.is_amended_base,
            is_storno: trace.is_storno_self,
            currency: row.currency_metadata.currency,
            buyer_name,
            payment,
            // PR-73 / ADR-0040 §addendum — bank-account snapshot on the
            // list row. `None` for pre-PR-73 / CLI-issued rows.
            bank_account: row
                .bank_snapshot
                .clone()
                .map(BankAccountSnapshotResponse::from_typed),
            row_kind: RowKind::Own,
            source_nav_invoice_number: None,
            issue_date,
            payment_deadline,
        });
    }
    // PR-213 / S215 — virtual union with `restored_invoice` (the
    // S180 NAV-as-DR mirror table). Neither table gets a `row_kind`
    // column; the union lives only here and on the wire shape per
    // ADR-0058. `restored_invoice` carries NAV-mirror rows the
    // tenant did NOT issue through ABERP (Billingo, manual, etc.) —
    // we can see them via `queryInvoiceDigest OUTBOUND` but cannot
    // act on them. ExtNav rows synthesize an `InvoiceListItem` with
    // `state: InvoiceState::Unknown` (we don't have the NAV lifecycle
    // from a digest), every operational field set to `None`
    // (`payment` / `bank_account` / `buyer_name` — the digest
    // doesn't carry buyer info), `sequence_number: 0` (placeholder),
    // and `fiscal_year` taken from `restore_year`. The `currency`
    // string is parsed via `Currency::iso_code` round-trip
    // (`HUF`/`EUR`); the app-layer `parse_digest_currency` gate
    // (S410 / [[no-sql-specific]] — no DB CHECK) makes any other value a
    // bug we surface loudly per CLAUDE.md rule 12.
    let restored = restore_outgoing::list_restored(&state.db_path, state.tenant.as_str())
        .context("read restored_invoice mirror for unified list")?;
    for ext in restored {
        items.push(restored_to_list_item(ext)?);
    }
    // S236 / PR-230b — third row source: `invoice_draft`. Drafts have
    // no allocated sequence (gap-free allocator hasn't run); they
    // surface in the unified list as `InvoiceState::Draft` with
    // `RowKind::Own` (they're our drafts) and `sequence_number: 0`
    // placeholder. The SPA renders them with a distinct chip and
    // disables NAV submit + PDF affordances; the operator's Issue
    // click promotes them through the existing allocator.
    let drafts = invoice_draft::list_drafts(&conn, state.tenant.as_str())
        .context("read invoice_draft mirror for unified list")?;
    for d in drafts {
        items.push(draft_to_list_item(d, &mut conn, state.tenant.as_str())?);
    }
    Ok(items)
}

/// PR-213 / S215 — pure mapping from a `restored_invoice` row to the
/// virtual-union [`InvoiceListItem`] wire shape per ADR-0058. Carries
/// the entire ExtNav-arm synthesis invariant in one place so the unit
/// test pin can reach it without a full AppState/ledger build-up.
///
/// CLAUDE.md rule 12 — closed-vocab currency is `Currency::iso_code`-
/// round-tripped; an unknown string loud-fails rather than silently
/// defaulting. This match (plus `parse_digest_currency` at the write
/// boundary) is the authoritative gate — S410 / [[no-sql-specific]]
/// removed the DuckDB `CHECK (currency IN ('HUF','EUR'))` from
/// `restored_invoice`.
fn restored_to_list_item(ext: restore_outgoing::RestoredInvoice) -> Result<InvoiceListItem> {
    let currency = match ext.currency.as_str() {
        "HUF" => Currency::Huf,
        "EUR" => Currency::Eur,
        other => {
            return Err(anyhow!(
                "restored_invoice.currency `{}` is not in the closed vocab \
                 (HUF/EUR) — DuckDB CHECK constraint should have rejected it",
                other
            ));
        }
    };
    // PR-216 / S218 — surface the in-row buyer snapshot
    // (`customer_name`) on the wire as `buyer_name`, matching the
    // Own-row convention (`InvoiceListItem.buyer_name = customer.name`
    // from the side-store `<ULID>.input.json`). Pre-backfill rows
    // carry NULL → `None`, which the SPA renders as the em-dash; the
    // 14 prod rows imported on 2026-06-01 sit in this state until the
    // boot-time backfill task ([`restore_outgoing::run_buyer_backfill_once`])
    // refills them from `queryInvoiceData`.
    Ok(InvoiceListItem {
        invoice_id: ext.id,
        sequence_number: 0,
        fiscal_year: ext.restore_year,
        state: InvoiceState::Unknown,
        total_gross: Some(ext.total_gross_minor),
        has_chain_children: false,
        is_storno: false,
        currency,
        buyer_name: ext.customer_name,
        payment: None,
        bank_account: None,
        row_kind: RowKind::ExtNav,
        source_nav_invoice_number: Some(ext.source_nav_invoice_number),
        // S242 / PR-236 — restored_invoice.issue_date is the NAV-emitted
        // `<invoiceIssueDate>` (NOT NULL by schema + `process_digest`
        // loud-fails when absent), already in `YYYY-MM-DD` form.
        issue_date: Some(ext.issue_date),
        // S262 / PR-251 — the digest mirror carries no payment deadline.
        payment_deadline: None,
    })
}

/// S236 / PR-230b — pure mapping from an `invoice_draft` row to the
/// virtual-union [`InvoiceListItem`] wire shape. Drafts have NO
/// allocated sequence (gap-free allocator hasn't run) and NO computed
/// total (the draft only carries the bridge data — partner_id +
/// product_id + qty); the SPA renders a placeholder for both. Buyer
/// name is best-effort looked up on the partner master since the
/// draft row stores only `partner_id`.
///
/// Closed-vocab `state: InvoiceState::Draft`. `RowKind::Own` because
/// drafts are ABERP-staged (vs. NAV-mirror ExtNav rows from S180).
/// `currency: Currency::Huf` placeholder — the draft v1 doesn't carry
/// a currency choice; the operator's Issue click resolves it from the
/// partner's saved defaults (the existing IssueInvoice form chooses).
fn draft_to_list_item(
    draft: invoice_draft::InvoiceDraft,
    conn: &mut Connection,
    tenant: &str,
) -> Result<InvoiceListItem> {
    let buyer_name = partners::get_partner(conn, tenant, &draft.partner_id)
        .ok()
        .flatten()
        .map(|p| p.legal_name);
    Ok(InvoiceListItem {
        invoice_id: draft.drf_id,
        sequence_number: 0,
        fiscal_year: 0,
        state: InvoiceState::Draft,
        total_gross: None,
        has_chain_children: false,
        is_storno: false,
        currency: Currency::Huf,
        buyer_name,
        payment: None,
        bank_account: None,
        row_kind: RowKind::Own,
        source_nav_invoice_number: None,
        // S242 / PR-236 — drafts have NO issue date by construction;
        // the SPA renders an empty cell (NOT an em-dash placeholder
        // per the PR brief) so the Outgoing column reflects "not yet
        // issued" without inventing a sentinel.
        issue_date: None,
        // S262 / PR-251 — pre-issuance drafts have no deadline; aging
        // excludes Draft rows by construction.
        payment_deadline: None,
    })
}

/// PR-65 / session-86 — best-effort read of the side-stored
/// [`InvoiceInputJson`] alongside a NAV-XML path, returning the
/// `customer.name` field for the SPA's Partner column. Returns
/// `None` for any failure (missing file, unreadable, malformed
/// JSON, blank name) — the list endpoint must not loud-fail when
/// the read-side enrichment misses, since the side-store is only
/// present for PR-47α+ SPA-issued invoices (CLI-issued invoices
/// and pre-PR-47α SPA-issued invoices never wrote one). Pinned by
/// `read_buyer_name_from_side_store_round_trip`.
fn read_buyer_name_from_side_store(nav_xml_path: &std::path::Path) -> Option<String> {
    let path = sibling_input_json_path(nav_xml_path);
    let bytes = std::fs::read(&path).ok()?;
    let parsed: issue_invoice::InvoiceInputJson = serde_json::from_slice(&bytes).ok()?;
    let trimmed = parsed.customer.name.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed.to_string())
    }
}

/// S369 / S370 — derive a chain child's own lifecycle state + latest
/// NAV ack from already-loaded ledger entries. Mirrors the
/// `get_invoice_detail` / `derive_state_for` trace walk for ONE child id
/// (no extra DB open — re-uses the caller's `entries` slice). Used to
/// surface a NAV-rejected storno / modification (the `ABORTED` ack NAV
/// returns for `INVOICE_LINE_ALREADY_EXISTS`) on the BASE's
/// chain-children list, which before S369 rendered only the kind chip
/// and so hid the failure. The chain-link flips mirror `derive_state_for`
/// so a child that is itself a chain base (e.g. a storno later modified)
/// derives its own terminal state correctly.
fn derive_chain_child_state(
    entries: &[Entry],
    child_id: &str,
) -> (InvoiceState, Option<AckStatus>) {
    let mut trace = InvoiceTrace::default();
    for entry in entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == child_id {
                trace.merge_entry(entry, child_id);
            }
        }
        if let Some(link) = extract_chain_link(entry) {
            if link.base_invoice_id == child_id {
                match link.kind {
                    EventKind::InvoiceStornoIssued => trace.is_storno_base = true,
                    EventKind::InvoiceModificationIssued => trace.is_amended_base = true,
                    _ => {}
                }
            } else if link.kind == EventKind::InvoiceStornoIssued
                && link.child_invoice_id == child_id
            {
                trace.is_storno_self = true;
            }
        }
    }
    let last_ack = trace.last_ack_status.as_deref().and_then(parse_ack_status);
    (trace.derive_state(), last_ack)
}

fn get_invoice_detail(state: &AppState, invoice_id: &str) -> Result<Option<InvoiceDetailResponse>> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for serve detail")?;
    let entries = ledger.entries().context("read audit ledger entries")?;

    let mut trace = InvoiceTrace::default();
    let mut audit_entries: Vec<AuditEntryView> = Vec::new();
    let mut chain_children: Vec<ChainChildView> = Vec::new();
    let mut found_any = false;
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == invoice_id {
                found_any = true;
                trace.merge_entry(entry, invoice_id);
                audit_entries.push(audit_view_of(entry));
            }
        }
        // PR-23 / ADR-0036 §4 — chain-link entries: flip the
        // base's trace into Storno / Amended. Detail view is
        // queried by id, so we only flip when this id IS the
        // base. The chain-link entry itself does NOT appear in
        // `audit_entries` for the base's detail view — those
        // entries belong to the storno / modification invoice's
        // own audit lineage; the base's lineage references them
        // only via the derived state label per ADR-0009 §2.
        //
        // PR-32 / session-36 — same pass also collects the
        // chain CHILD's id into `chain_children` so the detail
        // modal can list "WHICH children" alongside the badge's
        // "has children." Ordering is ledger-walk order
        // (insertion order into `Vec`), which is monotonically
        // increasing seq per ADR-0008 — operator-meaningful as
        // "chain entries in the order they were issued."
        if let Some(link) = extract_chain_link(entry) {
            if link.base_invoice_id == invoice_id {
                found_any = true;
                match link.kind {
                    EventKind::InvoiceStornoIssued => {
                        trace.is_storno_base = true;
                        // S369 — compute the storno child's own state +
                        // ack so the base's chain-children row surfaces a
                        // NAV-rejected storno (ABORTED ack), not just the
                        // kind chip.
                        let child_id = link.child_invoice_id;
                        let (child_state, child_ack) =
                            derive_chain_child_state(&entries, &child_id);
                        chain_children.push(ChainChildView {
                            kind: ChainChildKind::Storno,
                            invoice_id: child_id,
                            modification_index: link.modification_index,
                            state: child_state,
                            last_ack_status: child_ack,
                        });
                    }
                    EventKind::InvoiceModificationIssued => {
                        trace.is_amended_base = true;
                        let child_id = link.child_invoice_id;
                        let (child_state, child_ack) =
                            derive_chain_child_state(&entries, &child_id);
                        chain_children.push(ChainChildView {
                            kind: ChainChildKind::Amended,
                            invoice_id: child_id,
                            modification_index: link.modification_index,
                            state: child_state,
                            last_ack_status: child_ack,
                        });
                    }
                    _ => {}
                }
            } else if link.kind == EventKind::InvoiceStornoIssued
                && link.child_invoice_id == invoice_id
            {
                // ADR-0049 §Screen render — this invoice IS the storno.
                // The `InvoiceStornoIssued` payload carries no top-level
                // `invoice_id`, so `extract_invoice_id` never attributes
                // it to the storno's own audit lineage; this chain-link
                // walk is the only place the storno child's id surfaces.
                trace.is_storno_self = true;
                found_any = true;
            }
        }
    }

    let mut conn = state
        .db
        .read()
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let billing = read_invoice_row(&mut conn, invoice_id)?;

    if !found_any && billing.is_none() {
        return Ok(None);
    }

    // PR-44ε / session-53 — split the billing read into the four
    // non-currency fields the prior wire shape carried plus the
    // five currency-aware fields (`currency` always present;
    // exchange-rate + source + date + huf_equivalent only on the
    // non-HUF branch). When the billing row is gone but the ledger
    // remembers the invoice (the rare `Unknown`-derived branch), we
    // default `currency` to `Currency::Huf` so the wire shape stays
    // valid; the four rate fields stay `None` because there is no
    // metadata to surface.
    let (
        sequence_number,
        fiscal_year,
        total_gross,
        currency_metadata,
        bank_snapshot,
        invoice_note,
        line_notes,
        invoice_dates,
    ) = match billing {
        Some(row) => {
            // PR-82 — assemble the per-line notes view by walking
            // `row.ready_invoice.lines` (which carries each line's
            // `description` + `note` via the post-PR-82
            // `load_invoice` read). Filter out unannotated lines so
            // the SPA renderer can iterate the array directly
            // without per-row None checks.
            let line_notes_view: Vec<LineNoteView> = row
                .ready_invoice
                .lines
                .iter()
                .enumerate()
                .filter_map(|(idx, line)| {
                    let note_text = line.note.as_ref()?.trim();
                    if note_text.is_empty() {
                        return None;
                    }
                    Some(LineNoteView {
                        ordinal: idx as u32,
                        description: line.description.clone(),
                        note: note_text.to_string(),
                    })
                })
                .collect();
            // PR-99 Item 5 — three dates surfaced to the detail wire.
            // `ready_invoice.issue_date` is OffsetDateTime; the other
            // two are `Date`. All three render as canonical YYYY-MM-DD
            // for the SPA (the SPA's renderer reformats to the
            // operator's locale display form).
            let date_fmt = ::time::macros::format_description!("[year]-[month]-[day]");
            let issue_date = row.ready_invoice.issue_date.date().format(date_fmt).ok();
            let payment_deadline = row.ready_invoice.payment_deadline.format(date_fmt).ok();
            let delivery_date = row.ready_invoice.delivery_date.format(date_fmt).ok();
            (
                row.ready_invoice.sequence_number,
                row.ready_invoice.fiscal_year,
                row.ready_invoice.total_gross().map(|h| h.as_i64()),
                row.currency_metadata,
                row.bank_snapshot,
                row.invoice_note,
                line_notes_view,
                (issue_date, payment_deadline, delivery_date),
            )
        }
        None => (
            0,
            0,
            None,
            InvoiceCurrencyMetadata {
                currency: Currency::Huf,
                exchange_rate: None,
                exchange_rate_source: None,
                exchange_rate_date: None,
                huf_equivalent_total: None,
            },
            None,
            None,
            Vec::new(),
            (None, None, None),
        ),
    };
    // PR-33 / session-37 — typed wire emit of the latest NAV ack
    // for this invoice. `trace.last_ack_status` carries the raw
    // persisted string from `InvoiceAckStatusPayload.ack_status`;
    // parse it to the four-valued `AckStatus` enum at the wire
    // boundary. Unknown strings fall through to `None` (the audit-
    // entries drill-down still exposes the raw value).
    let last_ack_status = trace.last_ack_status.as_deref().and_then(parse_ack_status);
    let payment = trace.payment.clone().map(PaymentRecordSummary::from);
    Ok(Some(InvoiceDetailResponse {
        invoice_id: invoice_id.to_string(),
        sequence_number,
        fiscal_year,
        state: trace.derive_state(),
        total_gross,
        is_storno: trace.is_storno_self,
        audit_entries,
        chain_children,
        last_ack_status,
        currency: currency_metadata.currency,
        exchange_rate: currency_metadata.exchange_rate,
        exchange_rate_source: currency_metadata.exchange_rate_source,
        exchange_rate_date: currency_metadata.exchange_rate_date,
        huf_equivalent_total: currency_metadata.huf_equivalent_total,
        payment,
        // PR-73 / ADR-0040 §addendum — bank-account snapshot for the
        // SPA's "Pay to" sub-section. `null` for pre-PR-73 / CLI rows.
        bank_account: bank_snapshot.map(BankAccountSnapshotResponse::from_typed),
        // PR-82 — buyer-facing notes (global + per-line). NEVER on
        // the NAV XML wire (see ADR-0042); the SPA's
        // `InvoiceDetail.svelte` renders them so the operator can
        // preview what the buyer will see on the printed PDF.
        invoice_note,
        line_notes,
        // PR-99 Item 5 — three dates rendered on the detail meta-grid.
        issue_date: invoice_dates.0,
        payment_deadline: invoice_dates.1,
        delivery_date: invoice_dates.2,
    }))
}

fn get_audit_for_invoice(state: &AppState, invoice_id: &str) -> Result<Vec<AuditEntryView>> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for serve audit")?;
    let entries = ledger.entries().context("read audit ledger entries")?;
    let mut out = Vec::new();
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == invoice_id {
                out.push(audit_view_of(entry));
            }
        }
    }
    Ok(out)
}

fn audit_view_of(entry: &Entry) -> AuditEntryView {
    // PR-27 — the full typed payload as raw JSON. Every
    // `audit_payloads::*` type serialises via `serde_json::to_vec`
    // (F9 — closed in PR-6.1) so the bytes always parse cleanly;
    // a malformed payload falls back to `Null` rather than
    // panicking, so a corrupted entry is inspector-visible per
    // CLAUDE.md rule 12.
    let mut payload = serde_json::from_slice::<serde_json::Value>(&entry.payload)
        .unwrap_or(serde_json::Value::Null);
    // PR-76 — when the entry is an `InvoiceAckStatus`, parse the
    // `<technicalValidationMessages>` array out of the verbatim NAV
    // ack body (`response_xml`) and graft it onto the payload as a
    // sibling field. The SPA's `invoice-timeline.ts` renders the array
    // inline under the ack node so an operator staring at "Rejected"
    // in the state chip sees WHY without digging through logs. Only
    // ABORTED acks actually carry validation messages; SAVED /
    // PROCESSING / RECEIVED parse to an empty array, which the SPA
    // renders as nothing additional — the field name is the same
    // either way so the wire shape stays uniform.
    if entry.kind == EventKind::InvoiceAckStatus {
        if let Some(messages) = parse_ack_technical_validations(&payload) {
            if let serde_json::Value::Object(ref mut map) = payload {
                map.insert(
                    "technical_validation_messages".to_string(),
                    serde_json::json!(messages
                        .into_iter()
                        .map(TechnicalValidationBody::from)
                        .collect::<Vec<_>>()),
                );
            }
        }
    }
    AuditEntryView {
        seq: entry.seq.as_u64(),
        kind: format!("{:?}", entry.kind),
        actor: entry.actor.user_id.clone(),
        // ADR-0008 §"Entry shape" names two timestamps: `time_wall`
        // (RFC3339, operator-readable) and `time_mono` (monotonic
        // nanos since process start, drift-immune). The serve view
        // wants the operator-readable form.
        occurred_at: entry.time_wall.to_string(),
        // PR-26 — reuse the existing chain-link probe. The probe
        // already short-circuits on kind first per ADR-0036 §4, so
        // the cost is bounded for non-chain entries. PR-32 widened
        // the probe's return to also carry the chain child id; the
        // audit-entry view consumes only the base id here.
        chain_base_invoice_id: extract_chain_link(entry).map(|link| link.base_invoice_id),
        payload,
    }
}

/// PR-76 — extract the `response_xml` bytes from an
/// [`audit_payloads::InvoiceAckStatusPayload`] JSON Value and parse the
/// per-rule `<technicalValidationMessages>` array out of them. Returns
/// `None` when the payload shape does not match (corrupt entry — the
/// caller leaves the payload unchanged so the inspector-visible
/// fall-back posture from `audit_view_of` carries over).
fn parse_ack_technical_validations(
    payload: &serde_json::Value,
) -> Option<Vec<TechnicalValidation>> {
    let bytes_arr = payload.get("response_xml")?.as_array()?;
    let mut bytes: Vec<u8> = Vec::with_capacity(bytes_arr.len());
    for v in bytes_arr {
        let n = v.as_u64()?;
        if n > 0xFF {
            return None;
        }
        bytes.push(n as u8);
    }
    find_all_technical_validations(&bytes).ok()
}

/// PR-44ε / session-53 — currency-aware billing read bundle.
///
/// The pre-PR-44ε `read_invoice_row` returned just
/// `(ReadyInvoice, IdempotencyKey)`. PR-44ε threads the five
/// PR-44γ-added DuckDB columns (`currency`, `exchange_rate`,
/// `exchange_rate_source`, `exchange_rate_date`,
/// `huf_equivalent_total`) into the same read so the list-row +
/// detail-modal wire surfaces (`InvoiceListItem` /
/// `InvoiceDetailResponse`) can render currency + rate metadata
/// without a second DB hit. The currency lookup runs inside the
/// same `Transaction` as `load_ready_invoice_by_id`, keeping the
/// per-invoice read at one open-tx-commit per the existing serve
/// posture.
///
/// The `IdempotencyKey` is preserved on the bundle even though no
/// PR-44ε caller consumes it — `read_invoice_row` is a shared
/// helper between `list_invoices` and `get_invoice_detail`, and
/// future callers (chain-currency-match diagnostics, retry-side
/// idempotency assertions) may want the key. Dropping it would be
/// a regression on the pre-PR-44ε surface; keeping it is zero
/// runtime cost (the value was read inside `load_ready_invoice_by_id`
/// regardless).
struct ReadInvoiceRow {
    ready_invoice: ReadyInvoice,
    #[allow(dead_code)]
    idempotency_key: billing::IdempotencyKey,
    currency_metadata: InvoiceCurrencyMetadata,
    /// PR-73 / ADR-0040 §addendum — typed bank-account snapshot loaded
    /// from the five `bank_account_*` invoice columns. `None` for pre-
    /// PR-73 / CLI-issued rows (those rows have NULL across all five
    /// columns; `InvoiceBankSnapshot.into_typed()` returns `None`).
    bank_snapshot: Option<aberp_billing::BankAccountSnapshot>,
    /// PR-82 — buyer-facing per-invoice note ("Megjegyzés") loaded
    /// from the `invoice.invoice_note` column. `None` for invoices the
    /// operator did not annotate AND for pre-PR-82 rows (the migration
    /// added the column without backfill). Per-line notes ride on
    /// `ready_invoice.lines[i].note` via the billing crate's
    /// `load_invoice` read.
    invoice_note: Option<String>,
}

/// Scoped read tx + billing lookup; returns None if the row is not
/// present.
fn read_invoice_row(conn: &mut Connection, invoice_id: &str) -> Result<Option<ReadInvoiceRow>> {
    let tx = conn
        .transaction()
        .context("begin read transaction for invoice lookup (serve)")?;
    let pair = billing::load_ready_invoice_by_id(&tx, invoice_id)
        .context("billing::load_ready_invoice_by_id (serve)")?;
    let pair = match pair {
        Some(p) => p,
        None => {
            tx.commit().context("commit read transaction (serve)")?;
            return Ok(None);
        }
    };
    let currency_metadata = load_invoice_currency_metadata_in_tx(&tx, invoice_id)
        .context("load_invoice_currency_metadata_in_tx (serve)")?;
    // PR-73 / ADR-0040 §addendum — read the five bank-snapshot columns
    // in the same tx so list + detail share one read trip.
    let bank_snapshot = load_invoice_bank_snapshot_in_tx(&tx, invoice_id)
        .context("load_invoice_bank_snapshot_in_tx (serve)")?
        .into_typed();
    // PR-82 — read the buyer-facing per-invoice note in the SAME tx so
    // the list + detail wire surfaces share one read trip with the rest
    // of the row's data. Per-line notes already round-trip through
    // `pair.0.lines[i].note` because `load_ready_invoice_by_id` selects
    // the column.
    let invoice_note = billing::load_invoice_note_in_tx(&tx, invoice_id)
        .context("billing::load_invoice_note_in_tx (serve)")?;
    tx.commit().context("commit read transaction (serve)")?;
    Ok(Some(ReadInvoiceRow {
        ready_invoice: pair.0,
        idempotency_key: pair.1,
        currency_metadata,
        bank_snapshot,
        invoice_note,
    }))
}

// ── State derivation from the audit-ledger trace ─────────────────────

/// Per-invoice accumulator for the audit-ledger walk.
///
/// PR-23 / ADR-0036 §2 extends this with four new fact-bits over
/// the pre-PR-23 five-bit shape (`has_draft`,
/// `has_submission_response`, `has_retry_requested`,
/// `has_marked_abandoned`, `last_ack_status`):
///
///   - `has_attempt` — `InvoiceSubmissionAttempt` exists for this
///     invoice (PR-19 / ADR-0032 §4). Drives the `Pending` /
///     `PendingNavExists` labels at the state-2 ladder branch.
///   - `latest_response_is_recovered` — the most-recent
///     `InvoiceSubmissionResponse`'s `response_xml` carries
///     `<QueryInvoiceDataResponse>` bytes per ADR-0034 §4. Drives
///     the `Recovered` vs `Submitted` distinction at the state-3
///     ladder branch.
///   - `latest_check_outcome` — the most-recent
///     `InvoiceCheckPerformed`'s `outcome` field (PR-20 / ADR-0033
///     §6). Drives the `PendingNavExists` sub-label.
///   - `is_storno_base` / `is_amended_base` — set by
///     [`extract_chain_link`] from
///     `InvoiceStornoIssuedPayload` / `InvoiceModificationIssuedPayload`
///     entries whose `base_invoice_id` equals this invoice's id
///     (PR-10 / ADR-0023, PR-11 / ADR-0024). Drives the `Storno` /
///     `Amended` labels.
#[derive(Default)]
struct InvoiceTrace {
    has_draft: bool,
    /// PR-23 / ADR-0036 §2 — state-2 Pending evidence.
    has_attempt: bool,
    has_submission_response: bool,
    /// PR-23 / ADR-0036 §5 — most-recent Response's
    /// recovered-or-original discriminator.
    latest_response_is_recovered: bool,
    has_retry_requested: bool,
    has_marked_abandoned: bool,
    last_ack_status: Option<String>,
    /// PR-23 / ADR-0036 §6 — most-recent Layer-2 check outcome.
    /// Values per ADR-0033 §2: `"exists"` / `"absent"` / `"failure"`.
    latest_check_outcome: Option<String>,
    /// PR-23 / ADR-0036 §4 — base of an `InvoiceStornoIssued` chain
    /// entry. Set via [`extract_chain_link`].
    is_storno_base: bool,
    /// PR-23 / ADR-0036 §4 — base of an `InvoiceModificationIssued`
    /// chain entry. Set via [`extract_chain_link`].
    is_amended_base: bool,
    /// ADR-0049 §Screen render (session 156) — this invoice IS a storno
    /// (the chain CHILD, not the base). Set via [`extract_chain_link`]
    /// when an `InvoiceStornoIssued` entry's `storno_invoice_id`
    /// (`child_invoice_id`) equals this invoice's id. The billing tables
    /// store the storno line with a POSITIVE `unit_price` (negation lives
    /// only in the NAV-XML render path), so the SPA needs this flag to
    /// negate the displayed total — matching the buyer-facing PDF, which
    /// parses the negated NAV XML. Does NOT change `derive_state` (the
    /// storno child's own NAV ladder is independent of being a storno).
    is_storno_self: bool,
    /// PR-70 / ADR-0039 §2 — most-recent `InvoicePaymentRecorded`
    /// payload's operator-facing fields for the SPA's Paid chip.
    /// `Some(...)` when at least one payment entry exists for this
    /// invoice; the audit ledger is append-only so once `Some`,
    /// stays `Some`. Does NOT change `derive_state` — paid-vs-unpaid
    /// is operational metadata, separate from the NAV regulatory
    /// ladder per ADR-0039 §3.
    payment: Option<PaymentRecord>,
    /// S434 — an `InvoiceLocalOnlyEmitted` entry exists for this invoice
    /// (issued under a NAV-disabled tenant; never submitted to NAV). Set
    /// via `merge_entry`; read by `derive_state` to return `LocalOnly`.
    has_local_only: bool,
}

impl InvoiceTrace {
    fn merge_entry(&mut self, entry: &Entry, invoice_id: &str) {
        match entry.kind {
            EventKind::InvoiceDraftCreated => self.has_draft = true,
            EventKind::InvoiceSubmissionAttempt => {
                // PR-23 / ADR-0036 §2 — state-2 Pending evidence.
                // The cross-invoice contamination guard parses the
                // payload's `invoice_id` field; pre-PR-23 the
                // walker collapsed Attempt into the catch-all `_`
                // arm and the Pending classification was invisible
                // at the UI layer.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceSubmissionAttemptPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.has_attempt = true;
                    }
                }
            }
            EventKind::InvoiceSubmissionResponse => {
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceSubmissionResponsePayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.has_submission_response = true;
                        // PR-23 / ADR-0036 §5 — mirror the
                        // verifier's A91 prefix-match: a response
                        // whose first ~512 bytes contain
                        // `QueryInvoiceDataResponse` was emitted
                        // by `recover-from-nav` per ADR-0034 §4.
                        // Walk is in seq order; the LAST Response
                        // wins — `latest_response_is_recovered`
                        // is overwritten on each match.
                        self.latest_response_is_recovered =
                            is_recovered_response_xml(&parsed.response_xml);
                    }
                }
            }
            EventKind::InvoiceAckStatus => {
                if let Ok(parsed) = serde_json::from_slice::<audit_payloads::InvoiceAckStatusPayload>(
                    &entry.payload,
                ) {
                    if parsed.invoice_id == invoice_id {
                        self.last_ack_status = Some(parsed.ack_status);
                    }
                }
            }
            EventKind::InvoiceCheckPerformed => {
                // PR-23 / ADR-0036 §6 — Layer-2 outcome. Mirrors
                // ADR-0033 §6's command-side informational-only
                // posture: stuck_precondition does NOT consult
                // these entries; derive_state surfaces them at the
                // label level to give the operator a separate
                // signal that recommends `recover-from-nav` over
                // `retry-submission`.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceCheckPerformedPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.latest_check_outcome = Some(parsed.outcome);
                    }
                }
            }
            EventKind::InvoiceRetryRequested => {
                self.has_retry_requested = true;
            }
            EventKind::InvoiceMarkedAbandoned => {
                self.has_marked_abandoned = true;
            }
            EventKind::InvoiceLocalOnlyEmitted => {
                // S434 — same per-invoice contamination guard as the NAV
                // ladder entries: only flag this trace if the payload's
                // invoice_id matches the one being derived.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceLocalOnlyEmittedPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.has_local_only = true;
                    }
                }
            }
            EventKind::InvoicePaymentRecorded => {
                // PR-70 / ADR-0039 §2 — capture the operator-facing
                // payment fields onto the trace. Walk is in seq
                // order (oldest → newest), so the last matching
                // entry wins — defensive against a hypothetical
                // future "amend payment" PR that appends a fresh
                // entry without breaking the no-double-pay v1
                // invariant the route layer enforces.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoicePaymentRecordedPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.payment = Some(PaymentRecord {
                            paid_at: parsed.paid_at,
                            amount_minor: parsed.amount_minor,
                            currency: parsed.currency,
                            method: parsed.method,
                            reference: parsed.reference,
                        });
                    }
                }
            }
            _ => {}
        }
    }

    /// Derive the ADR-0009 §2 typestate label from the accumulated
    /// trace. PR-23 / ADR-0036 §3 extends the pre-PR-23 six-label
    /// ladder to eleven labels with the priority ordering:
    ///
    /// ```text
    /// 1. Abandoned             (matches stuck_precondition step 1)
    /// 2. Storno                (chain-link evidence; ADR-0009 §2)
    /// 3. Amended               (chain-link evidence; ADR-0009 §2)
    /// 4. Finalized             (matches stuck_precondition AlreadyFinalized)
    /// 5. Rejected              (matches stuck_precondition AlreadyRejected)
    /// 6. Recovered             (sub-label of Submitted; ADR-0034 §4)
    /// 7. Submitted             (matches stuck_precondition AwaitingAck)
    /// 8. PendingNavExists      (sub-label of Pending; ADR-0033 §6)
    /// 9. Pending               (matches stuck_precondition Pending; ADR-0032 §4)
    /// 10. Ready                 (Draft entered the ledger; no submit yet)
    /// 11. Unknown               (no entries for this invoice)
    /// ```
    ///
    /// The mirror invariant per ADR-0036 §1: for every state both
    /// this ladder and `audit_query::stuck_precondition` can name,
    /// the two MUST agree. Drift is the failure mode the
    /// `derive_state_label_table_mirror` test pins loud per
    /// CLAUDE.md rule 12.
    fn derive_state(&self) -> InvoiceState {
        // 1. Terminal-by-operator-decision wins over everything.
        if self.has_marked_abandoned {
            return InvoiceState::Abandoned;
        }
        // 2-3. Chain-link terminal — the base invoice's typestate
        //      transition per ADR-0009 §2. Storno and Amended are
        //      orthogonal (an invoice can be the base of both over
        //      its lifetime per ADR-0024 §7); the ladder picks
        //      Storno first if both are set. Operationally rare to
        //      see both on the same base; the audit-entries view
        //      exposes the full chain to the operator.
        if self.is_storno_base {
            return InvoiceState::Storno;
        }
        if self.is_amended_base {
            return InvoiceState::Amended;
        }
        // S434 — LOCAL ONLY: issued under a NAV-disabled tenant. Sits
        // below the operator-decision (Abandoned) and chain-link
        // (Storno/Amended) terminals — a local-only invoice can still be
        // stornoed/amended/abandoned — but ABOVE the NAV ladder, which
        // never fires for it (no Attempt/Response/ack rows exist).
        if self.has_local_only {
            return InvoiceState::LocalOnly;
        }
        // 4-5. Terminal-by-NAV from the ack status.
        match self.last_ack_status.as_deref() {
            Some("SAVED") => return InvoiceState::Finalized,
            Some("ABORTED") => return InvoiceState::Rejected,
            _ => {}
        }
        // 6-7. State-3: Response exists, no terminal ack, no
        //      abandon. The Recovered / Submitted sub-label split
        //      mirrors ADR-0034 §4's chain-walk-by-order posture
        //      at the byte level (response_xml root element prefix
        //      per ADR-0035 §4 / A91).
        if self.has_submission_response {
            if self.latest_response_is_recovered {
                return InvoiceState::Recovered;
            }
            return InvoiceState::Submitted;
        }
        // 8-9. State-2: Attempt exists, no Response, no abandon.
        //      The PendingNavExists / Pending sub-label split
        //      mirrors ADR-0033 §6's informational-only Layer-2
        //      posture at the UI level.
        if self.has_attempt {
            if matches!(self.latest_check_outcome.as_deref(), Some("exists")) {
                return InvoiceState::PendingNavExists;
            }
            return InvoiceState::Pending;
        }
        // 10. Pre-submission: Draft entered the ledger.
        if self.has_draft {
            return InvoiceState::Ready;
        }
        // 11. No entries for this invoice id.
        InvoiceState::Unknown
    }
}

/// PR-23 / ADR-0036 §5 — recovered-Response discriminator.
///
/// Mirrors ADR-0035 §4 / A91's prefix-match local-name check at
/// the UI level: a NAV-emitted `response_xml` whose first ~512
/// bytes contain the substring `QueryInvoiceDataResponse` was
/// emitted by `recover-from-nav` per ADR-0034 §4 (which reuses
/// the existing `InvoiceSubmissionResponsePayload` shape with
/// `<QueryInvoiceDataResponse>` bytes rather than
/// `<ManageInvoiceResponse>`).
///
/// 512-byte window: the root element appears in the first ~200
/// bytes on every NAV-emitted body (XML prolog + optional
/// whitespace + optional namespace-prefixed open tag). Bounded so
/// a malformed or oversized payload doesn't scan the whole body.
///
/// Substring scan rather than exact prefix-match per
/// ADR-0036 §"Adversarial review" #2 + CLAUDE.md rule 2: the
/// dependency on quick-xml or the verifier crate's prefix-match
/// helper is not justified for the UI label split. A future PR
/// can upgrade the discriminator additively if operational
/// evidence surfaces.
fn is_recovered_response_xml(response_xml: &[u8]) -> bool {
    let window = &response_xml[..response_xml.len().min(512)];
    window
        .windows(NEEDLE_QUERY_INVOICE_DATA_RESPONSE.len())
        .any(|w| w == NEEDLE_QUERY_INVOICE_DATA_RESPONSE)
}

/// The substring scanned by [`is_recovered_response_xml`].
/// Module-level constant so the discriminator's exact bytes are
/// auditable in one place per ADR-0036 §5.
const NEEDLE_QUERY_INVOICE_DATA_RESPONSE: &[u8] = b"QueryInvoiceDataResponse";

/// PR-23 / ADR-0036 §4 — chain-link detection probe.
///
/// `InvoiceStornoIssuedPayload` and
/// `InvoiceModificationIssuedPayload` do NOT carry a top-level
/// `invoice_id` field; the existing [`extract_invoice_id`] probe
/// returns `None` for these entries. This sister probe walks the
/// per-payload chain-link fields and returns the chain entry's
/// own invoice id (`storno_invoice_id` / `modification_invoice_id`)
/// alongside the `base_invoice_id` so the BASE invoice's trace
/// can be flipped into Storno / Amended at the list-and-detail
/// walker level AND the base's detail view can list its children
/// (PR-32 / Option T).
///
/// PR-32 / session-36 — extended in place rather than forked into
/// a sister probe per reuse-over-fork (A106). The added field
/// `child_invoice_id` is the chain entry's own id, parsed from
/// whichever payload-specific field carries it; every call site
/// that previously consumed `(kind, base_id)` is updated to
/// destructure the [`ChainLink`] struct.
///
/// Returns `None` for every other `EventKind` (the typed probe
/// would fail to decode on the wrong payload shape; we
/// short-circuit on kind match first to keep the cost bounded).
fn extract_chain_link(entry: &Entry) -> Option<ChainLink> {
    #[derive(Deserialize)]
    struct StornoProbe {
        storno_invoice_id: String,
        base_invoice_id: String,
        modification_index: u32,
    }
    #[derive(Deserialize)]
    struct ModificationProbe {
        modification_invoice_id: String,
        base_invoice_id: String,
        modification_index: u32,
    }
    match entry.kind {
        EventKind::InvoiceStornoIssued => {
            let probe: StornoProbe = serde_json::from_slice(&entry.payload).ok()?;
            Some(ChainLink {
                kind: entry.kind.clone(),
                child_invoice_id: probe.storno_invoice_id,
                base_invoice_id: probe.base_invoice_id,
                modification_index: probe.modification_index,
            })
        }
        EventKind::InvoiceModificationIssued => {
            let probe: ModificationProbe = serde_json::from_slice(&entry.payload).ok()?;
            Some(ChainLink {
                kind: entry.kind.clone(),
                child_invoice_id: probe.modification_invoice_id,
                base_invoice_id: probe.base_invoice_id,
                modification_index: probe.modification_index,
            })
        }
        _ => None,
    }
}

/// PR-32 / session-36 — chain-link probe return shape.
///
/// Carries the chain-link identifiers needed by every consumer:
///   - `child_invoice_id` — the chain entry's OWN invoice id (i.e.,
///     the storno or modification invoice itself).
///   - `base_invoice_id` — the BASE invoice the chain entry is
///     attached to.
///   - `modification_index` — the per-base chain index allocated by
///     `next_modification_index_in_tx` in `issue_storno.rs` /
///     `issue_modification.rs` (PR-41 / session-45 — surfaced on the
///     chain-children list per Option W). Shared name space across
///     stornos and modifications against the same base; the persisted
///     payload field is the same `modification_index: u32` on both
///     `InvoiceStornoIssuedPayload` and `InvoiceModificationIssuedPayload`.
///
/// Plus `kind`, the originating `EventKind` discriminant so callers
/// can match `InvoiceStornoIssued` / `InvoiceModificationIssued`
/// without re-parsing the payload.
struct ChainLink {
    kind: EventKind,
    child_invoice_id: String,
    base_invoice_id: String,
    modification_index: u32,
}

/// Extract the `invoice_id` field (if any) from an audit-ledger entry's
/// typed payload. Returns None for entries that don't carry an
/// invoice_id at all (none of the v3.0 payloads).
fn extract_invoice_id(entry: &Entry) -> Option<String> {
    // All current typed payloads carry an `invoice_id: String` field.
    // We parse permissively — a payload that fails to decode is
    // skipped rather than blowing up the entire serve view.
    #[derive(Deserialize)]
    struct Probe {
        invoice_id: String,
    }
    let probe: Probe = serde_json::from_slice(&entry.payload).ok()?;
    Some(probe.invoice_id)
}

// ──────────────────────────────────────────────────────────────────────
// S424 / session-424 — cross-domain audit-events screen
//
// `GET /api/audit-events` is the general, filterable view of the WHOLE
// ledger — it generalises `/audit/:invoice_id` (one invoice's chain)
// into "all operator activity, any domain, paginated + filtered". The
// audit-screen design report (docs/findings/audit-screen-design-2026-06-15.md)
// is authoritative; this is its §3 wire shape.
//
// Load-bearing constraints (design §2.1 + risk #1, [[no-sql-specific]]):
//   * NO new DB index. The ledger has no secondary index (S341 dropped
//     UNIQUE(seq) — duckdb#23046; S410 dropped CHECKs). Every read is a
//     full seq-order scan; filter/sort/paginate happen HERE in Rust.
//   * List rows OMIT payloads. Several payloads embed base64 NAV XML
//     (tens of KB each); a 50-row page of them would be multiple MB. The
//     row carries a one-line `summary` + `subject`; the full payload is
//     fetched lazily on row-expand via `/api/audit-events/:seq`.
//   * Per-row `hash_ok` (invariant 3, independently checkable via
//     `compute_entry_hash`) + a whole-ledger `verified` verdict (one
//     `verify_chain()` per request). The SPA renders rows at/after a
//     divergence as ✗ regardless of `hash_ok`.
//
// Deliberate rule-13 trim from the design's §3.2/§3.3: `before_seq` +
// `prev_cursor` are dropped. The SPA paginates newest-first and appends
// older rows via `next_cursor` — there is no backward-pagination
// consumer, so the speculative surface is deleted rather than shipped.
// ──────────────────────────────────────────────────────────────────────

/// Heartbeat kinds excluded from the audit-events list by default. The
/// storefront-poll heartbeat fires at the daemon cadence and would bury
/// every operator-meaningful entry; the dashboard recent-activity tile
/// already filters these. `?heartbeats=true` opts back in (design §4.5).
fn is_heartbeat_kind(kind: &EventKind) -> bool {
    matches!(
        kind,
        EventKind::QuoteIntakePollAttempted | EventKind::QuoteIntakePollCompleted
    )
}

/// Query params for `GET /api/audit-events`. All optional + defaulted;
/// the SPA omits absent facets so axum's scalar `Query` decode never
/// sees an empty value to misparse.
#[derive(Debug, Deserialize)]
pub struct AuditEventsQuery {
    /// Inclusive calendar-day lower bound (YYYY-MM-DD or any ISO-8601
    /// prefix; compared on the entry's RFC3339 wall-clock DATE).
    pub from: Option<String>,
    /// Inclusive calendar-day upper bound.
    pub to: Option<String>,
    /// Comma-joined `EventKind::as_str()` values, e.g.
    /// `invoice.payment_recorded,quote.operator_refused`.
    pub kinds: Option<String>,
    /// Comma-joined domain PREFIXES (the `as_str` segment before the
    /// first `.`), e.g. `invoice,quote`. The SPA's domain chips map to
    /// prefix sets (the compliance chip → 7 prefixes) — this is the
    /// chip's server-authoritative filter so `total_matched` is correct
    /// and pagination is meaningful (design §4.5).
    pub domains: Option<String>,
    /// Substring match across every subject-ish payload id (own id AND
    /// chain-base id — see `audit_summary::subject_matches`).
    pub subject: Option<String>,
    /// Substring match on `actor.user_id` (the operator identity).
    pub operator: Option<String>,
    /// Free-text needle across kind + actor + summary + subject + the
    /// payload JSON text.
    pub q: Option<String>,
    /// `"seq"` (default) | `"occurred_at"`.
    pub sort: Option<String>,
    /// `"desc"` (default) | `"asc"`.
    pub dir: Option<String>,
    /// Forward cursor: return rows positioned AFTER this seq in the
    /// active sort order.
    pub after_seq: Option<u64>,
    /// Page size, default 50, clamped 1..=200.
    pub limit: Option<u32>,
    /// Include the storefront-poll heartbeat kinds (default false).
    pub heartbeats: Option<bool>,
}

#[derive(Debug, Serialize)]
struct AuditEventsResponse {
    events: Vec<AuditEventRow>,
    page: PageInfo,
    chain: ChainStatus,
}

#[derive(Debug, Serialize)]
struct AuditEventRow {
    /// `aud_<ULID>`.
    id: String,
    seq: u64,
    /// `EventKind::as_str()` — the domain-prefixed wire string the SPA
    /// chips key on.
    kind: String,
    /// RFC3339 wall-clock.
    occurred_at: String,
    /// `actor.user_id`.
    actor: String,
    /// Resolved subject id (invoice_id / quote_id / …) for the Subject
    /// column; `None` for subjectless system entries.
    subject: Option<String>,
    /// ONE-LINE kind-aware summary (NOT the full payload). Empty when no
    /// verified summariser exists — the SPA renders the kind label.
    summary: String,
    /// Per-entry integrity: `compute_entry_hash(entry) == entry_hash`.
    hash_ok: bool,
    /// Whether a non-empty payload exists to drill into.
    has_payload: bool,
    /// 64-char hex chain anchors for the expanded row.
    prev_hash_hex: String,
    entry_hash_hex: String,
}

#[derive(Debug, Serialize)]
struct PageInfo {
    returned: u32,
    /// Seq to pass as `after_seq` for the next (older) page; `None` on
    /// the last page.
    next_cursor: Option<u64>,
    /// Count of rows matching the filters (the full scan is in hand).
    total_matched: u32,
}

#[derive(Debug, Clone, Serialize)]
struct ChainStatus {
    /// Whole chain genesis..head intact?
    verified: bool,
    head_seq: u64,
    /// `Some(seq)` + `reason` when `verify_chain` failed.
    first_divergence_seq: Option<u64>,
    reason: Option<String>,
}

#[derive(Debug, Serialize)]
struct AuditEventDetailView {
    seq: u64,
    kind: String,
    occurred_at: String,
    actor: String,
    subject: Option<String>,
    hash_ok: bool,
    prev_hash_hex: String,
    entry_hash_hex: String,
    /// The FULL typed payload as raw JSON — fetched lazily on row-expand.
    /// The SPA redacts sensitive fields client-side before render
    /// (Ervin 2026-06-15: redact-by-default + per-use show-raw confirm).
    payload: serde_json::Value,
}

/// S441 / ADR-0087 + ADR-0088 — boot the per-tenant DÁP/QES audit chain:
/// open the service session (+ crash recovery) and spawn the heartbeat
/// actor. Called from `run()` only when the tenant's `dap_enabled` is true,
/// so the keychain + TSA are never touched on the default (unsigned) path.
fn spawn_dap_audit_chain(
    recovery_state: &AppState,
    coordinator: &mut ShutdownCoordinator,
    heartbeat_secs: u64,
) -> Result<()> {
    let binary_hash = recovery_state
        .binary_hash
        .wait()
        .map_err(|e| anyhow!("binary hash unavailable for DÁP audit boot: {e}"))?;
    let tenant = recovery_state.tenant.clone();
    let db_path = (*recovery_state.db_path).clone();

    let service_key = crate::audit_dap_boot::load_or_provision_service_key(tenant.as_str())?;
    let actor = Actor::from_local_cli(Ulid::new().to_string(), "system:audit-service");

    // Open the service session BEFORE serving (ADR-0088: no daemon precedes
    // its session open) on a short-lived ledger handle, then drop it.
    let mut ledger = aberp_audit_ledger::Ledger::open(&db_path, tenant.clone(), binary_hash)
        .map_err(|e| anyhow!("open ledger for DÁP service session: {e}"))?;
    let tsa = aberp_audit_ledger::session::tsa::MockTimestampAuthority::new();
    let service = crate::audit_dap_boot::open_service_session_and_recover(
        &mut ledger,
        &tsa,
        actor.clone(),
        service_key,
    )?;
    drop(ledger);

    let deps = crate::audit_dap_boot::HeartbeatDeps {
        db_path,
        tenant,
        binary_hash,
        actor,
        service,
        interval: std::time::Duration::from_secs(heartbeat_secs.max(1)),
    };
    let token = coordinator.token.clone();
    let handle = tokio::spawn(async move {
        crate::audit_dap_boot::run_heartbeat_supervised(deps, token).await;
    });
    coordinator.register("audit-heartbeat", handle);
    tracing::info!(
        heartbeat_secs,
        "DÁP/QES audit chain booted: service session opened + heartbeat actor spawned (S441)"
    );
    Ok(())
}

/// Map a `verify_chain` failure to `(first_divergence_seq, reason)`.
fn verify_error_divergence(e: &LedgerVerifyError) -> (Option<u64>, String) {
    match e {
        LedgerVerifyError::Read(inner) => (None, format!("failed to read ledger: {inner}")),
        LedgerVerifyError::Chain(VerifyError::OutOfOrder { found, .. }) => {
            (Some(*found), e.to_string())
        }
        LedgerVerifyError::Chain(VerifyError::ChainBroken { seq }) => (Some(*seq), e.to_string()),
        LedgerVerifyError::Chain(VerifyError::TamperedAt { seq }) => (Some(*seq), e.to_string()),
        // S441 / ADR-0087 — signature + anchor divergences. The base
        // `verify_chain` (which this `LedgerVerifyError` wraps) never
        // returns these; they surface only through `verify_chain_signed`.
        // Mapped here for exhaustiveness so the base-chain operator path
        // stays loud (CLAUDE.md rule 12).
        LedgerVerifyError::Chain(VerifyError::SignatureInvalid { seq }) => {
            (Some(*seq), e.to_string())
        }
        LedgerVerifyError::Chain(VerifyError::SignatureMissingInSignedSession { seq }) => {
            (Some(*seq), e.to_string())
        }
        LedgerVerifyError::Chain(VerifyError::AnchorTampered { .. }) => (None, e.to_string()),
    }
}

/// RFC3339 wall-clock string for an entry; falls back to the time-crate
/// `Display` if formatting fails (never observed — the storage layer
/// already round-trips RFC3339).
fn entry_rfc3339(entry: &Entry) -> String {
    entry
        .time_wall
        .format(&time::format_description::well_known::Rfc3339)
        .unwrap_or_else(|_| entry.time_wall.to_string())
}

/// Calendar-day (YYYY-MM-DD) of an entry, for the `from`/`to` bounds.
fn entry_date(entry: &Entry) -> String {
    entry_rfc3339(entry).chars().take(10).collect()
}

/// Free-text `q` predicate: needle (already lowercased) against kind +
/// actor + summary + subject + the payload JSON text. The payload-text
/// arm is the design's named haystack (§3.2) — it finds a recipient
/// email or NAV transaction id that the one-line summary omits. Lossy
/// UTF-8 over the bytes; acceptable full-scan cost for small per-tenant
/// ledgers (design risk #4).
fn entry_matches_freetext(entry: &Entry, needle_lower: &str) -> bool {
    if entry.kind.as_str().to_lowercase().contains(needle_lower) {
        return true;
    }
    if entry.actor.user_id.to_lowercase().contains(needle_lower) {
        return true;
    }
    if crate::audit_summary::summary_of(entry)
        .to_lowercase()
        .contains(needle_lower)
    {
        return true;
    }
    if let Some(subject) = crate::audit_summary::subject_of(entry) {
        if subject.to_lowercase().contains(needle_lower) {
            return true;
        }
    }
    String::from_utf8_lossy(&entry.payload)
        .to_lowercase()
        .contains(needle_lower)
}

/// Project one entry into a list row (payload OMITTED — design §3.3).
fn audit_event_row_of(entry: &Entry) -> AuditEventRow {
    AuditEventRow {
        id: entry.id.to_prefixed_string(),
        seq: entry.seq.as_u64(),
        kind: entry.kind.as_str().to_string(),
        occurred_at: entry_rfc3339(entry),
        actor: entry.actor.user_id.clone(),
        subject: crate::audit_summary::subject_of(entry),
        summary: crate::audit_summary::summary_of(entry),
        hash_ok: compute_entry_hash(entry) == entry.entry_hash,
        has_payload: !entry.payload.is_empty(),
        prev_hash_hex: hex::encode(entry.prev_hash.as_bytes()),
        entry_hash_hex: hex::encode(entry.entry_hash.as_bytes()),
    }
}

/// Open the ledger, scan + verify, then filter / sort / paginate in Rust
/// (no index — [[no-sql-specific]]). Whole-chain verify runs once per
/// request (O(N), N small); per-row `hash_ok` is the independently
/// checkable invariant 3.
fn audit_events_request(state: &AppState, query: &AuditEventsQuery) -> Result<AuditEventsResponse> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for audit-events")?;
    let entries = ledger.entries().context("read audit ledger entries")?;

    // ── Whole-chain verdict (design §3.4). head_seq is the max seq. ──
    let head_seq = entries.last().map(|e| e.seq.as_u64()).unwrap_or(0);
    let chain = match ledger.verify_chain() {
        Ok(_) => ChainStatus {
            verified: true,
            head_seq,
            first_divergence_seq: None,
            reason: None,
        },
        Err(e) => {
            let (first_divergence_seq, reason) = verify_error_divergence(&e);
            ChainStatus {
                verified: false,
                head_seq,
                first_divergence_seq,
                reason: Some(reason),
            }
        }
    };

    Ok(build_audit_events_response(&entries, query, chain))
}

/// Pure filter / sort / paginate / row-projection over an entry slice +
/// a precomputed [`ChainStatus`]. Split out of `audit_events_request` so
/// the load-bearing logic is unit-testable without an `AppState` or an
/// open `Ledger` (CLAUDE.md rule 9 — the filter/sort/paginate matrix is
/// pinned directly, not through a heavy serve harness).
fn build_audit_events_response(
    entries: &[Entry],
    query: &AuditEventsQuery,
    chain: ChainStatus,
) -> AuditEventsResponse {
    // ── Pre-compute the filter needles once (not per-entry). ──
    let include_heartbeats = query.heartbeats.unwrap_or(false);
    let csv_set = |o: &Option<String>| -> Option<std::collections::HashSet<String>> {
        o.as_ref().map(|s| {
            s.split(',')
                .map(|k| k.trim().to_string())
                .filter(|k| !k.is_empty())
                .collect()
        })
    };
    let kinds_filter = csv_set(&query.kinds);
    let domains_filter = csv_set(&query.domains);
    let trimmed_lower = |o: &Option<String>| -> Option<String> {
        o.as_ref()
            .map(|s| s.trim().to_lowercase())
            .filter(|s| !s.is_empty())
    };
    let operator_needle = trimmed_lower(&query.operator);
    let subject_needle = trimmed_lower(&query.subject);
    let q_needle = trimmed_lower(&query.q);
    let day_bound = |o: &Option<String>| -> Option<String> {
        o.as_ref()
            .map(|s| s.trim())
            .filter(|s| !s.is_empty())
            .map(|s| s.chars().take(10).collect::<String>())
    };
    let from_date = day_bound(&query.from);
    let to_date = day_bound(&query.to);

    // ── Filter (full scan in Rust). ──
    let mut matched: Vec<&Entry> = entries
        .iter()
        .filter(|e| {
            if !include_heartbeats && is_heartbeat_kind(&e.kind) {
                return false;
            }
            if let Some(kinds) = &kinds_filter {
                if !kinds.contains(e.kind.as_str()) {
                    return false;
                }
            }
            if let Some(domains) = &domains_filter {
                let prefix = e.kind.as_str().split('.').next().unwrap_or("");
                if !domains.contains(prefix) {
                    return false;
                }
            }
            if let Some(op) = &operator_needle {
                if !e.actor.user_id.to_lowercase().contains(op.as_str()) {
                    return false;
                }
            }
            if let Some(subj) = &subject_needle {
                if !crate::audit_summary::subject_matches(e, subj) {
                    return false;
                }
            }
            if from_date.is_some() || to_date.is_some() {
                let date = entry_date(e);
                if let Some(f) = &from_date {
                    if date.as_str() < f.as_str() {
                        return false;
                    }
                }
                if let Some(t) = &to_date {
                    if date.as_str() > t.as_str() {
                        return false;
                    }
                }
            }
            if let Some(needle) = &q_needle {
                if !entry_matches_freetext(e, needle) {
                    return false;
                }
            }
            true
        })
        .collect();

    let total_matched = matched.len() as u32;

    // ── Sort (seq | occurred_at; default seq). Tie-break on seq so the
    //    order is deterministic across refreshes (CLAUDE.md rule 12). ──
    let descending = query.dir.as_deref().map(|d| d != "asc").unwrap_or(true);
    match query.sort.as_deref() {
        Some("occurred_at") => {
            matched.sort_by(|a, b| a.time_wall.cmp(&b.time_wall).then(a.seq.cmp(&b.seq)))
        }
        _ => matched.sort_by_key(|a| a.seq),
    }
    if descending {
        matched.reverse();
    }

    // ── Seq-cursor pagination (forward only). Position-based so it is
    //    correct for either sort order given a stable filter set; if the
    //    cursor row was filtered out between pages it restarts from the
    //    top (safe — no skip/dup within a stable filter). ──
    let limit = query.limit.unwrap_or(50).clamp(1, 200) as usize;
    let start = match query.after_seq {
        Some(cursor) => matched
            .iter()
            .position(|e| e.seq.as_u64() == cursor)
            .map(|i| i + 1)
            .unwrap_or(0),
        None => 0,
    };
    let remaining = &matched[start.min(matched.len())..];
    let page: Vec<&Entry> = remaining.iter().take(limit).copied().collect();
    let returned = page.len() as u32;
    let next_cursor = if remaining.len() > page.len() {
        page.last().map(|e| e.seq.as_u64())
    } else {
        None
    };

    let events = page.iter().map(|e| audit_event_row_of(e)).collect();

    AuditEventsResponse {
        events,
        page: PageInfo {
            returned,
            next_cursor,
            total_matched,
        },
        chain,
    }
}

/// `GET /api/audit-events/:seq` — the single FULL entry (payload
/// included) for the row-expand drill-down. Returns `Ok(None)` → 404
/// when no entry carries that seq.
fn audit_event_detail_request(state: &AppState, seq: u64) -> Result<Option<AuditEventDetailView>> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for audit-event detail")?;
    let entries = ledger.entries().context("read audit ledger entries")?;
    let entry = match entries.iter().find(|e| e.seq.as_u64() == seq) {
        Some(e) => e,
        None => return Ok(None),
    };
    // Full typed payload as raw JSON; a malformed payload (DB tampering)
    // falls back to Null rather than panicking (CLAUDE.md rule 12).
    let mut payload = serde_json::from_slice::<serde_json::Value>(&entry.payload)
        .unwrap_or(serde_json::Value::Null);
    // Parity with `audit_view_of`: graft the parsed NAV technical-
    // validation messages onto an InvoiceAckStatus payload.
    if entry.kind == EventKind::InvoiceAckStatus {
        if let Some(messages) = parse_ack_technical_validations(&payload) {
            if let serde_json::Value::Object(ref mut map) = payload {
                map.insert(
                    "technical_validation_messages".to_string(),
                    serde_json::json!(messages
                        .into_iter()
                        .map(TechnicalValidationBody::from)
                        .collect::<Vec<_>>()),
                );
            }
        }
    }
    Ok(Some(AuditEventDetailView {
        seq: entry.seq.as_u64(),
        kind: entry.kind.as_str().to_string(),
        occurred_at: entry_rfc3339(entry),
        actor: entry.actor.user_id.clone(),
        subject: crate::audit_summary::subject_of(entry),
        hash_ok: compute_entry_hash(entry) == entry.entry_hash,
        prev_hash_hex: hex::encode(entry.prev_hash.as_bytes()),
        entry_hash_hex: hex::encode(entry.entry_hash.as_bytes()),
        payload,
    }))
}

/// `GET /api/audit-events` handler — auth-gated, blocking scan offloaded.
async fn handle_audit_events(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<AuditEventsQuery>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let result =
        tokio::task::spawn_blocking(move || audit_events_request(&state_for_task, &query)).await;
    match result {
        Ok(Ok(resp)) => Json(resp).into_response(),
        Ok(Err(e)) => internal_error("audit_events_request", e),
        Err(join_err) => internal_error(
            "audit_events_request:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

/// `GET /api/audit-events/:seq` handler — single full entry for expand.
async fn handle_audit_event_detail(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(seq): AxumPath<u64>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_for_task = state.clone();
    let result =
        tokio::task::spawn_blocking(move || audit_event_detail_request(&state_for_task, seq)).await;
    match result {
        Ok(Ok(Some(view))) => Json(view).into_response(),
        Ok(Ok(None)) => (
            StatusCode::NOT_FOUND,
            Json(error_body(format!("no audit ledger entry at seq {seq}"))),
        )
            .into_response(),
        Ok(Err(e)) => internal_error("audit_event_detail_request", e),
        Err(join_err) => internal_error(
            "audit_event_detail_request:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

// ──────────────────────────────────────────────────────────────────────
// S426 / ADR-0082 — Snapshots tab handlers
// ──────────────────────────────────────────────────────────────────────

/// One snapshot row in the operator UI. Mirrors `aberp_snapshot::SnapshotMeta`
/// plus pre-rendered human strings so the SPA stays dumb.
#[derive(Serialize)]
struct SnapshotListItem {
    seq: u64,
    created_at: String,
    byte_size: u64,
    size_human: String,
    valid: bool,
    invoice_count: i64,
    audit_count: i64,
    chain_len: u64,
    age_human: String,
    validation_error: Option<String>,
    dir: String,
}

/// `GET /api/snapshots` response.
#[derive(Serialize)]
struct SnapshotsListResponse {
    store_dir: String,
    daemon_disabled: bool,
    interval_secs: u64,
    snapshots: Vec<SnapshotListItem>,
}

/// `POST /api/snapshots/now` response.
#[derive(Serialize)]
struct SnapshotNowResponse {
    created: SnapshotListItem,
}

/// `POST /api/snapshots/restore` request body.
#[derive(Deserialize)]
struct SnapshotRestoreBody {
    selector: String,
    to: String,
    confirm: bool,
}

/// `POST /api/snapshots/restore` response.
#[derive(Serialize)]
struct SnapshotRestoreResponse {
    restored_seq: u64,
    target: String,
}

fn snapshot_item(
    r: &aberp_snapshot::SnapshotRecord,
    now: time::OffsetDateTime,
) -> SnapshotListItem {
    SnapshotListItem {
        seq: r.meta.seq,
        created_at: crate::snapshot::rfc3339(r.meta.created_at),
        byte_size: r.meta.byte_size,
        size_human: crate::snapshot::human_size(r.meta.byte_size),
        valid: r.meta.valid,
        invoice_count: r.meta.invoice_count,
        audit_count: r.meta.audit_count,
        chain_len: r.meta.chain_len,
        age_human: crate::snapshot::human_age(r.age(now)),
        validation_error: r.meta.validation_error.clone(),
        dir: r.dir.display().to_string(),
    }
}

fn list_snapshots_request(state: &AppState) -> Result<SnapshotsListResponse> {
    let store_dir = crate::snapshot::resolve_store(state.tenant.as_str(), None)?;
    let records =
        aberp_snapshot::list_snapshots(&store_dir).map_err(|e| anyhow!("list snapshots: {e}"))?;
    let now = time::OffsetDateTime::now_utc();
    Ok(SnapshotsListResponse {
        store_dir: store_dir.display().to_string(),
        daemon_disabled: crate::snapshot::is_disabled(),
        interval_secs: crate::snapshot::interval_from_env().as_secs(),
        snapshots: records.iter().map(|r| snapshot_item(r, now)).collect(),
    })
}

fn snapshot_now_request(state: &AppState) -> Result<SnapshotNowResponse> {
    let store_dir = crate::snapshot::resolve_store(state.tenant.as_str(), None)?;
    let binary_hash = state
        .binary_hash
        .wait()
        .context("binary hash for snapshot")?;
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login_for_audit(state));
    let policy = crate::snapshot::policy_from_env();
    let rec = crate::snapshot::run_cycle(
        &state.db_path,
        &store_dir,
        &state.tenant,
        binary_hash,
        actor,
        &policy,
    )?;
    Ok(SnapshotNowResponse {
        created: snapshot_item(&rec, time::OffsetDateTime::now_utc()),
    })
}

fn snapshot_restore_request(
    state: &AppState,
    body: &SnapshotRestoreBody,
) -> Result<SnapshotRestoreResponse> {
    let target = std::path::PathBuf::from(&body.to);
    let store_dir = crate::snapshot::resolve_store(state.tenant.as_str(), None)?;
    let binary_hash = state
        .binary_hash
        .wait()
        .context("binary hash for restore")?;
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login_for_audit(state));
    let rec = crate::snapshot::restore_and_emit(
        &state.db_path,
        &store_dir,
        &body.selector,
        &target,
        &state.tenant,
        binary_hash,
        actor,
    )?;
    Ok(SnapshotRestoreResponse {
        restored_seq: rec.meta.seq,
        target: body.to.clone(),
    })
}

/// `GET /api/snapshots` — list managed snapshots.
async fn handle_list_snapshots(headers: HeaderMap, State(state): State<AppState>) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let s = state.clone();
    match tokio::task::spawn_blocking(move || list_snapshots_request(&s)).await {
        Ok(Ok(resp)) => Json(resp).into_response(),
        Ok(Err(e)) => internal_error("list_snapshots_request", e),
        Err(join_err) => internal_error(
            "list_snapshots_request:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

/// `POST /api/snapshots/now` — take one validated snapshot now.
async fn handle_snapshot_now(headers: HeaderMap, State(state): State<AppState>) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let s = state.clone();
    match tokio::task::spawn_blocking(move || snapshot_now_request(&s)).await {
        Ok(Ok(resp)) => Json(resp).into_response(),
        Ok(Err(e)) => internal_error("snapshot_now_request", e),
        Err(join_err) => internal_error(
            "snapshot_now_request:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

/// `POST /api/snapshots/restore` — guarded restore. The prod-overwrite /
/// no-confirm refusal is checked up front and returned as a 400 (operator-
/// correctable) rather than a 500 ([[trust-code-not-operator]]).
async fn handle_snapshot_restore(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(body): Json<SnapshotRestoreBody>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    // Guard BEFORE any work — a refused restore never even looks at the store.
    let target = std::path::PathBuf::from(&body.to);
    if let Err(e) = aberp_snapshot::ensure_restore_allowed(&target, body.confirm) {
        return (StatusCode::BAD_REQUEST, Json(error_body(format!("{e}")))).into_response();
    }
    let s = state.clone();
    match tokio::task::spawn_blocking(move || snapshot_restore_request(&s, &body)).await {
        Ok(Ok(resp)) => Json(resp).into_response(),
        Ok(Err(e)) => internal_error("snapshot_restore_request", e),
        Err(join_err) => internal_error(
            "snapshot_restore_request:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

// ──────────────────────────────────────────────────────────────────────
// S281 / PR-266 — Email-relay handlers (ADR-0007)
// ──────────────────────────────────────────────────────────────────────

/// Closed-vocab `submitter` identifier the relay route emits onto the
/// queue row + audit payload. The relay-token bearer authenticates the
/// caller; v1 only knows the storefront. Future surfaces (a second
/// sister service) would each get their own token and a distinct
/// submitter literal here.
const RELAY_SUBMITTER_STOREFRONT: &str = "storefront";

/// JSON body the route returns on validation failure. Stable shape so
/// the storefront branches on `code` (closed-vocab) rather than parsing
/// the message string.
#[derive(Serialize)]
struct RelayValidationErrorBody {
    error: &'static str,
    code: &'static str,
    message: String,
}

/// JSON body the route returns on 200 acceptance.
#[derive(Serialize)]
struct RelayAcceptedBody {
    audit_id: String,
}

/// `POST /api/internal/send-email` per ADR-0007. Bearer-gated by the
/// dedicated email-relay token (NOT the session token); on accept,
/// persists the row + writes attachments to disk + emits
/// `EmailRelayQueued` and returns 200 with the audit id.
///
/// **S307 / PR-276 — DEPRECATED.** ADR-0009 supersedes ADR-0007's push
/// posture with a polling architecture: the storefront enqueues to its
/// own filesystem and ABERP's [`crate::email_outbox_poll_daemon`] (S307)
/// pulls outbound. This route is kept functional for local-dev
/// (single-process testing) and for manual API testing; in production
/// it emits a one-line WARN per invocation so an operator notices a
/// stray storefront still pushing instead of enqueuing. The endpoint
/// will be removed in a session after the queue path has been
/// validated end-to-end through one real customer quote.
async fn handle_relay_send_email(
    headers: HeaderMap,
    State(state): State<AppState>,
    body_bytes: axum::body::Bytes,
) -> Response {
    // S307 / PR-276 — deprecation warning. ADR-0009 supersedes the
    // push-based relay; production callers should be on the
    // email-outbox queue path. Local-dev / manual-API-testing is the
    // only legitimate non-dev-mode caller, so we WARN once per
    // request rather than 410-ing the surface (a hard removal would
    // surprise an operator mid-troubleshoot).
    let dev_mode = std::env::var("ABERP_DEV_MODE")
        .ok()
        .map(|v| {
            let t = v.trim();
            t == "1" || t.eq_ignore_ascii_case("true")
        })
        .unwrap_or(false);
    if !dev_mode {
        tracing::warn!(
            "DEPRECATED POST /api/internal/send-email received in non-dev mode; \
             storefront should use the email-outbox queue path per ADR-0009 \
             (`GET /api/internal/email-queue` + ABERP poll daemon S307)"
        );
    }
    // 1. Authenticate with the dedicated email-relay keychain token.
    //    Distinct from `state.session_token` per ADR-0007 §Auth (two
    //    tokens → independent rotation).
    let expected_token = match email_relay_credentials_mod::read_token(state.tenant.as_str()) {
        Ok(z) => z,
        Err(email_relay_credentials_mod::EmailRelayCredentialsError::Missing { tenant_id }) => {
            tracing::warn!(
                tenant = %tenant_id,
                "email-relay route called but no keychain token configured for this tenant"
            );
            return (
                StatusCode::SERVICE_UNAVAILABLE,
                Json(serde_json::json!({
                    "error": "email_relay_not_configured",
                    "message": "ABERP has no email-relay bearer token configured for this tenant; \
                                set ABERP_EMAIL_RELAY_TOKEN in the OS keychain first."
                })),
            )
                .into_response();
        }
        Err(e) => {
            tracing::error!(error = %e, "keychain read failed for email-relay token");
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(error_body("keychain read failed".to_string())),
            )
                .into_response();
        }
    };
    if let Some(resp) = check_bearer_rejection(&headers, &expected_token) {
        return resp;
    }

    // 2. Rate-limit per submitter — v1 has one submitter
    //    ("storefront") but the bucket is keyed by the submitter
    //    literal so a future per-token identity slots in cleanly.
    let now_instant = std::time::Instant::now();
    if let Err(retry_after) = state
        .email_relay_rate_limiter
        .try_acquire(RELAY_SUBMITTER_STOREFRONT, now_instant)
    {
        let mut resp = (
            StatusCode::TOO_MANY_REQUESTS,
            Json(serde_json::json!({
                "error": "rate_limited",
                "retry_after_secs": retry_after,
                "message": format!(
                    "submitter `{RELAY_SUBMITTER_STOREFRONT}` exceeded {} requests/min; \
                     retry after {retry_after}s",
                    email_relay::MAX_RELAY_PER_MINUTE
                ),
            })),
        )
            .into_response();
        if let Ok(hv) = axum::http::HeaderValue::from_str(&format!("{retry_after}")) {
            resp.headers_mut().insert("Retry-After", hv);
        }
        return resp;
    }

    // 3. Size cap pre-check — refuse 25 MB+ bodies BEFORE we
    //    serde_json::from_slice the whole thing (defence in depth on
    //    top of axum's own body limit).
    if (body_bytes.len() as u64) > email_relay::MAX_RELAY_BODY_BYTES {
        return (
            StatusCode::PAYLOAD_TOO_LARGE,
            Json(serde_json::json!({
                "error": "request_too_large",
                "code": "body_too_large",
                "max_bytes": email_relay::MAX_RELAY_BODY_BYTES,
                "got_bytes": body_bytes.len(),
            })),
        )
            .into_response();
    }

    // 4. Parse the body JSON.
    let wire: email_relay::RelayRequestBody = match serde_json::from_slice(&body_bytes) {
        Ok(b) => b,
        Err(e) => {
            return (
                StatusCode::BAD_REQUEST,
                Json(serde_json::json!({
                    "error": "bad_json",
                    "message": format!("body is not valid JSON: {e}"),
                })),
            )
                .into_response();
        }
    };

    // 5. Run validation.
    let validated = match email_relay::validate(RELAY_SUBMITTER_STOREFRONT, wire) {
        Ok(v) => v,
        Err(verr) => {
            let status = match verr.code {
                email_relay::ValidationCode::BodyTooLarge
                | email_relay::ValidationCode::AttachmentTooLarge
                | email_relay::ValidationCode::TooManyAttachments => StatusCode::PAYLOAD_TOO_LARGE,
                _ => StatusCode::BAD_REQUEST,
            };
            return (
                status,
                Json(RelayValidationErrorBody {
                    error: "validation_failed",
                    code: verr.code.as_str(),
                    message: verr.message,
                }),
            )
                .into_response();
        }
    };

    // 6. Persist to DB + write attachments to disk + emit audit.
    let row_id = Ulid::new().to_string();
    let attachments_rel_dir = if validated.attachments.is_empty() {
        None
    } else {
        Some(row_id.clone())
    };
    let attachments_root =
        match email_relay_queue::attachments_root_for_tenant(state.tenant.as_str()) {
            Ok(p) => p,
            Err(e) => return internal_error("resolve email-relay attachments root", e),
        };

    if let Some(rel) = &attachments_rel_dir {
        let abs = attachments_root.join(rel);
        for (i, att) in validated.attachments.iter().enumerate() {
            if let Err(e) = email_relay_queue::write_attachment(&abs, i, &att.filename, &att.bytes)
            {
                return internal_error("write email-relay attachment to disk", e);
            }
        }
    }

    let to_json = match serde_json::to_string(&validated.to) {
        Ok(s) => s,
        Err(e) => {
            return internal_error(
                "serialize to-recipients for queue row",
                anyhow!("serde_json::to_string: {e}"),
            )
        }
    };
    let cc_json = if validated.cc.is_empty() {
        None
    } else {
        Some(match serde_json::to_string(&validated.cc) {
            Ok(s) => s,
            Err(e) => {
                return internal_error(
                    "serialize cc-recipients for queue row",
                    anyhow!("serde_json::to_string: {e}"),
                )
            }
        })
    };

    let db = state.db.clone();
    let row_id_for_blocking = row_id.clone();
    let to_json_for_blocking = to_json.clone();
    let cc_json_for_blocking = cc_json.clone();
    let subject_for_blocking = validated.subject.clone();
    let body_text_for_blocking = validated.body_text.clone();
    let body_html_for_blocking = validated.body_html.clone();
    let attachments_rel_dir_for_blocking = attachments_rel_dir.clone();
    let recipient_hash_for_blocking = validated.recipient_hash.clone();
    let byte_size = validated.byte_size;
    let insert_res = tokio::task::spawn_blocking(move || -> anyhow::Result<()> {
        let conn = db.write().with_context(|| {
            format!(
                "open DuckDB at {} for relay queue insert",
                db.db_path().display()
            )
        })?;
        email_relay_queue::insert_queued(
            &conn,
            &row_id_for_blocking,
            RELAY_SUBMITTER_STOREFRONT,
            &to_json_for_blocking,
            cc_json_for_blocking.as_deref(),
            &subject_for_blocking,
            &body_text_for_blocking,
            body_html_for_blocking.as_deref(),
            attachments_rel_dir_for_blocking.as_deref(),
            &recipient_hash_for_blocking,
            byte_size,
            time::OffsetDateTime::now_utc(),
        )
    })
    .await;
    match insert_res {
        Ok(Ok(())) => {}
        Ok(Err(e)) => return internal_error("insert relay queue row", e),
        Err(join) => {
            return internal_error("relay queue insert task panicked", anyhow!("join: {join}"))
        }
    }

    // 7. Emit the `EmailRelayQueued` audit row. spawn_blocking for the
    //    DuckDB write; we don't await it before responding (operator-
    //    facing UX-fast, post-issue-async posture) — but we DO log
    //    on audit-write failure so a corrupted ledger surfaces in
    //    tracing.
    let deps = crate::email_relay_daemon::EmailRelayDaemonDeps {
        db_path: (*state.db_path).clone(),
        db: state.db.clone(),
        tenant: state.tenant.clone(),
        binary_hash: match state.binary_hash.wait() {
            Ok(b) => b,
            Err(e) => {
                tracing::warn!(
                    error = %e,
                    "binary_hash compute failed at email-relay accept; \
                     audit skipped (defensive — the row is queued)"
                );
                return (StatusCode::OK, Json(RelayAcceptedBody { audit_id: row_id }))
                    .into_response();
            }
        },
        operator_login: operator_login_for_audit(&state),
        seller_toml_path: match setup_seller_info::seller_toml_path_for_tenant(
            state.tenant.as_str(),
        ) {
            Ok(p) => p,
            Err(e) => return internal_error("resolve seller.toml path for relay audit", e),
        },
        secrets_cache: state.secrets_cache.clone(),
    };
    crate::email_relay_daemon::write_relay_audit(
        &deps,
        aberp_audit_ledger::EventKind::EmailRelayQueued,
        EmailRelayAuditPayload::queued(
            RELAY_SUBMITTER_STOREFRONT,
            &row_id,
            &validated.recipient_hash,
            &validated.subject,
            validated.byte_size,
        ),
    )
    .await;

    (StatusCode::OK, Json(RelayAcceptedBody { audit_id: row_id })).into_response()
}

/// `GET /api/email-relay/queue?state=queued|sending|sent|failed&limit=N`.
/// Read-only operator inspector (session-token gated). Returns rows
/// newest-first; default limit 100, max 500.
async fn handle_list_email_relay_queue(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(q): Query<std::collections::HashMap<String, String>>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let state_filter = match q.get("state").map(|s| s.as_str()) {
        Some("queued") => Some(email_relay_queue::QueueState::Queued),
        Some("sending") => Some(email_relay_queue::QueueState::Sending),
        Some("sent") => Some(email_relay_queue::QueueState::Sent),
        Some("failed") => Some(email_relay_queue::QueueState::Failed),
        Some(other) => {
            return (
                StatusCode::BAD_REQUEST,
                Json(serde_json::json!({
                    "error": "bad_state_filter",
                    "message": format!("unknown state `{other}`; allowed: queued/sending/sent/failed"),
                })),
            )
                .into_response();
        }
        None => None,
    };
    let limit = q
        .get("limit")
        .and_then(|s| s.parse::<usize>().ok())
        .unwrap_or(100)
        .min(500);
    let db = state.db.clone();
    let rows_res = tokio::task::spawn_blocking(move || -> anyhow::Result<Vec<_>> {
        let conn = db.read().with_context(|| {
            format!(
                "open DuckDB at {} for relay queue list",
                db.db_path().display()
            )
        })?;
        email_relay_queue::list_rows(&conn, state_filter, limit)
    })
    .await;
    let rows = match rows_res {
        Ok(Ok(r)) => r,
        Ok(Err(e)) => return internal_error("list relay queue rows", e),
        Err(join) => {
            return internal_error("relay queue list task panicked", anyhow!("join: {join}"))
        }
    };
    let wire: Vec<serde_json::Value> = rows
        .into_iter()
        .map(|r| {
            serde_json::json!({
                "id": r.id,
                "created_at": r.created_at,
                "submitter": r.submitter,
                "subject": r.subject,
                "state": r.state.as_str(),
                "attempt_n": r.attempt_n,
                "last_error": r.last_error,
                "sent_at": r.sent_at,
                "recipient_hash": r.recipient_hash,
                "byte_size": r.byte_size,
                "attachments_dir": r.attachments_dir,
                "has_html": r.body_html.is_some(),
                "to_count": serde_json::from_str::<Vec<String>>(&r.to_recipients_json)
                    .map(|v| v.len())
                    .unwrap_or(0),
            })
        })
        .collect();
    Json(serde_json::json!({ "rows": wire })).into_response()
}

/// `GET /api/email-relay/queue/:id`. Single-row read with full body
/// preview (subject + first 4 KiB of body_text) so the operator can
/// triage a failed row without round-tripping a separate route.
async fn handle_get_email_relay_row(
    headers: HeaderMap,
    State(state): State<AppState>,
    axum::extract::Path(id): axum::extract::Path<String>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let db = state.db.clone();
    let row_res = tokio::task::spawn_blocking(move || -> anyhow::Result<_> {
        let conn = db.read().with_context(|| {
            format!(
                "open DuckDB at {} for relay queue row",
                db.db_path().display()
            )
        })?;
        email_relay_queue::read_row(&conn, &id)
    })
    .await;
    let row = match row_res {
        Ok(Ok(Some(r))) => r,
        Ok(Ok(None)) => {
            return (
                StatusCode::NOT_FOUND,
                Json(error_body("row not found".to_string())),
            )
                .into_response()
        }
        Ok(Err(e)) => return internal_error("read relay queue row", e),
        Err(join) => {
            return internal_error("relay queue read task panicked", anyhow!("join: {join}"))
        }
    };
    let body_text_preview = if row.body_text.len() > 4096 {
        format!(
            "{}…[truncated, total {} bytes]",
            &row.body_text[..4096],
            row.body_text.len()
        )
    } else {
        row.body_text.clone()
    };
    let to_addrs: Vec<String> = serde_json::from_str(&row.to_recipients_json).unwrap_or_default();
    let cc_addrs: Vec<String> = row
        .cc_recipients_json
        .as_deref()
        .map(|s| serde_json::from_str(s).unwrap_or_default())
        .unwrap_or_default();
    Json(serde_json::json!({
        "id": row.id,
        "created_at": row.created_at,
        "submitter": row.submitter,
        "subject": row.subject,
        "state": row.state.as_str(),
        "attempt_n": row.attempt_n,
        "last_error": row.last_error,
        "sent_at": row.sent_at,
        "recipient_hash": row.recipient_hash,
        "byte_size": row.byte_size,
        "attachments_dir": row.attachments_dir,
        "has_html": row.body_html.is_some(),
        "to_count": to_addrs.len(),
        "cc_count": cc_addrs.len(),
        "body_text_preview": body_text_preview,
    }))
    .into_response()
}

/// Read the boot-cached operator login for audit-actor stamping. Used
/// by the email-relay handlers (they don't run inside `require_ready`
/// for the receive route — the relay endpoint is sister-service-auth,
/// not operator-auth — so we extract the login eagerly).
fn operator_login_for_audit(state: &AppState) -> String {
    let guard = state.boot_state.read();
    match guard {
        Ok(b) => match &*b {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
            ServeBootState::NeedsSetup => "system".to_string(),
        },
        Err(_) => "system".to_string(),
    }
}

