    fn sanity_prod_matching_tax_number_passes() {
        let report = sanity_check_environment(
            true,
            PROD_IDENTITY,
            Some("24904362-2-41"),
            true,
            false,
            true,
        );
        assert!(
            report.fatal.is_none(),
            "matching identity must not be fatal"
        );
    }

    /// A dev build skips the tax_number check entirely — any identity is
