    /// S197 / PR-197 — `Content-Disposition` filename for the AP XML
    /// download. Built from `<supplier_tax>_<invoice_number>.xml`;
    /// filesystem-reserved chars MUST be sanitised so the
    /// browser-saved file opens cleanly on every operator host
    /// (Windows refuses `/`, `:`, `*`, `?` in filenames; the
    /// supplier-issued invoice numbers carry `/` routinely per NAV
    /// convention).
    #[test]
    fn incoming_xml_filename_sanitises_reserved_chars() {
        assert_eq!(
            incoming_xml_filename("12345678", "SUP-2026/000001"),
            "12345678_SUP-2026_000001.xml",
        );
        assert_eq!(
            incoming_xml_filename("87654321", "INV\\2026:001"),
            "87654321_INV_2026_001.xml",
        );
        assert_eq!(
            incoming_xml_filename("11112222", "OK-2026-001"),
            "11112222_OK-2026-001.xml",
        );
    }

    /// S197 / PR-197 — `sanitize_filename_part` is the per-char
    /// transform. CLAUDE.md rule 5 — code (not model) handles this
    /// deterministic mapping; the test pins every reserved class.
    #[test]
    fn sanitize_filename_part_maps_every_reserved_class() {
        // Path separators.
        assert_eq!(sanitize_filename_part("a/b"), "a_b");
        assert_eq!(sanitize_filename_part("a\\b"), "a_b");
        // Windows-reserved metas.
        assert_eq!(
            sanitize_filename_part("a:b*c?d\"e<f>g|h"),
            "a_b_c_d_e_f_g_h"
        );
        // Control chars.
        assert_eq!(sanitize_filename_part("a\x00b\x1fc"), "a_b_c");
        // Unicode + dots pass through verbatim.
        assert_eq!(sanitize_filename_part("Árvíztűrő.2026"), "Árvíztűrő.2026");
    }

    #[test]
    fn derive_state_ladder() {
        // Pre-PR-23 ladder test preserved verbatim — every assertion
        // here still holds under the ADR-0036 §3 extended ladder
        // (the new labels are additions; no pre-PR-23 label
        // changed).
        let mut t = InvoiceTrace::default();
        assert_eq!(t.derive_state(), InvoiceState::Unknown);
        t.has_draft = true;
        assert_eq!(t.derive_state(), InvoiceState::Ready);
        t.has_submission_response = true;
        assert_eq!(t.derive_state(), InvoiceState::Submitted);
        t.last_ack_status = Some("RECEIVED".to_string());
        assert_eq!(t.derive_state(), InvoiceState::Submitted);
        t.last_ack_status = Some("SAVED".to_string());
        assert_eq!(t.derive_state(), InvoiceState::Finalized);
        t.last_ack_status = Some("ABORTED".to_string());
        assert_eq!(t.derive_state(), InvoiceState::Rejected);
        // Abandoned wins over every NAV terminal.
        t.has_marked_abandoned = true;
        assert_eq!(t.derive_state(), InvoiceState::Abandoned);
    }

    // ── PR-23 / ADR-0036 §8 — parameterized expected-label table ──
    //
    // The mirror invariant per ADR-0036 §1: for every state both
    // this ladder and `audit_query::stuck_precondition` can name,
    // the two MUST agree. Drift is the failure mode CLAUDE.md
    // rule 12 names; the parameterized table pins it loud.
    //
    // Test fixtures are duplicated from `audit_query.rs::tests`
    // per ADR-0036 §"Adversarial review" #1 (cross-module
    // `#[cfg(test)] pub(crate)` lift deferred until a third
    // module needs the same shape).

